def _resolve_application_paths():
    """Dev: project folder.
    Installed EXE: bundled data in install dir + user data (Characters, portraits, etc.)
    also under the install dir on C: (per user request for everything under the C: install folder).
    Previously used LOCALAPPDATA for user data to follow Windows conventions.
    """
    if getattr(sys, "frozen", False):
        bundle_dir = sys._MEIPASS
        install_dir = os.path.dirname(sys.executable)
        # Use install_dir for user data so Characters/portraits go next to the EXE
        # (e.g. C:\D&D Before v1.1\Characters\...) instead of AppData\Local.
        user_data_dir = install_dir
    else:
        bundle_dir = os.path.dirname(os.path.abspath(__file__))
        install_dir = bundle_dir
        user_data_dir = bundle_dir
    os.makedirs(user_data_dir, exist_ok=True)
    os.makedirs(os.path.join(user_data_dir, "Characters"), exist_ok=True)
    os.makedirs(os.path.join(user_data_dir, "Characters", "portraits"), exist_ok=True)
    os.makedirs(os.path.join(user_data_dir, "Characters", "sidebar_backgrounds"), exist_ok=True)
    os.makedirs(os.path.join(user_data_dir, "Theme BG"), exist_ok=True)
    return bundle_dir, install_dir, user_data_dir


BUNDLE_DIR, APP_DIR, SCRIPT_DIR = _resolve_application_paths()
HEALTH_ASSETS_DIR = os.path.join(SCRIPT_DIR, "assets")


def _resolve_app_icon_path():
    """Return the best on-disk icon for window/taskbar branding (.ico preferred on Windows)."""
    candidates = []
    for base in (BUNDLE_DIR, APP_DIR, SCRIPT_DIR):
        if sys.platform == "win32":
            candidates.extend([
                os.path.join(base, "icon.ico"),
                os.path.join(base, "Icon.ico"),
            ])
        candidates.extend([
            os.path.join(base, "icon.png"),
            os.path.join(base, "Icon.png"),
        ])
    for path in candidates:
        if os.path.isfile(path):
            return path
    return None


def apply_app_icon_to_window(window):
    """Apply D&D Before icon to any Tk/CTk window (replaces Python/CustomTkinter defaults)."""
    icon_path = _resolve_app_icon_path()
    if not icon_path:
        return
    try:
        if sys.platform == "win32" and icon_path.lower().endswith(".ico"):
            window.iconbitmap(default=icon_path)
            return
        if HAS_PIL and Image and ImageTk:
            photo = ImageTk.PhotoImage(Image.open(icon_path))
            window._app_icon_photo = photo
            window.iconphoto(True, photo)
    except Exception:
        pass


def _install_app_icon_hook():
    """Ensure every CTk root and popup uses our icon instead of CustomTkinter's default."""
    if getattr(_install_app_icon_hook, "_installed", False):
        return
    _install_app_icon_hook._installed = True

    _orig_ctk_init = ctk.CTk.__init__

    def _ctk_init(self, *args, **kwargs):
        _orig_ctk_init(self, *args, **kwargs)
        self.after_idle(lambda: apply_app_icon_to_window(self))

    ctk.CTk.__init__ = _ctk_init

    _orig_toplevel_init = ctk.CTkToplevel.__init__

    def _toplevel_init(self, *args, **kwargs):
        _orig_toplevel_init(self, *args, **kwargs)
        self.after_idle(lambda: apply_app_icon_to_window(self))

    ctk.CTkToplevel.__init__ = _toplevel_init


_install_app_icon_hook()

