class OverlayDropdownHelper:
    """Shared dismiss logic for floating overlay picker popups."""

    _owners = []
    _global_root = None
    _global_binds_installed = False

    @classmethod
    def register(cls, owner):
        cls.close_all_except(owner)
        if owner not in cls._owners:
            cls._owners.append(owner)
        cls._ensure_global_binds(owner)

    @classmethod
    def unregister(cls, owner):
        if owner in cls._owners:
            cls._owners.remove(owner)

    @classmethod
    def close_all(cls):
        for owner in list(cls._owners):
            try:
                owner._hide_dropdown()
            except (AttributeError, tk.TclError):
                pass

    @classmethod
    def close_all_except(cls, owner):
        for other in list(cls._owners):
            if other is not owner:
                try:
                    other._hide_dropdown()
                except (AttributeError, tk.TclError):
                    pass

    @classmethod
    def _binding_target(cls, owner):
        """Use the underlying tk widget; CTk's unbind_all is restricted."""
        top = owner.winfo_toplevel()
        return getattr(top, "tk", top)

    @classmethod
    def _ensure_global_binds(cls, owner):
        root = cls._binding_target(owner)
        if cls._global_binds_installed and cls._global_root == root:
            return
        cls._global_root = root
        # Install once and leave bound; handlers no-op when no overlays are open.
        root.bind_all("<Button-1>", cls._on_global_pointer, add="+")
        root.bind_all("<ButtonRelease-1>", cls._on_global_pointer, add="+")
        root.bind_all("<Escape>", cls._on_global_escape, add="+")
        cls._global_binds_installed = True

    @classmethod
    def _on_global_pointer(cls, event):
        for owner in list(cls._owners):
            try:
                if not owner._dropdown_is_open():
                    continue
                if owner._event_targets_owner(event):
                    continue
                owner.after_idle(owner._hide_dropdown)
            except (AttributeError, tk.TclError):
                continue

    @classmethod
    def _on_global_escape(cls, _event):
        cls.close_all()

    @staticmethod
    def destroy_toplevel(dropdown):
        if not dropdown:
            return
        try:
            if not dropdown.winfo_exists():
                return
            try:
                dropdown.grab_release()
            except tk.TclError:
                pass
            dropdown.withdraw()
            dropdown.update_idletasks()
            dropdown.destroy()
        except tk.TclError:
            pass

    @staticmethod
    def widget_in_toplevel(widget, toplevel):
        if widget is None or toplevel is None:
            return False
        try:
            if not toplevel.winfo_exists():
                return False
            current = widget
            while current is not None:
                if current == toplevel:
                    return True
                try:
                    current = current.master
                except (AttributeError, tk.TclError):
                    break
            return widget.winfo_toplevel() == toplevel
        except tk.TclError:
            return False

    @staticmethod
    def bind_option_button(btn, value, handler):
        btn.configure(command=lambda v=value: handler(v))
        btn.bind(
            "<ButtonRelease-1>",
            lambda _e, v=value: btn.after(0, lambda: handler(v)),
            add="+",
        )


class FeatAutocompleteCombo(ctk.CTkFrame):
    """Searchable overlay feat picker.

    - Default dropdown (no text / arrow click): only shows feats for which prereqs are met.
    - Typing: searches the full list (or pool) and shows all name matches, including unmet
      prereqs (greyed, still selectable).
    Ability prereqs are evaluated against live total scores (racial + magic items + ASI + etc.).
    """

    def __init__(
        self, master, sheet, width=280, feat_pool=None, on_select=None,
        general_feat_index=None, **kwargs,
    ):
        super().__init__(master, fg_color="transparent", **kwargs)
        self.sheet = sheet
        self.feat_pool = list(feat_pool) if feat_pool else None
        self.on_select = on_select
        self.general_feat_index = general_feat_index
        self._panel_width = width
        self._dropdown = None
        self._overlay_selecting = False
        self._suppress_dropdown_reopen = False

        self._input_row = ctk.CTkFrame(self, fg_color="transparent")
        self._input_row.pack(fill="x")
        self.entry = ctk.CTkEntry(self._input_row, width=max(120, width - 34))
        self.entry.pack(side="left", fill="x", expand=True)
        self.entry.bind("<KeyRelease>", self._on_key_release)
        self.entry.bind("<Return>", self._on_return)
        self.entry.bind("<Escape>", lambda _e: self._hide_dropdown())
        self.entry.bind("<Down>", self._on_arrow_down)
        self.entry.bind("<FocusOut>", self._on_focus_out)

        self._arrow_btn = ctk.CTkButton(
            self._input_row, text="▾", width=30, height=28,
            fg_color="#3a3a3a", hover_color="#555555",
            command=self._toggle_dropdown,
        )
        self._arrow_btn.pack(side="left", padx=(4, 0))
        self.bind("<Destroy>", self._on_destroy)

    def _widget_alive(self):
        try:
            return bool(self.winfo_exists()) and bool(self.entry.winfo_exists())
        except tk.TclError:
            return False

    def _on_destroy(self, _event=None):
        self._hide_dropdown()

    def _on_focus_out(self, _event=None):
        self.after(120, self._hide_if_focus_lost)

    def _hide_if_focus_lost(self):
        if not self._dropdown_is_open():
            return
        try:
            focus = self.focus_get()
        except tk.TclError:
            focus = None
        if focus is self.entry:
            return
        if self._dropdown and focus and OverlayDropdownHelper.widget_in_toplevel(focus, self._dropdown):
            return
        self._hide_dropdown()

    def get(self):
        if not self._widget_alive():
            return ""
        try:
            return self.entry.get().strip()
        except tk.TclError:
            return ""

    def set(self, value):
        if not self._widget_alive():
            return
        try:
            self.entry.delete(0, "end")
            if value:
                self.entry.insert(0, str(value))
        except tk.TclError:
            pass

    def bind(self, sequence, func, add=None):
        if add is not None:
            return self.entry.bind(sequence, func, add=add)
        return self.entry.bind(sequence, func)

    def _on_select(self, feat_name):
        if self._overlay_selecting:
            return
        self._overlay_selecting = True
        self._hide_dropdown()
        self.set(feat_name)
        if self.on_select:
            self.after_idle(lambda name=feat_name: self._run_on_select(name))
        self.after(100, lambda: setattr(self, "_overlay_selecting", False))

    def _run_on_select(self, feat_name):
        if not self.on_select:
            return
        try:
            self.on_select(feat_name)
        except Exception:
            pass

    def _on_return(self, _event):
        matches = self.sheet._get_filtered_feat_options(
            self.get(), self.feat_pool, self.general_feat_index,
        )
        if matches:
            # Pick the top result. During no-search this is always eligible (list filtered).
            # During search, eligibles sort first; if only unmet match the text, top one
            # (unmet) will be selected -- this is intentional so typed search can pick any.
            self._on_select(matches[0][0])
            return
        self._hide_dropdown()

    def _on_arrow_down(self, _event):
        self._show_dropdown()
        return "break"

    def _on_key_release(self, _event):
        if not self._widget_alive():
            return
        if self._suppress_dropdown_reopen:
            return
        self._show_dropdown()

    def _dropdown_is_open(self):
        if not self._dropdown:
            return False
        try:
            return bool(self._dropdown.winfo_exists())
        except tk.TclError:
            return False

    def _toggle_dropdown(self):
        if not self._widget_alive():
            return
        if self._dropdown_is_open():
            self._hide_dropdown()
        else:
            try:
                self.entry.focus_set()
            except tk.TclError:
                return
            self._show_dropdown()

    def _point_in_widget(self, widget, x_root, y_root):
        if widget is None:
            return False
        try:
            if not widget.winfo_exists():
                return False
            wx = widget.winfo_rootx()
            wy = widget.winfo_rooty()
            ww = widget.winfo_width()
            wh = widget.winfo_height()
            return wx <= x_root < wx + ww and wy <= y_root < wy + wh
        except tk.TclError:
            return False

    def _event_targets_owner(self, event):
        widget = getattr(event, "widget", None)
        if self._dropdown and OverlayDropdownHelper.widget_in_toplevel(widget, self._dropdown):
            return True
        if self._dropdown and self._point_in_widget(self._dropdown, event.x_root, event.y_root):
            return True
        return self._point_in_widget(self, event.x_root, event.y_root)

    def _hide_dropdown(self):
        dropdown = self._dropdown
        self._dropdown = None
        OverlayDropdownHelper.unregister(self)
        OverlayDropdownHelper.destroy_toplevel(dropdown)
        self._suppress_dropdown_reopen = True
        self.after(150, lambda: setattr(self, "_suppress_dropdown_reopen", False))

    def _show_dropdown(self):
        if not self._widget_alive():
            return
        try:
            matches = self.sheet._get_filtered_feat_options(
                self.get(), self.feat_pool, self.general_feat_index,
            )
        except Exception:
            return
        if not matches:
            self._hide_dropdown()
            return

        OverlayDropdownHelper.close_all_except(self)
        self._hide_dropdown()
        try:
            visible_rows = min(len(matches), 8)
            scroll_height = min(FEAT_DROPDOWN_MAX_HEIGHT, visible_rows * 30 + 8)
            overlay_height = scroll_height + 10

            self.update_idletasks()
            overlay_width = max(self.winfo_width(), self._panel_width)
            x = self.winfo_rootx()
            y = self.winfo_rooty() + self.winfo_height() + 2

            screen_w = self.winfo_screenwidth()
            screen_h = self.winfo_screenheight()
            x = max(0, min(x, screen_w - overlay_width))
            if y + overlay_height > screen_h:
                y = max(0, self.winfo_rooty() - overlay_height - 2)

            self._dropdown = ctk.CTkToplevel(self.winfo_toplevel())
            self._dropdown.withdraw()
            self._dropdown.overrideredirect(True)
            self._dropdown.attributes("-topmost", True)
            self._dropdown.configure(fg_color="#2F2F2F")

            panel = ctk.CTkFrame(self._dropdown, fg_color="#2F2F2F", corner_radius=6)
            panel.pack(fill="both", expand=True, padx=1, pady=1)

            scroll = ctk.CTkScrollableFrame(
                panel, fg_color="#2F2F2F", width=overlay_width - 6, height=scroll_height,
            )
            scroll.pack(fill="both", expand=True, padx=2, pady=2)

            for feat_name, eligible in matches:
                btn = ctk.CTkButton(
                    scroll,
                    text=feat_name,
                    anchor="w",
                    height=28,
                    fg_color="#2F2F2F",
                    hover_color="#3a3a3a" if eligible else "#2a2a2a",
                    text_color="#f0f0f0" if eligible else "#888888",
                )
                btn.pack(fill="x", padx=2, pady=1)
                OverlayDropdownHelper.bind_option_button(btn, feat_name, self._on_select)

            self._dropdown.geometry(f"{overlay_width}x{overlay_height}+{x}+{y}")
            self._dropdown.deiconify()
            self._dropdown.lift()
            OverlayDropdownHelper.register(self)
        except tk.TclError:
            self._dropdown = None
            OverlayDropdownHelper.unregister(self)


class InventoryHoverDropdown(ctk.CTkFrame):
    """Non-searchable overlay dropdown for inventory-filtered options.

    Click the field or arrow to open a floating hover list positioned over the
    UI (does not expand the surrounding layout). Supports get(), set(), and
    configure(command=..., values=...).
    """

    def __init__(self, master, options=None, width=280, command=None, **kwargs):
        super().__init__(master, fg_color="transparent", **kwargs)
        self.options = list(options) if options is not None else []
        self.command = command
        self._value = ""
        self._panel_width = width
        self._dropdown = None
        self._overlay_selecting = False

        self._input_row = ctk.CTkFrame(self, fg_color="transparent")
        self._input_row.pack(fill="x")

        self.display_btn = ctk.CTkButton(
            self._input_row,
            text="(none)",
            anchor="w",
            width=max(120, width - 34),
            height=28,
            fg_color="#343638",
            hover_color="#3a3a3a",
            text_color="#888888",
            command=self._toggle_dropdown,
        )
        self.display_btn.pack(side="left", fill="x", expand=True)

        self._arrow_btn = ctk.CTkButton(
            self._input_row, text="▾", width=30, height=28,
            fg_color="#3a3a3a", hover_color="#555555",
            command=self._toggle_dropdown,
        )
        self._arrow_btn.pack(side="left", padx=(4, 0))
        self.bind("<Destroy>", self._on_destroy)

    def _widget_alive(self):
        try:
            return bool(self.winfo_exists()) and bool(self.display_btn.winfo_exists())
        except tk.TclError:
            return False

    def _on_destroy(self, _event=None):
        self._hide_dropdown()

    def get(self):
        return str(self._value or "").strip()

    def set(self, value):
        self._value = str(value or "").strip()
        self._update_display()

    def configure(self, **kwargs):
        if "command" in kwargs:
            self.command = kwargs["command"]
        if "values" in kwargs:
            self.options = list(kwargs["values"] or [])

    def _update_display(self):
        if not self._widget_alive():
            return
        if self._value:
            self.display_btn.configure(text=self._value, text_color="#f0f0f0")
        else:
            self.display_btn.configure(text="(none)", text_color="#888888")

    def _on_select(self, item_name):
        if self._overlay_selecting:
            return
        self._overlay_selecting = True
        self._hide_dropdown()
        self.set(item_name)
        if self.command:
            self.after_idle(lambda value=item_name: self._run_command(value))
        self.after(100, lambda: setattr(self, "_overlay_selecting", False))

    def _run_command(self, item_name):
        if not self.command:
            return
        try:
            self.command(item_name)
        except Exception:
            pass

    def _dropdown_is_open(self):
        if not self._dropdown:
            return False
        try:
            return bool(self._dropdown.winfo_exists())
        except tk.TclError:
            return False

    def _toggle_dropdown(self):
        if not self._widget_alive():
            return
        if self._dropdown_is_open():
            self._hide_dropdown()
        else:
            self._show_dropdown()

    def _point_in_widget(self, widget, x_root, y_root):
        if widget is None:
            return False
        try:
            if not widget.winfo_exists():
                return False
            wx = widget.winfo_rootx()
            wy = widget.winfo_rooty()
            ww = widget.winfo_width()
            wh = widget.winfo_height()
            return wx <= x_root < wx + ww and wy <= y_root < wy + wh
        except tk.TclError:
            return False

    def _event_targets_owner(self, event):
        widget = getattr(event, "widget", None)
        if self._dropdown and OverlayDropdownHelper.widget_in_toplevel(widget, self._dropdown):
            return True
        if self._dropdown and self._point_in_widget(self._dropdown, event.x_root, event.y_root):
            return True
        return self._point_in_widget(self, event.x_root, event.y_root)

    def _hide_dropdown(self):
        dropdown = self._dropdown
        self._dropdown = None
        OverlayDropdownHelper.unregister(self)
        OverlayDropdownHelper.destroy_toplevel(dropdown)

    def _show_dropdown(self):
        if not self._widget_alive():
            return
        options = list(self.options or [])
        if not options:
            self._hide_dropdown()
            return

        OverlayDropdownHelper.close_all_except(self)
        self._hide_dropdown()
        try:
            visible_rows = min(len(options), 10)
            scroll_height = min(300, visible_rows * 26 + 8)
            overlay_height = scroll_height + 10

            self.update_idletasks()
            overlay_width = max(self.winfo_width(), self._panel_width)
            x = self.winfo_rootx()
            y = self.winfo_rooty() + self.winfo_height() + 2

            screen_w = self.winfo_screenwidth()
            screen_h = self.winfo_screenheight()
            x = max(0, min(x, screen_w - overlay_width))
            if y + overlay_height > screen_h:
                y = max(0, self.winfo_rooty() - overlay_height - 2)

            self._dropdown = ctk.CTkToplevel(self.winfo_toplevel())
            self._dropdown.withdraw()
            self._dropdown.overrideredirect(True)
            self._dropdown.attributes("-topmost", True)
            self._dropdown.configure(fg_color="#2F2F2F")

            panel = ctk.CTkFrame(self._dropdown, fg_color="#2F2F2F", corner_radius=6)
            panel.pack(fill="both", expand=True, padx=1, pady=1)

            scroll = ctk.CTkScrollableFrame(
                panel, fg_color="#2F2F2F", width=overlay_width - 6, height=scroll_height,
            )
            scroll.pack(fill="both", expand=True, padx=2, pady=2)

            for item_name in options:
                btn = ctk.CTkButton(
                    scroll,
                    text=item_name or "(none)",
                    anchor="w",
                    height=24,
                    fg_color="#2F2F2F",
                    hover_color="#3a3a3a",
                )
                btn.pack(fill="x", padx=2, pady=1)
                OverlayDropdownHelper.bind_option_button(btn, item_name, self._on_select)

            self._dropdown.geometry(f"{overlay_width}x{overlay_height}+{x}+{y}")
            self._dropdown.deiconify()
            self._dropdown.lift()
            OverlayDropdownHelper.register(self)
        except tk.TclError:
            self._dropdown = None
            OverlayDropdownHelper.unregister(self)


class InventoryGearAutocompleteCombo(ctk.CTkFrame):
    """Searchable overlay picker for owned inventory gear (weapons, armor, shields)."""

    def __init__(
        self, master, sheet, width=150, variable=None, options=None,
        on_select=None, **kwargs,
    ):
        self.weapon_slot_index = kwargs.pop("weapon_slot_index", None)
        self.gear_type = kwargs.pop("gear_type", None)
        page_size = kwargs.pop("page_size", INVENTORY_GEAR_PAGE_SIZE)
        super().__init__(master, fg_color="transparent", **kwargs)
        self.sheet = sheet
        self.options = list(options) if options is not None else []
        self.on_select = on_select
        self._panel_width = width
        self._page_size = max(1, int(page_size or INVENTORY_GEAR_PAGE_SIZE))
        self._dropdown = None
        self._overlay_selecting = False
        self._suppress_dropdown_reopen = False
        self._dropdown_page = 0
        self._dropdown_matches = []

        self._input_row = ctk.CTkFrame(self, fg_color="transparent")
        self._input_row.pack(fill="x")
        self.entry = ctk.CTkEntry(
            self._input_row, width=max(120, width - 34), textvariable=variable,
        )
        self.entry.pack(side="left", fill="x", expand=True)
        self.entry.bind("<KeyRelease>", self._on_key_release)
        self.entry.bind("<Return>", self._on_return)
        self.entry.bind("<Escape>", lambda _e: self._hide_dropdown())
        self.entry.bind("<Down>", self._on_arrow_down)
        self.entry.bind("<FocusOut>", self._on_focus_out)

        self._arrow_btn = ctk.CTkButton(
            self._input_row, text="▾", width=30, height=28,
            fg_color="#3a3a3a", hover_color="#555555",
            command=self._toggle_dropdown,
        )
        self._arrow_btn.pack(side="left", padx=(4, 0))
        self.bind("<Destroy>", self._on_destroy)

    def _widget_alive(self):
        try:
            return bool(self.winfo_exists()) and bool(self.entry.winfo_exists())
        except tk.TclError:
            return False

    def _on_destroy(self, _event=None):
        self._hide_dropdown()

    def _on_focus_out(self, _event=None):
        self.after(120, self._hide_if_focus_lost)

    def _hide_if_focus_lost(self):
        if not self._dropdown_is_open():
            return
        try:
            focus = self.focus_get()
        except tk.TclError:
            focus = None
        if focus is self.entry:
            return
        if self._dropdown and focus and OverlayDropdownHelper.widget_in_toplevel(focus, self._dropdown):
            return
        self._hide_dropdown()

    def get(self):
        if not self._widget_alive():
            return ""
        try:
            return self.entry.get().strip()
        except tk.TclError:
            return ""

    def set(self, value):
        if not self._widget_alive():
            return
        try:
            self.entry.delete(0, "end")
            if value:
                self.entry.insert(0, str(value))
        except tk.TclError:
            pass

    def bind(self, sequence, func, add=None):
        if add is not None:
            return self.entry.bind(sequence, func, add=add)
        return self.entry.bind(sequence, func)

    def configure(self, **kwargs):
        if "values" in kwargs:
            self.options = list(kwargs["values"] or [])
            self._dropdown_page = 0
            self.refresh_option_list()
        if "command" in kwargs:
            self.on_select = kwargs["command"]

    def refresh_option_list(self):
        """Refresh open overlay matches from the latest owned-inventory gear list."""
        self._dropdown_page = 0
        if not self._dropdown_is_open():
            return
        matches = self._filtered_matches()
        if not matches:
            self._hide_dropdown()
            return
        self._dropdown_matches = matches
        self._render_dropdown_page()

    def _resolve_options(self):
        sheet = getattr(self, "sheet", None)
        if sheet is None:
            return list(self.options or [])
        slot_idx = getattr(self, "weapon_slot_index", None)
        if slot_idx is not None and hasattr(sheet, "_weapon_dropdown_values_for_slot"):
            try:
                return sheet._weapon_dropdown_values_for_slot(slot_idx)
            except Exception:
                pass
        gear_type = getattr(self, "gear_type", None)
        if gear_type == "armor" and hasattr(sheet, "_armor_dropdown_values"):
            try:
                return sheet._armor_dropdown_values()
            except Exception:
                pass
        if gear_type == "shield" and hasattr(sheet, "_shield_dropdown_values"):
            try:
                return sheet._shield_dropdown_values()
            except Exception:
                pass
        return list(self.options or [])

    def _filtered_matches(self):
        options = self._resolve_options()
        try:
            return self.sheet._get_filtered_weapon_options(self.get(), options)
        except Exception:
            return options

    def _on_select(self, weapon_name):
        if self._overlay_selecting:
            return
        self._overlay_selecting = True
        self._hide_dropdown()
        self.set(weapon_name)
        if self.on_select and str(weapon_name or "").strip():
            self.after_idle(lambda name=weapon_name: self._run_on_select(name))
        self.after(100, lambda: setattr(self, "_overlay_selecting", False))

    def _run_on_select(self, weapon_name):
        if not self.on_select:
            return
        try:
            self.on_select(weapon_name)
        except Exception:
            pass

    def _on_return(self, _event):
        matches = self._filtered_matches()
        if matches:
            self._on_select(matches[0])
            return
        self._hide_dropdown()

    def _on_arrow_down(self, _event):
        self._show_dropdown()
        return "break"

    def _on_key_release(self, _event):
        if not self._widget_alive():
            return
        if self._suppress_dropdown_reopen:
            return
        self._dropdown_page = 0
        self._show_dropdown()

    def _dropdown_is_open(self):
        if not self._dropdown:
            return False
        try:
            return bool(self._dropdown.winfo_exists())
        except tk.TclError:
            return False

    def _toggle_dropdown(self):
        if not self._widget_alive():
            return
        if self._dropdown_is_open():
            self._hide_dropdown()
        else:
            try:
                self.entry.focus_set()
            except tk.TclError:
                return
            self._dropdown_page = 0
            self._show_dropdown()

    def _point_in_widget(self, widget, x_root, y_root):
        if widget is None:
            return False
        try:
            if not widget.winfo_exists():
                return False
            wx = widget.winfo_rootx()
            wy = widget.winfo_rooty()
            ww = widget.winfo_width()
            wh = widget.winfo_height()
            return wx <= x_root < wx + ww and wy <= y_root < wy + wh
        except tk.TclError:
            return False

    def _event_targets_owner(self, event):
        widget = getattr(event, "widget", None)
        if self._dropdown and OverlayDropdownHelper.widget_in_toplevel(widget, self._dropdown):
            return True
        if self._dropdown and self._point_in_widget(self._dropdown, event.x_root, event.y_root):
            return True
        return self._point_in_widget(self, event.x_root, event.y_root)

    def _hide_dropdown(self):
        dropdown = self._dropdown
        self._dropdown = None
        self._dropdown_matches = []
        OverlayDropdownHelper.unregister(self)
        OverlayDropdownHelper.destroy_toplevel(dropdown)
        self._suppress_dropdown_reopen = True
        self.after(150, lambda: setattr(self, "_suppress_dropdown_reopen", False))

    def _set_dropdown_page(self, page_index):
        self._dropdown_page = max(0, int(page_index or 0))
        self._render_dropdown_page()

    def _render_dropdown_page(self):
        if not self._dropdown_is_open():
            return
        try:
            scroll = self._dropdown_scroll
            pager = self._dropdown_pager
        except AttributeError:
            return
        for w in scroll.winfo_children():
            w.destroy()
        for w in pager.winfo_children():
            w.destroy()

        matches = self._dropdown_matches
        if not matches:
            self._hide_dropdown()
            return

        total_pages = max(1, (len(matches) + self._page_size - 1) // self._page_size)
        if self._dropdown_page >= total_pages:
            self._dropdown_page = total_pages - 1
        start = self._dropdown_page * self._page_size
        page_items = matches[start:start + self._page_size]

        for item_name in page_items:
            btn = ctk.CTkButton(
                scroll, text=item_name, anchor="w", height=26,
                fg_color="#2F2F2F", hover_color="#3a3a3a",
            )
            btn.pack(fill="x", padx=2, pady=1)
            OverlayDropdownHelper.bind_option_button(btn, item_name, self._on_select)

        if total_pages > 1:
            for page_i in range(total_pages):
                fg = "#c77626" if page_i == self._dropdown_page else "#3a3a3a"
                ctk.CTkButton(
                    pager, text=str(page_i + 1), width=28, height=24,
                    fg_color=fg, hover_color="#555555",
                    command=lambda p=page_i: self._set_dropdown_page(p),
                ).pack(side="left", padx=2, pady=2)

    def _show_dropdown(self):
        if not self._widget_alive():
            return
        matches = self._filtered_matches()
        if not matches:
            self._hide_dropdown()
            return

        OverlayDropdownHelper.close_all_except(self)
        self._hide_dropdown()
        self._dropdown_matches = matches
        try:
            visible_rows = min(len(matches), self._page_size)
            scroll_height = min(WEAPON_DROPDOWN_MAX_HEIGHT, visible_rows * 28 + 8)
            pager_height = 34 if len(matches) > self._page_size else 0
            overlay_height = scroll_height + pager_height + 10

            self.update_idletasks()
            overlay_width = max(self.winfo_width(), self._panel_width)
            x = self.winfo_rootx()
            y = self.winfo_rooty() + self.winfo_height() + 2

            screen_w = self.winfo_screenwidth()
            screen_h = self.winfo_screenheight()
            x = max(0, min(x, screen_w - overlay_width))
            if y + overlay_height > screen_h:
                y = max(0, self.winfo_rooty() - overlay_height - 2)

            self._dropdown = ctk.CTkToplevel(self.winfo_toplevel())
            self._dropdown.withdraw()
            self._dropdown.overrideredirect(True)
            self._dropdown.attributes("-topmost", True)
            self._dropdown.configure(fg_color="#2F2F2F")

            self._dropdown_panel = ctk.CTkFrame(self._dropdown, fg_color="#2F2F2F", corner_radius=6)
            self._dropdown_panel.pack(fill="both", expand=True, padx=1, pady=1)

            self._dropdown_scroll = ctk.CTkScrollableFrame(
                self._dropdown_panel, fg_color="#2F2F2F",
                width=overlay_width - 6, height=scroll_height,
            )
            self._dropdown_scroll.pack(fill="both", expand=True, padx=2, pady=(2, 0))

            self._dropdown_pager = ctk.CTkFrame(self._dropdown_panel, fg_color="transparent")
            if pager_height:
                self._dropdown_pager.pack(fill="x", padx=4, pady=(0, 2))

            self._render_dropdown_page()

            self._dropdown.geometry(f"{overlay_width}x{overlay_height}+{x}+{y}")
            self._dropdown.deiconify()
            self._dropdown.lift()
            OverlayDropdownHelper.register(self)
        except tk.TclError:
            self._dropdown = None
            OverlayDropdownHelper.unregister(self)


WeaponAutocompleteCombo = InventoryGearAutocompleteCombo


class SpellAutocompleteCombo(ctk.CTkFrame):
    """Searchable spell picker — dropdown activates after 3+ typed characters."""

    MIN_SEARCH_LEN = 3

    def __init__(self, master, sheet, width=420, on_select=None, **kwargs):
        super().__init__(master, fg_color="transparent", **kwargs)
        self.sheet = sheet
        self.on_select = on_select
        self._panel_width = width
        self._dropdown = None
        self._overlay_selecting = False
        self._suppress_dropdown_reopen = False

        self._input_row = ctk.CTkFrame(self, fg_color="transparent")
        self._input_row.pack(fill="x")
        self.entry = ctk.CTkEntry(self._input_row, width=max(120, width - 34))
        self.entry.pack(side="left", fill="x", expand=True)
        self.entry.bind("<KeyRelease>", self._on_key_release)
        self.entry.bind("<Return>", self._on_return)
        self.entry.bind("<Escape>", lambda _e: self._hide_dropdown())
        self.entry.bind("<Down>", self._on_arrow_down)
        self.entry.bind("<FocusOut>", self._on_focus_out)

        self._arrow_btn = ctk.CTkButton(
            self._input_row, text="▾", width=30, height=28,
            fg_color="#3a3a3a", hover_color="#555555",
            command=self._toggle_dropdown,
        )
        self._arrow_btn.pack(side="left", padx=(4, 0))
        self.bind("<Destroy>", self._on_destroy)

    def _widget_alive(self):
        try:
            return bool(self.winfo_exists()) and bool(self.entry.winfo_exists())
        except tk.TclError:
            return False

    def _on_destroy(self, _event=None):
        self._hide_dropdown()

    def _on_focus_out(self, _event=None):
        self.after(120, self._hide_if_focus_lost)

    def _hide_if_focus_lost(self):
        if not self._dropdown_is_open():
            return
        try:
            focus = self.focus_get()
        except tk.TclError:
            focus = None
        if focus is self.entry:
            return
        if self._dropdown and focus and OverlayDropdownHelper.widget_in_toplevel(focus, self._dropdown):
            return
        self._hide_dropdown()

    def get(self):
        if not self._widget_alive():
            return ""
        try:
            return self.entry.get().strip()
        except tk.TclError:
            return ""

    def set(self, value):
        if not self._widget_alive():
            return
        try:
            self.entry.delete(0, "end")
            if value:
                self.entry.insert(0, str(value))
        except tk.TclError:
            pass

    def _filter_spells(self, query):
        q = str(query or "").strip()
        if len(q) < self.MIN_SEARCH_LEN:
            return []
        folded = q.lower()
        return [
            name for name in self.sheet._sorted_dropdown(self.sheet.spells_db.keys())
            if folded in name.lower()
        ][:80]

    def _on_select(self, spell_name):
        if self._overlay_selecting:
            return
        self._overlay_selecting = True
        self._hide_dropdown()
        self.set(spell_name)
        if self.on_select:
            self.after_idle(lambda name=spell_name: self._run_on_select(name))
        self.after(100, lambda: setattr(self, "_overlay_selecting", False))

    def _run_on_select(self, spell_name):
        if not self.on_select:
            return
        try:
            self.on_select(spell_name)
        except Exception:
            pass

    def _on_return(self, _event):
        matches = self._filter_spells(self.get())
        if matches:
            self._on_select(matches[0])
            return
        self._hide_dropdown()

    def _on_arrow_down(self, _event):
        self._show_dropdown()
        return "break"

    def _on_key_release(self, _event):
        if not self._widget_alive() or self._suppress_dropdown_reopen:
            return
        self._show_dropdown()

    def _dropdown_is_open(self):
        if not self._dropdown:
            return False
        try:
            return bool(self._dropdown.winfo_exists())
        except tk.TclError:
            return False

    def _toggle_dropdown(self):
        if not self._widget_alive():
            return
        if self._dropdown_is_open():
            self._hide_dropdown()
        else:
            try:
                self.entry.focus_set()
            except tk.TclError:
                return
            self._show_dropdown()

    def _hide_dropdown(self):
        dropdown = self._dropdown
        self._dropdown = None
        OverlayDropdownHelper.unregister(self)
        OverlayDropdownHelper.destroy_toplevel(dropdown)
        self._suppress_dropdown_reopen = True
        self.after(150, lambda: setattr(self, "_suppress_dropdown_reopen", False))

    def _show_dropdown(self):
        if not self._widget_alive():
            return
        matches = self._filter_spells(self.get())
        if not matches:
            self._hide_dropdown()
            return

        OverlayDropdownHelper.close_all_except(self)
        self._hide_dropdown()
        try:
            x = self.entry.winfo_rootx()
            y = self.entry.winfo_rooty() + self.entry.winfo_height()
            overlay_width = max(self._panel_width, self.entry.winfo_width() + 34)
            row_height = 26
            visible_rows = min(len(matches), 10)
            overlay_height = visible_rows * row_height + 8

            self._dropdown = tk.Toplevel(self)
            self._dropdown.withdraw()
            self._dropdown.overrideredirect(True)
            self._dropdown.attributes("-topmost", True)

            list_frame = tk.Frame(self._dropdown, bg="#2b2b2b", highlightthickness=1, highlightbackground="#555555")
            list_frame.pack(fill="both", expand=True)

            for spell_name in matches[:visible_rows]:
                row = tk.Label(
                    list_frame, text=spell_name, anchor="w", bg="#2b2b2b", fg="#DCE4EE",
                    font=("Segoe UI", 11), padx=8, pady=4, cursor="hand2",
                )
                row.pack(fill="x")
                row.bind(
                    "<Button-1>",
                    lambda _e, name=spell_name: self._on_select(name),
                )
                row.bind("<Enter>", lambda _e, lbl=row: lbl.configure(bg="#3a3a3a"))
                row.bind("<Leave>", lambda _e, lbl=row: lbl.configure(bg="#2b2b2b"))

            self._dropdown.geometry(f"{overlay_width}x{overlay_height}+{x}+{y}")
            self._dropdown.deiconify()
            self._dropdown.lift()
            OverlayDropdownHelper.register(self)
        except tk.TclError:
            self._dropdown = None
            OverlayDropdownHelper.unregister(self)


