    def _maximize_startup_window(self):
        """Open in windowed mode, maximized to fill the current screen."""
        self.root.update_idletasks()
        try:
            self.root.state("zoomed")
        except Exception:
            screen_w = self.root.winfo_screenwidth()
            screen_h = self.root.winfo_screenheight()
            self.root.geometry(f"{screen_w}x{screen_h}+0+0")

    def _toggle_window_maximize(self, event=None):
        """Escape toggles between maximized and restored window size."""
        if self.root.state() == "zoomed":
            self.root.state("normal")
        else:
            self.root.state("zoomed")

    def create_gui(self):
        """Build the main GUI layout with sidebar navigation"""
        nav_button_width = 180
        sidebar_width = nav_button_width + 16

        # Sidebar
        sidebar = ctk.CTkFrame(self.root, width=sidebar_width, corner_radius=0)
        sidebar.pack(side="left", fill="y")
        sidebar.pack_propagate(False)

        # Background canvas for custom local sidebar image (placed first so packed content draws on top)
        self.sidebar = sidebar  # keep ref for refresh
        self.sidebar_bg_canvas = tk.Canvas(
            sidebar, highlightthickness=0, bd=0, bg="#1f1f1f"
        )
        self.sidebar_bg_canvas.place(x=0, y=0, relwidth=1, relheight=1)
        # Bind resize to refresh bg image scaling
        sidebar.bind("<Configure>", lambda e: self.root.after_idle(self._refresh_sidebar_background))

        # Hamburger menu button at the top of the sidebar (small, like bottom toolbar buttons)
        self.hamburger_btn = ctk.CTkButton(
            sidebar, text="☰", width=40, height=36,
            fg_color="#3a3a3a", hover_color="#555555",
            font=ctk.CTkFont(size=18, weight="bold"),
            command=self._show_hamburger_menu
        )
        self.hamburger_btn.pack(pady=(6, 2), padx=8)

        # "Character" label removed per request

        # Navigation buttons
        self.nav_buttons = []
        for page in ["Stats", "Inventory", "Combat"]:
            btn = ctk.CTkButton(sidebar, text=page, width=nav_button_width, height=45, 
                                fg_color=getattr(self, 'primary_button_color', '#c77626'),
                                command=lambda p=page: self.switch_page(p))
            btn.pack(pady=8, padx=8)
            self.nav_buttons.append(btn)

        # Spells + Buffs split half-width on same line (per request)
        half_w = 86
        spells_buffs_row = ctk.CTkFrame(sidebar, fg_color="transparent")
        spells_buffs_row.pack(pady=2, padx=8)
        btn_spells = ctk.CTkButton(
            spells_buffs_row, text="Spells", width=half_w, height=45,
            fg_color=getattr(self, 'primary_button_color', '#c77626'),
            command=lambda: self.switch_page("Spells")
        )
        btn_spells.pack(side="left", padx=(0, 4))
        btn_buffs = ctk.CTkButton(
            spells_buffs_row, text="Buffs", width=half_w, height=45,
            fg_color=getattr(self, 'primary_button_color', '#c77626'),
            command=lambda: self.switch_page("Buffs")
        )
        btn_buffs.pack(side="left", padx=(4, 0))
        self.nav_buttons.append(btn_spells)
        self.nav_buttons.append(btn_buffs)

        for page in ["Feats & Features", "Description"]:
            btn = ctk.CTkButton(sidebar, text=page, width=nav_button_width, height=45, 
                                fg_color=getattr(self, 'primary_button_color', '#c77626'),
                                command=lambda p=page: self.switch_page(p))
            btn.pack(pady=8, padx=8)
            self.nav_buttons.append(btn)

        # SB Portrait: larger 9:16 image above the roll chat (when enabled in hamburger).
        # Uses same source portrait image, center-cropped to 9:16 (like description portrait), no border.
        # Larger size; clipping is acceptable per request.
