    @staticmethod
    def _characters_dir():
        os.makedirs(CHARACTERS_DIR, exist_ok=True)
        return CHARACTERS_DIR

    def _apply_window_icon(self):
        apply_app_icon_to_window(self.root)

    def _start_ui_callback_queue(self):
        if self._ui_queue_draining:
            return
        self._ui_queue_draining = True
        self.root.after(50, self._drain_ui_callback_queue)

    def _drain_ui_callback_queue(self):
        if self._closing:
            self._ui_queue_draining = False
            return
        root = getattr(self, "root", None)
        if root is None:
            self._ui_queue_draining = False
            return
        try:
            if not root.winfo_exists():
                self._ui_queue_draining = False
                return
            while True:
                callback, args, kwargs = self._ui_callback_queue.get_nowait()
                try:
                    callback(*args, **kwargs)
                except (RuntimeError, tk.TclError):
                    pass
                except Exception as exc:
                    print(f"UI callback error: {exc}")
        except queue.Empty:
            pass
        except (RuntimeError, tk.TclError):
            self._ui_queue_draining = False
            return
        try:
            if root.winfo_exists() and not self._closing:
                self.root.after(50, self._drain_ui_callback_queue)
            else:
                self._ui_queue_draining = False
        except (RuntimeError, tk.TclError):
            self._ui_queue_draining = False

    def _schedule_on_main(self, callback, *args, **kwargs):
        """Queue a callback for the Tk main thread (safe from background sync threads)."""
        if self._closing:
            return
        try:
            self._ui_callback_queue.put_nowait((callback, args, kwargs))
            self._start_ui_callback_queue()
        except Exception:
            pass

    def _read_last_character_path(self):
        try:
            with open(LAST_CHARACTER_FILE, "r", encoding="utf-8") as f:
                path = json.load(f).get("path", "")
            if path and os.path.isfile(path):
                return path
        except (FileNotFoundError, json.JSONDecodeError, OSError, TypeError):
            pass
        return None

    def _remember_character_path(self, file_path):
        self.last_character_path = file_path
        try:
            with open(LAST_CHARACTER_FILE, "w", encoding="utf-8") as f:
                json.dump({"path": file_path}, f, indent=2)
        except OSError as e:
            print(f"Could not remember last character path: {e}")

    def _update_window_title(self):
        name = self.data.get("name", "New Hero")
        self.root.title(f"D&D 3.5 Character Sheet - {name}")

