    def _gear_enchants_db_for_type(self, gear_type):
        if gear_type == "weapon":
            return getattr(self, "weapon_enchants_db", {}) or {}
        if gear_type == "armor":
            return getattr(self, "armor_enchants_db", {}) or {}
        if gear_type == "shield":
            return getattr(self, "shield_enchants_db", {}) or {}
        return {}

    def _enchant_applies_to_gear(self, enchant_info, gear_type):
        applies = str((enchant_info or {}).get("applies_to") or "both").strip().lower()
        if gear_type == "armor":
            return applies in ("armor", "both")
        if gear_type == "shield":
            return applies in ("shield", "both")
        return True

    def _armor_category_from_data(self, armor=None):
        armor = armor if armor is not None else (self.data.get("armor") or {})
        category = str(armor.get("category", "") or "").strip().lower()
        if not category:
            info = self._lookup_armor_info(armor.get("name", ""))
            category = str(info.get("category", "") or "").strip().lower()
        if self._normalize_special_material(armor.get("material")) == "Mithral":
            if category == "heavy":
                return "medium"
            if category == "medium":
                return "light"
        return category

    def _armor_is_metal(self, armor=None):
        armor = armor if armor is not None else (self.data.get("armor") or {})
        material = self._normalize_special_material(armor.get("material"))
        if material == "Dragonhide":
            return False
        category = self._armor_category_from_data(armor)
        if category in ("medium", "heavy"):
            return True
        name = str(armor.get("name", "") or "").lower()
        non_metal_light = ("leather", "padded", "hide", "studded")
        if category == "light":
            if any(keyword in name for keyword in non_metal_light):
                return False
            metal_light = ("chain shirt", "breastplate", "scale mail", "chainmail", "ring mail")
            if any(keyword in name for keyword in metal_light):
                return True
        return material in ("Mithral", "Adamantine", "Common") and category != "light"

    def _shield_is_tower(self, shield=None):
        shield = shield if shield is not None else (self.data.get("shield") or {})
        return "tower" in str(shield.get("name", "") or "").lower()

    def _enchant_restrictions_met(self, enchant_info, gear_type):
        restrictions = (enchant_info or {}).get("restrictions") or []
        if not restrictions:
            return True, ""
        reasons = []
        for restriction in restrictions:
            if restriction == "light_armor" and gear_type == "armor":
                if self._armor_category_from_data() != "light":
                    reasons.append("requires light armor")
            elif restriction == "metal_armor" and gear_type == "armor":
                if not self._armor_is_metal():
                    reasons.append("requires metal armor")
            elif restriction == "no_tower_shield" and gear_type == "shield":
                if self._shield_is_tower():
                    reasons.append("not available for tower shields")
        return (not reasons), "; ".join(reasons)

    def _resolve_gear_enchant_info(self, gear_type, enchant_name):
        db = self._gear_enchants_db_for_type(gear_type)
        text = str(enchant_name or "").strip()
        if not text:
            return "", None
        info = db.get(text)
        if info is None:
            for db_name, db_info in db.items():
                if str(db_name).lower() == text.lower():
                    return db_name, db_info
        return text, info

    def _filter_gear_enchants(self, gear_type, enchants):
        cleaned = []
        for name in list(enchants or []):
            text, info = self._resolve_gear_enchant_info(gear_type, name)
            if info is None:
                continue
            if not self._enchant_applies_to_gear(info, gear_type):
                continue
            allowed, _reason = self._enchant_restrictions_met(info, gear_type)
            if not allowed:
                continue
            if text not in cleaned:
                cleaned.append(text)
        return cleaned

    def _get_weapon_enchants(self, idx):
        weapons = self.data.get("weapons") or []
        if not (0 <= idx < len(weapons)):
            return [], ""
        weapon = weapons[idx]
        enchants = self._filter_gear_enchants("weapon", weapon.get("enchants"))
        return enchants, str(weapon.get("bane_foe") or "").strip()

    def _set_weapon_enchants(self, idx, enchants, *, bane_foe=None):
        weapons = self.data.get("weapons") or []
        if not (0 <= idx < len(weapons)):
            return
        weapon = weapons[idx]
        weapon["enchants"] = self._filter_gear_enchants("weapon", enchants)
        if bane_foe is not None:
            weapon["bane_foe"] = str(bane_foe or "").strip()
        combat_key = self._get_weapon_combat_key(idx, weapon)
        config = self.data.setdefault("combat", {}).setdefault("weapons", {}).setdefault(
            combat_key, self._default_combat_weapon_config(weapon),
        )
        config["enchants"] = list(weapon["enchants"])
        if bane_foe is not None:
            config["bane_foe"] = weapon["bane_foe"]
        self._mark_combat_page_stale()
        self.invalidate_caches(combat=True, defenses=True, skills=True, saves=True)
        self._sync_magic_item_prepared_spells_if_needed(force=True)
        self._mark_cloud_sync_dirty()

    def _set_gear_enchants(self, gear_type, enchants):
        if gear_type not in ("armor", "shield"):
            return
        gear = self.data.setdefault(gear_type, {})
        gear["enchants"] = self._filter_gear_enchants(gear_type, enchants)
        self.invalidate_caches(defenses=True, skills=True, saves=True)
        self._sync_magic_item_prepared_spells_if_needed(force=True)
        self._mark_cloud_sync_dirty()
        if hasattr(self, "defenses_frame") and self._is_page_active("Defenses"):
            self.refresh_defenses()

    def _format_gear_enchant_body(self, enchant_info):
        """Readable enchant body for feature cards — description, then effects, then notes."""
        info = enchant_info or {}
        parts = []
        desc = str(info.get("description", "") or "").strip()
        if desc:
            parts.append(desc)

        effect_lines = []
        effects = self._resolve_gear_enchant_effects(info)
        for skill, amount in sorted((effects.get("skill_bonus") or {}).items()):
            if amount:
                sign = "+" if int(amount) > 0 else ""
                effect_lines.append(f"{sign}{amount} {skill}")
        for save_key, save_label in (
            ("fort_save", "Fortitude"),
            ("reflex_save", "Reflex"),
            ("will_save", "Will"),
        ):
            save_amount = int(effects.get(save_key, 0) or 0)
            if save_amount:
                effect_lines.append(f"{save_label} save {save_amount:+d}")
        for defense in effects.get("defenses") or []:
            if not isinstance(defense, dict):
                continue
            dtype = str(defense.get("type", "") or "").strip()
            value = str(defense.get("value", "") or "").strip()
            effect_desc = str(defense.get("desc", "") or "").strip()
            if dtype and value:
                line = f"{dtype} {value}"
                if effect_desc:
                    line = f"{line} ({effect_desc})"
                effect_lines.append(line)
            elif effect_desc:
                effect_lines.append(effect_desc)
        if info.get("will_save"):
            effect_lines.append(f"Will save: {info['will_save']}")
        if info.get("price_bonus") is not None:
            effect_lines.append(f"+{info['price_bonus']} price bonus")
        if info.get("flat_gp") is not None:
            effect_lines.append(f"{info['flat_gp']} gp")
        abilities = self._get_gear_enchant_abilities("", info)
        granted_spells = abilities.get("granted_spells") or []
        if granted_spells:
            spell_text = ", ".join(granted_spells)
            effect_lines.append(
                f"Granted spell{'s' if len(granted_spells) != 1 else ''}: {spell_text}",
            )
        uses_per_day = int(abilities.get("uses_per_day") or 0)
        if uses_per_day > 0:
            effect_lines.append(f"Uses/day: {uses_per_day}")
        max_charges = int(abilities.get("max_charges") or 0)
        if max_charges > 0:
            effect_lines.append(f"Charges: {max_charges}")
        if effect_lines:
            parts.append("\n".join(effect_lines))

        notes = str(info.get("notes", "") or "").strip()
        if notes:
            parts.append(notes)
        return "\n".join(parts)

    def _magic_item_card_slot_label(self, item):
        if item.get("is_gear_enchant"):
            return str(item.get("label") or "Gear").strip() or "Gear"
        if item.get("custom_feature"):
            return "Custom Feature"
        if item.get("is_custom"):
            gear_type = str(item.get("gear_type") or "wondrous").strip().title()
            return gear_type or "Wondrous"
        return str(item.get("label") or "Misc").strip() or "Misc"

    def _format_gear_enchant_detail(self, enchant_info):
        info = enchant_info or {}
        extra = []
        effects = info.get("effects") or {}
        for defense in effects.get("defenses") or []:
            if not isinstance(defense, dict):
                continue
            dtype = str(defense.get("type", "") or "").strip()
            value = str(defense.get("value", "") or "").strip()
            desc = str(defense.get("desc", "") or "").strip()
            if dtype and value:
                extra.append(f"{dtype} {value}" + (f" ({desc})" if desc else ""))
            elif desc:
                extra.append(desc)
        if info.get("will_save"):
            extra.append(f"Will save: {info['will_save']}")
        if info.get("price_bonus") is not None:
            extra.append(f"+{info['price_bonus']} price bonus")
        if info.get("flat_gp") is not None:
            extra.append(f"{info['flat_gp']} gp")
        detail = str(info.get("description", "") or "").strip()
        if extra:
            detail = f"{detail} | {' | '.join(extra)}" if detail else " | ".join(extra)
        notes = str(info.get("notes", "") or "").strip()
        if notes:
            detail = f"{detail} — {notes}" if detail else notes
        return detail

    def _open_gear_enchants_popup(self, gear_type):
        if gear_type not in ("armor", "shield"):
            return
        gear = self.data.setdefault(gear_type, {})
        gear_name = str(gear.get("name") or gear_type.title()).strip() or gear_type.title()
        db = self._gear_enchants_db_for_type(gear_type)
        if not db:
            messagebox.showinfo(
                "Enchantments",
                f"No {gear_type} enchant database loaded.",
            )
            return
        selected = set(self._filter_gear_enchants(gear_type, gear.get("enchants")))

        popup = ctk.CTkToplevel(self.root)
        popup.title(f"{gear_type.title()} Enchantments — {gear_name}")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=840, min_height=660)

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=24, pady=(8, 20))
        ctk.CTkButton(
            footer, text="Close", width=120, height=36,
            fg_color=getattr(self, "primary_button_color", "#c77626"), command=popup.destroy,
        ).pack(anchor="e")

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=24, pady=(16, 8))

        ctk.CTkLabel(
            body, text=f"Select {gear_type.title()} Enchantments",
            font=ctk.CTkFont(size=20, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        detail_frame = ctk.CTkFrame(body, fg_color="#2F2F2F", height=52, corner_radius=6)
        detail_frame.pack(fill="x", pady=(0, 8))
        detail_frame.pack_propagate(False)
        detail_label = ctk.CTkLabel(
            detail_frame,
            text="Hover an enchantment to see its summary.",
            wraplength=740,
            justify="left",
            text_color="#aaaaaa",
            anchor="nw",
        )
        detail_label.pack(fill="both", expand=True, padx=10, pady=8)

        scroll = ctk.CTkScrollableFrame(body, height=430)
        scroll.pack(fill="both", expand=True)

        checkbox_vars = {}

        def update_enchants():
            chosen = [name for name, var in checkbox_vars.items() if var.get()]
            self._set_gear_enchants(gear_type, chosen)

        needs_cleanup = False
        for enchant_name in sorted(db.keys()):
            info = db[enchant_name]
            if not self._enchant_applies_to_gear(info, gear_type):
                continue
            allowed, restriction_reason = self._enchant_restrictions_met(info, gear_type)
            row = ctk.CTkFrame(scroll)
            row.pack(fill="x", pady=3, padx=4)

            var = BooleanVar(value=enchant_name in selected)
            checkbox_vars[enchant_name] = var

            cb = ctk.CTkCheckBox(
                row, text=enchant_name, variable=var, width=220,
                command=update_enchants,
            )
            cb.pack(side="left", padx=8, pady=6)
            if not allowed:
                cb.configure(state="disabled")
                if enchant_name in selected:
                    var.set(False)
                    needs_cleanup = True

            def show_detail(event=None, enchant_info=info, blocked_reason=restriction_reason):
                detail = self._format_gear_enchant_detail(enchant_info)
                if blocked_reason:
                    detail = f"Unavailable: {blocked_reason}. {detail}".strip()
                detail_label.configure(
                    text=self._truncate_to_lines(detail, max_lines=2, line_width=74),
                )

            def hide_detail(event=None):
                detail_label.configure(text="Hover an enchantment to see its summary.")

            row.bind("<Enter>", show_detail)
            row.bind("<Leave>", hide_detail)
            cb.bind("<Enter>", show_detail)
            cb.bind("<Leave>", hide_detail)

        if needs_cleanup:
            update_enchants()

    def open_armor_enchants_popup(self):
        self._open_gear_enchants_popup("armor")

    def open_shield_enchants_popup(self):
        self._open_gear_enchants_popup("shield")

    def load_mundane_weapons_db(self):
        try:
            with open(self._json_path("Mundane_Weapons.json"), "r", encoding="utf-8") as f:
                self.mundane_weapons_db = json.load(f)
            print(f"✅ Loaded {len(self.mundane_weapons_db)} mundane weapons")
        except Exception as e:
            self.mundane_weapons_db = {}
            print(f"⚠️ Could not load Mundane_Weapons.json: {e}")

    def load_armor_shields_db(self):
        try:
            with open(self._json_path("armor_shields.json"), "r", encoding="utf-8") as f:
                self.armor_shields_db = json.load(f)
            armor_count = len(self.armor_shields_db.get("armor", {}))
            shield_count = len(self.armor_shields_db.get("shields", {}))
            print(f"✅ Loaded {armor_count} armor and {shield_count} shields from armor_shields.json")
        except Exception as e:
            messagebox.showerror("Armor Load Error", f"Could not read armor_shields.json:\n{e}")
            self.armor_shields_db = {"armor": {}, "shields": {}}

    def load_mundane_armors_shields_db(self):
        """Load the richer flat Mundane_Armors_Shields.json (for search/purchase)."""
        try:
            with open(self._json_path("Mundane_Armors_Shields.json"), "r", encoding="utf-8") as f:
                self.mundane_armors_shields_db = json.load(f)
            print(f"✅ Loaded {len(self.mundane_armors_shields_db or {})} entries from Mundane_Armors_Shields.json")
        except Exception as e:
            print(f"⚠️ Could not load Mundane_Armors_Shields.json: {e}")
            self.mundane_armors_shields_db = {}

    def load_adventuring_gear_db(self):
        """Load Adventuring_Gear.json (mundane gear + special substances + tools/kits)."""
        try:
            with open(self._json_path("Adventuring_Gear.json"), "r", encoding="utf-8") as f:
                self.adventuring_gear_db = json.load(f)
            print(f"✅ Loaded {len(self.adventuring_gear_db or {})} entries from Adventuring_Gear.json")
        except Exception as e:
            print(f"⚠️ Could not load Adventuring_Gear.json: {e}")
            self.adventuring_gear_db = {}

    def _lookup_armor_info(self, name):
        key = str(name or "").strip()
        if not key:
            return {}
        db = (getattr(self, "armor_shields_db", {}) or {}).get("armor", {})
        if key in db:
            return db[key]
        for k, v in db.items():
            if k.lower() == key.lower():
                return v
        mundane = (getattr(self, "mundane_armors_shields_db", {}) or {}).get(key) or {}
        if mundane.get("kind") == "armor":
            return mundane
        return {}

    def _lookup_shield_info(self, name):
        key = str(name or "").strip()
        if not key:
            return {}
        db = (getattr(self, "armor_shields_db", {}) or {}).get("shields", {})
        if key in db:
            return db[key]
        for k, v in db.items():
            if k.lower() == key.lower():
                return v
        mundane = (getattr(self, "mundane_armors_shields_db", {}) or {}).get(key) or {}
        if mundane.get("kind") == "shield":
            return mundane
        return {}

    def _normalize_special_material(self, material):
        text = str(material or "Common").strip()
        if not text:
            return "Common"
        for option in SPECIAL_MATERIAL_OPTIONS:
            if text.lower() == option.lower():
                return option
        return "Common"

    def _weapon_profile(self, name, info=None):
        info = info or self._lookup_mundane_weapon_info(name)
        lname = str(name or "").strip().lower()
        special = info.get("special") or []
        special_text = " ".join(str(s) for s in special).lower()
        desc = str(info.get("special_description", "") or "").lower()
        category = str(info.get("category", "") or "").lower()
        haystack = " ".join((lname, special_text, desc, category))

        is_wood = any(keyword in haystack for keyword in _WEAPON_WOOD_KEYWORDS)
        is_wood = is_wood or "wooden" in haystack
        is_metal = category == "ammunition" or (
            not is_wood
            and not any(keyword in haystack for keyword in _WEAPON_METAL_EXCLUDE_KEYWORDS)
        )

        if category == "ammunition":
            size = "ammunition"
        elif any(keyword in lname for keyword in _WEAPON_TWO_HANDED_KEYWORDS):
            size = "two_handed"
        elif any(keyword in lname for keyword in _WEAPON_LIGHT_KEYWORDS):
            size = "light"
        elif float(info.get("weight", 0) or 0) <= 3:
            size = "light"
        else:
            size = "one_handed"
        return {
            "metal": bool(is_metal),
            "wood": bool(is_wood),
            "size": size,
            "category": category,
        }

    def _shield_is_wooden(self, name, info=None):
        info = info or self._lookup_shield_info(name)
        haystack = " ".join([
            str(name or "").lower(),
            " ".join(str(s) for s in (info.get("special") or [])).lower(),
            str(info.get("special_description", "") or "").lower(),
        ])
        return "wooden" in haystack or "wood" in haystack

    def _valid_weapon_materials(self, name, info=None):
        if not str(name or "").strip():
            return list(SPECIAL_MATERIAL_OPTIONS)
        profile = self._weapon_profile(name, info)
        valid = ["Common"]
        if profile["metal"]:
            valid.extend(["Mithral", "Adamantine", "Cold Iron", "Alchemical Silver"])
        if profile["wood"]:
            valid.append("Darkwood")
        return [m for m in SPECIAL_MATERIAL_OPTIONS if m in valid]

    def _valid_armor_materials(self, name, info=None):
        if not str(name or "").strip():
            return list(SPECIAL_MATERIAL_OPTIONS)
        valid = ["Common", "Mithral", "Adamantine", "Dragonhide"]
        return [m for m in SPECIAL_MATERIAL_OPTIONS if m in valid]

    def _valid_shield_materials(self, name, info=None):
        if not str(name or "").strip():
            return list(SPECIAL_MATERIAL_OPTIONS)
        info = info or self._lookup_shield_info(name)
        valid = ["Common", "Mithral", "Adamantine", "Dragonhide"]
        if self._shield_is_wooden(name, info):
            valid.append("Darkwood")
        return [m for m in SPECIAL_MATERIAL_OPTIONS if m in valid]

    def _halve_special_material_weight(self, weight):
        weight = float(weight or 0)
        if weight <= 0:
            return 0
        return max(0.5, round(weight / 2, 1))

    def _weapon_material_cost_modifier(self, name, info, material):
        info = info or self._lookup_mundane_weapon_info(name)
        profile = self._weapon_profile(name, info)
        material = self._normalize_special_material(material)
        if material == "Common":
            return 0
        if material == "Adamantine":
            return 60 if profile["size"] == "ammunition" else 3000
        if material == "Cold Iron":
            return int(info.get("value", info.get("cost", 0)) or 0)
        if material == "Alchemical Silver":
            if profile["size"] == "ammunition":
                return 2
            if profile["size"] == "light":
                return 20
            if profile["size"] == "two_handed":
                return 180
            return 90
        if material == "Mithral":
            weight = float(info.get("weight", 0) or 0)
            return int(round(weight * 500))
        if material == "Darkwood":
            weight = float(info.get("weight", 0) or 0)
            return int(round(weight * 10))
        return 0

    def _armor_material_cost_modifier(self, info, material):
        material = self._normalize_special_material(material)
        category = str(info.get("category", "") or "").strip().lower()
        if material == "Adamantine":
            return {"light": 5000, "medium": 10000, "heavy": 15000}.get(category, 0)
        if material == "Mithral":
            return {"light": 1000, "medium": 4000, "heavy": 9000}.get(category, 0)
        if material == "Dragonhide":
            return int(info.get("value", info.get("cost", 0)) or 0)
        return 0

    def _shield_material_cost_modifier(self, info, material, shield_name=""):
        material = self._normalize_special_material(material)
        if material == "Adamantine":
            return 2000
        if material == "Mithral":
            return 1000
        if material == "Dragonhide":
            return int(info.get("value", info.get("cost", 0)) or 0)
        if material == "Darkwood":
            weight = float(info.get("weight", 0) or 0)
            return int(round(weight * 10))
        return 0

    def _get_weapon_material_combat_effects(self, weapon):
        material = self._normalize_special_material(weapon.get("material"))
        name = str(weapon.get("name", "") or "").strip()
        if not name or material == "Common":
            return {"attack": 0, "damage": 0, "notes": []}
        profile = self._weapon_profile(name)
        attack = 0
        damage = 0
        notes = []
        if material in ("Adamantine", "Mithral", "Darkwood"):
            attack = 1
            notes.append(f"{material}: masterwork +1 attack")
        if material == "Adamantine":
            notes.append("Adamantine: bypasses hardness < 20; overcomes DR/adamantine")
        if material == "Cold Iron":
            notes.append("Cold iron: overcomes DR/cold iron")
        if material == "Alchemical Silver":
            damage = -1
            notes.append("Alchemical silver: -1 damage (min 1); overcomes DR/silver")
        if material == "Mithral":
            notes.append("Mithral: half weight")
        if material == "Darkwood":
            notes.append("Darkwood: half weight; masterwork")
        return {"attack": attack, "damage": damage, "notes": notes}

    def _apply_weapon_material_stats(self, idx, *, update_ui=True):
        if idx < 0 or idx >= len(self.data.get("weapons", [])):
            return
        weapon = self.data["weapons"][idx]
        name = str(weapon.get("name", "") or "").strip()
        info = self._lookup_mundane_weapon_info(name)
        material = self._normalize_special_material(weapon.get("material"))
        valid = self._valid_weapon_materials(name, info)
        if material not in valid:
            material = "Common"
            weapon["material"] = material
        if not info:
            return

        base_weight = float(info.get("weight", 0) or 0)
        base_value = float(info.get("value", info.get("cost", 0)) or 0)
        weight = base_weight
        value = base_value + self._weapon_material_cost_modifier(name, info, material)
        if material in ("Mithral", "Darkwood"):
            weight = self._halve_special_material_weight(base_weight)
        elif material == "Cold Iron":
            value = base_value * 2

        weapon["weight"] = weight
        weapon["value"] = value

        if update_ui:
            was_rebuilding = getattr(self, "_rebuilding_ui", False)
            self._rebuilding_ui = True
            try:
                for key, val in (("value", value),):
                    reg = f"weapon_{idx}_{key}"
                    if reg in self.widget_registry:
                        try:
                            self.widget_registry[reg].set(str(val))
                        except Exception:
                            pass
                    if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
                        if key in self.weapon_vars[idx]:
                            try:
                                self.weapon_vars[idx][key].set(str(val))
                            except Exception:
                                pass
                if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
                    mat_var = self.weapon_vars[idx].get("material")
                    if mat_var is not None:
                        mat_var.set(material)
            finally:
                self._rebuilding_ui = was_rebuilding

    def _apply_armor_material_stats(self, *, update_ui=True):
        armor = self.data.setdefault("armor", {})
        name = str(armor.get("name", "") or "").strip()
        info = self._lookup_armor_info(name)
        material = self._normalize_special_material(armor.get("material"))
        valid = self._valid_armor_materials(name, info)
        if material not in valid:
            material = "Common"
            armor["material"] = material
        if not info:
            return

        base_weight = int(info.get("weight", 0) or 0)
        base_value = int(info.get("value", info.get("cost", 0)) or 0)
        base_max_dex = int(info.get("max_dex", 99) or 99)
        base_acp = int(info.get("armor_check_penalty", 0) or 0)

        weight = base_weight
        value = base_value + self._armor_material_cost_modifier(info, material)
        max_dex = base_max_dex
        acp = base_acp

        if material == "Mithral":
            weight = int(round(base_weight / 2)) or base_weight
            max_dex = min(99, base_max_dex + 2) if base_max_dex < 99 else 99
            acp = min(0, base_acp + 3)
        elif material == "Adamantine":
            acp = min(0, base_acp + 1)
        elif material == "Dragonhide":
            value = base_value * 2

        armor["category"] = str(info.get("category", "") or "").strip().lower()
        armor["weight"] = weight
        armor["value"] = value
        armor["max_dex"] = max_dex
        armor["armor_check_penalty"] = acp

        if update_ui and hasattr(self, "armor_vars"):
            was_rebuilding = getattr(self, "_rebuilding_ui", False)
            self._rebuilding_ui = True
            try:
                for key, val in (
                    ("value", value), ("max_dex", max_dex),
                    ("armor_check_penalty", acp),
                ):
                    if key in self.armor_vars:
                        self.armor_vars[key].set(str(val))
                mat_var = self.armor_vars.get("material")
                if mat_var is not None:
                    mat_var.set(material)
            finally:
                self._rebuilding_ui = was_rebuilding

    def _apply_shield_material_stats(self, *, update_ui=True):
        shield = self.data.setdefault("shield", {})
        name = str(shield.get("name", "") or "").strip()
        info = self._lookup_shield_info(name)
        material = self._normalize_special_material(shield.get("material"))
        valid = self._valid_shield_materials(name, info)
        if material not in valid:
            material = "Common"
            shield["material"] = material
        if not info:
            return

        base_weight = int(info.get("weight", 0) or 0)
        base_value = int(info.get("value", info.get("cost", 0)) or 0)
        base_acp = int(info.get("armor_check_penalty", 0) or 0)
        raw_max_dex = info.get("max_dex")

        weight = base_weight
        value = base_value + self._shield_material_cost_modifier(info, material, name)
        acp = base_acp

        if material == "Mithral":
            weight = int(round(base_weight / 2)) or base_weight
            acp = min(0, base_acp + 3)
            if raw_max_dex is not None:
                shield["max_dex"] = min(99, int(raw_max_dex or 0) + 2)
        elif material == "Adamantine":
            acp = min(0, base_acp + 1)
        elif material == "Darkwood":
            weight = int(round(base_weight / 2)) or base_weight
            acp = min(0, base_acp + 2)
        elif material == "Dragonhide":
            value = base_value * 2

        shield["weight"] = weight
        shield["value"] = value
        shield["armor_check_penalty"] = acp

        if update_ui and hasattr(self, "shield_vars"):
            was_rebuilding = getattr(self, "_rebuilding_ui", False)
            self._rebuilding_ui = True
            try:
                for key, val in (("value", value), ("armor_check_penalty", acp)):
                    if key in self.shield_vars:
                        self.shield_vars[key].set(str(val))
                mat_var = self.shield_vars.get("material")
                if mat_var is not None:
                    mat_var.set(material)
            finally:
                self._rebuilding_ui = was_rebuilding

    def _resolve_magic_item_name(self, item_name):
        name = str(item_name or "").strip()
        if not name:
            return name
        return ENERGY_RESISTANCE_RING_ALIASES.get(name, name)

    def _lookup_magic_item_info(self, json_slot, item_name):
        resolved = self._resolve_magic_item_name(item_name)
        slot_data = self.magic_items_db.get(json_slot, {})
        info = slot_data.get(resolved)
        if info:
            return resolved, info
        return resolved, slot_data.get(item_name)

    def _find_magic_item_json_slot_for_name(self, item_name):
        name = str(item_name or "").strip()
        if not name:
            return None
        if not getattr(self, "magic_items_db", None):
            self.load_magic_items_db()
        resolved = self._resolve_magic_item_name(name)
        base = self._extract_parenthetical_base_name(name)
        names_lower = {
            name.lower(),
            resolved.lower(),
            base.lower(),
        }
        for json_slot, slot_db in (self.magic_items_db or {}).items():
            if not isinstance(slot_db, dict):
                continue
            for db_name in slot_db:
                if str(db_name).strip().lower() in names_lower:
                    return json_slot
        return None

    def _iter_active_gear_enchant_records(self):
        """Yield (gear_type, enchant_name, enchant_info) for worn armor, shield, and wielded weapon enchants."""
        armor = self._get_live_armor_data()
        if str(armor.get("status", "")).strip().lower() == "worn":
            for enchant_name in armor.get("enchants") or []:
                name = str(enchant_name or "").strip()
                if not name:
                    continue
                resolved_name, info = self._resolve_gear_enchant_info("armor", name)
                if info:
                    yield "armor", resolved_name or name, info
        shield = self._get_live_shield_data()
        if str(shield.get("status", "")).strip().lower() == "worn":
            for enchant_name in shield.get("enchants") or []:
                name = str(enchant_name or "").strip()
                if not name:
                    continue
                resolved_name, info = self._resolve_gear_enchant_info("shield", name)
                if info:
                    yield "shield", resolved_name or name, info
        for idx, weapon in enumerate(self.data.get("weapons") or []):
            if str(weapon.get("status", "")).strip().lower() != "wielded":
                continue
            enchants, _bane = self._get_weapon_enchants(idx)
            for enchant_name in enchants:
                name = str(enchant_name or "").strip()
                if not name:
                    continue
                resolved_name, info = self._resolve_gear_enchant_info("weapon", name)
                if info:
                    yield "weapon", resolved_name or name, info

    def _gear_enchant_defense_source_label(self, gear_type):
        return str(gear_type or "").strip().lower()

    def _format_gear_enchant_defense_entry(self, defense, gear_type):
        """Build a compact defense row like 'Immunity Acid (armor)' or 'Resistance 10 Acid (armor)'."""
        source = self._gear_enchant_defense_source_label(gear_type)
        source_label = f"({source})" if source else ""
        element = str(defense.get("desc", "") or "").strip()
        value = str(defense.get("value", "") or "").strip()
        dtype = str(defense.get("type", "Resistance") or "Resistance").strip()
        dtype_lower = dtype.lower()

        if dtype_lower == "immunity":
            element_name = value or element
            return {
                "type": dtype,
                "value": element_name,
                "desc": source_label,
                "auto": True,
            }
        if dtype_lower == "resistance":
            return {
                "type": dtype,
                "value": value,
                "desc": f"{element} {source_label}".strip() if element else source_label,
                "auto": True,
            }
        return {
            "type": dtype,
            "value": value,
            "desc": source_label,
            "auto": True,
        }

    def _get_gear_enchant_defense_entries(self):
        """Defense entries from worn armor/shield enchants (SR and fortification use best value)."""
        entries = []
        best_sr = None
        best_sr_source = ""
        best_fort_pct = None
        best_fort_source = ""
        for gear_type, _enchant_name, info in self._iter_active_gear_enchant_records():
            if gear_type not in ("armor", "shield"):
                continue
            source_label = f"({self._gear_enchant_defense_source_label(gear_type)})"
            defenses = (self._resolve_gear_enchant_effects(info)).get("defenses") or []
            if not isinstance(defenses, list):
                continue
            for defense in defenses:
                if not isinstance(defense, dict):
                    continue
                element = str(defense.get("desc", "") or "").strip()
                value = str(defense.get("value", "") or "").strip()
                dtype = str(defense.get("type", "Resistance") or "Resistance").strip()
                if not element and not value:
                    continue
                dtype_lower = dtype.lower()
                if dtype_lower == "sr":
                    amount = self._parse_resistance_numeric_value(value)
                    if amount is None:
                        continue
                    if best_sr is None or amount > best_sr:
                        best_sr = amount
                        best_sr_source = source_label
                    continue
                if dtype_lower == "fortification":
                    amount = self._parse_resistance_numeric_value(value)
                    if amount is None:
                        continue
                    if best_fort_pct is None or amount > best_fort_pct:
                        best_fort_pct = amount
                        best_fort_source = source_label
                    continue
                entries.append(self._format_gear_enchant_defense_entry(defense, gear_type))
        if best_sr is not None:
            entries.append({
                "type": "SR",
                "value": str(best_sr),
                "desc": best_sr_source,
                "auto": True,
            })
        if best_fort_pct is not None:
            entries.append({
                "type": "Fortification",
                "value": f"{best_fort_pct}%",
                "desc": best_fort_source,
                "auto": True,
            })
        return entries

    def _get_magic_item_defense_entries(self):
        entries = []
        for item in self._get_all_magic_item_features():
            defenses = (item.get("info") or {}).get("effects", {}).get("defenses") or []
            if not isinstance(defenses, list):
                continue
            for defense in defenses:
                if not isinstance(defense, dict):
                    continue
                desc = str(defense.get("desc", "") or "").strip()
                value = str(defense.get("value", "") or "").strip()
                dtype = str(defense.get("type", "Resistance") or "Resistance").strip()
                if not desc and not value:
                    continue
                label = item.get("name", "Magic Item")
                entries.append({
                    "type": dtype,
                    "value": value,
                    "desc": f"{desc} ({label})" if desc else label,
                    "auto": True,
                })
        return entries

    def _get_equipment_defense_entries(self):
        entries = []
        armor = self._get_live_armor_data()
        if (
            str(armor.get("status", "")).strip().lower() == "worn"
            and self._normalize_special_material(armor.get("material")) == "Adamantine"
        ):
            category = str(armor.get("category", "") or "").strip().lower()
            if not category:
                info = self._lookup_armor_info(armor.get("name", ""))
                category = str(info.get("category", "") or "").strip().lower()
            dr_value = ADAMANTINE_ARMOR_DR.get(category)
            if dr_value:
                entries.append({
                    "type": "DR",
                    "value": dr_value,
                    "desc": f"Adamantine armor ({armor.get('name', 'Armor')})",
                    "auto": True,
                })
        entries.extend(self._get_gear_enchant_defense_entries())
        return entries

    def _on_weapon_material_changed(self, idx, choice):
        if idx >= len(self.data.get("weapons", [])):
            return
        self.data["weapons"][idx]["material"] = self._normalize_special_material(choice)
        self._apply_weapon_material_stats(idx)
        self.refresh_encumbrance_display()
        self._mark_combat_page_stale()
        self.invalidate_caches()
        self.refresh_all()

    def _on_armor_material_changed(self, choice):
        self.data.setdefault("armor", {})["material"] = self._normalize_special_material(choice)
        self._apply_armor_material_stats()
        self.refresh_encumbrance_display()
        self._update_monk_ac_display()
        self.invalidate_caches()
        self.refresh_all()

    def _on_shield_material_changed(self, choice):
        self.data.setdefault("shield", {})["material"] = self._normalize_special_material(choice)
        self._apply_shield_material_stats()
        self.refresh_encumbrance_display()
        self._update_monk_ac_display()
        self.invalidate_caches()
        self.refresh_all()

    def _get_carrying_capacity_limits(self, strength_score=None):
        """Return (light_max, medium_max, heavy_max) in lb. after size adjustment."""
        if strength_score is None:
            strength_score = self._effective_ability_score("Strength")
        try:
            strength_score = max(0, int(strength_score or 0))
        except (TypeError, ValueError):
            strength_score = 0
        if strength_score <= 0:
            return (0, 0, 0)
        if strength_score <= 29:
            light_max, medium_max, heavy_max = CARRYING_CAPACITY_BY_STR[strength_score]
        else:
            ones = strength_score % 10
            base_score = 20 + ones
            light_max, medium_max, heavy_max = CARRYING_CAPACITY_BY_STR[base_score]
            multiplier = 4 ** ((strength_score - base_score) // 10)
            light_max *= multiplier
            medium_max *= multiplier
            heavy_max *= multiplier
        size_mult = SIZE_CARRYING_CAPACITY_MULTIPLIER.get(
            self._get_effective_size(), 1.0,
        )
        # Apply Carry_Cap multiplier from bonuses (max across magic items, feats, spells, buffs). >1 increases capacity.
        try:
            bonuses = self.get_all_bonuses()
            carry_mult = float(bonuses.get("carry_cap", 1.0) or 1.0)
        except Exception:
            carry_mult = 1.0
        if carry_mult <= 0:
            carry_mult = 1.0
        return (
            int(light_max * size_mult * carry_mult),
            int(medium_max * size_mult * carry_mult),
            int(heavy_max * size_mult * carry_mult),
        )

    def _get_magic_item_weight(self, item_name, json_slot):
        if not item_name or not str(item_name).strip():
            return 0.0
        item_info = self.magic_items_db.get(json_slot, {}).get(str(item_name).strip(), {})
        effects = item_info.get("effects") or {}
        try:
            return float(effects.get("weight", 0) or 0)
        except (TypeError, ValueError):
            return 0.0

    def _get_total_coins(self, location="person"):
        """Total number of coins across all denominations for a given location (person/container/banked)."""
        coins = self.data.get("coins") or {}
        loc_coins = coins.get(location, {}) if isinstance(coins, dict) else {}
        total = 0
        for c in ("PP", "GP", "EP", "SP", "CP"):
            try:
                total += int(loc_coins.get(c, 0) or 0)
            except (TypeError, ValueError):
                pass
        return total

    def _get_coin_weight(self, location="person"):
        """50 coins = 1 lb (standard D&D 3.5 / Pathfinder rule). Only 'person' location counts for encumbrance by default."""
        return self._get_total_coins(location) / 50.0

    def _get_container_capacity_per_unit(self, name):
        """Storage capacity (lb) one inventory unit of this item provides, or 0."""
        if not name or not str(name).strip():
            return 0.0
        name_str = str(name).strip()
        name_lower = name_str.lower()

        match = re.search(r"\(container:\s*([\d.]+)\)", name_str, flags=re.I)
        if match:
            try:
                return float(match.group(1))
            except (TypeError, ValueError):
                pass

        is_small = self._get_effective_size() == "Small"
        size_mult = 0.5 if is_small else 1.0

        if "bag of holding" in name_lower:
            if re.search(r"type\s*iv\b", name_lower):
                return 1500.0
            if re.search(r"type\s*iii\b", name_lower):
                return 1000.0
            if re.search(r"type\s*ii\b", name_lower):
                return 500.0
            if re.search(r"type\s*i\b", name_lower):
                return 250.0
            return 250.0

        if "backpack" in name_lower:
            return 30.0 * size_mult

        if "pouch" in name_lower and "belt" in name_lower:
            return 5.0 * size_mult

        return 0.0

    def _get_total_container_storage_capacity(self):
        """Sum capacity from carried container items (person + container tabs; banked excluded)."""
        total = 0.0
        for item in self.data.get("inventory") or []:
            loc = str(item.get("location", "person")).strip().lower()
            if loc == "banked":
                continue
            name = str(item.get("name", "")).strip()
            if not name:
                continue
            unit_cap = self._get_container_capacity_per_unit(name)
            if unit_cap <= 0:
                continue
            try:
                qty = max(1, int(item.get("quantity", 1) or 1))
            except (TypeError, ValueError):
                qty = 1
            total += unit_cap * qty
        return total

    def _get_container_storage_used(self, *, extra_weight=0.0):
        """Weight stored in the container tab: items there plus coins in the container pool."""
        used = 0.0
        for item in self.data.get("inventory") or []:
            if str(item.get("location", "person")).strip().lower() != "container":
                continue
            try:
                unit_weight = float(item.get("weight", 0) or 0)
                qty = max(1, int(item.get("quantity", 1) or 1))
            except (TypeError, ValueError):
                unit_weight = 0.0
                qty = 1
            used += unit_weight * qty
        used += self._get_coin_weight("container")
        used += float(extra_weight or 0)
        return used

    def _container_can_store(self, extra_weight=0.0):
        """Return (ok, reason) where reason is 'no_containers' or 'over_capacity'."""
        capacity = self._get_total_container_storage_capacity()
        if capacity <= 0:
            return False, "no_containers"
        used = self._get_container_storage_used(extra_weight=extra_weight)
        if used > capacity + 0.0001:
            return False, "over_capacity"
        return True, None

    def _show_container_storage_limit_popup(self, reason="over_capacity", extra_detail=""):
        """Dark-mode notice when container storage is full or unavailable."""
        capacity = self._get_total_container_storage_capacity()
        used = self._get_container_storage_used()
        cap_txt = self._format_encumbrance_weight(capacity)
        used_txt = self._format_encumbrance_weight(used)

        if reason == "no_containers":
            message = (
                "You have no containers to store items in.\n\n"
                "Add a belt pouch, backpack, bag of holding, or an item with "
                "(Container: XX) in its name to gain storage space."
            )
        else:
            message = (
                "Cannot store this — container space is limited.\n\n"
                f"Container storage: {used_txt} / {cap_txt} lb used."
            )
        if extra_detail:
            message = f"{message}\n\n{extra_detail}"

        popup = ctk.CTkToplevel(self.root)
        popup.title("Container Storage")
        popup.transient(self.root)
        popup.grab_set()
        popup.configure(fg_color=THEME_DARK_BG)

        primary = getattr(self, "primary_button_color", "#c77626")
        ctk.CTkLabel(
            popup,
            text="Container Storage",
            font=ctk.CTkFont(size=18, weight="bold"),
            text_color=primary,
        ).pack(pady=(16, 8))
        ctk.CTkLabel(
            popup,
            text=message,
            font=ctk.CTkFont(size=13),
            text_color="#cccccc",
            wraplength=340,
            justify="left",
        ).pack(padx=24, pady=(0, 12))

        ctk.CTkButton(
            popup,
            text="OK",
            width=100,
            fg_color=primary,
            hover_color=getattr(self, "primary_hover_color", "#a56b32"),
            command=popup.destroy,
        ).pack(pady=(4, 18))
        self._size_and_center_popup_to_content(popup, min_width=380, min_height=200)

    def refresh_container_storage_display(self):
        if not hasattr(self, "container_storage_label"):
            return
        try:
            capacity = self._get_total_container_storage_capacity()
            used = self._get_container_storage_used()
            cap_txt = self._format_encumbrance_weight(capacity)
            used_txt = self._format_encumbrance_weight(used)
            if capacity <= 0:
                text = "Container: — / — lb"
                color = "#888888"
            else:
                text = f"Container: {used_txt} / {cap_txt} lb"
                ratio = used / capacity if capacity > 0 else 0
                if used > capacity + 0.0001:
                    color = "#ff6666"
                elif ratio >= 0.9:
                    color = "#ffaa44"
                elif ratio >= 0.75:
                    color = "#ffcc66"
                else:
                    color = "#88cc88"
            self.container_storage_label.configure(text=text, text_color=color)
            tooltip = [
                "Container storage tracks items and coins in the Container tab.",
                "",
                "Container carry (No / Yes / Mount):",
                "  No — container tab ignored for encumbrance.",
                "  Yes — rider bears container tab (backpack/pouch rules).",
                "  Mount — rider ignores container tab; mount bears it when riding.",
                "  Extradimensional storage caps at 30 lb (backpack) + 5 lb (belt pouch).",
                "",
                "Capacity sources:",
                "  Belt pouch — 5 lb (2.5 lb if Small)",
                "  Backpack — 30 lb (15 lb if Small)",
                "  Bag of Holding I–IV — 250 / 500 / 1000 / 1500 lb",
                "  (Container: XX) in an item name — +XX lb",
            ]
            if capacity > 0:
                tooltip.extend([
                    "",
                    f"Used: {used_txt} lb",
                    f"Capacity: {cap_txt} lb",
                    f"Available: {self._format_encumbrance_weight(max(0, capacity - used))} lb",
                ])
            self._bind_hover_tooltip(self.container_storage_label, "\n".join(tooltip), wraplength=360)
        except Exception as exc:
            print(f"Container storage display error: {exc}")

    def _get_coin_volume_cuft(self, location="person"):
        """500 coins = 1 cubic foot (standard storage/bulk rule)."""
        return self._get_total_coins(location) / 500.0

    def _iter_carried_inventory_items(self):
        """Yield inventory on person or in the container tab (banked items excluded)."""
        for item in self.data.get("inventory") or []:
            loc = str(item.get("location", "person")).strip().lower()
            if loc in ("person", "container"):
                yield item

    def _item_is_extradimensional_storage(self, name):
        name_lower = str(name or "").strip().lower()
        if "bag of holding" in name_lower:
            return True
        if "portable hole" in name_lower:
            return True
        if "handy haversack" in name_lower:
            return True
        if "haversack" in name_lower and "heward" in name_lower:
            return True
        return False

    def _has_carried_backpack(self):
        for item in self._iter_carried_inventory_items():
            if "backpack" in str(item.get("name", "")).lower():
                return True
        return False

    def _has_carried_belt_pouch(self):
        for item in self._iter_carried_inventory_items():
            name_lower = str(item.get("name", "")).lower()
            if "pouch" in name_lower and "belt" in name_lower:
                return True
        return False

    def _has_carried_extradimensional_storage(self):
        for item in self._iter_carried_inventory_items():
            if self._item_is_extradimensional_storage(item.get("name")):
                return True
        for item_name in self.data.get("magic_items") or []:
            if item_name and self._item_is_extradimensional_storage(item_name):
                return True
        return False

    def _get_mundane_container_encumbrance_cap(self):
        """Backpack/pouch weight that still counts when extradimensional storage is present."""
        is_small = self._get_effective_size() == "Small"
        size_mult = 0.5 if is_small else 1.0
        cap = 0.0
        if self._has_carried_backpack():
            cap += 30.0 * size_mult
        if self._has_carried_belt_pouch():
            cap += 5.0 * size_mult
        return cap

    def _get_carrying_container_mode(self):
        """How container-tab weight applies: 'no', 'yes' (on rider), or 'mount'."""
        cc = self.data.get("carrying_container", "no")
        if cc is True:
            return "yes"
        if cc is False:
            return "no"
        if cc in ("no", "yes", "mount"):
            return cc
        return "no"

    def _effective_carrying_container_mode(self):
        """Stored container mode, but Mount requires a selected mount."""
        mode = self._get_carrying_container_mode()
        if mode == "mount" and not self._has_mount():
            return "no"
        return mode

    def _compute_container_tab_encumbrance_weight(self, *, for_mount=False):
        """Container-tab weight that counts toward encumbrance (backpack/pouch/extradimensional rules)."""
        tab_weight = self._get_container_storage_used()
        if tab_weight <= 0:
            return 0.0
        mode = self._effective_carrying_container_mode()
        if for_mount or mode == "mount":
            if self._has_carried_extradimensional_storage():
                cap = self._get_mundane_container_encumbrance_cap()
                if cap > 0:
                    return min(tab_weight, cap)
            return tab_weight
        if not self._has_carried_backpack() and not self._has_carried_belt_pouch():
            return 0.0
        if self._has_carried_extradimensional_storage():
            cap = self._get_mundane_container_encumbrance_cap()
            return min(tab_weight, cap) if cap > 0 else 0.0
        return tab_weight

    def _get_container_encumbrance_weight(self, *, for_mount=False):
        """Container-tab weight applied to rider or mount encumbrance."""
        mode = self._effective_carrying_container_mode()
        if for_mount:
            if mode != "mount":
                return 0.0
            return self._compute_container_tab_encumbrance_weight(for_mount=True)
        if mode != "yes":
            return 0.0
        return self._compute_container_tab_encumbrance_weight(for_mount=False)

    def _get_character_description_weight_lbs(self):
        """Parse character body weight (lb.) from the Description tab."""
        desc = self.data.get("description") or {}
        raw = str(desc.get("weight", "") or "").strip()
        if hasattr(self, "description_weight_var"):
            try:
                raw = str(self.description_weight_var.get() or raw).strip()
            except Exception:
                pass
        match = re.search(r"([\d.]+)", raw)
        if not match:
            return 0.0
        try:
            return max(0.0, float(match.group(1)))
        except (TypeError, ValueError):
            return 0.0

    def _get_container_encumbrance_note(self):
        """Short explanation of how container weight affects encumbrance right now."""
        stored = self._get_carrying_container_mode()
        mode = self._effective_carrying_container_mode()
        if mode == "no":
            if stored == "mount" and not self._has_mount():
                return "Container carry: Mount — select a mount in the mount popup first."
            return "Container carry: No — container tab weight not on rider or mount."
        if mode == "mount":
            tab_weight = self._get_container_storage_used()
            applied_mount = self._get_container_encumbrance_weight(for_mount=True)
            if applied_mount <= 0:
                return "Container carry: Mount — container tab empty or not applied."
            if self._has_carried_extradimensional_storage() and applied_mount < tab_weight:
                cap = self._get_mundane_container_encumbrance_cap()
                return (
                    f"Container carry: Mount — {self._format_encumbrance_weight(applied_mount)} lb. "
                    f"on mount (capped at {self._format_encumbrance_weight(cap)} lb.; "
                    f"rider ignores container tab)"
                )
            return (
                f"Container carry: Mount — {self._format_encumbrance_weight(applied_mount)} lb. "
                f"on mount when riding (rider ignores container tab)"
            )
        if not self._has_carried_backpack() and not self._has_carried_belt_pouch():
            return "Container carry: Yes — need a backpack or belt pouch to count container weight."
        tab_weight = self._get_container_storage_used()
        applied = self._get_container_encumbrance_weight()
        if applied <= 0:
            return "Container tab weight not applied to rider encumbrance."
        if self._has_carried_extradimensional_storage() and applied < tab_weight:
            cap = self._get_mundane_container_encumbrance_cap()
            return (
                f"Container encumbrance: {self._format_encumbrance_weight(applied)} lb. "
                f"(capped at {self._format_encumbrance_weight(cap)} lb.; "
                f"extradimensional storage ignores the rest)"
            )
        return (
            f"Container encumbrance: {self._format_encumbrance_weight(applied)} lb. "
            f"(full container tab weight on rider)"
        )

    def _get_total_carried_weight(self):
        """Sum weight from coins, inventory (person + container if carried), and equipped magic items.

        Weapon/armor/shield slot widgets do not contribute weight here — those items are
        counted once via the general inventory list.
        """
        total = 0.0

        total += self._get_coin_weight("person")

        for item in self.data.get("inventory") or []:
            loc = str(item.get("location", "person")).strip().lower()
            if loc != "person":
                continue
            try:
                unit_weight = float(item.get("weight", 0) or 0)
                qty = int(item.get("quantity", 1) or 1)
            except (TypeError, ValueError):
                unit_weight = 0.0
                qty = 1
            total += unit_weight * max(1, qty)

        total += self._get_container_encumbrance_weight()

        magic_items = self.data.get("magic_items") or []
        labels = getattr(self, "magic_labels_list", None) or [
            "Head", "Face", "Neck", "Shoulders",
            "Body", "Torso", "Arms", "Wrists",
            "Ring 1", "Ring 2", "Waist", "Feet",
            "Misc 1", "Misc 2", "Misc 3", "Misc 4",
        ]
        for index, item_name in enumerate(magic_items):
            if not item_name or not str(item_name).strip():
                continue
            label = labels[index] if index < len(labels) else "Misc"
            json_slot = MAGIC_ITEM_SLOT_MAP.get(label, label)
            total += self._get_magic_item_weight(item_name, json_slot)

        return total

    def _on_carrying_container_mode_changed(self, choice):
        mode = str(choice or "No").strip().lower()
        if mode == "mount":
            if not self._has_mount():
                messagebox.showinfo(
                    "Mount",
                    "Select a mount in the mount popup before shifting container weight to your mount.",
                )
                seg = getattr(self, "carrying_container_seg", None)
                if seg is not None:
                    try:
                        if seg.winfo_exists():
                            seg.set("No")
                    except Exception:
                        pass
                return
            normalized = "mount"
        elif mode == "yes":
            normalized = "yes"
        else:
            normalized = "no"
        self._set_carrying_container_mode(normalized)

    def _set_carrying_container_mode(self, mode):
        """Set how container-tab weight applies: no, yes (rider), or mount."""
        normalized = str(mode or "no").strip().lower()
        if normalized not in ("no", "yes", "mount"):
            normalized = "no"
        self.data["carrying_container"] = normalized
        self.refresh_encumbrance_display()
        if hasattr(self, "inv_frame") and self.inv_frame.winfo_exists():
            self.refresh_inventory()
        if hasattr(self, "_refresh_mount_movement_if_needed"):
            self._refresh_mount_movement_if_needed()

    def _get_encumbrance_load_state(self):
        """Determine current load tier and raw encumbrance penalties from carried weight."""
        carried = self._get_total_carried_weight()
        light_max, medium_max, heavy_max = self._get_carrying_capacity_limits()
        if carried <= light_max:
            load = "light"
        elif carried <= medium_max:
            load = "medium"
        elif carried <= heavy_max:
            load = "heavy"
        else:
            load = "overloaded"
        effects = dict(ENCUMBRANCE_LOAD_EFFECTS.get(load, ENCUMBRANCE_LOAD_EFFECTS["light"]))
        return {
            "carried": carried,
            "light_max": light_max,
            "medium_max": medium_max,
            "heavy_max": heavy_max,
            "load": load,
            "load_label": load.capitalize(),
            **effects,
        }

    def _resolve_armor_acp(self, armor=None):
        armor = armor if armor is not None else (self.data.get("armor") or {})
        if armor.get("armor_check_penalty") is not None:
            return int(armor.get("armor_check_penalty") or 0)
        info = self._lookup_armor_info(armor.get("name", ""))
        return int(info.get("armor_check_penalty", 0) or 0)

    def _resolve_shield_acp(self, shield=None):
        shield = shield if shield is not None else (self.data.get("shield") or {})
        if shield.get("armor_check_penalty") is not None:
            return int(shield.get("armor_check_penalty") or 0)
        info = self._lookup_shield_info(shield.get("name", ""))
        return int(info.get("armor_check_penalty", 0) or 0)

    def _is_wearing_buckler(self, shield=None):
        """True when a buckler is worn (SRD: -1 attack when wielding a melee weapon in that arm)."""
        shield = shield if shield is not None else (self.data.get("shield") or {})
        if str(shield.get("status", "")).strip().lower() != "worn":
            return False
        name = str(shield.get("name", "")).strip()
        if not name:
            return False
        if "buckler" in name.lower():
            return True
        info = self._lookup_shield_info(name)
        haystack = " ".join([
            name.lower(),
            str(info.get("category", "") or "").lower(),
            str(info.get("special_description", "") or "").lower(),
        ])
        return "buckler" in haystack

    def _get_buckler_melee_attack_penalty(self, weapon_style):
        """Buckler penalty: -1 attack only when wielding a two-handed weapon."""
        if weapon_style == "2H" and self._is_wearing_buckler():
            return -1
        return 0

    def _get_armor_shield_acp(self):
        """Armor + shield ACP only (before comparing with load encumbrance)."""
        penalty = 0
        armor = self.data.get("armor") or {}
        if armor.get("status") == "worn":
            penalty += self._resolve_armor_acp(armor)
        shield = self.data.get("shield") or {}
        if shield.get("status") == "worn":
            penalty += self._resolve_shield_acp(shield)
        return penalty

    def _get_load_acp(self):
        return int(self._get_encumbrance_load_state().get("check_penalty", 0) or 0)

    def _get_armor_encumbrance_penalties(self):
        """Max Dex and armor check penalty from worn armor and shield."""
        max_dex = 99
        check_penalty = 0

        armor = self.data.get("armor") or {}
        if armor.get("status") == "worn":
            max_dex = int(armor.get("max_dex", 99) or 99)
            check_penalty += self._resolve_armor_acp(armor)

        shield = self.data.get("shield") or {}
        if shield.get("status") == "worn":
            check_penalty += self._resolve_shield_acp(shield)

        return {
            "max_dex": max_dex,
            "check_penalty": check_penalty,
        }

    def _get_combined_encumbrance_penalties(self):
        """Worst-of armor vs. load for max Dex, check penalty, land speed, and run multiplier."""
        armor_pen = self._get_armor_encumbrance_penalties()
        load_pen = self._get_encumbrance_load_state()
        return {
            "max_dex": min(armor_pen["max_dex"], load_pen["max_dex"]),
            "check_penalty": min(armor_pen["check_penalty"], load_pen["check_penalty"]),
            "load_land_speed": load_pen["land_speed"],
            "load_run_multiplier": load_pen["run_multiplier"],
            "load": load_pen["load"],
            "carried": load_pen["carried"],
            "heavy_max": load_pen["heavy_max"],
            "armor_penalties": armor_pen,
            "load_penalties": load_pen,
        }

    def _get_effective_armor_check_penalty(self):
        return self._get_combined_encumbrance_penalties()["check_penalty"]

    def _get_weapon_nonproficiency_penalty(self, weapon_name):
        if not HAS_PROFICIENCY_SUPPORT or _proficiency_support is None:
            return 0
        return int(_proficiency_support.get_weapon_nonproficiency_penalty(self, weapon_name) or 0)

    def _get_armor_nonproficiency_check_penalty(self):
        if not HAS_PROFICIENCY_SUPPORT or _proficiency_support is None:
            return 0
        return int(_proficiency_support.get_armor_nonproficiency_check_penalty(self) or 0)

    def _get_attack_nonproficiency_penalty(self, weapon_name=""):
        return self._get_weapon_nonproficiency_penalty(weapon_name) + self._get_armor_nonproficiency_check_penalty()

    def _get_ability_check_nonproficiency_penalty(self, ability_name):
        ability = str(ability_name or "").strip()
        if ability not in ("Strength", "Dexterity"):
            return 0
        return self._get_armor_nonproficiency_check_penalty()

    def _skill_subject_to_armor_check_penalty(self, skill_key):
        if not hasattr(self, "skill_vars") or skill_key not in self.skill_vars:
            return False
        return self.skill_vars[skill_key].get("ability_key") in ("Str", "Dex")

    def _format_encumbrance_weight(self, weight):
        rounded = round(float(weight or 0), 1)
        if abs(rounded - round(rounded)) < 0.05:
            return str(int(round(rounded)))
        return f"{rounded:g}"

    def refresh_encumbrance_display(self):
        if not hasattr(self, "encumbrance_label"):
            return
        try:
            state = self._get_encumbrance_load_state()
            carried = self._format_encumbrance_weight(state["carried"])
            heavy_max = self._format_encumbrance_weight(state["heavy_max"])
            load = state["load"]
            self.encumbrance_label.configure(
                text=f"{carried}/{heavy_max} ({state['load_label']})",
                text_color=ENCUMBRANCE_LOAD_COLORS.get(load, "#aaaaaa"),
            )
            combined = self._get_combined_encumbrance_penalties()
            tooltip_lines = [
                f"Carried: {carried} lb.",
            ]
            try:
                total_coins = self._get_total_coins()
                if total_coins > 0:
                    coin_lbs = self._format_encumbrance_weight(self._get_coin_weight())
                    coin_cuft = self._format_encumbrance_weight(self._get_coin_volume_cuft())
                    tooltip_lines.append(
                        f"Coins: {total_coins} ({coin_lbs} lb, {coin_cuft} cu ft)"
                    )
            except Exception:
                pass
            tooltip_lines.extend([
                f"Light load: up to {self._format_encumbrance_weight(state['light_max'])} lb.",
                f"Medium load: up to {self._format_encumbrance_weight(state['medium_max'])} lb.",
                f"Heavy load: up to {heavy_max} lb.",
                "",
                self._get_container_encumbrance_note(),
                "",
                f"Load penalties: max Dex +{state['max_dex']}, "
                f"check {state['check_penalty']:+d}",
            ])
            if state.get("uses_armor_speed_table") or state["land_speed"] is not None:
                run_note = (
                    f"×{state['run_multiplier']} run"
                    if state.get("run_multiplier") is not None
                    else "run restricted"
                )
                if state.get("uses_armor_speed_table"):
                    before_armor = self._get_land_speed_before_armor()
                    load_speed = self._get_load_land_speed(before_armor)
                    if load_speed >= before_armor and self._race_ignores_armor_and_load_land_speed_penalty():
                        tooltip_lines.append(
                            f"Load speed: {load_speed} ft. land (dwarf: no reduction), {run_note}",
                        )
                    else:
                        tooltip_lines.append(
                            f"Load speed: {before_armor} → {load_speed} ft. land "
                            f"(armor speed table), {run_note}",
                        )
                else:
                    tooltip_lines.append(
                        f"Load speed: {state['land_speed']} ft. land, {run_note}",
                    )
            armor_pen = combined["armor_penalties"]
            if self.data.get("armor", {}).get("status") == "worn":
                tooltip_lines.extend([
                    "",
                    f"Armor: max Dex +{armor_pen['max_dex']}, check {armor_pen['check_penalty']:+d}",
                ])
            tooltip_lines.extend([
                "",
                f"Applied (worst of armor/load): max Dex +{combined['max_dex']}, "
                f"check {combined['check_penalty']:+d}",
            ])
            self._bind_hover_tooltip(self.encumbrance_label, "\n".join(tooltip_lines), wraplength=360)
            self.refresh_container_storage_display()
            refresh_mount = getattr(self, "_mount_popup_refresh_load", None)
            if callable(refresh_mount):
                try:
                    refresh_mount()
                except Exception:
                    pass
        except Exception as exc:
            print(f"Encumbrance display error: {exc}")

    def _get_armor_category(self):
        armor = self.data.get("armor", {})
        if armor.get("status") != "worn":
            return None
        category = str(armor.get("category", "") or "").strip().lower()
        if not category:
            info = self._lookup_armor_info(armor.get("name", ""))
            category = str(info.get("category", "") or "").strip().lower()
        if not category:
            return None
        if self._normalize_special_material(armor.get("material")) == "Mithral":
            if category == "heavy":
                return "medium"
            if category == "medium":
                return "light"
        return category

    def _race_ignores_armor_and_load_land_speed_penalty(self):
        """Dwarves retain land speed in medium/heavy armor or medium/heavy load (3.5 SRD)."""
        return (self.data.get("race") or "").strip() == "Dwarf"

    def _lookup_armor_reduced_speed(self, land_speed):
        """Map base land speed to armored speed using the medium/heavy armor table."""
        land_speed = int(land_speed or 0)
        exact = {base: reduced for base, reduced in ARMOR_REDUCED_SPEED_TABLE}
        if land_speed in exact:
            return exact[land_speed]
        if land_speed < ARMOR_REDUCED_SPEED_TABLE[0][0]:
            return max(0, land_speed - 5)
        if land_speed > ARMOR_REDUCED_SPEED_TABLE[-1][0]:
            return land_speed - 30
        for i in range(len(ARMOR_REDUCED_SPEED_TABLE) - 1):
            low_base, low_reduced = ARMOR_REDUCED_SPEED_TABLE[i]
            high_base, high_reduced = ARMOR_REDUCED_SPEED_TABLE[i + 1]
            if low_base < land_speed < high_base:
                ratio = (land_speed - low_base) / (high_base - low_base)
                return round(low_reduced + ratio * (high_reduced - low_reduced))
        return land_speed

    def _get_armor_land_speed(self, before_armor):
        """Land speed from worn medium/heavy armor (no encumbrance adjustment)."""
        before_armor = int(before_armor or 0)
        if self._get_armor_category() in ("medium", "heavy"):
            if self._race_ignores_armor_and_load_land_speed_penalty():
                return before_armor
            return self._lookup_armor_reduced_speed(before_armor)
        return before_armor

    def _get_land_speed_before_armor(self):
        """Land speed after racial, enhancement, and class bonuses — before armor/load."""
        if self._get_active_wild_shape_form():
            return int(self._get_active_wild_shape_form().get("speed", {}).get("land", 0) or 0)
        race = self.data.get("race", "Human")
        base_land = int(self.races.get(race, {}).get("speed", 30) or 30)
        spell_b = self.get_spell_bonuses()
        magic_b = self.get_magic_item_bonuses()
        buff_b = self.get_buff_bonuses()
        speed_bonus = max(
            int(spell_b.get("speed_bonus", 0) or 0),
            int(magic_b.get("speed_bonus", 0) or 0),
            int(buff_b.get("speed_bonus", 0) or 0),
        )
        class_speed_bonus = 0
        if self._get_barbarian_class_bonuses().get("fast_movement") and self._get_armor_category() != "heavy":
            class_speed_bonus = int(self._get_barbarian_class_bonuses().get("speed_bonus", 0) or 0)
        return base_land + speed_bonus + class_speed_bonus

    def _get_load_land_speed(self, before_armor):
        """Land speed from encumbrance — uses the armor speed table for medium/heavy load."""
        before_armor = int(before_armor or 0)
        load_state = self._get_encumbrance_load_state()
        if (
            self._race_ignores_armor_and_load_land_speed_penalty()
            and load_state.get("load") in ("medium", "heavy")
        ):
            return before_armor
        if load_state.get("uses_armor_speed_table"):
            return self._lookup_armor_reduced_speed(before_armor)
        load_cap = load_state.get("land_speed")
        if load_cap is None:
            return before_armor
        return int(load_cap)

    def _resolve_land_speed_penalties(self, before_armor):
        """
        3.5 SRD: when wearing armor, use the worse land speed from armor or load.
        Do not stack both penalties.
        """
        before_armor = int(before_armor or 0)
        armor_speed = self._get_armor_land_speed(before_armor)
        load_speed = self._get_load_land_speed(before_armor)
        final_land = min(armor_speed, load_speed)

        lines = []
        armor_cat = self._get_armor_category()
        load_state = self._get_encumbrance_load_state()
        load_label = load_state.get("load_label", "Load")
        wearing_armor = armor_cat in ("medium", "heavy")
        has_load_cap = bool(
            load_state.get("uses_armor_speed_table") or load_state.get("land_speed") is not None
        )

        if wearing_armor and has_load_cap:
            if armor_speed <= load_speed:
                cat_label = (armor_cat or "armor").replace("_", " ").title()
                lines.append(
                    f"{cat_label} armor (worn): {before_armor} → {final_land} ft. "
                    f"(worse than {load_label.lower()} load {load_speed} ft.)",
                )
            else:
                lines.append(
                    f"{load_label} load: {before_armor} → {final_land} ft. "
                    f"(worse than {armor_cat} armor {armor_speed} ft.)",
                )
        elif wearing_armor and armor_speed < before_armor:
            cat_label = (armor_cat or "armor").replace("_", " ").title()
            lines.append(f"{cat_label} armor (worn): {before_armor} → {armor_speed} ft.")
        elif has_load_cap and load_speed < before_armor:
            lines.append(f"{load_label} load: {before_armor} → {load_speed} ft.")

        if self._race_ignores_armor_and_load_land_speed_penalty() and final_land >= before_armor:
            dwarf_note = False
            if wearing_armor and self._lookup_armor_reduced_speed(before_armor) < before_armor:
                dwarf_note = True
            if load_state.get("load") in ("medium", "heavy") and self._lookup_armor_reduced_speed(before_armor) < before_armor:
                dwarf_note = True
            if dwarf_note:
                lines.append("Dwarf: land speed unaffected by medium/heavy armor or load.")

        return {
            "before_armor": before_armor,
            "armor_speed": armor_speed,
            "load_speed": load_speed,
            "final_land": final_land,
            "lines": lines,
        }

    def _get_armor_run_multiplier(self):
        if self._get_armor_category() == "heavy":
            return 3
        return 4

    def _get_run_multiplier(self):
        """Worst-of armor vs. load run multiplier (lower multiplier wins)."""
        armor_mult = self._get_armor_run_multiplier()
        load_mult = self._get_encumbrance_load_state().get("run_multiplier")
        if load_mult is None:
            return armor_mult
        return min(armor_mult, int(load_mult))

    def _apply_armor_to_speed(self, speed):
        """Apply medium/heavy armor speed table to a single movement total."""
        speed = int(speed or 0)
        if speed <= 0:
            return 0
        if self._get_armor_category() in ("medium", "heavy"):
            return self._lookup_armor_reduced_speed(speed)
        return speed

    def _speed_for_granted_mode(self, base_speed, granted, speed_bonus=0):
        """Enhancement bonus + armor only when the mode is explicitly granted."""
        if not granted:
            return 0
        base_speed = int(base_speed or 0)
        if base_speed <= 0:
            return 0
        return self._apply_armor_to_speed(base_speed + int(speed_bonus or 0))

    def _on_armor_selected(self, choice):
        display_name = str(choice or "").strip()
        if not display_name:
            return
        _base, info = self._resolve_armor_display_name(display_name)
        if not info:
            return
        item = self._find_inventory_item_by_display_name(display_name, "armor")
        acp = int(info.get("armor_check_penalty", 0) or 0)
        if hasattr(self, "armor_vars"):
            self.armor_vars["name"].set(display_name)
            mat_combo = self.armor_vars.get("material_combo")
            if mat_combo is not None:
                mat_combo.configure(values=self._valid_armor_materials(display_name, info))
            self.armor_vars["bonus"].set(str(info.get("ac_bonus", 0)))
            self.armor_vars["max_dex"].set(str(info.get("max_dex", 99)))
            if "value" in self.armor_vars:
                self.armor_vars["value"].set(str(info.get("value", 0)))
            if "armor_check_penalty" in self.armor_vars:
                self.armor_vars["armor_check_penalty"].set(str(acp))
        self.data["armor"]["name"] = display_name
        self.data["armor"]["inventory_id"] = str(item.get("inventory_id") or "").strip() if item else ""
        self.data["armor"]["category"] = info.get("category", "")
        self.data["armor"]["bonus"] = int(info.get("ac_bonus", 0) or 0)
        self.data["armor"]["max_dex"] = int(info.get("max_dex", 99) or 99)
        self.data["armor"]["value"] = int(info.get("value", 0) or 0)
        self.data["armor"]["weight"] = int(info.get("weight", 0) or 0)
        self.data["armor"]["armor_check_penalty"] = acp
        self._apply_armor_material_stats()
        self._refresh_armor_status_combo()
        self.refresh_all()

    def _on_shield_selected(self, choice):
        display_name = str(choice or "").strip()
        if not display_name:
            return
        _base, info = self._resolve_shield_display_name(display_name)
        if not info:
            return
        item = self._find_inventory_item_by_display_name(display_name, "shield")
        acp = int(info.get("armor_check_penalty", 0) or 0)
        if hasattr(self, "shield_vars"):
            self.shield_vars["name"].set(display_name)
            mat_combo = self.shield_vars.get("material_combo")
            if mat_combo is not None:
                mat_combo.configure(values=self._valid_shield_materials(display_name, info))
            self.shield_vars["bonus"].set(str(info.get("ac_bonus", 0)))
            if "value" in self.shield_vars:
                self.shield_vars["value"].set(str(info.get("value", 0)))
            if "armor_check_penalty" in self.shield_vars:
                self.shield_vars["armor_check_penalty"].set(str(acp))
        self.data["shield"]["name"] = display_name
        self.data["shield"]["inventory_id"] = str(item.get("inventory_id") or "").strip() if item else ""
        self.data["shield"]["bonus"] = int(info.get("ac_bonus", 0) or 0)
        self.data["shield"]["value"] = int(info.get("value", 0) or 0)
        self.data["shield"]["weight"] = int(info.get("weight", 0) or 0)
        self.data["shield"]["armor_check_penalty"] = acp
        self._apply_shield_material_stats()
        self._refresh_shield_status_combo()
        self.refresh_all()

    def _generate_inventory_item_id(self):
        return str(random.randint(100000000, 999999999))

    def _ensure_inventory_item_ids(self):
        for item in self.data.get("inventory") or []:
            if not isinstance(item, dict):
                continue
            if not str(item.get("inventory_id") or "").strip():
                item["inventory_id"] = self._generate_inventory_item_id()

    def _extract_parenthetical_base_name(self, display_name):
        text = str(display_name or "").strip()
        match = re.search(r"\(([^)]+)\)\s*$", text)
        if match:
            return match.group(1).strip()
        return text

    def _resolve_weapon_display_name(self, display_name):
        text = str(display_name or "").strip()
        if not text:
            return "", {}
        info = self._lookup_mundane_weapon_info(text)
        if info:
            return text, info
        base = self._extract_parenthetical_base_name(text)
        if base and base.lower() != text.lower():
            info = self._lookup_mundane_weapon_info(base)
            if info:
                return base, info
        return text, {}

    def _resolve_armor_display_name(self, display_name):
        text = str(display_name or "").strip()
        if not text:
            return "", {}
        info = self._lookup_armor_info(text)
        if info:
            return text, info
        base = self._extract_parenthetical_base_name(text)
        if base and base.lower() != text.lower():
            info = self._lookup_armor_info(base)
            if info:
                return base, info
        mundane = (getattr(self, "mundane_armors_shields_db", {}) or {}).get(base) or {}
        if mundane.get("kind") == "armor":
            return base, mundane
        return text, {}

    def _resolve_shield_display_name(self, display_name):
        text = str(display_name or "").strip()
        if not text:
            return "", {}
        info = self._lookup_shield_info(text)
        if info:
            return text, info
        base = self._extract_parenthetical_base_name(text)
        if base and base.lower() != text.lower():
            info = self._lookup_shield_info(base)
            if info:
                return base, info
        mundane = (getattr(self, "mundane_armors_shields_db", {}) or {}).get(base) or {}
        if mundane.get("kind") == "shield":
            return base, mundane
        return text, {}

    def _inventory_item_is_ammunition(self, item):
        """True for arrows, bolts, bullets, and other ammunition — not weapon slots."""
        if not isinstance(item, dict):
            return False
        name = str(item.get("name", "")).strip()
        if not name:
            return False
        if self._classify_ammo_item(name):
            return True
        _, info = self._resolve_weapon_display_name(name)
        return str(info.get("category", "")).lower() == "ammunition"

    def _inventory_item_is_weapon(self, item):
        if not isinstance(item, dict):
            return False
        if self._inventory_item_is_ammunition(item):
            return False
        if str(item.get("gear_type") or "").lower() == "weapon":
            return True
        _, info = self._resolve_weapon_display_name(item.get("name", ""))
        return bool(info)

    def _inventory_item_is_armor(self, item):
        if not isinstance(item, dict):
            return False
        if str(item.get("gear_type") or "").lower() == "armor":
            return True
        _, info = self._resolve_armor_display_name(item.get("name", ""))
        return bool(info)

    def _inventory_item_is_shield(self, item):
        if not isinstance(item, dict):
            return False
        if str(item.get("gear_type") or "").lower() == "shield":
            return True
        _, info = self._resolve_shield_display_name(item.get("name", ""))
        return bool(info)

    def _inventory_gear_display_names(self, gear_type):
        self._ensure_inventory_item_ids()
        names = []
        checker = {
            "weapon": self._inventory_item_is_weapon,
            "armor": self._inventory_item_is_armor,
            "shield": self._inventory_item_is_shield,
        }.get(gear_type)
        if not checker:
            return []
        for item in self.data.get("inventory") or []:
            if not checker(item):
                continue
            name = str(item.get("name", "")).strip()
            if name:
                names.append(name)
        return sorted(set(names), key=str.lower)

    def _find_inventory_item_by_display_name(
        self, display_name, gear_type=None, exclude_inventory_ids=None,
    ):
        text = str(display_name or "").strip()
        if not text:
            return None
        excluded = {
            str(inv_id).strip()
            for inv_id in (exclude_inventory_ids or [])
            if str(inv_id).strip()
        }
        self._ensure_inventory_item_ids()
        for item in self.data.get("inventory") or []:
            if str(item.get("name", "")).strip().lower() != text.lower():
                continue
            if gear_type == "weapon" and not self._inventory_item_is_weapon(item):
                continue
            if gear_type == "armor" and not self._inventory_item_is_armor(item):
                continue
            if gear_type == "shield" and not self._inventory_item_is_shield(item):
                continue
            inv_id = str(item.get("inventory_id") or "").strip()
            if inv_id and inv_id in excluded:
                continue
            return item
        return None

    def _get_weapon_slot_assignment(self, idx):
        """Return (display_name, inventory_id) for a weapon slot using live UI when available."""
        name_from_ui = None
        if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
            try:
                name_from_ui = str(self.weapon_vars[idx]["name"].get() or "").strip()
            except (KeyError, tk.TclError):
                name_from_ui = ""
        weapons = self.data.get("weapons") or []
        weapon = weapons[idx] if idx < len(weapons) else {}
        if name_from_ui is not None:
            name = name_from_ui
        else:
            name = str(weapon.get("name") or "").strip()
        if not name:
            return "", ""
        inv_id = str(weapon.get("inventory_id") or "").strip()
        if inv_id:
            item = self._find_inventory_item_by_id(inv_id)
            if item:
                return name, inv_id
        if name:
            item = self._find_inventory_item_by_display_name(name, "weapon")
            if item:
                inv_id = str(item.get("inventory_id") or "").strip()
        return name, inv_id

    def _get_assigned_weapon_inventory_ids(self, exclude_slot_idx=None):
        """Inventory IDs already assigned to weapon slots (optionally excluding one slot)."""
        assigned = set()
        weapons = self.data.get("weapons") or []
        for i in range(len(weapons)):
            if exclude_slot_idx is not None and i == exclude_slot_idx:
                continue
            name, inv_id = self._get_weapon_slot_assignment(i)
            if not name:
                continue
            if inv_id:
                assigned.add(inv_id)
                continue
            item = self._find_inventory_item_by_display_name(
                name, "weapon", exclude_inventory_ids=assigned,
            )
            if item:
                candidate = str(item.get("inventory_id") or "").strip()
                if candidate:
                    assigned.add(candidate)
        return assigned

    def _find_inventory_item_by_id(self, inventory_id):
        inv_id = str(inventory_id or "").strip()
        if not inv_id:
            return None
        for item in self.data.get("inventory") or []:
            if str(item.get("inventory_id") or "").strip() == inv_id:
                return item
        return None

    def _find_inventory_index_by_id(self, inventory_id):
        inv_id = str(inventory_id or "").strip()
        if not inv_id:
            return None
        for idx, item in enumerate(self.data.get("inventory") or []):
            if str(item.get("inventory_id") or "").strip() == inv_id:
                return idx
        return None

    def _find_gear_inventory_item_for_conversion(
        self, gear_type, inventory_id, mundane_display_name, slot_index=None,
    ):
        """Locate the personal inventory row tied to a gear conversion."""
        self._ensure_inventory_item_ids()
        inv_id = str(inventory_id or "").strip()
        if inv_id:
            item = self._find_inventory_item_by_id(inv_id)
            if item is not None:
                return item, inv_id

        mundane = str(mundane_display_name or "").strip()
        if not mundane:
            return None, inv_id

        exclude_ids = None
        if gear_type == "weapon" and slot_index is not None:
            exclude_ids = self._get_assigned_weapon_inventory_ids(exclude_slot_idx=slot_index)

        item = self._find_inventory_item_by_display_name(
            mundane, gear_type, exclude_inventory_ids=exclude_ids,
        )
        if item is not None:
            return item, str(item.get("inventory_id") or "").strip()
        return None, inv_id

    def _apply_inventory_magical_conversion(
        self, item, *, display_name, enh, magical_value, gear_type, enchants,
    ):
        if not isinstance(item, dict):
            return
        item["name"] = display_name
        item["enh"] = enh
        item["value"] = magical_value
        if gear_type in ("weapon", "armor", "shield"):
            item["gear_type"] = gear_type
        if gear_type in ("armor", "shield"):
            item["enchants"] = list(enchants)

    def _weapon_inventory_location(self, idx):
        weapon = self._get_weapon_slot(idx)
        inv_id = str(weapon.get("inventory_id") or "").strip()
        if inv_id:
            item = self._find_inventory_item_by_id(inv_id)
            if item:
                return str(item.get("location", "person") or "person").strip().lower()
        name = str(weapon.get("name") or "").strip()
        item = self._find_inventory_item_by_display_name(name, "weapon")
        if item:
            return str(item.get("location", "person") or "person").strip().lower()
        return "person"

    def _weapon_status_options_for_slot(self, idx):
        if self._weapon_inventory_location(idx) == "person":
            return ["wielded", "stowed", "dropped"]
        return ["storage"]

    def _armor_status_options(self):
        inv_id = str(self.data.get("armor", {}).get("inventory_id") or "").strip()
        if inv_id:
            item = self._find_inventory_item_by_id(inv_id)
            if item and str(item.get("location", "person")).strip().lower() != "person":
                return ["storage"]
        name = str(self.data.get("armor", {}).get("name") or "").strip()
        item = self._find_inventory_item_by_display_name(name, "armor")
        if item and str(item.get("location", "person")).strip().lower() != "person":
            return ["storage"]
        return ["worn", "stored"]

    def _shield_status_options(self):
        inv_id = str(self.data.get("shield", {}).get("inventory_id") or "").strip()
        if inv_id:
            item = self._find_inventory_item_by_id(inv_id)
            if item and str(item.get("location", "person")).strip().lower() != "person":
                return ["storage"]
        name = str(self.data.get("shield", {}).get("name") or "").strip()
        item = self._find_inventory_item_by_display_name(name, "shield")
        if item and str(item.get("location", "person")).strip().lower() != "person":
            return ["storage"]
        return ["worn", "stored"]

    def _refresh_weapon_status_combo(self, idx):
        if not hasattr(self, "weapon_vars") or idx >= len(self.weapon_vars):
            return
        combo = self.weapon_vars[idx].get("status_combo")
        if combo is None:
            return
        options = self._weapon_status_options_for_slot(idx)
        current = str(self.weapon_vars[idx]["status"].get() or "").strip().lower()
        combo.configure(values=options)
        was_rebuilding = getattr(self, "_rebuilding_ui", False)
        self._rebuilding_ui = True
        try:
            if current in options:
                try:
                    combo.set(current)
                except tk.TclError:
                    self.weapon_vars[idx]["status"].set(current)
            else:
                new_status = options[0]
                try:
                    combo.set(new_status)
                except tk.TclError:
                    self.weapon_vars[idx]["status"].set(new_status)
                if idx < len(self.data.get("weapons", [])):
                    self.data["weapons"][idx]["status"] = new_status
        finally:
            self._rebuilding_ui = was_rebuilding

    def _refresh_armor_status_combo(self):
        if not hasattr(self, "armor_vars") or not self.armor_vars.get("status_combo"):
            return
        opts = self._armor_status_options()
        current = self.armor_vars["status"].get()
        self.armor_vars["status_combo"].configure(values=opts)
        if current not in opts:
            new_status = opts[0]
            self.armor_vars["status"].set(new_status)
            self.data.setdefault("armor", {})["status"] = new_status

    def _refresh_shield_status_combo(self):
        if not hasattr(self, "shield_vars") or not self.shield_vars.get("status_combo"):
            return
        opts = self._shield_status_options()
        current = self.shield_vars["status"].get()
        self.shield_vars["status_combo"].configure(values=opts)
        if current not in opts:
            new_status = opts[0]
            self.shield_vars["status"].set(new_status)
            self.data.setdefault("shield", {})["status"] = new_status

    def _get_weapon_combat_key(self, idx, weapon_data=None):
        weapon = weapon_data or self._get_weapon_slot(idx)
        inv_id = str(weapon.get("inventory_id") or "").strip()
        if inv_id:
            return inv_id
        name = str(weapon.get("name") or "").strip()
        item = self._find_inventory_item_by_display_name(name, "weapon")
        if item and str(item.get("inventory_id") or "").strip():
            return str(item["inventory_id"])
        return str(idx)

    def _migrate_combat_weapon_keys_by_inventory_id(self):
        combat_weapons = self.data.setdefault("combat", {}).setdefault("weapons", {})
        migrated = {}
        for key, cfg in list(combat_weapons.items()):
            if key not in migrated:
                migrated[key] = copy.deepcopy(cfg)
        for i, weapon in enumerate(self.data.get("weapons") or []):
            inv_id = str(weapon.get("inventory_id") or "").strip()
            old_key = str(i)
            if not inv_id:
                name = str(weapon.get("name") or "").strip()
                item = self._find_inventory_item_by_display_name(name, "weapon")
                if item:
                    inv_id = str(item.get("inventory_id") or "").strip()
                    weapon["inventory_id"] = inv_id
            if old_key in migrated and inv_id:
                if inv_id not in migrated:
                    migrated[inv_id] = migrated.pop(old_key)
                else:
                    migrated[inv_id].update(migrated.pop(old_key))
        self.data["combat"]["weapons"] = migrated

    def _weapon_dropdown_values(self, slot_idx=None):
        if slot_idx is not None:
            return self._weapon_dropdown_values_for_slot(slot_idx)
        return self._inventory_gear_display_names("weapon")

    def _weapon_dropdown_values_for_slot(self, slot_idx):
        """Owned inventory weapons not already assigned to other weapon slots."""
        self._ensure_inventory_item_ids()
        assigned_ids = self._get_assigned_weapon_inventory_ids(exclude_slot_idx=slot_idx)
        names = []
        for item in self.data.get("inventory") or []:
            if not self._inventory_item_is_weapon(item):
                continue
            inv_id = str(item.get("inventory_id") or "").strip()
            if inv_id and inv_id in assigned_ids:
                continue
            name = str(item.get("name", "")).strip()
            if name:
                names.append(name)
        return sorted(set(names), key=str.lower)

    def _armor_dropdown_values(self):
        return self._inventory_gear_display_names("armor")

    def _shield_dropdown_values(self):
        return self._inventory_gear_display_names("shield")

    def _inventory_knight_helmet_image(self, *, size=22):
        """Knight helm icon for the armor auto-equip button (theme-colored)."""
        color_key = getattr(self, "primary_button_color", "#c77626")
        cache = getattr(self, "_inventory_knight_helmet_cache", None)
        cache_key = (size, color_key)
        if isinstance(cache, dict) and cache_key in cache:
            return cache[cache_key]
        if not HAS_PIL:
            return None

        source_path = self._json_path("knight_helmet.png")
        if not os.path.isfile(source_path):
            source_path = os.path.join(APP_DIR, "knight_helmet.png")
        if not os.path.isfile(source_path):
            return None

        hex_color = str(color_key or "#c77626").lstrip("#")
        if len(hex_color) == 6:
            rgb = tuple(int(hex_color[i:i + 2], 16) for i in (0, 2, 4))
        else:
            rgb = (199, 118, 38)

        with Image.open(source_path) as source:
            img = source.convert("RGBA").resize((size, size), Image.Resampling.LANCZOS)
        pixels = img.load()
        tint_r, tint_g, tint_b = rgb
        for y in range(size):
            for x in range(size):
                _, _, _, alpha = pixels[x, y]
                if alpha < 8:
                    pixels[x, y] = (0, 0, 0, 0)
                else:
                    pixels[x, y] = (tint_r, tint_g, tint_b, alpha)

        ctk_img = ctk.CTkImage(light_image=img, dark_image=img, size=(size, size))
        if not isinstance(cache, dict):
            cache = {}
        cache[cache_key] = ctk_img
        self._inventory_knight_helmet_cache = cache
        return ctk_img

    def _inventory_magic_orb_image(self, *, size=22):
        """Crystal-ball icon for the magical item conversion button."""
        cache = getattr(self, "_inventory_magic_orb_cache", None)
        cache_key = size
        if isinstance(cache, dict) and cache_key in cache:
            return cache[cache_key]
        if not HAS_PIL:
            return None

        source_path = self._json_path("magic_orb_icon.png")
        if not os.path.isfile(source_path):
            source_path = os.path.join(APP_DIR, "magic_orb_icon.png")
        if not os.path.isfile(source_path):
            return None

        bg_rgb = (236, 232, 231)
        line_rgb = (40, 169, 158)  # THEME_TEAL

        with Image.open(source_path) as source:
            img = source.convert("RGBA")
            width, height = img.size
            side = min(width, height)
            left = (width - side) // 2
            top = (height - side) // 2
            img = img.crop((left, top, left + side, top + side))
            img = img.resize((size, size), Image.Resampling.LANCZOS)

        pixels = img.load()
        for y in range(size):
            for x in range(size):
                r, g, b, _alpha = pixels[x, y]
                dist = ((r - bg_rgb[0]) ** 2 + (g - bg_rgb[1]) ** 2 + (b - bg_rgb[2]) ** 2) ** 0.5
                if dist < 28:
                    pixels[x, y] = (0, 0, 0, 0)
                else:
                    strength = min(255, int((dist - 28) * 10))
                    pixels[x, y] = (line_rgb[0], line_rgb[1], line_rgb[2], max(40, strength))

        ctk_img = ctk.CTkImage(light_image=img, dark_image=img, size=(size, size))
        if not isinstance(cache, dict):
            cache = {}
        cache[cache_key] = ctk_img
        self._inventory_magic_orb_cache = cache
        return ctk_img

    def _inventory_coins_image(self, *, size=24):
        """Stacked-coins icon for the inventory coins widget header."""
        color_key = getattr(self, "primary_button_color", "#c77626")
        cache = getattr(self, "_inventory_coins_image_cache", None)
        cache_key = (size, color_key)
        if isinstance(cache, dict) and cache_key in cache:
            return cache[cache_key]
        if not HAS_PIL:
            return None

        source_path = self._json_path("money_coinsIcon.png")
        if not os.path.isfile(source_path):
            source_path = os.path.join(APP_DIR, "money_coinsIcon.png")
        if not os.path.isfile(source_path):
            return None

        hex_color = str(color_key or "#c77626").lstrip("#")
        if len(hex_color) == 6:
            rgb = tuple(int(hex_color[i:i + 2], 16) for i in (0, 2, 4))
        else:
            rgb = (199, 118, 38)

        with Image.open(source_path) as source:
            img = source.convert("RGBA")
            width, height = img.size
            side = min(width, height)
            left = (width - side) // 2
            top = (height - side) // 2
            img = img.crop((left, top, left + side, top + side))
            img = img.resize((size, size), Image.Resampling.LANCZOS)

        pixels = img.load()
        tint_r, tint_g, tint_b = rgb
        for y in range(size):
            for x in range(size):
                r, g, b, alpha = pixels[x, y]
                if alpha < 8:
                    pixels[x, y] = (0, 0, 0, 0)
                    continue
                lum = (r * 0.299 + g * 0.587 + b * 0.114)
                if lum > 235:
                    pixels[x, y] = (0, 0, 0, 0)
                else:
                    strength = max(40, min(255, int(lum * 1.2)))
                    pixels[x, y] = (tint_r, tint_g, tint_b, strength)

        ctk_img = ctk.CTkImage(light_image=img, dark_image=img, size=(size, size))
        if not isinstance(cache, dict):
            cache = {}
        cache[cache_key] = ctk_img
        self._inventory_coins_image_cache = cache
        return ctk_img

    def _add_inventory_auto_equip_button(
        self, parent, icon, tooltip, command, *, image=None, magic_style=False,
    ):
        btn_kwargs = dict(
            width=28,
            height=28,
            fg_color="transparent",
            border_width=0,
            hover_color="#3a3a3a",
            command=command,
        )
        if image is not None:
            btn = ctk.CTkButton(parent, text="", image=image, **btn_kwargs)
        elif magic_style:
            btn = ctk.CTkButton(
                parent,
                text=icon,
                text_color=THEME_TEAL,
                font=ctk.CTkFont(size=16),
                **btn_kwargs,
            )
        else:
            btn = ctk.CTkButton(
                parent,
                text=icon,
                text_color=getattr(self, "primary_button_color", "#c77626"),
                font=ctk.CTkFont(size=16),
                **btn_kwargs,
            )
        btn.pack(side="right")
        self._bind_hover_tooltip(btn, tooltip)
        return btn

    def _build_inventory_section_header(
        self,
        parent,
        title,
        *,
        icon,
        tooltip,
        command,
        icon_image=None,
        magic_command=None,
        magic_tooltip="Convert to magical item",
    ):
        header = ctk.CTkFrame(parent, fg_color="transparent")
        header.pack(fill="x", padx=8, pady=8)
        ctk.CTkLabel(
            header, text=title, font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(side="left", anchor="w")
        if magic_command is not None:
            self._add_inventory_auto_equip_button(
                parent=header,
                icon="✦",
                tooltip=magic_tooltip,
                command=magic_command,
                image=self._inventory_magic_orb_image(),
                magic_style=True,
            )
        self._add_inventory_auto_equip_button(
            parent=header,
            icon=icon,
            tooltip=tooltip,
            command=command,
            image=icon_image,
        )
        return header

    def _open_magical_conversion_wizard(self, gear_type):
        if not HAS_MAGIC_CONVERSION_WIZARD or MagicalItemConversionWizard is None:
            messagebox.showerror(
                "Magical Conversion",
                "magical_item_conversion_wizard.py is missing from the app folder.",
            )
            return
        MagicalItemConversionWizard(
            self,
            gear_type,
            on_complete=self._begin_magical_conversion_with_purchase,
        )

    def _begin_magical_conversion_with_purchase(self, result):
        """Open the standard coin payment popup, then apply the conversion."""
        if not isinstance(result, dict):
            return False
        if bool(result.get("gifted")):
            return self._apply_magical_item_conversion(result, payment_already_collected=True)
        display_name = str(result.get("display_name") or "").strip() or "Magical item"
        cost_gp = float(result.get("cost_gp", 0) or 0)
        if cost_gp > 0.001:
            buy_entry = {
                "name": f"Magical conversion: {display_name}",
                "cost": cost_gp,
                "value": cost_gp,
            }

            def _on_paid(_entry, purchase_popup):
                purchase_popup.destroy()
                self._apply_magical_item_conversion(
                    result, payment_already_collected=True,
                )

            self._open_buy_payment_popup(
                buy_entry,
                None,
                on_purchase_complete=_on_paid,
            )
            return True
        return self._apply_magical_item_conversion(result, payment_already_collected=True)

    def _apply_magical_item_conversion(self, result, *, payment_already_collected=False):
        if not isinstance(result, dict):
            return False
        gear_type = str(result.get("gear_type") or "").strip().lower()
        display_name = str(result.get("display_name") or "").strip()
        enh = max(0, int(result.get("enhancement", 0) or 0))
        enchants = list(result.get("enchants") or [])
        magical_value = float(result.get("magical_value", 0) or 0)
        cost_gp = float(result.get("cost_gp", 0) or 0)
        cost_xp = int(result.get("cost_xp", 0) or 0)
        gifted = bool(result.get("gifted"))
        crafted = bool(result.get("crafted"))
        inventory_id = str(result.get("inventory_id") or "").strip()
        mundane_display_name = str(result.get("mundane_display_name") or "").strip()
        slot_index = result.get("slot_index")

        if not display_name:
            messagebox.showwarning("Magical Conversion", "Magical item name is required.")
            return False
        if enh <= 0 and not enchants:
            messagebox.showwarning(
                "Magical Conversion",
                "Choose at least a +1 enhancement bonus or one special ability.",
            )
            return False
        if not payment_already_collected and not gifted and cost_gp > 0:
            available_gp = self._get_coin_pools_gp_total(["person", "container", "banked"])
            if not self._spend_coins_across_locations(cost_gp, ["person", "container", "banked"]):
                messagebox.showerror(
                    "Magical Conversion",
                    f"Not enough coins to pay {cost_gp:,.2f} gp for this conversion.\n\n"
                    f"Available across Person, Container, and Banked: {available_gp:,.2f} gp.",
                )
                return False

        item, inventory_id = self._find_gear_inventory_item_for_conversion(
            gear_type,
            inventory_id,
            mundane_display_name,
            slot_index if gear_type == "weapon" else None,
        )

        if gear_type == "weapon":
            if slot_index is None or slot_index < 0 or slot_index >= 5:
                messagebox.showerror("Magical Conversion", "Invalid weapon slot.")
                return False
            if hasattr(self, "weapon_vars") and slot_index < len(self.weapon_vars):
                vdict = self.weapon_vars[slot_index]
                vdict["name"].set(display_name)
                if "enh" in vdict:
                    vdict["enh"].set(str(enh))
                if "value" in vdict:
                    vdict["value"].set(str(int(round(magical_value))))
            weapon = self.data["weapons"][slot_index]
            weapon["name"] = display_name
            weapon["enh"] = enh
            weapon["value"] = magical_value
            weapon["enchants"] = list(enchants)
            if inventory_id:
                weapon["inventory_id"] = inventory_id
            self._set_weapon_enchants(slot_index, enchants)
            self._refresh_weapon_status_combo(slot_index)
            self._refresh_gear_dropdowns()
            if hasattr(self, "combat_weapons_scroll") and self._is_page_active("Combat"):
                self.refresh_combat_page()
        elif gear_type == "armor":
            if hasattr(self, "armor_vars"):
                self.armor_vars["name"].set(display_name)
                if "enh" in self.armor_vars:
                    self.armor_vars["enh"].set(str(enh))
                if "value" in self.armor_vars:
                    self.armor_vars["value"].set(str(int(round(magical_value))))
            armor = self.data.setdefault("armor", {})
            armor["name"] = display_name
            armor["enh"] = enh
            armor["value"] = magical_value
            armor["enchants"] = list(enchants)
            if inventory_id:
                armor["inventory_id"] = inventory_id
            self._refresh_armor_status_combo()
        elif gear_type == "shield":
            if hasattr(self, "shield_vars"):
                self.shield_vars["name"].set(display_name)
                if "enh" in self.shield_vars:
                    self.shield_vars["enh"].set(str(enh))
                if "value" in self.shield_vars:
                    self.shield_vars["value"].set(str(int(round(magical_value))))
            shield = self.data.setdefault("shield", {})
            shield["name"] = display_name
            shield["enh"] = enh
            shield["value"] = magical_value
            shield["enchants"] = list(enchants)
            if inventory_id:
                shield["inventory_id"] = inventory_id
            self._refresh_shield_status_combo()
        else:
            messagebox.showerror("Magical Conversion", f"Unsupported gear type: {gear_type}")
            return False

        if item is not None:
            self._apply_inventory_magical_conversion(
                item,
                display_name=display_name,
                enh=enh,
                magical_value=magical_value,
                gear_type=gear_type,
                enchants=enchants,
            )

        self._refresh_gear_dropdowns()
        self.refresh_inventory(sync_first=False)
        self.refresh_encumbrance_display()
        self._refresh_coin_ui_if_visible()
        self.refresh_all()
        self._cloud_sync_dirty = True
        if hasattr(self, "tabview"):
            try:
                self.refresh_feats_scope("magical_items")
            except Exception:
                pass
        if gifted or cost_gp <= 0:
            pay_note = ""
        elif payment_already_collected:
            pay_note = f" — purchased for {cost_gp:,.0f} gp"
        else:
            pay_note = f" — paid {cost_gp:,.0f} gp"
        messagebox.showinfo(
            "Magical Conversion",
            f"Converted to:\n{display_name}{pay_note}",
        )
        return True

    def _person_inventory_gear_candidates(self, gear_type, *, exclude_assigned=True):
        """Gear on the person tab that resolves for the given slot type."""
        self._ensure_inventory_item_ids()
        checker = {
            "weapon": self._inventory_item_is_weapon,
            "armor": self._inventory_item_is_armor,
            "shield": self._inventory_item_is_shield,
        }.get(gear_type)
        if not checker:
            return []
        excluded_ids = set()
        if gear_type == "weapon" and exclude_assigned:
            excluded_ids = self._get_assigned_weapon_inventory_ids()
        elif gear_type == "armor" and exclude_assigned:
            inv_id = str(self.data.get("armor", {}).get("inventory_id") or "").strip()
            if inv_id:
                excluded_ids.add(inv_id)
            else:
                name = str(self.data.get("armor", {}).get("name") or "").strip()
                item = self._find_inventory_item_by_display_name(name, "armor")
                if item:
                    candidate = str(item.get("inventory_id") or "").strip()
                    if candidate:
                        excluded_ids.add(candidate)
        elif gear_type == "shield" and exclude_assigned:
            inv_id = str(self.data.get("shield", {}).get("inventory_id") or "").strip()
            if inv_id:
                excluded_ids.add(inv_id)
            else:
                name = str(self.data.get("shield", {}).get("name") or "").strip()
                item = self._find_inventory_item_by_display_name(name, "shield")
                if item:
                    candidate = str(item.get("inventory_id") or "").strip()
                    if candidate:
                        excluded_ids.add(candidate)

        candidates = []
        for item in self.data.get("inventory") or []:
            if not isinstance(item, dict):
                continue
            if str(item.get("location", "person") or "person").strip().lower() != "person":
                continue
            if not checker(item):
                continue
            inv_id = str(item.get("inventory_id") or "").strip()
            if inv_id and inv_id in excluded_ids:
                continue
            name = str(item.get("name", "")).strip()
            if not name:
                continue
            if gear_type == "weapon":
                _base, info = self._resolve_weapon_display_name(name)
                if not info:
                    continue
            elif gear_type == "armor":
                _base, info = self._resolve_armor_display_name(name)
                if not info:
                    continue
            else:
                _base, info = self._resolve_shield_display_name(name)
                if not info:
                    continue
            candidates.append(item)
        return candidates

    def _weapon_slot_is_empty(self, idx):
        name = ""
        if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
            try:
                name = str(self.weapon_vars[idx]["name"].get() or "").strip()
            except (KeyError, tk.TclError):
                name = ""
        if not name:
            weapons = self.data.get("weapons") or []
            if idx < len(weapons):
                name = str(weapons[idx].get("name") or "").strip()
        return not bool(name)

    def _armor_slot_is_empty(self):
        name = ""
        if hasattr(self, "armor_vars"):
            try:
                name = str(self.armor_vars["name"].get() or "").strip()
            except (KeyError, tk.TclError):
                name = ""
        if not name:
            name = str(self.data.get("armor", {}).get("name") or "").strip()
        return not bool(name)

    def _shield_slot_is_empty(self):
        name = ""
        if hasattr(self, "shield_vars"):
            try:
                name = str(self.shield_vars["name"].get() or "").strip()
            except (KeyError, tk.TclError):
                name = ""
        if not name:
            name = str(self.data.get("shield", {}).get("name") or "").strip()
        return not bool(name)

    def _show_gear_equipped_reminder_popup(self, equipped_labels):
        if not equipped_labels:
            messagebox.showinfo(
                "Auto-Equip",
                "No matching items were found in personal inventory, or every slot is already filled.",
            )
            return
        lines = "\n".join(f"• {label}" for label in equipped_labels)
        messagebox.showinfo(
            "Items Equipped",
            f"{lines}\n\n"
            "Items equipped. You must wield weapons to show attacks in Combat.\n"
            "On the Combat page, use the ⚔ button on Owned Weapons (or set status to Wielded on Inventory).",
        )

    def _auto_equip_weapons_from_person_inventory(self):
        equipped = []
        candidates = [
            item for item in self._person_inventory_gear_candidates("weapon")
            if not self._inventory_item_is_ammunition(item)
        ]
        cand_idx = 0
        for slot_idx in range(5):
            if cand_idx >= len(candidates):
                break
            if not self._weapon_slot_is_empty(slot_idx):
                continue
            item = candidates[cand_idx]
            cand_idx += 1
            display_name = str(item.get("name", "")).strip()
            if not display_name or self._inventory_item_is_ammunition(item):
                continue
            self._on_weapon_selected(slot_idx, display_name)
            equipped.append(display_name)
        self._show_gear_equipped_reminder_popup(equipped)

    def _auto_equip_armor_from_person_inventory(self):
        if not self._armor_slot_is_empty():
            messagebox.showinfo("Auto-Equip", "The armor slot is already filled.")
            return
        candidates = self._person_inventory_gear_candidates("armor")
        if not candidates:
            self._show_gear_equipped_reminder_popup([])
            return
        display_name = str(candidates[0].get("name", "")).strip()
        if display_name:
            self._on_armor_selected(display_name)
            self._show_gear_equipped_reminder_popup([display_name])
        else:
            self._show_gear_equipped_reminder_popup([])

    def _auto_equip_shield_from_person_inventory(self):
        if not self._shield_slot_is_empty():
            messagebox.showinfo("Auto-Equip", "The shield slot is already filled.")
            return
        candidates = self._person_inventory_gear_candidates("shield")
        if not candidates:
            self._show_gear_equipped_reminder_popup([])
            return
        display_name = str(candidates[0].get("name", "")).strip()
        if display_name:
            self._on_shield_selected(display_name)
            self._show_gear_equipped_reminder_popup([display_name])
        else:
            self._show_gear_equipped_reminder_popup([])

    def _set_weapon_slot_status(self, idx, status):
        status = str(status or "").strip().lower()
        if not status:
            return
        if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
            try:
                self.weapon_vars[idx]["status"].set(status)
            except (KeyError, tk.TclError):
                pass
        weapons = self.data.setdefault("weapons", [])
        if idx < len(weapons):
            weapons[idx]["status"] = status
        self._refresh_weapon_status_combo(idx)
        self._mark_cloud_sync_dirty()

    def _toggle_weapon_wielded_for_summaries(self, idx):
        """Toggle wielded/stowed so the weapon appears or disappears in Attack Summaries."""
        weapon = self._get_weapon_slot(idx)
        if not str(weapon.get("name") or "").strip():
            return
        current = str(weapon.get("status", "")).strip().lower()
        if current == "wielded":
            self._set_weapon_slot_status(idx, "stowed")
        else:
            self._set_weapon_slot_status(idx, "wielded")
        if hasattr(self, "combat_weapons_scroll") and self._is_page_active("Combat"):
            self.refresh_combat_page()
        else:
            self._mark_combat_page_stale()
            self._refresh_combat_attack_summaries()

    def _race_dropdown_values(self):
        """Return race list for the dropdown: core SRD races (alpha) first,
        then a visual separator, then all other races (alpha).
        """
        if not hasattr(self, "races") or not self.races:
            return []
        core_srd = ["Dwarf", "Elf", "Gnome", "Half-Elf", "Half-Orc", "Halfling", "Human"]
        all_races = list(self.races.keys())
        core = sorted([r for r in core_srd if r in all_races])
        others = sorted([r for r in all_races if r not in core])
        separator = "────────────────────"
        if others:
            return core + [separator] + others
        return core

    def _lookup_mundane_weapon_info(self, name):
        if not hasattr(self, "mundane_weapons_db") or not self.mundane_weapons_db:
            self.load_mundane_weapons_db()
        if not name:
            return {}
        key = str(name).strip()
        db = self.mundane_weapons_db or {}
        if key in db:
            return db[key]
        for k, v in db.items():
            if k.lower() == key.lower():
                return v
        return {}

    def _on_weapon_selected(self, idx, choice):
        display_name = str(choice or "").strip()
        if not display_name:
            return
        _base, info = self._resolve_weapon_display_name(display_name)
        if not info:
            return
        if idx >= len(self.data.get("weapons", [])):
            return
        assigned_elsewhere = self._get_assigned_weapon_inventory_ids(exclude_slot_idx=idx)
        item = self._find_inventory_item_by_display_name(
            display_name, "weapon", exclude_inventory_ids=assigned_elsewhere,
        )
        w = self.data["weapons"][idx]
        w["name"] = display_name
        w["inventory_id"] = str(item.get("inventory_id") or "").strip() if item else ""
        # Autofill core fields from Mundane_Weapons.json
        w["weight"] = float(info.get("weight", w.get("weight", 0) or 0))
        w["value"] = float(info.get("value", info.get("cost", w.get("value", 0) or 0)))
        w["range"] = int(info.get("range", w.get("range", 0) or 0))
        w["damage"] = info.get("damage_m", info.get("damage", w.get("damage", "")))
        # special qualities summary
        sp = info.get("special_description", "") or ""
        if isinstance(info.get("special"), (list, tuple)) and info["special"]:
            tags = ", ".join(info["special"])
            sp = (tags + (". " if sp else "")) + sp
        w["special"] = sp.strip()
        w["critical"] = info.get("critical", w.get("critical", "x2"))

        # Update the name var if we have the direct reference (the combo itself usually already reflects the choice)
        if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
            vdict = self.weapon_vars[idx]
            if "name" in vdict:
                try:
                    vdict["name"].set(display_name)
                except Exception:
                    pass
            mat_combo = vdict.get("material_combo")
            if mat_combo is not None:
                mat_combo.configure(values=self._valid_weapon_materials(display_name, info))

        # Block traces during the numeric box sets to avoid re-entrant syncs reading
        # a partially-updated state (one box new, others still old) and writing stale
        # values back to data. This eliminates the "weight goes up 1 then back to 0" flicker.
        was_rebuilding = getattr(self, "_rebuilding_ui", False)
        self._rebuilding_ui = True
        try:
            # Set the inventory boxes DIRECTLY from the info (source of truth), not from w
            # (to avoid any timing where a prior sync overwrote w with 0 from old UI).
            # This ensures non-zero values from Mundane_Weapons.json actually appear.
            value_val = info.get("value", info.get("cost", 0))
            range_val = info.get("range", 0)

            # ALWAYS attempt via registry (survives list clobbering)
            for k, val in (("value", value_val), ("range", range_val)):
                reg = f"weapon_{idx}_{k}"
                if reg in self.widget_registry:
                    try:
                        sv = self.widget_registry[reg]
                        if isinstance(sv, ctk.StringVar):
                            sv.set(str(val))
                        elif hasattr(sv, "set"):
                            sv.set(str(val))
                    except Exception:
                        pass
            # Direct vdict if available (now that combat no longer clobbers the list)
            if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
                vdict = self.weapon_vars[idx]
                for k, val in (("value", value_val), ("range", range_val)):
                    if k in vdict and isinstance(vdict[k], ctk.StringVar):
                        try:
                            vdict[k].set(str(val))
                        except Exception:
                            pass
        finally:
            self._rebuilding_ui = was_rebuilding

        # Now that boxes are updated, do one clean sync so data matches the new UI values.
        try:
            self._sync_weapon_slots_from_widgets()
        except Exception:
            pass

        self._refresh_weapon_status_combo(idx)
        self._refresh_gear_dropdowns()

        # Push threat/crit (and die) into the combat config
        self._apply_weapon_mundane_to_combat(idx, info)
        self._apply_weapon_material_stats(idx)

        # If the combat Owned Weapons table is currently built (live widgets), push the
        # updated Damage Die / Threat / Crit directly into the combo boxes so the user sees
        # the change immediately on the Combat page without having to rebuild.
        self._push_mundane_updates_to_combat_widgets(idx, info)

        self.refresh_encumbrance_display()
        self.refresh_all()

        # Ensure display updates
        try:
            self.root.update_idletasks()
        except Exception:
            pass

    def _apply_weapon_mundane_to_combat(self, idx, info):
        """When a mundane weapon is chosen in inventory, seed the per-weapon combat config Threat/Crit."""
        if idx < 0 or idx > 4:
            return
        combat_key = self._get_weapon_combat_key(idx)
        combat = self.data.setdefault("combat", {}).setdefault("weapons", {}).setdefault(combat_key, {})
        # Seed/overwrite the base threat/crit/die from the chosen mundane weapon.
        # (User can still use the temp override boxes on Combat page or the enh/feat_atk/feat_dmg on Inventory.)
        threat = str(info.get("threat_range", "20") or "20").strip()
        mult = str(info.get("crit_multiplier", "x2") or "x2").strip()
        combat["threat_range"] = threat
        combat["crit_multiplier"] = mult
        die = info.get("damage_m", "")
        if die in (globals().get("DAMAGE_DICE") or []):
            combat["damage_die"] = die
        # damage type guess (always set from mundane for consistency)
        t = str(info.get("type", "")).split()[0].capitalize() if info.get("type") else ""
        if t in ("Bludgeoning", "Piercing", "Slashing"):
            combat["damage_type"] = t

    def _push_mundane_updates_to_combat_widgets(self, idx, info):
        """If the Combat page's 'Owned Weapons' table is currently built, push the
        Damage Die / Threat / Crit values from the mundane selection into the live
        combo widgets so the user sees them update without needing a full page rebuild.
        """
        if not hasattr(self, "_combat_weapon_widgets"):
            return
        widgets = self._combat_weapon_widgets.get(idx) or self._combat_weapon_widgets.get(str(idx))
        if not widgets:
            return
        try:
            die = info.get("damage_m", "")
            if die and "damage_die" in widgets:
                widgets["damage_die"].set(die)
            threat = str(info.get("threat_range", "20") or "20").strip()
            if "threat_range" in widgets:
                widgets["threat_range"].set(threat)
            mult = self._normalize_crit_multiplier(info.get("crit_multiplier", "x2"))
            if "crit_multiplier" in widgets:
                widgets["crit_multiplier"].set(mult)
        except Exception:
            pass

    def _show_weapon_special_info(self, idx):
        weapon = self._get_weapon_slot(idx)
        name = str(weapon.get("name", "") or "Weapon").strip() or "Weapon"
        info = self._lookup_mundane_weapon_info(name)
        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Weapon: {name}")
        popup.transient(self.root)
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=440, min_height=280)

        ctk.CTkLabel(popup, text=name, font=ctk.CTkFont(size=16, weight="bold")).pack(pady=(10, 4))

        dm = info.get("damage_m", weapon.get("damage", "?"))
        crit = info.get("critical", weapon.get("critical", "?"))
        rng = info.get("range", weapon.get("range", 0))
        typ = info.get("type", "?")
        ctk.CTkLabel(
            popup,
            text=f"Damage (M): {dm}    Crit: {crit}    Range Inc: {rng} ft    Type: {typ}",
            font=ctk.CTkFont(size=12),
        ).pack(pady=4)

        ctk.CTkLabel(popup, text="Special Qualities", font=ctk.CTkFont(weight="bold", size=13)).pack(anchor="w", padx=14, pady=(10, 2))

        sp_desc = info.get("special_description", "") or "No special qualities listed."
        tags = info.get("special", [])
        if tags:
            tag_line = "Tags: " + ", ".join(tags)
            ctk.CTkLabel(popup, text=tag_line, text_color="#aaaaaa").pack(anchor="w", padx=14)
        ctk.CTkLabel(popup, text=sp_desc, wraplength=400, justify="left").pack(anchor="w", padx=14, pady=(2, 8))

        ctk.CTkButton(popup, text="Close", width=100, command=popup.destroy).pack(pady=8)

    def load_spells_db(self):
        try:
            with open(self._json_path("spells.json"), "r", encoding="utf-8") as f:
                base_spells = json.load(f)
            self.spells_db = self._merge_custom_spells_into_db(base_spells)
            for name, info in list(self.spells_db.items()):
                self.spells_db[name] = self._normalize_spell_class_levels(info)
            self._rebuild_spell_indexes()
            custom_count = len(self.load_custom_spells_file())
            if custom_count:
                print(
                    f"✅ Loaded {len(self.spells_db)} spells "
                    f"({custom_count} custom from Custom_Spells.json)",
                )
            else:
                print(f"✅ Loaded {len(self.spells_db)} spells from spells.json")
        except Exception as e:
            messagebox.showerror("Spell Load Error", f"Could not read spells.json:\n{e}")
            self.spells_db = self._merge_custom_spells_into_db({})
            self._sorted_spells = []
            self._spells_by_class_level = defaultdict(list)

        # Load PHB2 spells (always merge so they are usable if added to known; popup toggle controls if they appear in the big database list to avoid bloat)
        self.phb2_spells_db = {}
        self.phb2_spell_names = set()
        try:
            phb2_path = self._json_path("PHB2_Spells.json")
            if os.path.isfile(phb2_path):
                with open(phb2_path, "r", encoding="utf-8") as f:
                    self.phb2_spells_db = json.load(f)
                self.phb2_spell_names = set(self.phb2_spells_db.keys())
                # Merge into main db
                for name, info in self.phb2_spells_db.items():
                    if name not in self.spells_db:
                        self.spells_db[name] = info
                if self.phb2_spell_names:
                    for name in list(self.phb2_spell_names):
                        if name in self.spells_db:
                            self.spells_db[name] = self._normalize_spell_class_levels(self.spells_db[name])
                    self._rebuild_spell_indexes()
                    print(f"✅ Loaded {len(self.phb2_spell_names)} PHB2 spells (toggle in spell DB popup ☰ to include in list)")
        except Exception as e:
            print(f"⚠️ Could not load PHB2_Spells.json: {e}")

        self.include_phb2_spells = False  # default: off in database popup list

    def load_buffs_db(self):
        """Load buff effect type definitions (maps nice names to bonus keys/subs used by accumulator)."""
        try:
            with open(self._json_path("buffs.json"), "r", encoding="utf-8") as f:
                self.buffs_db = json.load(f)
            print(f"✅ Loaded {len(self.buffs_db)} buff effect types from buffs.json")
        except Exception as e:
            print(f"⚠️ Could not load buffs.json ({e}); using built-in fallback")
            self.buffs_db = self._default_buffs_db()

