    def _get_buffs_dropdown_values(self):
        """Sorted list of buff effect type display names for the dropdown."""
        if not hasattr(self, "buffs_db") or not self.buffs_db:
            self.load_buffs_db()
        keys = list((self.buffs_db or {}).keys())
