        self._hp_delta_mitigation_used = set()
        self._hp_delta_combo_last = "5"
        self.hp_delta_var = ctk.StringVar(value="5")

        amount_row = ctk.CTkFrame(hp_row, fg_color="transparent")
        amount_row.pack(side="left", padx=(0, 6))
        amount_btn_row = ctk.CTkFrame(amount_row, fg_color="transparent")
        amount_btn_row.pack(side="left")
        ctk.CTkButton(
            amount_btn_row, text="−", width=28, height=36, fg_color="#b83232", hover_color="#d04040",
            font=ctk.CTkFont(size=18, weight="bold"), command=self._decrement_hp_delta_amount,
        ).pack(side="left", padx=(0, 3))
        self.hp_delta_entry = ctk.CTkEntry(
            amount_btn_row, textvariable=self.hp_delta_var, width=52, height=36, justify="center",
        )
        self.hp_delta_entry.pack(side="left")
        self.hp_delta_entry.bind("<FocusOut>", lambda _e: self._on_hp_delta_amount_changed(), add="+")
        self.hp_delta_entry.bind("<Return>", lambda _e: self._on_hp_delta_amount_changed(), add="+")
        ctk.CTkButton(
            amount_btn_row, text="+", width=28, height=36, fg_color="#2d8a4e", hover_color="#3aa35c",
            font=ctk.CTkFont(size=18, weight="bold"), command=self._increment_hp_delta_amount,
        ).pack(side="left", padx=(3, 0))

        action_row = ctk.CTkFrame(amount_row, fg_color="transparent")
        action_row.pack(side="left", padx=(8, 0))
        lethal_col = ctk.CTkFrame(action_row, fg_color="transparent")
        lethal_col.pack(side="left")
        ctk.CTkButton(
            lethal_col, text="Lethal", width=72, height=32, fg_color="#b83232", hover_color="#d04040",
            command=self.apply_lethal_damage_from_entry,
        ).pack(anchor="w")
        ctk.CTkButton(
            lethal_col, text="Non-lethal", width=72, height=32, fg_color="#666666", hover_color="#777777",
            command=self.apply_nonlethal_damage_from_entry,
        ).pack(anchor="w", pady=(4, 0))
        ctk.CTkButton(
            action_row, text="Heal", width=72, height=68, fg_color="#2d8a4e", hover_color="#3aa35c",
            command=self.apply_heal_from_entry,
        ).pack(side="left", padx=(6, 0))

        self.register_widget("current_hp", self.current_hp_var)

        hp_meta = ctk.CTkFrame(health_frame, fg_color="transparent")
        hp_meta.pack(fill="x", padx=8, pady=(0, 6))

        self.max_hp_label = ctk.CTkLabel(hp_meta, text="Max: 10", font=ctk.CTkFont(size=14))
        self.max_hp_label.pack(anchor="w", padx=4)
        self.fast_healing_label = ctk.CTkLabel(
            hp_meta, text="",
            font=ctk.CTkFont(size=12, weight="bold"),
            text_color=getattr(self, "secondary_button_color", THEME_TEAL),
        )
        self.fast_healing_label.pack(anchor="w", padx=4)

        temp_row = ctk.CTkFrame(hp_meta, fg_color="transparent")
        temp_row.pack(fill="x", pady=(6, 0))

        temp_btn_row = ctk.CTkFrame(temp_row, fg_color="transparent")
        temp_btn_row.pack(side="left", padx=(4, 10))
        ctk.CTkButton(
            temp_btn_row, text="+", width=28, height=28, fg_color="#2d8a4e", hover_color="#3aa35c",
            font=ctk.CTkFont(size=16, weight="bold"), command=self.increment_temp_hp,
        ).pack(side="left", padx=(0, 3))
        ctk.CTkButton(
            temp_btn_row, text="−", width=28, height=28, fg_color="#b83232", hover_color="#d04040",
            font=ctk.CTkFont(size=16, weight="bold"), command=self.decrement_temp_hp,
        ).pack(side="left")

        self.temp_hp_label = ctk.CTkLabel(
            temp_row, text=str(self.data["health"].get("temp_hp", 0)),
            font=ctk.CTkFont(size=20, weight="bold"), text_color=THEME_ORANGE, width=80,
            cursor="hand2",
        )
        self.temp_hp_label.pack(side="left", padx=4)
        self.temp_hp_label.bind("<Button-1>", lambda e: self._prompt_set_temp_hp())
        ctk.CTkLabel(
            temp_row, text="Temp HP", font=ctk.CTkFont(size=12), text_color="#888888",
        ).pack(side="left", padx=(4, 0))

        rest_row = ctk.CTkFrame(health_frame, fg_color="transparent")
        rest_row.pack(fill="x", padx=8, pady=(10, 4))
        rest_icon = self._health_widget_icon("rest_camp_icon.jpg", size=30)
        heal_nl_icon = self._health_widget_icon("heal_nonlethal_icon.jpg", size=30)
        self._health_icon_rest = rest_icon
        self._health_icon_heal_nl = heal_nl_icon
        self.rest_btn = ctk.CTkButton(
            rest_row,
            text="" if rest_icon else "🌙",
            image=rest_icon,
            width=40,
            height=36,
            fg_color="transparent",
            border_width=0,
            hover_color="#3a3a3a",
            font=ctk.CTkFont(size=20),
            command=self.perform_rest,
        )
        self.rest_btn.pack(side="left")
        self.heal_nonlethal_btn = ctk.CTkButton(
            rest_row,
            text="" if heal_nl_icon else "♥",
            image=heal_nl_icon,
            width=40,
            height=36,
            fg_color="transparent",
            border_width=0,
            hover_color="#3a3a3a",
            font=ctk.CTkFont(size=18),
            command=self.heal_nonlethal_by_level,
        )
        self.heal_nonlethal_btn.pack(side="left", padx=(4, 0))
        ctk.CTkLabel(
            rest_row, text="Rest",
            font=ctk.CTkFont(size=13, weight="bold"), text_color="#aaaaaa",
        ).pack(side="left", padx=(8, 0))
        self._bind_hover_tooltip(
            self.rest_btn,
            "Rest: reset prepared spells to Ready, regain HP equal to your level, "
            "clear Fatigued and Exhausted, and refresh all per-day class abilities "
            "and magical item uses.",
            wraplength=320,
        )
        self._bind_hover_tooltip(
            self.heal_nonlethal_btn,
            "Heal nonlethal damage equal to your character level.",
            wraplength=320,
        )

        self.affliction_status_label = ctk.CTkLabel(
            health_frame,
            text="",
            font=ctk.CTkFont(size=11),
            text_color=getattr(self, "primary_button_color", THEME_ORANGE),
            wraplength=300,
            justify="left",
            anchor="w",
        )
        
        self.refresh_health_display()
        self.refresh_level_up_button()

        # --- Elemental resistances summary ---
        resist_summary_frame = ctk.CTkFrame(class_health_row)
        resist_summary_frame.grid(row=0, column=2, sticky="nsew", padx=(10, 0))
        self._build_elemental_resistance_panel(resist_summary_frame)

        # --- Defenses ---
        defenses_frame = ctk.CTkFrame(class_health_row)
        defenses_frame.grid(row=0, column=3, sticky="nsew", padx=(10, 0))

        ctk.CTkLabel(defenses_frame, text="Defenses", font=ctk.CTkFont(size=18, weight="bold")).pack(anchor="w", padx=8, pady=5)

        add_frame = ctk.CTkFrame(defenses_frame)
        add_frame.pack(fill="x", padx=8, pady=5)
        
        self.def_type_combo = ctk.CTkComboBox(
            add_frame, values=self._get_defense_type_options(), width=110,
        )
        self.def_type_combo.set("Resistance")
        self._configure_editable_defense_type_combo(self.def_type_combo)
        self.def_type_combo.pack(side="left", padx=4)
        
        self.def_value_entry = ctk.CTkEntry(add_frame, width=60, placeholder_text="Value")
        self.def_value_entry.pack(side="left", padx=4)
        
        self.def_desc_entry = ctk.CTkEntry(add_frame, width=160, placeholder_text="Fire / Cold / Electricity / Sonic / Acid")
        self.def_desc_entry.pack(side="left", padx=4)
        
        ctk.CTkButton(add_frame, text="+", width=40, fg_color=getattr(self, 'primary_button_color', '#c77626'),
                      command=self.add_defense).pack(side="left", padx=4)

        self.defenses_scroll = ctk.CTkScrollableFrame(defenses_frame, height=140)
        self.defenses_scroll.pack(fill="both", expand=True, padx=8, pady=5)

        self.refresh_defenses()

        # ===================== MAIN ROW – narrow Abilities, wider Skills =====================
        main_row = ctk.CTkFrame(self.stats_frame)
        main_row.pack(fill="both", expand=True, padx=15, pady=10)

        self.main_row = main_row
        initial_col_w = self._stats_main_column_width()
        for col_idx in range(3):
            main_row.columnconfigure(col_idx, weight=1, minsize=initial_col_w)
        main_row.rowconfigure(0, weight=1)

        # ===================== ABILITY SCORES (Column 0) =====================
        left_main = ctk.CTkFrame(main_row)
        left_main.grid(row=0, column=0, sticky="nsew", padx=8)

        ability_title_row = ctk.CTkFrame(left_main, fg_color="transparent")
        ability_title_row.pack(fill="x", pady=8)
        ctk.CTkLabel(
            ability_title_row, text="Ability Scores",
            font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(side="left")
        self.abilities_locked = self._get_abilities_lock_state()
        self.abilities_lock_btn = ctk.CTkButton(
            ability_title_row,
            text="🔓",
            width=28,
            height=28,
            command=self._toggle_abilities_lock,
        )
        self.abilities_lock_btn.pack(side="left", padx=(8, 0))

        self.ability_raging_banner = ctk.CTkFrame(left_main, fg_color="transparent")
        self.ability_raging_label = ctk.CTkLabel(
            self.ability_raging_banner,
            text="",
            font=ctk.CTkFont(size=22, weight="bold"),
            text_color=THEME_RAGE_RED,
            anchor="center",
        )
        self.ability_raging_label.pack(fill="x", pady=(2, 0))

        self.ability_section = ctk.CTkFrame(left_main, fg_color="transparent")
        self.ability_section.pack(fill="x", pady=5)
        ability_section = self.ability_section

        ability_count = len(self.data["abilities"])
        for col, width in enumerate(ABILITY_COLUMN_WIDTHS):
            ability_section.grid_columnconfigure(col, minsize=width)

        ability_table = ctk.CTkFrame(ability_section, fg_color="transparent")
        ability_table.grid(
            row=0, column=0, columnspan=len(ABILITY_COLUMN_WIDTHS), sticky="ew",
        )
        for col, width in enumerate(ABILITY_COLUMN_WIDTHS):
            ability_table.grid_columnconfigure(col, minsize=width)

        self.ability_totals_border = ctk.CTkFrame(
            ability_table,
            fg_color="#1F1F1F",
            border_width=2,
            border_color=THEME_ORANGE,
            corner_radius=6,
        )
        self.ability_totals_border.grid(
            row=0, column=5, columnspan=2, rowspan=ability_count + 1,
            sticky="nsew", padx=(4, 2), pady=2,
        )

        # (Animal companion 🐺 button relocated below for better layout next to abilities)

        totals_inner = ctk.CTkFrame(self.ability_totals_border, fg_color="transparent")
        totals_inner.pack(fill="both", expand=True, padx=2, pady=2)
        totals_inner.grid_columnconfigure(0, minsize=ABILITY_COLUMN_WIDTHS[5])
        totals_inner.grid_columnconfigure(1, minsize=ABILITY_COLUMN_WIDTHS[6])

        self.ability_total_mod_headers = []
        for col, txt in enumerate(("Total", "Mod")):
            header_lbl = ctk.CTkLabel(
                totals_inner,
                text=txt,
                width=ABILITY_COLUMN_WIDTHS[5 + col],
                anchor="center",
                text_color=THEME_ORANGE,
                font=ctk.CTkFont(weight="bold"),
            )
            header_lbl.grid(
                row=0,
                column=col,
                padx=ABILITY_TOTAL_MOD_PADX[col],
                pady=(0, 4),
                sticky="ew",
            )
            self.ability_total_mod_headers.append(header_lbl)

        input_headers = ["Ability", "Base", "Racial", "Enh", "Misc"]
        for col, (txt, width) in enumerate(zip(input_headers, ABILITY_COLUMN_WIDTHS[:5])):
            ctk.CTkLabel(
                ability_table, text=txt, width=width, anchor="center",
            ).grid(row=0, column=col, padx=2, pady=(0, 4), sticky="ew")

        self.ability_vars = {}
        self.ability_name_lbls = {}
        # Always lay out in canonical order; do not rely on dict key order from data.
        for row_idx, ab in enumerate(ABILITY_NAMES, start=1):
            name_lbl = ctk.CTkLabel(
                ability_table, text=ABILITY_DISPLAY_NAMES.get(ab, ab),
                width=ABILITY_COLUMN_WIDTHS[0], anchor="w",
            )
            name_lbl.grid(row=row_idx, column=0, padx=2, pady=2, sticky="w")
            self.ability_name_lbls[ab] = name_lbl

            base_var = ctk.StringVar(value=str(self.data["abilities"][ab]["base"]))
            base_entry = ctk.CTkEntry(
                ability_table, textvariable=base_var, width=ABILITY_COLUMN_WIDTHS[1],
            )
            base_entry.grid(row=row_idx, column=1, padx=2, pady=2)
            base_var.trace("w", self._trace_refresh)
            self.register_widget(f"ability_{ab}_base", base_var)

