        self.armor_name_combo.grid(row=0, column=1, padx=2, sticky="ew")
        self.register_widget("armor_name", name_var)
        name_var.trace("w", self._trace_inventory)

        armor_material = self._normalize_special_material(self.data["armor"].get("material"))
        armor_material_var = ctk.StringVar(value=armor_material)
        self.armor_material_combo = ctk.CTkComboBox(
            row,
            values=self._valid_armor_materials(self.data["armor"].get("name", "")),
            variable=armor_material_var,
            width=ARMOR_INVENTORY_COLUMNS[2][1],
            command=self._on_armor_material_changed,
        )
        self.armor_material_combo.grid(row=0, column=2, padx=2, sticky="w")
        self.register_widget("armor_material", armor_material_var)
        armor_material_var.trace("w", self._trace_inventory)

        self.armor_vars = {
            "status": status_var,
            "status_combo": armor_status_combo,
            "name": name_var,
            "material": armor_material_var,
            "material_combo": self.armor_material_combo,
        }
        armor_info = self._lookup_armor_info(self.data["armor"].get("name", ""))
        default_acp = self.data["armor"].get("armor_check_penalty", armor_info.get("armor_check_penalty", 0))
