    def _parse_crit_multiplier_int(self, value):
        raw = str(value or "x2").strip().lower()
        if raw.startswith("x"):
            raw = raw[1:]
        try:
            mult = int(raw)
        except ValueError:
            mult = 2
        return mult if mult > 0 else 2

    def _apply_crit_multiplier_to_die(self, die, multiplier):
        mult = max(1, int(multiplier or 2))
        match = re.match(r"^(\d+)d(\d+)$", str(die or "").strip(), re.I)
        if match:
            return f"{int(match.group(1)) * mult}d{match.group(2)}"
        return die

    def _get_preview_attack_summary_values(self, data, shift_held=None, ctrl_held=None, alt_held=None):
        """Apply Shift (crit), Ctrl (bane), and Alt (single highest attack) preview adjustments."""
        if shift_held is None:
            shift_held = getattr(self, "_combat_shift_preview", False)
        if ctrl_held is None:
            ctrl_held = getattr(self, "_combat_ctrl_preview", False)
        if alt_held is None:
            alt_held = getattr(self, "_combat_alt_preview", False)

        die = data.get("die", "1d8")
        total_mod = int(data.get("total_damage_mod", 0) or 0)
        attack_bonuses = list(data.get("attack_bonuses", []))
        if alt_held and attack_bonuses:
            attack_bonuses = [attack_bonuses[0]]

        if ctrl_held:
            bane_enh = int(data.get("bane_enh_bonus", 0) or 0)
            if bane_enh:
                total_mod += bane_enh
                attack_bonuses = [bonus + bane_enh for bonus in attack_bonuses]

        if shift_held:
            crit_mult = self._parse_crit_multiplier_int(data.get("crit_multiplier", "x2"))
            die = self._apply_crit_multiplier_to_die(die, crit_mult)
            if total_mod:
                total_mod *= crit_mult

        return die, total_mod, attack_bonuses

    def _build_attack_summary_damage_display(self, data, shift_held=None, ctrl_held=None):
        """Build attack-summary damage text; Shift applies crit multiplier to die+mod; Ctrl shows Bane damage."""
        die, total_mod, _ = self._get_preview_attack_summary_values(data, shift_held, ctrl_held)
        damage_str = (
            f"{die}{self._format_modifier(total_mod)}"
            if total_mod
            else die
        )
        damage_str = self._append_sneak_attack_to_damage_die(
            damage_str, data.get("style", "1H"),
        )
        dmg_parts = [damage_str]
        if data.get("extra_damage_parts"):
            dmg_parts.append("plus " + " ".join(data["extra_damage_parts"]))
        if ctrl_held and data.get("bane_damage_parts"):
            bane_parts = self._format_damage_parts_with_bane_foe(
                data["bane_damage_parts"], data.get("bane_foe"),
            )
            dmg_parts.append("plus " + " ".join(bane_parts))
        if shift_held and data.get("burst_damage_parts"):
            dmg_parts.append("plus " + " ".join(data["burst_damage_parts"]))
        critical_parts = list(data.get("critical_parts") or [])
        if ctrl_held and data.get("bane_text_parts"):
            critical_parts.extend(data["bane_text_parts"])
        if shift_held and data.get("burst_text_parts"):
            critical_parts.extend(data["burst_text_parts"])
        if critical_parts:
            dmg_parts.append(" · ".join(critical_parts))
        return " ".join(dmg_parts)

    def _build_attack_summary_attack_parts(self, data, shift_held=None, ctrl_held=None, alt_held=None):
        weapon_name = data.get("name", "Weapon")
        enchant_parts = []
        gem_parts = []
        if data.get("enchants"):
            enchant_display = self._format_weapon_enchants_for_summary(
                data["enchants"], data.get("bane_foe"),
            )
            enchant_parts.append(f" — {', '.join(enchant_display)}")
        weapon_idx = data.get("weapon_idx")
        if weapon_idx is not None and HAS_AUGMENT_GEMS:
            gem_suffix = self.weapon_attack_gem_suffix(int(weapon_idx))
            if gem_suffix:
                gem_parts.append(gem_suffix)
        _, _, attack_bonuses = self._get_preview_attack_summary_values(
            data, shift_held, ctrl_held, alt_held=alt_held,
        )
        style = str(data.get("style") or "")
        weather_impossible = bool(data.get("weather_ranged_impossible"))
        attack_str = self._format_attack_bonus_string(attack_bonuses)
        if attack_str:
            enchant_parts.append(f" [{attack_str}]")
        if weather_impossible and style in ("Ranged", "Thrown"):
            enchant_parts.append(" [Weather: ranged impossible]")
        else:
            weather_penalty = int(data.get("weather_attack_penalty", 0) or 0)
            if weather_penalty:
                enchant_parts.append(
                    f" [Weather {self._format_modifier(weather_penalty)}]",
                )
        if shift_held:
            burst_atk = int(data.get("burst_attack_bonus", 0) or 0)
            if burst_atk:
                enchant_parts.append(f" {self._format_modifier(burst_atk)} crit atk")
        return weapon_name, "".join(enchant_parts), "".join(gem_parts)

    def _build_attack_summary_attack_display(self, data, shift_held=None, ctrl_held=None, alt_held=None):
        weapon_name, enchant_suffix, gem_suffix = self._build_attack_summary_attack_parts(
            data, shift_held, ctrl_held, alt_held=alt_held,
        )
        return weapon_name + enchant_suffix + gem_suffix

    def _build_weapon_enchant_descriptions_tooltip(self, weapon_idx):
        weapon = self._get_weapon_slot(weapon_idx)
        config = self._get_combat_weapon_config(weapon_idx, weapon)
        enchants = list(config.get("enchants", []) or [])
        if not enchants:
            return ""
        bane_foe = str(config.get("bane_foe", "") or "").strip()
        lines = []
        for enchant_name in enchants:
            info = self.weapon_enchants_db.get(enchant_name, {})
            display_name = enchant_name
            if enchant_name == "Bane" and bane_foe:
                display_name = f"Bane vs {bane_foe.lower()}"
            desc = str(info.get("description", "") or "").strip() or "(No description)"
            lines.append(f"{display_name}\n{desc}")
        return "\n\n".join(lines)

    def _update_weapon_attack_summary_labels(self, idx, data, shift_held=None, ctrl_held=None, alt_held=None):
        weapon_name, enchant_suffix, gem_suffix = self._build_attack_summary_attack_parts(
            data, shift_held, ctrl_held, alt_held=alt_held,
        )
        name_lbl = getattr(self, "_combat_summary_weapon_name_labels", {}).get(idx)
        suffix_lbl = getattr(self, "_combat_summary_attack_suffix_labels", {}).get(idx)
        gem_lbl = getattr(self, "_combat_summary_gem_suffix_labels", {}).get(idx)
        for lbl, text in (
            (name_lbl, weapon_name),
            (suffix_lbl, enchant_suffix),
            (gem_lbl, gem_suffix),
        ):
            if not lbl:
                continue
            try:
                if lbl.winfo_exists():
                    lbl.configure(text=text)
            except Exception:
                pass
        atk_label = getattr(self, "_combat_summary_attack_labels", {}).get(idx)
        if atk_label and not suffix_lbl and not gem_lbl:
            try:
                if atk_label.winfo_exists():
                    atk_label.configure(text=weapon_name + enchant_suffix + gem_suffix)
            except Exception:
                pass

    def _ensure_combat_shift_preview_bindings(self):
        if getattr(self, "_combat_shift_bindings_set", False):
            return
        self._combat_shift_preview = False
        self._combat_ctrl_preview = False
        self._combat_alt_preview = False
        for seq in ("<KeyPress-Shift_L>", "<KeyPress-Shift_R>"):
            self.root.bind_all(seq, self._on_combat_shift_press, add="+")
        for seq in ("<KeyRelease-Shift_L>", "<KeyRelease-Shift_R>"):
            self.root.bind_all(seq, self._on_combat_shift_release, add="+")
        for seq in ("<KeyPress-Control_L>", "<KeyPress-Control_R>"):
            self.root.bind_all(seq, self._on_combat_ctrl_press, add="+")
        for seq in ("<KeyRelease-Control_L>", "<KeyRelease-Control_R>"):
            self.root.bind_all(seq, self._on_combat_ctrl_release, add="+")
        for seq in ("<KeyPress-Alt_L>", "<KeyPress-Alt_R>"):
            self.root.bind_all(seq, self._on_combat_alt_press, add="+")
        for seq in ("<KeyRelease-Alt_L>", "<KeyRelease-Alt_R>"):
            self.root.bind_all(seq, self._on_combat_alt_release, add="+")
        self._combat_shift_bindings_set = True

    def _on_combat_shift_press(self, event=None):
        if not self._is_page_active("Combat"):
            return
        if getattr(self, "_combat_shift_preview", False):
            return
        self._combat_shift_preview = True
        self._refresh_combat_modifier_preview_displays()

    def _on_combat_shift_release(self, event=None):
        if not getattr(self, "_combat_shift_preview", False):
            return
        self._combat_shift_preview = False
        self._refresh_combat_modifier_preview_displays()

    def _on_combat_ctrl_press(self, event=None):
        if not self._is_page_active("Combat"):
            return
        if getattr(self, "_combat_ctrl_preview", False):
            return
        self._combat_ctrl_preview = True
        self._refresh_combat_modifier_preview_displays()

    def _on_combat_ctrl_release(self, event=None):
        if not getattr(self, "_combat_ctrl_preview", False):
            return
        self._combat_ctrl_preview = False
        self._refresh_combat_modifier_preview_displays()

    def _on_combat_alt_press(self, event=None):
        if not self._is_page_active("Combat"):
            return
        if getattr(self, "_combat_alt_preview", False):
            return
        self._combat_alt_preview = True
        self._refresh_combat_modifier_preview_displays()

    def _on_combat_alt_release(self, event=None):
        if not getattr(self, "_combat_alt_preview", False):
            return
        self._combat_alt_preview = False
        self._refresh_combat_modifier_preview_displays()

    def _refresh_combat_modifier_preview_displays(self):
        if not hasattr(self, "combat_summary_scroll"):
            return
        shift = getattr(self, "_combat_shift_preview", False)
        ctrl = getattr(self, "_combat_ctrl_preview", False)
        alt = getattr(self, "_combat_alt_preview", False)
        for idx in getattr(self, "_combat_summary_attack_labels", {}):
            dmg_label = getattr(self, "_combat_summary_damage_labels", {}).get(idx)
            try:
                data = self._compute_weapon_attack_data(idx)
                self._update_weapon_attack_summary_labels(
                    idx, data, shift_held=shift, ctrl_held=ctrl, alt_held=alt,
                )
                if dmg_label and dmg_label.winfo_exists():
                    dmg_display = self._build_attack_summary_damage_display(data, shift_held=shift, ctrl_held=ctrl)
                    dmg_label.configure(text=" " + dmg_display if dmg_display else "")
            except Exception:
                continue
        for key in getattr(self, "_combat_natural_summary_attack_labels", {}):
            atk_label = self._combat_natural_summary_attack_labels.get(key)
            dmg_label = getattr(self, "_combat_natural_summary_damage_labels", {}).get(key)
            entry = getattr(self, "_combat_natural_attack_entries", {}).get(key)
            if not entry:
                continue
            try:
                attack_def = self._merged_natural_attack_def(entry)
                feature_name = entry.get("feature_name", "Special Feature")
                atk_name = attack_def.get("name", "Natural Attack")
                display_name = f"{atk_name} ({feature_name})"
                data = self._compute_natural_attack_data(attack_def, display_name)
                data["name"] = display_name
                if atk_label and atk_label.winfo_exists():
                    atk_label.configure(
                        text=self._build_attack_summary_attack_display(data, shift_held=shift, ctrl_held=ctrl),
                    )
                if dmg_label and dmg_label.winfo_exists():
                    dmg_display = self._build_attack_summary_damage_display(data, shift_held=shift, ctrl_held=ctrl)
                    dmg_label.configure(text=" " + dmg_display if dmg_display else "")
            except Exception:
                continue
        self._refresh_flurry_of_blows_shift_display()

    def _refresh_flurry_of_blows_shift_display(self):
        params = getattr(self, "_combat_flurry_summary_params", None)
        label = getattr(self, "_combat_flurry_summary_label", None)
        if not params or not label:
            return
        try:
            if not label.winfo_exists():
                return
        except Exception:
            return
        shift = getattr(self, "_combat_shift_preview", False)
        monk_level = params["monk_level"]
        die_level = params.get("die_level", monk_level)
        die = self._get_monk_unarmed_die(die_level)
        if shift:
            die = self._apply_crit_multiplier_to_die(die, 2)
        dmg_mod = self._effective_ability_mod(params.get("dmg_abil", "Strength"))
        dmg_b = int(params.get("dmg_b", 0) or 0)
        total_dmg_mod = dmg_mod + dmg_b
        if shift and total_dmg_mod:
            total_dmg_mod *= 2
        dmg_line = f"{die} {self._format_modifier(total_dmg_mod)}"
        bases = self._get_monk_flurry_bases(monk_level)
        tohit_mod = self._effective_ability_mod(params.get("tohit_abil", "Strength"))
        tohit_b = int(params.get("tohit_b", 0) or 0)
        atk_strs = [self._format_modifier(base + tohit_mod + tohit_b) for base in bases]
        atk_line = "/".join(atk_strs)
        label.configure(
            text=f"Attacks: {atk_line}   Damage: {dmg_line} ({len(bases)} attacks)",
        )

    def _on_combat_expertise_points_change(self, value):
        self._ensure_combat_expertise_var()
        points = min(
            max(0, self._parse_feat_slider_value(value)),
            self._get_feat_slider_max_points(),
        )
        self.combat_expertise_var.set(str(points))
        self.data["combat_expertise"] = points
        self.data["combat_expertise_active"] = points > 0
        if hasattr(self, "combat_expertise_value_label"):
            self.combat_expertise_value_label.configure(text=str(points))
        self._refresh_combat_attack_summaries()
        self.calculate_ac()
        self._update_combat_footer()
        self._update_monk_ac_display()

    def _build_wielded_weapons_feat_sliders(self, parent):
        """PA / CE sliders in the top-right of the Owned Weapons widget."""
        self._ensure_combat_expertise_var()
        self._ensure_power_attack_vars()
        max_pts = self._get_feat_slider_max_points()

        self.combat_expertise_slider_row = ctk.CTkFrame(parent, fg_color="transparent")
        ctk.CTkLabel(
            self.combat_expertise_slider_row, text="Combat Expertise",
            font=ctk.CTkFont(size=11, weight="bold"), width=118, anchor="e",
        ).pack(side="left", padx=(6, 4))
        ce_saved = min(self.get_combat_expertise_points(), max_pts)
        self.combat_expertise_slider = ctk.CTkSlider(
            self.combat_expertise_slider_row,
            from_=0,
            to=max(1, max_pts),
            number_of_steps=max(1, max_pts),
            width=110,
            command=self._on_combat_expertise_points_change,
        )
        self.combat_expertise_slider.set(ce_saved if max_pts > 0 else 0)
        if max_pts <= 0:
            self.combat_expertise_slider.configure(state="disabled")
        self.combat_expertise_slider.pack(side="left", padx=4)
        self.combat_expertise_value_label = ctk.CTkLabel(
            self.combat_expertise_slider_row, text=str(ce_saved), width=22, anchor="e",
        )
        self.combat_expertise_value_label.pack(side="left", padx=(2, 6))

        self.power_attack_slider_row = ctk.CTkFrame(parent, fg_color="transparent")
        ctk.CTkLabel(
            self.power_attack_slider_row, text="Power Attack",
            font=ctk.CTkFont(size=11, weight="bold"), width=118, anchor="e",
        ).pack(side="left", padx=(6, 4))
        pa_saved = min(self.get_power_attack_points(), max_pts)
        self.power_attack_slider = ctk.CTkSlider(
            self.power_attack_slider_row,
            from_=0,
            to=max(1, max_pts),
            number_of_steps=max(1, max_pts),
            width=110,
            command=self._on_power_attack_points_change,
        )
        self.power_attack_slider.set(pa_saved if max_pts > 0 else 0)
        if max_pts <= 0:
            self.power_attack_slider.configure(state="disabled")
        self.power_attack_slider.pack(side="left", padx=4)
        self.power_attack_value_label = ctk.CTkLabel(
            self.power_attack_slider_row, text=str(pa_saved), width=22, anchor="e",
        )
        self.power_attack_value_label.pack(side="left", padx=(2, 6))

        self.register_widget("combat_expertise", self.combat_expertise_var)
        self.register_widget("power_attack_points", self.power_attack_points_var)
        self._refresh_wielded_weapons_feat_sliders()

    def _refresh_wielded_weapons_feat_sliders(self):
        if not hasattr(self, "combat_feat_sliders_frame"):
            return
        has_ce = self.has_combat_expertise_feat()
        has_pa = self.has_power_attack_feat()
        if not has_ce and not has_pa:
            self.combat_feat_sliders_frame.pack_forget()
            self.data["combat_expertise"] = 0
            self.data["power_attack_points"] = 0
            return

        self.combat_feat_sliders_frame.pack(side="right", anchor="ne", padx=4, pady=2)
        max_pts = self._get_feat_slider_max_points()

        if has_ce:
            self.combat_expertise_slider_row.pack(fill="x", pady=(4, 2))
            ce_pts = min(self.get_combat_expertise_points(), max_pts)
            if max_pts > 0:
                self.combat_expertise_slider.configure(
                    state="normal",
                    to=max_pts,
                    number_of_steps=max_pts,
                )
                self.combat_expertise_slider.set(ce_pts)
            else:
                ce_pts = 0
                self.combat_expertise_slider.configure(state="disabled")
                self.combat_expertise_slider.set(0)
            self.combat_expertise_value_label.configure(text=str(ce_pts))
            self.data["combat_expertise"] = ce_pts
        else:
            self.combat_expertise_slider_row.pack_forget()
            self.data["combat_expertise"] = 0

        if has_pa:
            self.power_attack_slider_row.pack(fill="x", pady=(2, 4))
            pa_pts = min(self.get_power_attack_points(), max_pts)
            if max_pts > 0:
                self.power_attack_slider.configure(
                    state="normal",
                    to=max_pts,
                    number_of_steps=max_pts,
                )
                self.power_attack_slider.set(pa_pts)
            else:
                pa_pts = 0
                self.power_attack_slider.configure(state="disabled")
                self.power_attack_slider.set(0)
            self.power_attack_value_label.configure(text=str(pa_pts))
            self.data["power_attack_points"] = pa_pts
        else:
            self.power_attack_slider_row.pack_forget()
            self.data["power_attack_points"] = 0

    def _sync_combat_expertise_to_data(self):
        if hasattr(self, "combat_expertise_var"):
            try:
                self.data["combat_expertise"] = int(self.combat_expertise_var.get() or 0)
            except Exception:
                self.data["combat_expertise"] = 0
        self.data["combat_expertise_active"] = self.get_combat_expertise_points() > 0

    def has_power_attack_feat(self):
        self._rebuild_feat_cache()
        return "Power Attack" in self._selected_feats

    def _ensure_power_attack_vars(self):
        if not hasattr(self, "power_attack_points_var"):
            saved = int(self.data.get("power_attack_points", 0) or 0)
            self.power_attack_points_var = ctk.StringVar(value=str(max(0, min(5, saved))))

    def get_power_attack_points(self):
        if not self.has_power_attack_feat():
            return 0
        try:
            raw = (
                self.power_attack_points_var.get()
                if hasattr(self, "power_attack_points_var")
                else self.data.get("power_attack_points", 0)
            )
            points = int(raw or 0)
            return min(max(0, points), self._get_feat_slider_max_points())
        except Exception:
            return 0

    def _weapon_qualifies_for_power_attack(self, style, hit_ability):
        return hit_ability == "Strength" and style in ("1H", "2H")

    def _get_weapon_power_attack_modifiers(self, style, hit_ability):
        points = self.get_power_attack_points()
        if points <= 0 or not self._weapon_qualifies_for_power_attack(style, hit_ability):
            return 0, 0
        attack_penalty = -points
        damage_bonus = points * 2 if style == "2H" else points
        return attack_penalty, damage_bonus

    def _on_power_attack_points_change(self, value):
        self._ensure_power_attack_vars()
        points = min(
            max(0, self._parse_feat_slider_value(value)),
            self._get_feat_slider_max_points(),
        )
        self.power_attack_points_var.set(str(points))
        self.data["power_attack_points"] = points
        self.data["power_attack_active"] = points > 0
        if hasattr(self, "power_attack_value_label"):
            self.power_attack_value_label.configure(text=str(points))
        self._refresh_combat_attack_summaries()

    def _sync_power_attack_to_data(self):
        if hasattr(self, "power_attack_points_var"):
            try:
                self.data["power_attack_points"] = int(self.power_attack_points_var.get() or 0)
            except Exception:
                self.data["power_attack_points"] = 0
        self.data["power_attack_active"] = self.get_power_attack_points() > 0
            
    def calculate_saves(self):
        """Calculate Fortitude, Reflex, and Will saves - now includes feat bonuses"""
        if not hasattr(self, "fort_label"):
            return
        try:
            if not self.fort_label.winfo_exists():
                return
        except tk.TclError:
            return
        try:
            save_totals = self._compute_save_totals()
            fort_total = save_totals["fort"]
            ref_total = save_totals["ref"]
            will_total = save_totals["will"]
            trap_sense = self._get_barbarian_class_bonuses().get("trap_sense", 0)

            save_label_color = getattr(self, "primary_button_color", THEME_ORANGE)
            self.fort_label.configure(text=f"Fort\n{fort_total:+}", text_color=save_label_color)
            ref_text = f"Ref\n{ref_total:+}"
            if trap_sense:
                ref_text += f"\n(+{trap_sense} vs traps)"
            self.ref_label.configure(text=ref_text, text_color=save_label_color)
            will_text = f"Will\n{will_total:+}"
            rage_will = self._get_rage_bonuses().get("will_save", 0)
            if rage_will:
                will_text += f"\n(+{rage_will} rage)"
            self.will_label.configure(text=will_text, text_color=save_label_color)

            for save_type, save_lbl in (
                ("fort", self.fort_label),
                ("ref", self.ref_label),
                ("will", self.will_label),
            ):
                tooltip = self._get_save_breakdown_tooltip(save_type)
                self._bind_hover_tooltip(save_lbl, tooltip, wraplength=300)
                box = getattr(self, f"{save_type}_box", None)
                if box is not None:
                    self._bind_hover_tooltip(box, tooltip, wraplength=300)

        except Exception as e:
            print(f"Save calc error: {e}")
            
    # ===================== SPELL UI METHODS =====================
    def add_known_spell(self, spell_name):
        """Add a spell (including domain spells, which are regular spells) to the regular known_spells / spellbook.
        Domain spells will still always appear in the separated non-deletable Domain category.
        After explicit add, DB searches will mark them "Already Known".
        """
        if spell_name not in self.data.get("known_spells", []):
            self.data["known_spells"].append(spell_name)
            self._refresh_spells_known_if_visible()  # only update spellbook side; do not touch Prepared Spells for Today
            self._update_wizard_spellbook_requirement_label()

    def force_prepare_spell(self, spell_name):
        """Force a known spell directly into Prepared spells for today.
        Bypasses prayer/memorize/meditate requirements and does not count against spells per day or slot limits.
        Marked with is_forced so it shows an F badge and is excluded from counts.
        """
        if not spell_name or spell_name not in self.data.get("known_spells", []):
            return
        if self._wizard_blocks_spellcasting():
            messagebox.showwarning(
                "Spellbooks Required",
                self._wizard_spellbook_shortage_message(),
                parent=self.root,
            )
            return
        base_level = self._get_spell_level_for_character(spell_name)
        entry = {
            "spell": spell_name,
            "metamagic": [],
            "base_level": base_level,
            "slot_level": base_level,
            "is_forced": True,
        }
        norm = self._normalize_prepared_entry(entry)
        self.data.setdefault("prepared_spells", []).append(norm)
        self._refresh_spells_known_if_visible()
        if hasattr(self, "spells_frame") and self._is_page_active("Spells"):
            self.refresh_spells_page(refresh_prepared=True)
        else:
            self._mark_spells_page_stale()
    
    def update_spell_state(self, entry_key, state, spell_name=None):
        if "spell_states" not in self.data:
            self.data["spell_states"] = {}

        if state != "Active":
            self.data.get("spell_skill_choices", {}).pop(entry_key, None)

        if state == "Active" and self._wizard_blocks_spellcasting():
            prepared_spell = None
            for entry in self.data.get("prepared_spells", []):
                if self._prepared_entry_key(entry) == entry_key:
                    prepared_spell = self._normalize_prepared_entry(entry).get("spell")
                    break
            if prepared_spell and prepared_spell in set(self.data.get("known_spells", [])):
                messagebox.showwarning(
                    "Spellbooks Required",
                    self._wizard_spellbook_shortage_message(),
                    parent=self.root,
                )
                state = "Ready"

        self.data["spell_states"][entry_key] = state
        if hasattr(self, "spell_state_vars") and entry_key in self.spell_state_vars:
            self.spell_state_vars[entry_key].set(state)

        # In-place style updates for prepared spells name text and dropdown (no full refresh)
        if hasattr(self, "prepared_widgets") and entry_key in self.prepared_widgets:
            w = self.prepared_widgets[entry_key]
            if 'name_lbl' in w:
                lbl = w['name_lbl']
                if state == "Active":
                    lbl.configure(text_color=getattr(self, 'secondary_button_color', THEME_TEAL))
                elif state == "Ready":
                    lbl.configure(text_color="white")
                else:
                    lbl.configure(text_color="#888888")
            if 'state_dropdown' in w:
                dd = w['state_dropdown']
                if state == "Ready":
                    dd.configure(fg_color=getattr(self, 'primary_button_color', THEME_ORANGE), text_color="white", button_color=getattr(self, 'primary_button_color', THEME_ORANGE))
                elif state == "Active":
                    dd.configure(fg_color=getattr(self, 'secondary_button_color', THEME_TEAL), text_color="white", button_color=getattr(self, 'secondary_button_color', THEME_TEAL))
                else:
                    dd.configure(fg_color="#666666", text_color="#888888", button_color="#666666")

        if state == "Active" and spell_name:
            if not self._apply_spell_skill_on_activate(entry_key, spell_name):
                self.data["spell_states"][entry_key] = "Ready"
                if hasattr(self, "spell_state_vars") and entry_key in self.spell_state_vars:
                    self.spell_state_vars[entry_key].set("Ready")
                self.data.get("spell_skill_choices", {}).pop(entry_key, None)
                # No spellbook (known spells) refresh on state change per request
                return
            self.auto_add_defense_from_spell(spell_name)
            self._apply_spell_health_on_activate(entry_key, spell_name)

        # In-place style updates already handled above for prepared rows (name colors + dropdown).
        # Do NOT refresh the Spell book (known spells list / ×N etc.) when changing Ready/Expended/Active.
        # Only perform global work for Active (to apply effects to AC/stats/etc.).
        if state == "Active":
            self._spells_built_for_key = self._get_spells_page_key()
            self.invalidate_caches()
            self.refresh_all()
        else:
            if hasattr(self, "spells_frame") and self._is_page_active("Spells"):
                self._spells_built_for_key = self._get_spells_page_key()
            else:
                self._mark_spells_page_stale()
                self.invalidate_caches()

    def remove_known_spell(self, spell_name):
        if spell_name in self.data.get("known_spells", []):
            self.data["known_spells"].remove(spell_name)
            remaining_prepared = []
            for entry in self.data.get("prepared_spells", []):
                if self._normalize_prepared_entry(entry)["spell"] == spell_name:
                    if self._is_spell_like_prepared_entry(entry):
                        # Keep SLA entries even if the spell name is removed from known; sync manages them
                        remaining_prepared.append(entry)
                        continue
                    key = self._prepared_entry_key(entry)
                    self.data.get("spell_states", {}).pop(key, None)
                    self.data.get("spell_skill_choices", {}).pop(key, None)
                    continue
                remaining_prepared.append(entry)
            self.data["prepared_spells"] = remaining_prepared
            self.data["pending_prepared_spells"] = [
                entry for entry in self.data.get("pending_prepared_spells", [])
                if self._normalize_prepared_entry(entry)["spell"] != spell_name
            ]
            self.data.get("spell_states", {}).pop(spell_name, None)
            # clean assignment for removed known spell
            self.data.get("spell_class_assignments", {}).pop(spell_name, None)
            self._refresh_spells_known_if_visible()  # only update spellbook side; do not refresh Prepared Spells for Today panel
            self._update_wizard_spellbook_requirement_label()
            # Note: prepared data was cleaned above, but we intentionally avoid refreshing the prepared panel here per request
            # (the panel will reflect the change on its next refresh for other reasons)
            self.refresh_all()
    
    def _decrement_prepared_or_prompt_remove_from_spellbook(self, spell_name):
        """Minus button in Spellbook: reduce prepped/pending count by 1 for this spell.

        When the last copy is removed, prompts to delete from spellbook. If already at 0,
        clicking − prompts to remove from spellbook directly.
        """
        prepared_entries = list(self.data.get("prepared_spells", []))
        pending_entries = list(self.data.get("pending_prepared_spells", []))

        def _is_removable(entry):
            norm = self._normalize_prepared_entry(entry)
            return (
                norm["spell"] == spell_name
                and not self._is_spell_like_prepared_entry(entry)
                and not self._is_magic_item_prepared_entry(entry)
                and not self._is_consumable_prepared_entry(entry)
            )

        matching_prepared = [e for e in prepared_entries if _is_removable(e)]
        matching_pending = [e for e in pending_entries if _is_removable(e)]
        count = len(matching_prepared) + len(matching_pending)

        if count == 0:
            if messagebox.askyesno(
                "Remove from Spellbook?",
                f"{spell_name} has no preparations. Remove it from your spellbook?",
            ):
                self.remove_known_spell(spell_name)
            return

        if matching_prepared:
            entry_to_remove = matching_prepared[0]
            entry_key = self._prepared_entry_key(entry_to_remove)
            self.data["prepared_spells"] = [
                e for e in prepared_entries if self._prepared_entry_key(e) != entry_key
            ]
            self.data.get("spell_states", {}).pop(entry_key, None)
            self.data.get("spell_skill_choices", {}).pop(entry_key, None)
        else:
            entry_to_remove = matching_pending[0]
            entry_key = self._prepared_entry_key(entry_to_remove)
            self.data["pending_prepared_spells"] = [
                e for e in pending_entries if self._prepared_entry_key(e) != entry_key
            ]

        self._mark_spells_page_stale()
        self._refresh_spells_known_if_visible()

        if count == 1:
            if messagebox.askyesno(
                "Remove from Spellbook?",
                f"{spell_name} is no longer prepared. Remove it from your spellbook?",
            ):
                self.remove_known_spell(spell_name)
            return

        # Targeted light updates for prepared side and per-day instead of full refresh_spells_page()
        # (avoids redundant known rebuild + materials + commit label + full overhead that caused lag)
        if hasattr(self, "spells_frame") and self._is_page_active("Spells"):
            try:
                self.rebuild_spells_per_day()
            except Exception:
                pass
            if hasattr(self, "_refresh_prepared_spells_panel"):
                try:
                    self._refresh_prepared_spells_panel()
                except Exception:
                    pass
            # Optional: keep material/ other light if needed, but skip to minimize lag on simple decrement
            # self._refresh_material_list()
            # self.update_spells_per_day()
            # etc.
    
    def filter_spells(self):
        if not hasattr(self, 'all_spells_scroll'): return
        for widget in self.all_spells_scroll.winfo_children():
            widget.destroy()
        search_term = self.spell_search_var.get().lower()
        character_classes = [
            cls_name for cls_name, _lvl in self._get_class_level_slots()
            if cls_name not in ("None", "", None)
        ]
        
        # Domain spells are regular spells too: allow searching them in the database
        # even if they appear in the special Domain category of the spellbook.
        # They are only marked "already known" after explicit manual add to spellbook.

        for name, info in self.spells_db.items():
            spell_classes = self._get_spell_classes(info)
            if spell_classes and not any(c in spell_classes for c in character_classes):
                continue
            if search_term in name.lower() or search_term in info.get("description", "").lower():
                row = ctk.CTkFrame(self.all_spells_scroll)
                row.pack(fill="x", pady=2, padx=5)
                char_lvl = self._get_spell_level_for_character(name)
                ctk.CTkLabel(row, text=f"{name} (Lv{char_lvl})", width=180, anchor="w").pack(side="left", padx=5)
                desc_preview = self._get_formatted_spell_description(name) or info.get("description", "")
                ctk.CTkLabel(row, text=desc_preview[:60] + "...", width=280, anchor="w").pack(side="left", padx=5)
                ctk.CTkButton(row, text="Add", width=80, fg_color=getattr(self, 'primary_button_color', '#c77626'),
                              command=lambda n=name: self.add_known_spell(n)).pack(side="right", padx=5)
    
