    def _on_cloud_status(self, message, is_error=False):
        if message == "__PUSH_TICK__":
            if self._cloud_sync_dirty and self.cloud_sync and self.cloud_sync.is_configured():
                self._schedule_on_main(self._cloud_push_character)
            return
        self._cloud_sync_status = message
        self._schedule_on_main(self._update_cloud_sync_status_label, message, is_error)

    def _on_cloud_remote_update(self, remote):
        self._schedule_on_main(self._handle_cloud_remote_update, remote)

    def _handle_cloud_remote_update(self, remote):
        if self._cloud_sync_applying_remote or getattr(self, "_startup_loading", False) or not remote:
            return
        remote_data = remote.get("data") or {}
        if not remote_data:
            return
        if getattr(self, "_afflictions_push_pending", False):
            self.cloud_sync.note_remote_character(remote)
            return
        if time.monotonic() < float(getattr(self, "_afflictions_poll_block_until", 0.0) or 0.0):
            self.cloud_sync.note_remote_character(remote)
            return
        if self._cloud_sync_dirty:
            if not messagebox.askyesno(
                "Cloud Update Available",
                "A newer cloud copy of this character is available.\n\n"
                "Reload it now? Unsynced local edits will be lost.",
            ):
                self.cloud_sync.note_remote_character(remote)
                return
        self._apply_cloud_character_data(remote_data)
        self.cloud_sync.note_remote_character(remote)
        self._cloud_sync_dirty = False
        self._update_cloud_sync_status_label("Reloaded from cloud")

    def _character_has_saveable_work(self):
        """True when the open sheet has meaningful content worth saving before a new character."""
        name = self._get_character_name(sync_to_data=False)
        if name and name != "New Hero":
            return True
        if self.last_character_path:
            return True
        if getattr(self, "_cloud_sync_dirty", False):
            return True
        for feat in self.data.get("general_feats") or []:
            if str(feat or "").strip():
                return True
        for feat in (self.data.get("bonus_feats") or {}).values():
            if str(feat or "").strip():
                return True
        classes = self.data.get("classes") or []
        levels = self.data.get("levels") or []
        if any(str(c or "").strip() not in ("", "None") for c in classes):
            return True
        if any(int(l or 0) > 0 for l in levels):
            return True
        return False

    def _save_character_before_new_creation(self, *, parent=None):
        """Persist the current character before starting the creation wizard."""
        if not self._character_has_saveable_work():
            return True
        try:
            self._sync_all_character_data()
        except Exception:
            pass
        if self.last_character_path:
            try:
                self._save_character_to_path(self.last_character_path, notify_cloud_error=True)
                return True
            except Exception as exc:
                messagebox.showerror(
                    "Save Character",
                    f"Could not save the current character:\n{exc}",
                    parent=parent,
                )
                return False
        name = self._get_character_name(sync_to_data=True)
        if (
            self.cloud_sync
            and self.cloud_sync.is_configured()
            and name
            and name != "New Hero"
        ):
            if self._cloud_push_character():
                return True
            if not messagebox.askyesno(
                "Save Character",
                "Cloud save failed. Create a new character anyway?",
                parent=parent,
            ):
                return False
            return True
        initial_name = (
            name.replace(" ", "_") + ".json"
            if name and name != "New Hero"
            else "character.json"
        )
        file_path = filedialog.asksaveasfilename(
            defaultextension=".json",
            filetypes=[("JSON files", "*.json")],
            title="Save Current Character Before Creating New",
            initialdir=self._characters_dir(),
            initialfile=initial_name,
        )
        if not file_path:
            return False
        try:
            self._save_character_to_path(file_path, notify_cloud_error=True)
            return True
        except Exception as exc:
            messagebox.showerror(
                "Save Character",
                f"Could not save the current character:\n{exc}",
                parent=parent,
            )
            return False

    def _apply_wizard_character(self, payload):
        """Apply character creation wizard output onto a fresh sheet."""
        if not payload or not isinstance(payload, dict):
            return False
        self.data = copy.deepcopy(self._default_character_data())
        wizard_only = {"skill_rank_data", "wizard_class", "wizard_starting_gold"}
        for key, value in payload.items():
            if key in wizard_only:
                continue
            self.data[key] = copy.deepcopy(value)
        for rank_key, rank_val in (payload.get("skill_rank_data") or {}).items():
            self.data[rank_key] = rank_val
        if payload.get("skill_rank_costs"):
            self.data["skill_rank_costs"] = copy.deepcopy(payload["skill_rank_costs"])
        self.data["character_id"] = ""
        self._normalize_character_data()
        if not self._rebuild_character_ui(show_progress=True):
            messagebox.showerror("Character Wizard", "Could not apply created character.")
            return False
        self._heal_character_to_full()
        self._update_window_title()
        self._cloud_sync_dirty = True
        return True

    def _open_character_creation_wizard(self, startup_popup=None):
        if not HAS_CHAR_WIZARD or CharacterCreationWizard is None:
            messagebox.showwarning(
                "Character Wizard",
                "Character creation wizard is not available.",
                parent=startup_popup or self.root,
            )
            return

        parent = startup_popup or self.root
        if not self._save_character_before_new_creation(parent=parent):
            return

        def on_complete(payload):
            if self._apply_wizard_character(payload):
                if startup_popup:
                    try:
                        startup_popup.destroy()
                    except tk.TclError:
                        pass
                self._finalize_startup(loaded_cloud=False)

        CharacterCreationWizard(self, on_complete=on_complete)

    def _apply_cloud_character_data(self, character_data):
        self._cancel_pending_refresh()
        self._cloud_sync_applying_remote = True
        self._skip_post_load_cloud_push = True
        try:
            prior_forced_token = max(
                0,
                int(self.data.get("last_applied_forced_rest_token", 0) or 0),
            )
            prior_xp_award_token = max(
                0,
                int(self.data.get("last_applied_dm_xp_award_token", 0) or 0),
            )
            self.data = copy.deepcopy(character_data)
            self.data["last_applied_forced_rest_token"] = prior_forced_token
            self.data["last_applied_dm_xp_award_token"] = prior_xp_award_token
            self._normalize_character_data()
            self._maybe_apply_forced_rest_from_status(self.data)

            # Restore saved theme for this character
            theme_name = self.data.get("theme", "Dicey Default")
            if theme_name in getattr(self, "THEMES", {}):
                self.current_theme = theme_name
                self.primary_button_color = self.THEMES[theme_name]["nav"]
                self.primary_hover_color = self.THEMES[theme_name]["hover_nav"]
                self.secondary_button_color = self.THEMES[theme_name].get("reload", self.THEMES[theme_name].get("secondary", "#28a99e"))
                self.secondary_hover_color = self.THEMES[theme_name].get("hover_reload", self.THEMES[theme_name].get("hover_secondary", "#1f7f75"))
                self._apply_theme(theme_name)
            if hasattr(self, "hamburger_sb_var"):
                try:
                    self.hamburger_sb_var.set(bool(self.data.get("sb_portrait", False)))
                except Exception:
                    pass

            # Extract any portrait image that came over cloud sync and save locally
            self._extract_and_save_cloud_portrait()
            self._refresh_sidebar_background()

            if not self._rebuild_character_ui(show_progress=True):
                messagebox.showerror("Cloud Sync", "Could not apply cloud character data.")
                self._cloud_sync_applying_remote = False
                self._skip_post_load_cloud_push = False
            elif self.cloud_sync and self.cloud_sync.is_configured():
                self._start_dm_status_polling()
        except Exception:
            self._cloud_sync_applying_remote = False
            self._skip_post_load_cloud_push = False
            raise

    def _init_cloud_sync(self, *, start_polling=False):
        # start_polling=False by default to avoid background thread causing UI stickiness/nonresponsiveness.
        # Sync now happens on explicit button, save, close, or open/load of character.
        if not HAS_CLOUD_SYNC:
            self._update_cloud_sync_status_label("module missing")
            return
        if self.cloud_sync:
            self.cloud_sync.stop()
        self.cloud_sync = CloudSyncManager(
            SYNC_CONFIG_FILE,
            on_remote_update=self._on_cloud_remote_update,
            on_status=self._on_cloud_status,
        )
        self.cloud_sync.load_config()
        # Adopt this sheet's character_id (if it has one) into the live config for correct per-character cloud targeting.
        if hasattr(self, 'data') and self.data:
            data_cid = self.data.get("character_id", "") or ""
            cfg_cid = self.cloud_sync.config.get("character_id", "") or ""
        if data_cid and data_cid != cfg_cid:
                self.cloud_sync.config["character_id"] = data_cid
                try:
                    self.cloud_sync.save_config({"character_id": data_cid})
                except Exception:
                    pass
        if self.cloud_sync.is_configured():
            try:
                self.cloud_sync.test_connection()
                # No auto start of poller for performance. User can still push/pull explicitly.
                self._update_cloud_sync_status_label("Cloud ready (manual sync)")
            except Exception as exc:
                self._update_cloud_sync_status_label(str(exc), is_error=True)
        else:
            self._update_cloud_sync_status_label("off")

    def _mark_cloud_sync_dirty(self):
        if self._cloud_sync_applying_remote:
            return
        self._cloud_sync_dirty = True
        if self.cloud_sync and self.cloud_sync.is_configured():
            self._update_cloud_sync_status_label("Unsaved cloud changes")

    def _on_defenses_data_changed(self):
        """Push resistance/defense updates to cloud for DM stat block live sync."""
        self._schedule_priority_cloud_push()

    def _schedule_priority_cloud_push(self, delay_ms=800):
        """Debounced cloud upload for HP, XP, AC, ability scores, and defenses."""
        if (
            getattr(self, "_closing", False)
            or getattr(self, "_startup_loading", False)
            or self._cloud_sync_applying_remote
            or not (self.cloud_sync and self.cloud_sync.is_configured())
        ):
            return
        self._mark_cloud_sync_dirty()
        timer = getattr(self, "_priority_cloud_push_timer", None)
        if timer:
            try:
                self.root.after_cancel(timer)
            except Exception:
                pass
        self._priority_cloud_push_timer = self.root.after(
            delay_ms, self._execute_priority_cloud_push,
        )

    def _schedule_post_load_cloud_sync(self):
        """After a local/cloud sheet load, push current XP and live stats to the server."""
        if (
            getattr(self, "_closing", False)
            or self._cloud_sync_applying_remote
            or not (self.cloud_sync and self.cloud_sync.is_configured())
        ):
            return
        if getattr(self, "_skip_post_load_cloud_push", False):
            self._skip_post_load_cloud_push = False
            return
        self.refresh_xp_display()
        self._sync_all_character_data()
        self._schedule_priority_cloud_push(delay_ms=1200)

    def _execute_priority_cloud_push(self):
        self._priority_cloud_push_timer = None
        if (
            getattr(self, "_closing", False)
            or getattr(self, "_startup_loading", False)
            or self._cloud_sync_applying_remote
            or getattr(self, "_cloud_save_in_progress", False)
            or not (self.cloud_sync and self.cloud_sync.is_configured())
            or not self._cloud_sync_dirty
        ):
            return
        self._cloud_push_character()

    def _cancel_priority_cloud_push(self):
        timer = getattr(self, "_priority_cloud_push_timer", None)
        if timer:
            try:
                self.root.after_cancel(timer)
            except Exception:
                pass
        self._priority_cloud_push_timer = None

    def _local_dm_status_payload(self):
        if HAS_CLOUD_SYNC:
            return CloudSyncManager.normalize_dm_status(self.data)
        afflictions = {
            str(key): bool(value)
            for key, value in sorted((self.data.get("afflictions") or {}).items())
        }
        negative_levels = max(0, int(self.data.get("negative_levels", 0) or 0))
        remote_damage = self.data.get("ability_damage") or {}
        ability_damage = {
            ability: max(0, int(remote_damage.get(ability, 0) or 0))
            for ability in (
                "Strength", "Dexterity", "Constitution",
                "Intelligence", "Wisdom", "Charisma",
            )
        }
        dm_weather = {"active": False}
        survival_days = {"starvation": 0, "thirst": 0, "exhaustion": 0}
        forced_rest = {"token": 0, "at": ""}
        if HAS_CLOUD_SYNC:
            dm_weather = CloudSyncManager._normalize_dm_weather(self.data)
            survival_days = CloudSyncManager._normalize_survival_days(self.data)
            forced_rest = CloudSyncManager._normalize_forced_rest(self.data)
        else:
            raw_survival = self.data.get("survival_days") or {}
            if isinstance(raw_survival, dict):
                for key in survival_days:
                    try:
                        survival_days[key] = max(0, int(raw_survival.get(key, 0) or 0))
                    except (TypeError, ValueError):
                        survival_days[key] = 0
            raw_forced = self.data.get("dm_forced_rest") or {}
            if isinstance(raw_forced, dict):
                try:
                    forced_rest["token"] = max(0, int(raw_forced.get("token", 0) or 0))
                except (TypeError, ValueError):
                    forced_rest["token"] = 0
                forced_rest["at"] = str(raw_forced.get("at") or "").strip()
        dm_xp_award = {"token": 0, "amount": 0, "at": ""}
        if HAS_CLOUD_SYNC:
            dm_xp_award = CloudSyncManager._normalize_dm_xp_award(self.data)
        return {
            "afflictions": afflictions,
            "negative_levels": negative_levels,
            "ability_damage": ability_damage,
            "dm_weather": dm_weather,
            "survival_days": survival_days,
            "forced_rest": forced_rest,
            "pending_nonlethal": 0,
            "dm_xp_award": dm_xp_award,
        }

    def _get_dm_weather_state(self):
        raw = self.data.get("dm_weather") or {}
        if not isinstance(raw, dict):
            return {"active": False}
        if HAS_CLOUD_SYNC:
            return CloudSyncManager._normalize_dm_weather({"dm_weather": raw})
        if not raw.get("active"):
            return {"active": False}
        return {
            "active": True,
            "summary": str(raw.get("summary") or "").strip(),
            "ranged_attack": int(raw.get("ranged_attack", 0) or 0),
            "ranged_attack_impossible": bool(raw.get("ranged_attack_impossible", False)),
            "melee_attack": int(raw.get("melee_attack", 0) or 0),
            "spot": int(raw.get("spot", 0) or 0),
            "search": int(raw.get("search", 0) or 0),
            "listen": int(raw.get("listen", 0) or 0),
        }

    def _get_weather_attack_modifiers(self, weapon_style):
        weather = self._get_dm_weather_state()
        if not weather.get("active"):
            return 0, False
        style = str(weapon_style or "")
        if style in ("Ranged", "Thrown"):
            if weather.get("ranged_attack_impossible"):
                return 0, True
            return int(weather.get("ranged_attack", 0) or 0), False
        return int(weather.get("melee_attack", 0) or 0), False

    def _get_weather_skill_penalty_for_key(self, skill_key):
        """DM weather penalty for Spot, Search, and Listen (Outdoors conditions from Behind)."""
        weather = self._get_dm_weather_state()
        if not weather.get("active"):
            return 0
        base = self._skill_base_name(skill_key) if hasattr(self, "_skill_base_name") else skill_key
        field = {
            "Spot": "spot",
            "Search": "search",
            "Listen": "listen",
        }.get(base)
        if not field:
            return 0
        return int(weather.get(field, 0) or 0)

    def _refresh_combat_weather_display(self):
        label = getattr(self, "combat_weather_label", None)
        if not label:
            return
        try:
            if not label.winfo_exists():
                return
        except Exception:
            return
        weather = self._get_dm_weather_state()
        if not weather.get("active"):
            label.configure(text="")
            return
        parts = [f"☁ {weather.get('summary') or 'Weather'}"]
        if weather.get("ranged_attack_impossible"):
            parts.append("Ranged attacks impossible")
        elif weather.get("ranged_attack"):
            parts.append(f"Ranged {weather['ranged_attack']:+d}")
        if weather.get("melee_attack"):
            parts.append(f"Melee {weather['melee_attack']:+d}")
        skill_bits = []
        for key, title in (("spot", "Spot"), ("search", "Search"), ("listen", "Listen")):
            val = int(weather.get(key, 0) or 0)
            if val:
                skill_bits.append(f"{title} {val:+d}")
        if skill_bits:
            parts.append(" · ".join(skill_bits))
        label.configure(text=" · ".join(parts))

    def _maybe_apply_forced_rest_from_status(self, status_payload):
        """Apply DM-forced rest when the cloud token advances (no popup)."""
        if not isinstance(status_payload, dict):
            return False
        forced = status_payload.get("forced_rest")
        if not isinstance(forced, dict):
            if HAS_CLOUD_SYNC:
                forced = CloudSyncManager._normalize_forced_rest(status_payload)
            else:
                forced = {}
        try:
            remote_token = max(0, int(forced.get("token", 0) or 0))
        except (TypeError, ValueError):
            remote_token = 0
        try:
            local_token = max(0, int(self.data.get("last_applied_forced_rest_token", 0) or 0))
        except (TypeError, ValueError):
            local_token = 0
        if remote_token <= local_token:
            return False
        self.data["last_applied_forced_rest_token"] = remote_token
        self.data["dm_forced_rest"] = {
            "token": remote_token,
            "at": str(forced.get("at") or "").strip(),
        }
        self._perform_forced_rest()
        return True

    def _maybe_apply_pending_nonlethal_from_status(self, status_payload):
        """Apply DM starvation nonlethal delta once, then ack-clear it on the next cloud push."""
        if not isinstance(status_payload, dict):
            return False
        if HAS_CLOUD_SYNC:
            remote_pending = CloudSyncManager._normalize_dm_pending_nonlethal(status_payload)
        else:
            try:
                remote_pending = max(0, int(status_payload.get("dm_pending_nonlethal", 0) or 0))
            except (TypeError, ValueError):
                remote_pending = 0
        try:
            already_applied = max(
                0, int(self.data.get("dm_pending_nonlethal_applied", 0) or 0),
            )
        except (TypeError, ValueError):
            already_applied = 0
        if remote_pending < already_applied:
            self.data["dm_pending_nonlethal_applied"] = remote_pending
            already_applied = remote_pending
        delta = remote_pending - already_applied
        if delta <= 0:
            return False
        self._set_nonlethal_damage(
            self._get_nonlethal_damage() + delta,
            refresh=False,
        )
        self.refresh_health_display()
        self.data["dm_pending_nonlethal_applied"] = remote_pending
        consumed = max(0, int(getattr(self, "_dm_pending_nonlethal_consumed", 0) or 0))
        self._dm_pending_nonlethal_consumed = consumed + delta
        self._schedule_priority_cloud_push(delay_ms=400)
        return True

    def _maybe_apply_dm_xp_award_from_status(self, status_payload):
        """Apply one-shot DM XP awards, then ack-clear them on the next cloud push."""
        if not isinstance(status_payload, dict):
            return False
        if HAS_CLOUD_SYNC:
            award = CloudSyncManager._normalize_dm_xp_award(status_payload)
        else:
            raw = status_payload.get("dm_xp_award")
            if not isinstance(raw, dict):
                award = {"token": 0, "amount": 0, "at": ""}
            else:
                try:
                    award = {
                        "token": max(0, int(raw.get("token", 0) or 0)),
                        "amount": int(raw.get("amount", 0) or 0),
                        "at": str(raw.get("at") or "").strip(),
                    }
                except (TypeError, ValueError):
                    award = {"token": 0, "amount": 0, "at": ""}
        try:
            remote_token = max(0, int(award.get("token", 0) or 0))
            amount = int(award.get("amount", 0) or 0)
        except (TypeError, ValueError):
            remote_token = 0
            amount = 0
        try:
            local_token = max(0, int(self.data.get("last_applied_dm_xp_award_token", 0) or 0))
        except (TypeError, ValueError):
            local_token = 0
        if remote_token <= local_token:
            return False
        if amount == 0:
            self.data["last_applied_dm_xp_award_token"] = remote_token
            return False
        new_xp = max(0, self._get_current_xp() + amount)
        self._set_current_xp(new_xp)
        self._sync_xp_to_data()
        self.data["last_applied_dm_xp_award_token"] = remote_token
        self.data["dm_xp_award"] = {
            "token": remote_token,
            "amount": 0,
            "at": str(award.get("at") or "").strip(),
        }
        self.refresh_xp_display()
        self.refresh_level_up_button()
        self._schedule_priority_cloud_push(delay_ms=400)
        return True

    def _sync_afflictions_from_remote(self, remote_data, *, silent=True):
        """Timestamp-merge afflictions from cloud without rebuilding the panel."""
        if not HAS_CLOUD_SYNC or not isinstance(remote_data, dict):
            return False
        if getattr(self, "_afflictions_push_pending", False):
            return False
        if time.monotonic() < float(getattr(self, "_afflictions_poll_block_until", 0.0) or 0.0):
            return False

        local_snap = self._affliction_sync_snapshot()
        old_afflictions = dict(local_snap.get("afflictions") or {})
        merged_aff, merged_ts = merge_afflictions_by_timestamp(local_snap, remote_data)

        changed_keys = [
            str(key)
            for key, val in merged_aff.items()
            if bool(old_afflictions.get(key, False)) != bool(val)
        ]
        if not changed_keys:
            self.data["afflictions"] = dict(merged_aff)
            self.data["afflictions_updated_at"] = dict(merged_ts)
            return False

        self._cloud_sync_applying_remote = True
        try:
            self.data["afflictions"] = dict(merged_aff)
            self.data["afflictions_updated_at"] = dict(merged_ts)
            if hasattr(self, "affliction_vars"):
                for key in changed_keys:
                    var = self.affliction_vars.get(key)
                    if var is not None:
                        var.set(bool(merged_aff.get(key, False)))
            if merged_aff.get("Staggered") and not old_afflictions.get("Staggered"):
                self._drop_wielded_weapons()
            self._affliction_penalties_cache = None
            self._schedule_scoped_refresh(
                abilities=True,
                skills=True,
                combat=True,
                saves=True,
                movement=True,
                defenses=True,
                health=True,
            )
            if self.cloud_sync:
                self.cloud_sync.note_dm_status(self.data)
        finally:
            self._cloud_sync_applying_remote = False
        return True

    def _apply_dm_status_payload(self, status_payload, *, silent=False):
        """Apply DM-controlled status fields and refresh only affected stats."""
        afflictions_applied = self._sync_afflictions_from_remote(
            status_payload or {}, silent=silent,
        )
        if HAS_CLOUD_SYNC:
            status = CloudSyncManager.normalize_dm_status(status_payload or {})
        else:
            status = self._local_dm_status_payload()
        self._maybe_apply_forced_rest_from_status(status_payload or {})
        pending_applied = self._maybe_apply_pending_nonlethal_from_status(status_payload or {})
        xp_award_applied = self._maybe_apply_dm_xp_award_from_status(status_payload or {})
        local_status = self._local_dm_status_payload()
        local_snap = self._affliction_sync_snapshot()
        local_status["afflictions"] = dict(local_snap.get("afflictions") or {})
        status_for_compare = dict(status)
        local_for_compare = dict(local_status)
        status_for_compare["pending_nonlethal"] = 0
        local_for_compare["pending_nonlethal"] = 0
        status_for_compare["dm_xp_award"] = {"token": 0, "amount": 0, "at": ""}
        local_for_compare["dm_xp_award"] = {"token": 0, "amount": 0, "at": ""}
        if status_for_compare == local_for_compare:
            if xp_award_applied and not silent:
                messagebox.showinfo(
                    "DM Sync",
                    "Experience synced from cloud (D&D Behind).",
                )
            elif pending_applied and not silent:
                messagebox.showinfo(
                    "DM Sync",
                    "Nonlethal damage synced from cloud (D&D Behind).",
                )
            elif not pending_applied and not xp_award_applied and not afflictions_applied and not silent:
                messagebox.showinfo("DM Sync", "No relevant status changes found in cloud.")
            return pending_applied or xp_award_applied or afflictions_applied

        ability_damage_changed = status.get("ability_damage") != local_status.get("ability_damage")
        weather_changed = status.get("dm_weather") != local_status.get("dm_weather")
        survival_changed = status.get("survival_days") != local_status.get("survival_days")

        self._cloud_sync_applying_remote = True
        try:
            self.data["negative_levels"] = max(0, int(status.get("negative_levels", 0) or 0))
            self.data["ability_damage"] = dict(status.get("ability_damage") or {})
            self.data["dm_weather"] = dict(status.get("dm_weather") or {"active": False})
            self.data["survival_days"] = dict(status.get("survival_days") or {})

            if getattr(self, "neg_levels_var", None) is not None:
                self.neg_levels_var.set(self.data["negative_levels"])
            self._update_ability_damage_display()

            if not afflictions_applied:
                self._affliction_penalties_cache = None
                self._schedule_scoped_refresh(
                    abilities=True,
                    skills=True,
                    combat=True,
                    saves=True,
                    movement=True,
                    defenses=True,
                    health=True,
                )
            if ability_damage_changed:
                self._update_ability_name_styles()
            if xp_award_applied:
                self.refresh_xp_display()
                self.refresh_level_up_button()

            if self.cloud_sync:
                self.cloud_sync.note_dm_status(self.data)
            if weather_changed:
                self._mark_combat_page_stale()
                self._refresh_combat_weather_display()
                if self._is_page_active("Combat"):
                    self._refresh_combat_attack_summaries()
                else:
                    self._combat_summaries_built_for_key = None
            if not silent:
                parts = ["Afflictions, negative levels, and ability damage"]
                if xp_award_applied:
                    parts.append("experience")
                if weather_changed:
                    parts.append("weather")
                if survival_changed:
                    parts.append("survival days")
                if pending_applied:
                    parts.append("nonlethal damage")
                messagebox.showinfo(
                    "DM Sync",
                    f"{', '.join(parts)} synced from cloud (D&D Behind).",
                )
            return True
        finally:
            self._cloud_sync_applying_remote = False

    def _on_dm_status_remote_update(self, status_payload):
        self._schedule_on_main(self._handle_dm_status_remote_update, status_payload)

    def _handle_dm_status_remote_update(self, status_payload):
        if getattr(self, "_startup_loading", False) or getattr(self, "_closing", False):
            return
        self._apply_dm_status_payload(status_payload, silent=True)

    def _stop_dm_status_poll_tick(self):
        poll_id = getattr(self, "_dm_status_poll_after_id", None)
        if poll_id is not None:
            try:
                self.root.after_cancel(poll_id)
            except Exception:
                pass
        self._dm_status_poll_after_id = None
        if self.cloud_sync:
            self.cloud_sync.stop_dm_status_polling()

    def _dm_status_poll_interval_ms(self):
        if not self.cloud_sync:
            return 5000
        return max(3000, int(self.cloud_sync.get_dm_status_poll_interval_sec() * 1000))

    def _schedule_dm_status_poll_tick(self, delay_ms=None):
        if getattr(self, "_closing", False):
            return
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            return
        self._stop_dm_status_poll_tick()
        if delay_ms is None:
            delay_ms = self._dm_status_poll_interval_ms()
        self._dm_status_poll_after_id = self.root.after(
            delay_ms, self._dm_status_poll_tick,
        )

    def _dm_status_poll_tick(self):
        self._dm_status_poll_after_id = None
        if (
            getattr(self, "_closing", False)
            or getattr(self, "_startup_loading", False)
            or not (self.cloud_sync and self.cloud_sync.is_configured())
        ):
            return
        self._pull_dm_status_from_cloud(silent=True)
        self._schedule_dm_status_poll_tick()

    def _pull_dm_status_from_cloud(self, *, silent=True):
        """Pull DM-controlled cloud fields (afflictions, weather, neg levels, ability damage, XP awards)."""
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            return False
        if getattr(self, "_afflictions_push_pending", False):
            return False
        if time.monotonic() < float(getattr(self, "_afflictions_poll_block_until", 0.0) or 0.0):
            return False
        try:
            remote = self.cloud_sync.fetch_dm_status()
            if not remote:
                return False
            if remote.get("unchanged"):
                return False
            if not isinstance(remote.get("data"), dict):
                return False
            if HAS_CLOUD_SYNC:
                status = CloudSyncManager.normalize_dm_status(remote["data"])
            else:
                status = self._local_dm_status_payload()
            return self._apply_dm_status_payload(status, silent=silent)
        except Exception:
            return False

    def _merge_dm_authoritative_fields_into_push_payload(self, payload):
        """Keep DM-pushed afflictions/weather on cloud when the player uploads HP and other local edits."""
        if not self.cloud_sync or not self.cloud_sync.is_configured() or not isinstance(payload, dict):
            return payload
        try:
            remote = self.cloud_sync.fetch_dm_status(force=True)
            if not remote or not isinstance(remote.get("data"), dict):
                return payload
            remote_status = CloudSyncManager.normalize_dm_status(remote["data"])
            local_snap = self._affliction_sync_snapshot()
            protect_local = bool(getattr(self, "_afflictions_push_pending", False))
            merged_aff, merged_ts = merge_afflictions_by_timestamp(
                local_snap, remote["data"], protect_local=protect_local,
            )
            payload["afflictions"] = merged_aff
            payload["afflictions_updated_at"] = merged_ts
            payload["negative_levels"] = max(
                0, int(remote_status.get("negative_levels", 0) or 0),
            )
            payload["ability_damage"] = dict(remote_status.get("ability_damage") or {})
            payload["dm_weather"] = dict(
                remote_status.get("dm_weather") or {"active": False},
            )
            payload["survival_days"] = dict(remote_status.get("survival_days") or {})
            remote_forced = remote_status.get("forced_rest") or {}
            if isinstance(remote_forced, dict):
                payload["dm_forced_rest"] = dict(remote_forced)
            consumed = max(0, int(getattr(self, "_dm_pending_nonlethal_consumed", 0) or 0))
            remote_pending = CloudSyncManager._normalize_dm_pending_nonlethal(remote["data"])
            if consumed > 0:
                cleared_pending = max(0, remote_pending - consumed)
                payload["dm_pending_nonlethal"] = cleared_pending
                self._dm_pending_nonlethal_consumed = 0
                if cleared_pending == 0:
                    self.data["dm_pending_nonlethal_applied"] = 0
                else:
                    self.data["dm_pending_nonlethal_applied"] = min(
                        max(0, int(self.data.get("dm_pending_nonlethal_applied", 0) or 0)),
                        cleared_pending,
                    )
            else:
                payload["dm_pending_nonlethal"] = remote_pending
            local_award = CloudSyncManager._normalize_dm_xp_award(self.data)
            remote_award = CloudSyncManager._normalize_dm_xp_award(remote["data"])
            if (
                local_award.get("token", 0) >= remote_award.get("token", 0)
                and local_award.get("amount", 0) == 0
                and remote_award.get("amount", 0) != 0
            ):
                payload["dm_xp_award"] = dict(local_award)
            else:
                payload["dm_xp_award"] = remote_award
            health = payload.setdefault("health", {})
            health["lethal_damage_taken"] = self._get_lethal_damage_taken()
            health["nonlethal_damage_taken"] = self._get_nonlethal_damage_taken()
            health["nonlethal_damage"] = health["nonlethal_damage_taken"]
            remote_tab = remote["data"].get("goods_services_tab")
            if isinstance(remote_tab, dict):
                remote_items = remote_tab.get("items")
                if isinstance(remote_items, list) and remote_items:
                    payload["goods_services_tab"] = copy.deepcopy(remote_tab)
        except Exception:
            pass
        return payload

    def _start_dm_status_polling(self, *, seed_from_local=True):
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            return
        if seed_from_local:
            self.cloud_sync.note_dm_status(self.data)
        self.cloud_sync.stop_dm_status_polling()
        self._schedule_dm_status_poll_tick(0)
        self._start_image_share_polling()
        self._start_follower_statblock_polling()

    def _sync_image_share_from_cloud(self):
        """Copy live cloud credentials + character_id into the image-share client."""
        if not self.image_share_sync:
            return
        if self.cloud_sync:
            try:
                self.cloud_sync.load_config()
            except Exception:
                pass
        self.image_share_sync.load_config()
        merged = dict(self.image_share_sync.config or {})
        if self.cloud_sync and getattr(self.cloud_sync, "config", None):
            src = self.cloud_sync.config
            for key in (
                "enabled", "supabase_url", "supabase_anon_key", "campaign_id",
                "character_id", "player_name", "dm_status_poll_interval_sec",
                "poll_interval_sec", "loot_poll_interval_sec",
            ):
                val = src.get(key)
                if val is not None and str(val).strip() != "":
                    merged[key] = val
        if not str(merged.get("character_id") or "").strip() and getattr(self, "data", None):
            cid = str(self.data.get("character_id") or "").strip()
            if cid:
                merged["character_id"] = cid
        if merged.get("enabled") is None:
            merged["enabled"] = True
        self.image_share_sync.config = merged

    def _start_image_share_polling(self):
        if not self.image_share_sync:
            return
        self._sync_image_share_from_cloud()
        if not self.image_share_sync.is_player_configured():
            return
        try:
            unseen = self.image_share_sync.fetch_unseen_images()
            if unseen:
                self._on_remote_shared_images(unseen)
        except Exception as exc:
            print(f"Image share initial fetch: {exc}")
        self.image_share_sync.start_polling()

    def _on_remote_shared_images(self, entries):
        self._schedule_on_main(self._handle_remote_shared_images, entries)

    def _handle_remote_shared_images(self, entries):
        if getattr(self, "_closing", False) or getattr(self, "_startup_loading", False):
            return
        if not entries:
            return
        already_seen = set()
        if self.image_share_sync:
            try:
                already_seen = self.image_share_sync.get_seen_image_ids()
            except Exception:
                pass
        queue = list(getattr(self, "_pending_shared_images", []) or [])
        seen_ids = {str(e.get("id") or "") for e in queue}
        for entry in entries:
            eid = str(entry.get("id") or "").strip()
            if eid and eid not in seen_ids and eid not in already_seen:
                queue.append(entry)
                seen_ids.add(eid)
        self._pending_shared_images = queue
        if not getattr(self, "_shared_image_popup_open", False):
            self._show_next_shared_image_popup()

    def _show_next_shared_image_popup(self):
        queue = list(getattr(self, "_pending_shared_images", []) or [])
        if not queue:
            self._shared_image_popup_open = False
            return
        entry = queue.pop(0)
        self._pending_shared_images = queue
        self._shared_image_popup_open = True
        self._show_shared_image_popup(entry)

    def _dismiss_shared_image_popup(self, entry, popup):
        if self.image_share_sync and entry:
            try:
                self.image_share_sync.mark_image_seen(entry.get("id"))
            except Exception:
                pass
        self._shared_image_popup_open = False
        try:
            if popup and popup.winfo_exists():
                popup.destroy()
        except Exception:
            pass
        self.root.after(120, self._show_next_shared_image_popup)

    def _show_shared_image_popup(self, entry):
        image_url = str(entry.get("image_url") or "").strip()
        if not image_url:
            self._dismiss_shared_image_popup(entry, None)
            return

        popup = ctk.CTkToplevel(self.root)
        popup.title(str(entry.get("title") or "Shared Image"))
        popup.geometry("680x560")
        popup.transient(self.root)
        popup.grab_set()
        popup.protocol(
            "WM_DELETE_WINDOW",
            lambda e=entry, p=popup: self._dismiss_shared_image_popup(e, p),
        )

        shared_by = str(entry.get("shared_by") or "DM").strip() or "DM"
        title = str(entry.get("title") or "Shared Image").strip()
        ctk.CTkLabel(
            popup, text=title, font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(padx=16, pady=(14, 2))
        ctk.CTkLabel(
            popup, text=f"Shared by {shared_by}", font=ctk.CTkFont(size=11), text_color="#aaaaaa",
        ).pack(padx=16, pady=(0, 6))

        img_frame = ctk.CTkFrame(popup, fg_color="#1a1a1a")
        img_frame.pack(fill="both", expand=True, padx=16, pady=6)
        status = ctk.CTkLabel(img_frame, text="Loading image...", text_color="#888888")
        status.pack(expand=True, padx=12, pady=40)

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(fill="x", padx=16, pady=12)
        ctk.CTkButton(
            footer, text="Close", width=90, fg_color="#555555",
            command=lambda e=entry, p=popup: self._dismiss_shared_image_popup(e, p),
        ).pack(side="right")

        popup._image_ref = None

        def _apply_image(pil_img):
            if not popup.winfo_exists():
                return
            status.destroy()
            if pil_img is None or not HAS_PIL:
                ctk.CTkLabel(
                    img_frame,
                    text="Could not load image preview.\nTry opening the URL in your browser.",
                    text_color="#d9a066", wraplength=520, justify="center",
                ).pack(expand=True, padx=12, pady=20)
                ctk.CTkButton(
                    img_frame, text="Open URL in Browser", fg_color="#4a6fa5",
                    command=lambda: __import__("webbrowser").open(image_url),
                ).pack(pady=(0, 12))
                return
            ctk_img = ctk.CTkImage(light_image=pil_img, dark_image=pil_img, size=pil_img.size)
            popup._image_ref = ctk_img
            ctk.CTkLabel(img_frame, text="", image=ctk_img).pack(expand=True, padx=8, pady=8)

        def _worker():
            pil_img = None
            if fetch_url_image_pil:
                try:
                    pil_img = fetch_url_image_pil(image_url)
                except Exception:
                    pil_img = None
            self._schedule_on_main(lambda: _apply_image(pil_img))

        threading.Thread(target=_worker, daemon=True).start()

    def _dm_sync_status_from_cloud(self):
        """Pull latest afflictions, negative_levels, ability_damage, and weather from cloud."""
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            messagebox.showwarning("Cloud Sync", "Cloud sync is not configured. Use the ☁ button in the sidebar to set it up.")
            return
        try:
            if not self._pull_dm_status_from_cloud(silent=False):
                messagebox.showinfo("DM Sync", "No relevant status changes found in cloud.")
        except Exception as e:
            messagebox.showerror("DM Sync Error", str(e))

    def _strip_portrait_from_payload(self, payload):
        desc = payload.get("description")
        if isinstance(desc, dict):
            desc.pop("portrait_base64", None)

    def _apply_cached_portrait_to_payload(self, payload):
        cache = getattr(self, "_cloud_portrait_cache", None) or {}
        portrait_b64 = cache.get("portrait_base64")
        if not portrait_b64:
            return
        desc = payload.setdefault("description", {})
        desc["portrait_base64"] = portrait_b64
        portrait_file = cache.get("portrait_file")
        if portrait_file:
            desc["portrait_file"] = portrait_file

    def _update_cloud_portrait_cache(self, *, portrait_base64="", portrait_file=""):
        if portrait_base64:
            self._cloud_portrait_cache = {
                "portrait_base64": portrait_base64,
                "portrait_file": portrait_file or "",
            }
        else:
            self._cloud_portrait_cache = {}

    def _prepare_cloud_push(self):
        """Sync UI into self.data and return a deep copy ready for upload, or None to skip."""
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            return None
        name = self._get_character_name(sync_to_data=True)
        if not name or name == "New Hero":
            return None
        data_cid = self.data.get("character_id", "") or ""
        if data_cid and data_cid != self.cloud_sync.config.get("character_id", ""):
            self.cloud_sync.config["character_id"] = data_cid
            try:
                self.cloud_sync.save_config({"character_id": data_cid})
            except Exception:
                pass
        self._sync_all_character_data()
        self._strip_portrait_base64()
        self._strip_follower_statblocks_from_data()
        payload = copy.deepcopy(self.data)
        self._strip_portrait_from_payload(payload)
        self._strip_follower_statblocks_from_data(payload)
        if getattr(self, "_portrait_needs_cloud_upload", False):
            self._embed_portrait_for_cloud()
            desc_src = self.data.get("description") or {}
            if desc_src.get("portrait_base64"):
                desc_dst = payload.setdefault("description", {})
                desc_dst["portrait_base64"] = desc_src["portrait_base64"]
                desc_dst["portrait_file"] = desc_src.get("portrait_file", "")
                self._update_cloud_portrait_cache(
                    portrait_base64=desc_src["portrait_base64"],
                    portrait_file=desc_src.get("portrait_file", ""),
                )
            self._strip_portrait_base64()
        else:
            self._apply_cached_portrait_to_payload(payload)
        return self._merge_dm_authoritative_fields_into_push_payload(payload)

    def _cloud_push_character(self):
        try:
            payload = self._prepare_cloud_push()
            if payload is None:
                return False
            pushed_afflictions = dict((payload or {}).get("afflictions") or {})
            pushed_ts = dict((payload or {}).get("afflictions_updated_at") or {})
            self.cloud_sync.upsert_character(
                payload,
                protect_local_afflictions=bool(getattr(self, "_afflictions_push_pending", False)),
            )
            self._strip_portrait_base64()
            self._portrait_needs_cloud_upload = False
            self._cloud_sync_dirty = False
            self._cloud_last_pushed_at = datetime.now(timezone.utc)
            if isinstance(payload, dict):
                self.data["afflictions"] = pushed_afflictions
                self.data["afflictions_updated_at"] = pushed_ts
            if getattr(self, "_afflictions_push_pending", False):
                snap = self._affliction_sync_snapshot()
                if snap.get("afflictions") == pushed_afflictions:
                    self._afflictions_push_pending = False
                    self._afflictions_poll_block_until = time.monotonic() + 3.0
            if self.cloud_sync:
                self.cloud_sync.note_dm_status(self.data)
            self._update_cloud_sync_status_label("Synced")
            return True
        except Exception as exc:
            self._update_cloud_sync_status_label(str(exc), is_error=True)
            return False

    def _bind_cloud_blur_save_handlers(self):
        """Save unsaved cloud changes when the user clicks out of the app."""
        try:
            self.root.bind("<Deactivate>", self._on_app_deactivate, add="+")
            self.root.bind("<Activate>", self._on_app_activate, add="+")
        except Exception:
            pass

    def _app_has_focus(self):
        try:
            return bool(self.root.focus_displayof())
        except tk.TclError:
            return False

    def _should_skip_blur_cloud_save(self):
        return (
            getattr(self, "_closing", False)
            or getattr(self, "_startup_loading", False)
            or self._cloud_sync_applying_remote
            or getattr(self, "_rebuilding_ui", False)
            or not self._cloud_sync_dirty
            or not (self.cloud_sync and self.cloud_sync.is_configured())
            or self._cloud_save_in_progress
        )

    def _on_app_deactivate(self, event=None):
        self._apply_sync_focus_state(focused=False)
        if self._should_skip_blur_cloud_save():
            return
        self._schedule_cloud_save_on_blur()

    def _on_app_activate(self, event=None):
        self._apply_sync_focus_state(focused=True)
        if self._cloud_blur_save_timer:
            try:
                self.root.after_cancel(self._cloud_blur_save_timer)
            except Exception:
                pass
            self._cloud_blur_save_timer = None

    def _apply_sync_focus_state(self, *, focused):
        from sync_intervals import FOCUS_SLOW_POLL_MULTIPLIER

        multiplier = 1 if focused else FOCUS_SLOW_POLL_MULTIPLIER
        if self.cloud_sync and hasattr(self.cloud_sync, "set_focus_multiplier"):
            self.cloud_sync.set_focus_multiplier(multiplier)
        for client in (
            getattr(self, "campaign_chat_sync", None),
            getattr(self, "roll_log_sync", None),
            getattr(self, "loot_sync", None),
            getattr(self, "homebrew_sync", None),
        ):
            if client and hasattr(client, "set_focus_multiplier"):
                if getattr(client, "is_live_mode", None) and client.is_live_mode():
                    client.set_focus_multiplier(1)
                else:
                    client.set_focus_multiplier(multiplier)

    def _set_campaign_chat_live_mode(self, active):
        """Fast chat/roll polling while the campaign chat window is open."""
        active = bool(active)
        for client in (
            getattr(self, "campaign_chat_sync", None),
            getattr(self, "roll_log_sync", None),
        ):
            if client and hasattr(client, "set_live_mode"):
                client.set_live_mode(active)
        self._apply_sync_focus_state(focused=self._app_has_focus())

    def _schedule_cloud_save_on_blur(self, delay_ms=500):
        if self._cloud_blur_save_timer:
            try:
                self.root.after_cancel(self._cloud_blur_save_timer)
            except Exception:
                pass
        self._cloud_blur_save_timer = self.root.after(delay_ms, self._try_cloud_save_on_blur)

    def _try_cloud_save_on_blur(self):
        self._cloud_blur_save_timer = None
        if self._should_skip_blur_cloud_save():
            return
        if self._app_has_focus():
            return
        self._begin_blur_cloud_save()

    def _show_cloud_save_progress(self, title="Saving to Cloud", message="Preparing character data..."):
        self._hide_cloud_save_progress()

        overlay = ctk.CTkToplevel(self.root)
        overlay.title(title)
        overlay.resizable(False, False)
        overlay.configure(fg_color=THEME_DARK_BG)
        overlay.transient(self.root)
        overlay.attributes("-topmost", True)
        try:
            overlay.grab_set()
        except Exception:
            pass

        frame = ctk.CTkFrame(overlay, fg_color=THEME_DARK_BG)
        frame.pack(fill="both", expand=True, padx=24, pady=20)

        ctk.CTkLabel(
            frame,
            text=title,
            font=ctk.CTkFont(size=18, weight="bold"),
            text_color=THEME_ORANGE,
        ).pack(pady=(0, 10))

        self._save_status_label = ctk.CTkLabel(
            frame,
            text=message,
            font=ctk.CTkFont(size=13),
            text_color="#cccccc",
        )
        self._save_status_label.pack(pady=(0, 12))

        self._save_progress = ctk.CTkProgressBar(
            frame,
            width=360,
            height=18,
            progress_color=THEME_ORANGE,
            fg_color=THEME_DARK_TRACK,
            corner_radius=8,
        )
        self._save_progress.pack(pady=(0, 4))
        self._save_progress.set(0.1)

        overlay.update_idletasks()
        width, height = 420, 150
        root_x = self.root.winfo_rootx()
        root_y = self.root.winfo_rooty()
        root_w = self.root.winfo_width()
        root_h = self.root.winfo_height()
        pos_x = root_x + max(0, (root_w - width) // 2)
        pos_y = root_y + max(0, (root_h - height) // 2)
        overlay.geometry(f"{width}x{height}+{pos_x}+{pos_y}")

        self._save_overlay = overlay
        self._pump_ui()

    def _update_cloud_save_progress(self, value, message=None):
        if not hasattr(self, "_save_progress") or self._save_progress is None:
            return
        self._save_progress.set(min(1.0, max(0.0, value)))
        if message and hasattr(self, "_save_status_label") and self._save_status_label:
            self._save_status_label.configure(text=message)
        self._pump_ui()

    def _hide_cloud_save_progress(self):
        if hasattr(self, "_save_overlay") and self._save_overlay:
            try:
                self._save_overlay.grab_release()
            except Exception:
                pass
            try:
                self._save_overlay.attributes("-topmost", False)
            except Exception:
                pass
            try:
                self._save_overlay.destroy()
            except Exception:
                pass
        self._save_overlay = None
        self._save_progress = None
        self._save_status_label = None

    def _close_save_needed(self):
        if self.last_character_path:
            return True
        if self.cloud_sync and self.cloud_sync.is_configured():
            name = self._get_character_name(sync_to_data=True)
            return bool(name and name != "New Hero")
        return False

    def _should_push_cloud_on_close(self):
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            return False
        name = self._get_character_name(sync_to_data=True)
        return bool(name and name != "New Hero")

    def _pause_for_save_overlay(self, seconds=0.55):
        end = time.monotonic() + max(0.0, float(seconds or 0))
        while time.monotonic() < end:
            self._pump_ui()
            time.sleep(0.03)

    def _perform_close_save(self):
        self._show_cloud_save_progress(
            title="Saving Character",
            message="Preparing...",
        )
        self._update_cloud_save_progress(0.1, "Preparing...")
        self._pump_ui()
        try:
            if self.last_character_path:
                self._update_cloud_save_progress(0.3, "Saving locally...")
                self._pump_ui()
                self._sync_all_character_data()
                self._strip_portrait_base64()
                with open(self.last_character_path, "w", encoding="utf-8") as handle:
                    json.dump(self.data, handle, indent=2, ensure_ascii=False)
                self._remember_character_path(self.last_character_path)
                if self._should_push_cloud_on_close():
                    self._update_cloud_save_progress(0.6, "Uploading to cloud...")
                    self._pump_ui()
                    self._cloud_push_character()
            else:
                self._sync_all_character_data()
                if self._should_push_cloud_on_close():
                    self._update_cloud_save_progress(0.5, "Uploading to cloud...")
                    self._pump_ui()
                    self._cloud_push_character()
            self._update_cloud_save_progress(1.0, "Save complete")
            self._pump_ui()
            self._pause_for_save_overlay(0.55)
        except Exception as exc:
            print(f"Auto-save on close failed: {exc}")
            self._update_cloud_save_progress(0.0, f"Save failed: {exc}")
            self._pump_ui()
            self._pause_for_save_overlay(1.0)
            if self._should_push_cloud_on_close():
                try:
                    self._cloud_push_character()
                except Exception as cloud_exc:
                    print(f"Cloud save on close failed: {cloud_exc}")
        finally:
            self._hide_cloud_save_progress()

    def _shutdown_app(self):
        self._stop_dm_status_poll_tick()
        if self.cloud_sync:
            try:
                self.cloud_sync.stop()
            except Exception:
                pass
            self.cloud_sync = None
        if self.loot_sync:
            try:
                self.loot_sync.stop_polling()
            except Exception:
                pass
            self.loot_sync = None
        if self.homebrew_sync:
            try:
                self.homebrew_sync.stop_polling()
            except Exception:
                pass
            self.homebrew_sync = None
        if self.roll_log_sync:
            try:
                self.roll_log_sync.stop_polling()
            except Exception:
                pass
            self.roll_log_sync = None
        if self.campaign_chat_sync:
            try:
                self.campaign_chat_sync.stop_polling()
            except Exception:
                pass
            self.campaign_chat_sync = None
        chat_win = getattr(self, "campaign_chat_window", None)
        if chat_win is not None:
            try:
                chat_win.close()
            except Exception:
                pass
        if self.image_share_sync:
            try:
                self.image_share_sync.stop_polling()
            except Exception:
                pass
            self.image_share_sync = None
        if self.follower_statblock_sync:
            try:
                self.follower_statblock_sync.stop_polling()
            except Exception:
                pass
            self.follower_statblock_sync = None
        if self.trade_sync:
            try:
                self.trade_sync.stop_polling()
            except Exception:
                pass
            self.trade_sync = None
        self.root.destroy()

    def save_character_to_cloud(self):
        """Save locally (if a file path exists) and upload the character to the cloud."""
        if not HAS_CLOUD_SYNC:
            messagebox.showerror("Cloud Sync", "cloud_sync.py is missing from the app folder.")
            return
        if not self.cloud_sync:
            self._init_cloud_sync()
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            self.open_cloud_sync_settings()
            return
        if self._cloud_save_in_progress:
            return

        name = self._get_character_name(sync_to_data=True)
        if not name or name == "New Hero":
            messagebox.showwarning("Cloud Save", "Give your character a name before saving to the cloud.")
            return

        self._cloud_save_in_progress = True
        self._show_cloud_save_progress(title="Saving Character", message="Preparing...")
        self._update_cloud_save_progress(0.1, "Preparing...")

        try:
            payload = self._prepare_cloud_push()
        except Exception as exc:
            self._cloud_save_in_progress = False
            self._hide_cloud_save_progress()
            self._update_cloud_sync_status_label(str(exc), is_error=True)
            return
        if payload is None:
            self._cloud_save_in_progress = False
            self._hide_cloud_save_progress()
            return

        if self.last_character_path:
            try:
                self._update_cloud_save_progress(0.3, "Saving locally...")
                self._strip_portrait_base64()
                with open(self.last_character_path, "w", encoding="utf-8") as handle:
                    json.dump(self.data, handle, indent=2, ensure_ascii=False)
                self._remember_character_path(self.last_character_path)
            except Exception as exc:
                self._cloud_save_in_progress = False
                self._update_cloud_save_progress(0.0, f"Local save failed: {exc}")
                self._update_cloud_sync_status_label(str(exc), is_error=True)
                self.root.after(2200, self._hide_cloud_save_progress)
                return

        self._update_cloud_save_progress(0.5, "Uploading to cloud...")

        def worker():
            error = None
            success = False
            try:
                self.cloud_sync.upsert_character(payload)
                success = True
            except Exception as exc:
                error = str(exc)

            def finish():
                self._cloud_save_in_progress = False
                try:
                    self._strip_portrait_base64()
                except Exception:
                    pass
                if success:
                    self._cloud_sync_dirty = False
                    self._cloud_last_pushed_at = datetime.now(timezone.utc)
                    self._cloud_sync_status = "Synced"
                    self._update_cloud_sync_status_label("Synced")
                    self._update_cloud_save_progress(1.0, "Save complete")
                    self.root.after(900, self._hide_cloud_save_progress)
                else:
                    self._update_cloud_sync_status_label(error or "Cloud save failed", is_error=True)
                    self._update_cloud_save_progress(0.0, error or "Cloud save failed")
                    self.root.after(2200, self._hide_cloud_save_progress)

            self._schedule_on_main(finish)

        threading.Thread(target=worker, daemon=True).start()

    def _begin_blur_cloud_save(self):
        if self._cloud_save_in_progress:
            return
        try:
            payload = self._prepare_cloud_push()
        except Exception as exc:
            self._update_cloud_sync_status_label(str(exc), is_error=True)
            return
        if payload is None:
            return

        if self.last_character_path:
            try:
                self._strip_portrait_base64()
                with open(self.last_character_path, "w", encoding="utf-8") as handle:
                    json.dump(self.data, handle, indent=2, ensure_ascii=False)
            except Exception:
                pass

        self._cloud_save_in_progress = True
        self._show_cloud_save_progress(title="Saving Character", message="Uploading to cloud...")
        self._update_cloud_save_progress(0.35, "Uploading to cloud...")

        def worker():
            error = None
            success = False
            try:
                self.cloud_sync.upsert_character(payload)
                success = True
            except Exception as exc:
                error = str(exc)

            def finish():
                self._cloud_save_in_progress = False
                try:
                    self._strip_portrait_base64()
                except Exception:
                    pass
                if success:
                    self._cloud_sync_dirty = False
                    self._cloud_last_pushed_at = datetime.now(timezone.utc)
                    self._cloud_sync_status = "Synced"
                    self._update_cloud_sync_status_label("Synced")
                    self._update_cloud_save_progress(1.0, "Cloud save complete")
                    self.root.after(900, self._hide_cloud_save_progress)
                else:
                    self._update_cloud_sync_status_label(error or "Cloud save failed", is_error=True)
                    self._update_cloud_save_progress(0.0, error or "Cloud save failed")
                    self.root.after(2200, self._hide_cloud_save_progress)

            self._schedule_on_main(finish)

        threading.Thread(target=worker, daemon=True).start()

    def _read_cloud_sync_config_dict(self) -> dict:
        if self.cloud_sync and getattr(self.cloud_sync, "config", None):
            return dict(self.cloud_sync.config)
        if HAS_CLOUD_SYNC:
            return read_sync_config_file(SYNC_CONFIG_FILE)
        if HAS_CAMPAIGN_ID_PICKER and load_campaign_sync_config:
            return load_campaign_sync_config(SYNC_CONFIG_FILE)
        return {}

    def _is_cloud_sync_configured(self) -> bool:
        return bool(self.cloud_sync and self.cloud_sync.is_configured())

    def _set_active_campaign_id(self, campaign_id: str) -> None:
        campaign_id = str(campaign_id or "").strip()
        base = self._read_cloud_sync_config_dict()
        if merge_saved_campaign_ids:
            merged = merge_saved_campaign_ids(base, campaign_id)
        else:
            merged = dict(base)
            merged["campaign_id"] = campaign_id
            saved = list(merged.get("saved_campaign_ids") or [])
            if campaign_id and campaign_id not in saved:
                saved.insert(0, campaign_id)
            merged["saved_campaign_ids"] = saved
        if HAS_CLOUD_SYNC:
            if not self.cloud_sync:
                self.cloud_sync = CloudSyncManager(
                    SYNC_CONFIG_FILE,
                    on_remote_update=self._on_cloud_remote_update,
                    on_status=self._on_cloud_status,
                )
            self.cloud_sync.save_config(merged)
        elif HAS_CAMPAIGN_ID_PICKER and save_campaign_sync_config:
            save_campaign_sync_config(SYNC_CONFIG_FILE, merged)

    def _create_campaign_picker_row(
        self, parent, *, on_change=None, combo_width=420, label="Campaign", pack=True,
    ):
        cfg = self._read_cloud_sync_config_dict()

        def _handle_campaign_change(campaign_id):
            self._set_active_campaign_id(campaign_id)
            if on_change:
                on_change(campaign_id)

        if HAS_CAMPAIGN_ID_PICKER and CampaignIdPickerRow is not None:
            row = CampaignIdPickerRow(
                parent,
                cfg,
                SYNC_CONFIG_FILE,
                label=label,
                combo_width=combo_width,
                primary_color=getattr(self, "primary_button_color", THEME_ORANGE),
                on_change=_handle_campaign_change,
            )
            if pack:
                row.pack(fill="x", pady=(0, 8))
            return row

        values = []
        if get_saved_campaign_ids:
            values = get_saved_campaign_ids(cfg)
        current = str(cfg.get("campaign_id", "") or "").strip()
        frame = ctk.CTkFrame(parent, fg_color="transparent")
        if pack:
            frame.pack(fill="x", pady=(0, 8))
        ctk.CTkLabel(frame, text=label, width=120, anchor="w").pack(side="left", padx=(0, 6))

        var = ctk.StringVar(value=current or (values[0] if values else ""))

        def _changed(choice):
            _handle_campaign_change(choice)

        def _persist_campaign_config(merged):
            nonlocal cfg, values, current
            cfg = dict(merged or {})
            values = get_saved_campaign_ids(cfg) if get_saved_campaign_ids else []
            current = str(cfg.get("campaign_id", "") or "").strip()
            combo.configure(values=values or [""])
            if current:
                combo.set(current)
            elif values:
                combo.set(values[0])
            _handle_campaign_change(combo.get())

        if open_manage_campaign_ids_popup:
            ctk.CTkButton(
                frame,
                text="+",
                width=36,
                height=28,
                fg_color=getattr(self, "primary_button_color", THEME_ORANGE),
                hover_color=getattr(self, "primary_hover_color", "#a56b32"),
                command=lambda: open_manage_campaign_ids_popup(
                    self.root,
                    cfg,
                    SYNC_CONFIG_FILE,
                    primary_color=getattr(self, "primary_button_color", THEME_ORANGE),
                    on_saved=_persist_campaign_config,
                ),
            ).pack(side="right")

        combo = ctk.CTkComboBox(
            frame,
            values=values or [""],
            variable=var,
            width=max(140, min(int(combo_width or 200), 240)),
            state="readonly",
            command=_changed,
        )
        combo.pack(side="left", fill="x", expand=True, padx=(0, 6))
        if current:
            combo.set(current)
        return frame

    def open_cloud_sync_settings(self):
        if not HAS_CLOUD_SYNC:
            messagebox.showerror("Cloud Sync", "cloud_sync.py is missing from the app folder.")
            return
        if not self.cloud_sync:
            self._init_cloud_sync()

        popup = ctk.CTkToplevel(self.root)
        popup.title("Cloud Sync Settings")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=560, min_height=620)

        body = ctk.CTkScrollableFrame(popup)
        body.pack(fill="both", expand=True, padx=20, pady=16)

        ctk.CTkLabel(
            body,
            text="Live Campaign Sync (Supabase)",
            font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))
        ctk.CTkLabel(
            body,
            text=(
                "Everyone uses the same campaign_id. Each player uses a unique character_id.\n"
                "Run supabase_setup.sql once in your Supabase project."
            ),
            wraplength=460,
            justify="left",
            text_color="#aaaaaa",
        ).pack(anchor="w", pady=(0, 12))

        cfg = dict(self.cloud_sync.load_config())
        fields = {}

        def add_field(label, key, placeholder="", show=None):
            ctk.CTkLabel(body, text=label, anchor="w").pack(fill="x", pady=(8, 2))
            var = ctk.StringVar(value=str(cfg.get(key, "") or ""))
            entry = ctk.CTkEntry(body, textvariable=var, placeholder_text=placeholder, show=show)
            entry.pack(fill="x")
            fields[key] = var

        add_field("Supabase URL", "supabase_url", "https://YOUR_PROJECT.supabase.co")
        add_field("Supabase anon key", "supabase_anon_key", show="*")
        if HAS_CAMPAIGN_ID_PICKER and CampaignIdPickerRow is not None:
            campaign_row = CampaignIdPickerRow(
                body,
                cfg,
                SYNC_CONFIG_FILE,
                label="Campaign",
                combo_width=420,
                primary_color=THEME_ORANGE,
            )
            campaign_row.pack(fill="x", pady=(8, 4))
            fields["campaign_id"] = campaign_row
        else:
            add_field("Game name", "campaign_id", "e.g. greyhawk-2026")
        add_field("Character ID (unique per sheet)", "character_id", self._suggest_cloud_character_id())
        add_field("Player name", "player_name", "Your name")

        enabled_var = ctk.BooleanVar(value=bool(cfg.get("enabled", True)))
        enabled_chk = ctk.CTkCheckBox(body, text="Enable live cloud sync", variable=enabled_var)
        enabled_chk.pack(anchor="w", pady=(12, 4))
        self._bind_hover_tooltip(
            enabled_chk,
            "Turns cloud sync on or off for this character. When off, the app "
            "works locally only and does not read from or write to Supabase.",
            wraplength=420,
        )

        auto_var = ctk.BooleanVar(value=bool(cfg.get("auto_sync", True)))
        auto_chk = ctk.CTkCheckBox(body, text="Auto-sync in background", variable=auto_var)
        auto_chk.pack(anchor="w", pady=(0, 8))
        self._bind_hover_tooltip(
            auto_chk,
            "When enabled, the app checks the cloud every few seconds for updates "
            "and uploads unsaved changes automatically. Use Sync Now for an immediate upload.",
            wraplength=420,
        )

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(fill="x", padx=20, pady=(0, 16))

        def _field_value(key):
            widget = fields[key]
            if hasattr(widget, "get_value"):
                return widget.get_value()
            return widget.get().strip()

        def save_settings():
            campaign_id = _field_value("campaign_id")
            new_cfg = {
                **dict(cfg),
                "enabled": bool(enabled_var.get()),
                "supabase_url": fields["supabase_url"].get().strip(),
                "supabase_anon_key": fields["supabase_anon_key"].get().strip(),
                "campaign_id": campaign_id,
                "character_id": fields["character_id"].get().strip(),
                "player_name": fields["player_name"].get().strip(),
                "auto_sync": bool(auto_var.get()),
                "poll_interval_sec": int(cfg.get("poll_interval_sec", 5) or 5),
                "push_interval_sec": int(cfg.get("push_interval_sec", 15) or 15),
            }
            if merge_saved_campaign_ids:
                new_cfg = merge_saved_campaign_ids(new_cfg, campaign_id)
            else:
                new_cfg["saved_campaign_ids"] = [campaign_id] if campaign_id else []
            self.cloud_sync.save_config(new_cfg)
            self._init_cloud_sync()
            self._init_loot_sync()
            self._init_homebrew_sync()
            self._init_roll_log_sync()
            self._init_campaign_chat_sync()
            self._init_image_share_sync()
            self._init_follower_statblock_sync()
            self._init_trade_sync()
            popup.destroy()

        def test_settings():
            temp_cfg = {
                "enabled": True,
                "supabase_url": fields["supabase_url"].get().strip(),
                "supabase_anon_key": fields["supabase_anon_key"].get().strip(),
                "campaign_id": _field_value("campaign_id"),
                "character_id": fields["character_id"].get().strip() or "test",
                "player_name": fields["player_name"].get().strip(),
                "auto_sync": True,
            }
            temp = CloudSyncManager(SYNC_CONFIG_FILE)
            temp.config = temp_cfg
            try:
                temp.test_connection()
                messagebox.showinfo("Cloud Sync", "Connection successful.", parent=popup)
            except Exception as exc:
                messagebox.showerror("Cloud Sync", str(exc), parent=popup)

        ctk.CTkButton(
            footer, text="Party Sheets", width=110, fg_color=getattr(self, 'secondary_button_color', THEME_TEAL), hover_color=getattr(self, 'secondary_hover_color', '#1f7f75'),
            command=lambda: (popup.destroy(), self.open_party_browser()),
        ).pack(side="left")
        ctk.CTkButton(
            footer, text="Test", width=80, fg_color="#666666", command=test_settings,
        ).pack(side="right", padx=(6, 0))
        ctk.CTkButton(
            footer, text="Save", width=90, fg_color=THEME_ORANGE, command=save_settings,
        ).pack(side="right", padx=(6, 0))
        ctk.CTkButton(
            footer, text="Sync Now", width=100, fg_color="#4a6fa5",
            command=lambda: self._cloud_push_character(),
        ).pack(side="right", padx=(6, 0))

    def _add_character_row(self, parent, row, load_callback, *, delete_callback=None):
        """Render one server character entry (used by chooser and party browser)."""
        char_id = row.get("character_id", "")
        player = row.get("player_name", "") or "Unknown"
        name = row.get("character_name", "") or char_id
        updated = str(row.get("updated_at", ""))[:19].replace("T", " ")
        item = ctk.CTkFrame(parent, fg_color="#2F2F2F")
        item.pack(fill="x", pady=4)
        ctk.CTkLabel(
            item, text=f"{player} — {name}", anchor="w",
            font=ctk.CTkFont(size=14, weight="bold"),
        ).pack(side="left", padx=12, pady=8)
        ctk.CTkLabel(
            item, text=updated, text_color="#888888",
        ).pack(side="left", padx=(0, 8))
        ctk.CTkButton(
            item, text="Load", width=70,
            command=lambda cid=char_id: load_callback(cid),
        ).pack(side="right", padx=10, pady=6)
        if delete_callback is not None:
            ctk.CTkButton(
                item, text="−", width=28, height=28,
                fg_color="#8b2e2e", hover_color="#a83a3a",
                font=ctk.CTkFont(size=18, weight="bold"),
                command=lambda r=row: delete_callback(r),
            ).pack(side="right", padx=(0, 4), pady=6)

    def open_party_browser(self):
        if not HAS_CLOUD_SYNC:
            messagebox.showerror("Cloud Sync", "cloud_sync.py is missing from the app folder.")
            return
        if not self.cloud_sync:
            self._init_cloud_sync()
        if not self.cloud_sync or not self.cloud_sync.is_configured():
            messagebox.showinfo("Cloud Sync", "Configure cloud sync first using the ☁ button.")
            return

        player_name = (self.cloud_sync.config.get("player_name") or "").strip()

        popup = ctk.CTkToplevel(self.root)
        popup.title("Campaign Party Sheets")
        popup.grab_set()
        self._center_popup_on_root(popup, 680, 620)

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=16, pady=12)
        ctk.CTkLabel(
            body,
            text="Server Characters",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(anchor="w", pady=(0, 4))

        tabview = ctk.CTkTabview(body)
        tabview.pack(fill="both", expand=True, pady=(4, 8))
        tab_all = tabview.add("All Server Characters")
        tab_mine = tabview.add("My Characters")

        scroll_all = ctk.CTkScrollableFrame(tab_all, height=380)
        scroll_all.pack(fill="both", expand=True, padx=4, pady=4)
        scroll_mine = ctk.CTkScrollableFrame(tab_mine, height=380)
        scroll_mine.pack(fill="both", expand=True, padx=4, pady=4)

        status = ctk.CTkLabel(body, text="Loading...", text_color="#aaaaaa")
        status.pack(anchor="w", pady=(2, 6))

        all_rows = []
        mine_rows = []

        def _add_rows_batched(scroll, rows, load_callback, *, delete_callback=None, batch_size=15):
            for widget in scroll.winfo_children():
                widget.destroy()
            if not rows:
                return

            def add_batch(start=0):
                end = min(start + batch_size, len(rows))
                for row in rows[start:end]:
                    self._add_character_row(
                        scroll, row, load_callback, delete_callback=delete_callback,
                    )
                try:
                    scroll.update_idletasks()
                except Exception:
                    pass
                if end < len(rows):
                    self.root.after(2, lambda: add_batch(end))

            add_batch()

        def populate(scroll, rows, empty_msg, *, delete_callback=None):
            if not rows:
                ctk.CTkLabel(scroll, text=empty_msg, text_color="#888888").pack(anchor="w", pady=10, padx=8)
                return
            _add_rows_batched(scroll, rows, load_remote, delete_callback=delete_callback)

        def delete_remote(row):
            char_id = str(row.get("character_id", "") or "").strip()
            display_name = (row.get("character_name", "") or "").strip() or char_id or "this character"
            if not char_id:
                messagebox.showerror("Delete Character", "Missing character ID.", parent=popup)
                return
            if not messagebox.askyesno(
                "Delete Character",
                f"Permanently delete '{display_name}' from the server?\n\n"
                "This cannot be undone.",
                parent=popup,
            ):
                return
            status.configure(text=f"Deleting {display_name}...", text_color="#aaaaaa")

            def worker():
                try:
                    self.cloud_sync.delete_character_by_id(char_id)
                    self._schedule_on_main(refresh_lists)
                except Exception as exc:
                    self._schedule_on_main(
                        lambda: (
                            status.configure(text=str(exc), text_color="#d9534f"),
                            messagebox.showerror("Delete Character", str(exc), parent=popup),
                        )
                    )

            threading.Thread(target=worker, daemon=True).start()

        def _finish_refresh(all_r, mine_r):
            nonlocal all_rows, mine_rows
            all_rows = all_r or []
            mine_rows = mine_r or []
            for scroll in (scroll_all, scroll_mine):
                for widget in scroll.winfo_children():
                    widget.destroy()
            populate(scroll_all, all_rows, "No characters found in this campaign yet.")
            if player_name:
                populate(
                    scroll_mine,
                    mine_rows,
                    f"No characters for player '{player_name}' yet.",
                    delete_callback=delete_remote,
                )
            else:
                populate(scroll_mine, [], "Set player_name in cloud settings to use this tab.")
            status.configure(
                text=f"{len(all_rows)} total  •  {len(mine_rows)} match your player name",
                text_color="#aaaaaa",
            )
            try:
                tabview.set("My Characters")
            except Exception:
                pass

        def refresh_lists():
            nonlocal player_name
            for scroll in (scroll_all, scroll_mine):
                for widget in scroll.winfo_children():
                    widget.destroy()
            player_name = (self.cloud_sync.config.get("player_name") or "").strip()
            status.configure(text="Loading characters from server...", text_color="#aaaaaa")

            def worker():
                try:
                    rows = self.cloud_sync.list_campaign_characters() or []
                    rows = sorted(rows, key=lambda r: str(r.get("updated_at") or ""), reverse=True)
                    mine_r = [
                        r for r in rows
                        if (r.get("player_name") or "").strip().lower() == player_name.lower()
                    ] if player_name else []
                    self._schedule_on_main(lambda: _finish_refresh(rows, mine_r))
                except Exception as exc:
                    self._schedule_on_main(lambda: status.configure(text=str(exc), text_color="#d9534f"))

            threading.Thread(target=worker, daemon=True).start()

        self._create_campaign_picker_row(
            body,
            on_change=lambda _cid: refresh_lists(),
            combo_width=520,
            pack=False,
        ).pack(fill="x", pady=(0, 8), before=tabview)

        def load_remote(character_id):
            try:
                remote = self.cloud_sync.fetch_character_by_id(character_id)
            except Exception as exc:
                messagebox.showerror("Cloud Sync", str(exc), parent=popup)
                return
            if not remote:
                messagebox.showerror("Cloud Sync", "Character not found.", parent=popup)
                return
            if self._cloud_sync_dirty and not messagebox.askyesno(
                "Load Cloud Character",
                "Replace your current sheet with the cloud copy?",
                parent=popup,
            ):
                return
            data = remote.get("data") or {}
            cid_from_row = remote.get("character_id", "") or ""
            if cid_from_row:
                data["character_id"] = cid_from_row
            self._apply_cloud_character_data(data)
            self._cloud_sync_dirty = False
            loaded_cid = remote.get("character_id", "") or ""
            loaded_player = remote.get("player_name", "") or ""
            updates = {}
            if loaded_cid:
                self.cloud_sync.config["character_id"] = loaded_cid
                updates["character_id"] = loaded_cid
            if loaded_player:
                self.cloud_sync.config["player_name"] = loaded_player
                updates["player_name"] = loaded_player
            try:
                if updates:
                    self.cloud_sync.save_config(updates)
            except Exception:
                pass
            try:
                own_remote = self.cloud_sync.fetch_character_revision()
                if own_remote:
                    self.cloud_sync.note_remote_character(own_remote)
            except Exception:
                pass
            popup.destroy()

        actions = ctk.CTkFrame(popup, fg_color="transparent")
        actions.pack(fill="x", padx=16, pady=(4, 12))
        ctk.CTkButton(
            actions, text="Refresh", width=100, fg_color="#666666", command=refresh_lists,
        ).pack(side="left")
        ctk.CTkButton(
            actions, text="Close", width=80, command=popup.destroy,
        ).pack(side="right")

        try:
            tabview.set("My Characters")
        except Exception:
            pass
        refresh_lists()

    def _show_startup_character_chooser(self):
        """Startup popup: list server characters with tabs. No more auto-load of 'latest'."""
        # Ensure cloud manager exists (but don't start polling yet, and avoid blocking test_connection
        # during startup so the chooser appears immediately).
        if HAS_CLOUD_SYNC:
            if not getattr(self, "cloud_sync", None):
                try:
                    self.cloud_sync = CloudSyncManager(
                        SYNC_CONFIG_FILE,
                        on_remote_update=self._on_cloud_remote_update,
                        on_status=self._on_cloud_status,
                    )
                    self.cloud_sync.load_config()
                    # Intentionally skip test_connection() here -- it is synchronous and can cause
                    # a long freeze on slow networks or first connection. The list fetch below will
                    # surface any connection problems.
                except Exception:
                    pass

        configured = bool(
            self.cloud_sync and self.cloud_sync.is_configured() if HAS_CLOUD_SYNC else False
        )
        player_name = ""
        if configured:
            player_name = (self.cloud_sync.config.get("player_name") or "").strip()

        popup = ctk.CTkToplevel(self.root)
        popup.title("Choose Character")
        popup.grab_set()
        self._center_popup_on_root(popup, 680, 620)  # room for tabbed lists of many characters without resize

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=16, pady=12)

        ctk.CTkLabel(
            body,
            text="Server Characters",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(anchor="w", pady=(0, 4))

        tabview = ctk.CTkTabview(body)
        tabview.pack(fill="both", expand=True, pady=(4, 8))
        tab_all = tabview.add("All Server Characters")
        tab_mine = tabview.add("My Characters")

        scroll_all = ctk.CTkScrollableFrame(tab_all, height=320)
        scroll_all.pack(fill="both", expand=True, padx=4, pady=4)

        scroll_mine = ctk.CTkScrollableFrame(tab_mine, height=320)
        scroll_mine.pack(fill="both", expand=True, padx=4, pady=4)

        try:
            tabview.set("My Characters")
        except Exception:
            pass

        status = ctk.CTkLabel(body, text="Loading...", text_color="#aaaaaa")
        status.pack(anchor="w", pady=(2, 6))

        all_rows = []
        mine_rows = []

        def _add_rows_batched(scroll, rows, do_load_callback, batch_size=15):
            """Add character rows in small batches using after() so the UI stays responsive
            even when there are many characters in the startup chooser.
            """
            for w in scroll.winfo_children():
                w.destroy()
            if not rows:
                return
            def add_batch(start=0):
                end = min(start + batch_size, len(rows))
                for r in rows[start:end]:
                    self._add_character_row(scroll, r, do_load_callback)
                try:
                    scroll.update_idletasks()
                except Exception:
                    pass
                if end < len(rows):
                    self.root.after(2, lambda: add_batch(end))
            add_batch()

        def populate(scroll, rows, empty_msg):
            if not rows:
                ctk.CTkLabel(scroll, text=empty_msg, text_color="#888888").pack(anchor="w", pady=10, padx=8)
                return
            # Use batched population to avoid long UI freeze when there are many rows
            _add_rows_batched(scroll, rows, do_load)

        def _finish_refresh(all_r, mine_r):
            nonlocal all_rows, mine_rows
            all_rows = all_r or []
            mine_rows = mine_r or []
            # clear previous
            for s in (scroll_all, scroll_mine):
                for w in s.winfo_children():
                    w.destroy()
            populate(scroll_all, all_rows, "No characters found in this campaign yet.")
            if player_name:
                populate(scroll_mine, mine_rows, f"No characters for player '{player_name}' yet.")
            else:
                populate(scroll_mine, [], "Set player_name in cloud settings to use this tab.")
            status.configure(
                text=f"{len(all_rows)} total  •  {len(mine_rows)} match your player name",
                text_color="#aaaaaa"
            )
            try:
                tabview.set("My Characters")
            except Exception:
                pass

        def refresh_lists():
            nonlocal player_name
            for s in (scroll_all, scroll_mine):
                for w in s.winfo_children():
                    w.destroy()
            if not self._is_cloud_sync_configured():
                status.configure(text="Cloud sync not configured — only local options available.", text_color="#d9534f")
                ctk.CTkLabel(scroll_all, text="Connect cloud in settings to see server characters.").pack(anchor="w", pady=10)
                ctk.CTkLabel(scroll_mine, text="Connect cloud in settings to see your characters.").pack(anchor="w", pady=10)
                return
            player_name = (self.cloud_sync.config.get("player_name") or "").strip()
            status.configure(text="Loading characters from server...", text_color="#aaaaaa")

            def worker():
                try:
                    rows = self.cloud_sync.list_campaign_characters() or []
                    rows = sorted(rows, key=lambda r: str(r.get("updated_at") or ""), reverse=True)
                    all_r = rows
                    mine_r = [
                        r for r in rows
                        if (r.get("player_name") or "").strip().lower() == player_name.lower()
                    ] if player_name else []
                    self._schedule_on_main(lambda: _finish_refresh(all_r, mine_r))
                except Exception as exc:
                    self._schedule_on_main(lambda: status.configure(text=str(exc), text_color="#d9534f"))

            threading.Thread(target=worker, daemon=True).start()

        self._create_campaign_picker_row(
            body,
            on_change=lambda _cid: refresh_lists(),
            combo_width=520,
            pack=False,
        ).pack(fill="x", pady=(0, 8), before=tabview)

        def do_load(character_id):
            try:
                remote = self.cloud_sync.fetch_character_by_id(character_id)
            except Exception as exc:
                messagebox.showerror("Cloud Sync", str(exc), parent=popup)
                return
            if not remote or not remote.get("data"):
                messagebox.showerror("Cloud Sync", "Character not found or has no data.", parent=popup)
                return
            if getattr(self, "_cloud_sync_dirty", False) and not messagebox.askyesno(
                "Load Cloud Character",
                "Replace your current sheet with the cloud copy?",
                parent=popup,
            ):
                return
            data = remote.get("data") or {}
            cid_from_row = remote.get("character_id", "") or ""
            if cid_from_row:
                data["character_id"] = cid_from_row  # ensure the loaded sheet carries the consistent cloud ID
            self._apply_cloud_character_data(data)
            self._cloud_sync_dirty = False
            # Adopt the loaded cloud entry's character_id and player_name into our config
            # so this machine now targets the correct unique slot and uses consistent player name.
            # This prevents duplicate instances of the same character on the server.
            loaded_cid = remote.get("character_id", "") or ""
            loaded_player = remote.get("player_name", "") or ""
            updates = {}
            if loaded_cid:
                self.cloud_sync.config["character_id"] = loaded_cid
                updates["character_id"] = loaded_cid
            if loaded_player:
                self.cloud_sync.config["player_name"] = loaded_player
                updates["player_name"] = loaded_player
            try:
                if updates:
                    self.cloud_sync.save_config(updates)
            except Exception:
                pass
            # Proactively note our own current (after possible config update) to avoid immediate "newer" prompt.
            try:
                own_remote = self.cloud_sync.fetch_character_revision()
                if own_remote:
                    self.cloud_sync.note_remote_character(own_remote)
            except Exception:
                pass
            self._update_window_title()
            self._finalize_startup(loaded_cloud=True)
            popup.destroy()

        def do_local_load():
            # Reuse existing loader (it handles progress, normalize, rebuild, remember path)
            if self.load_character():
                self._finalize_startup(loaded_cloud=False)
                popup.destroy()

        # Bottom action bar
        actions = ctk.CTkFrame(popup, fg_color="transparent")
        actions.pack(fill="x", padx=16, pady=(4, 12))

        btn_row = ctk.CTkFrame(actions, fg_color="transparent")
        btn_row.pack(side="left", expand=True)
        if HAS_CHAR_WIZARD:
            ctk.CTkButton(
                btn_row, text="Create Character", width=150,
                fg_color=self.primary_button_color,
                hover_color=self.primary_hover_color,
                command=lambda: self._open_character_creation_wizard(popup),
            ).pack(side="left", padx=(0, 10))
        ctk.CTkButton(
            btn_row, text="Load Local File...", width=150, fg_color="#555555",
            command=do_local_load,
        ).pack(side="left", padx=(0, 10))
        ctk.CTkButton(
            btn_row, text="Refresh", width=100, fg_color="#666666",
            command=refresh_lists,
        ).pack(side="left")

        ctk.CTkButton(
            actions, text="Close", width=90,
            command=lambda: (self._finalize_startup(loaded_cloud=False), popup.destroy()),
        ).pack(side="right")

        # Load lists on open
        refresh_lists()

        # If user closes the window with X, still start sync services
        popup.protocol("WM_DELETE_WINDOW", lambda: (self._finalize_startup(loaded_cloud=False), popup.destroy()))

    def _finalize_startup(self, *, loaded_cloud=False):
        """Start live polling and loot sync after the user has chosen (or skipped) a character."""
        if self.cloud_sync and self.cloud_sync.is_configured():
            if not loaded_cloud:
                # User closed/canceled the chooser or finished Create Character without loading a cloud
                # copy. Clear dirty and note whatever is on the server for our slot (if any) so the
                # poller doesn't immediately treat existing cloud data as newer than the local sheet.
                self._cloud_sync_dirty = False
                try:
                    remote = self.cloud_sync.fetch_character_revision()
                    if remote:
                        self.cloud_sync.note_remote_character(remote)
                    dm_remote = self.cloud_sync.fetch_dm_status()
                    if dm_remote and dm_remote.get("data"):
                        self.cloud_sync.note_dm_status(dm_remote["data"])
                except Exception:
                    pass
            # Full-character cloud polling stays off for responsiveness; DM status polls live.
            self._start_dm_status_polling(seed_from_local=loaded_cloud)
            self._update_cloud_sync_status_label("Cloud ready (DM status live)")
        # Loot sync (independent)
        try:
            self._init_loot_sync()
        except Exception:
            pass
        try:
            self._init_homebrew_sync()
        except Exception:
            pass
        try:
            self._init_roll_log_sync()
        except Exception:
            pass
        try:
            self._init_campaign_chat_sync()
        except Exception:
            pass
        try:
            self._init_image_share_sync()
        except Exception:
            pass
        try:
            self._init_follower_statblock_sync()
        except Exception:
            pass
        try:
            self._init_trade_sync()
        except Exception:
            pass

    def _save_character_to_path(self, file_path, *, notify_cloud_error=True):
        self._sync_all_character_data()
        self._normalize_feats_data()
        self._strip_portrait_base64()  # keep local JSONs lean; image lives as separate file in portraits/
        self._strip_follower_statblocks_from_data()
        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(self.data, f, indent=2, ensure_ascii=False)
        self._remember_character_path(file_path)
        self._update_window_title()
        cloud_ok = self._cloud_push_character()
        if (
            notify_cloud_error
            and self.cloud_sync
            and self.cloud_sync.is_configured()
            and not cloud_ok
        ):
            messagebox.showwarning(
                "Cloud Sync",
                "Character saved locally, but the cloud upload failed.\n"
                "Check your connection and cloud settings, then use Sync Now.",
            )
        print(f"✅ Character saved successfully to: {file_path}")

    def save_character(self):
        """Save via file dialog and remember this character for next launch."""
        try:
            self._sync_all_character_data()
            initial_name = self.data.get("name", "New_Hero").replace(" ", "_") + ".json"
            initial_file = (
                os.path.basename(self.last_character_path)
                if self.last_character_path
                else initial_name
            )
            file_path = filedialog.asksaveasfilename(
                defaultextension=".json",
                filetypes=[("JSON files", "*.json")],
                title="Save Character Sheet",
                initialdir=self._characters_dir(),
                initialfile=initial_file,
            )
            if not file_path:
                return False
            self._save_character_to_path(file_path)
            return True
        except Exception as e:
            messagebox.showerror("Save Error", f"Could not save character:\n{e}")
            return False

    def _pump_ui(self):
        """Force pending window/progress updates to paint before heavy work."""
        try:
            if hasattr(self, "_load_overlay") and self._load_overlay:
                self._load_overlay.update_idletasks()
                self._load_overlay.update()
        except Exception:
            pass
        try:
            if hasattr(self, "_save_overlay") and self._save_overlay:
                self._save_overlay.update_idletasks()
                self._save_overlay.update()
        except Exception:
            pass
        try:
            self.root.update_idletasks()
            self.root.update()
        except Exception:
            pass

    def _show_load_progress(self):
        self._hide_load_progress()

        overlay = ctk.CTkToplevel(self.root)
        overlay.title("Loading Character")
        overlay.resizable(False, False)
        overlay.configure(fg_color=THEME_DARK_BG)
        overlay.transient(self.root)
        overlay.attributes("-topmost", True)
        overlay.grab_set()

        frame = ctk.CTkFrame(overlay, fg_color=THEME_DARK_BG)
        frame.pack(fill="both", expand=True, padx=24, pady=20)

        ctk.CTkLabel(
            frame,
            text="Loading Character",
            font=ctk.CTkFont(size=18, weight="bold"),
            text_color=THEME_ORANGE,
        ).pack(pady=(0, 10))

        self._load_status_label = ctk.CTkLabel(
            frame,
            text="Starting...",
            font=ctk.CTkFont(size=13),
            text_color="#cccccc",
        )
        self._load_status_label.pack(pady=(0, 12))

        self._load_progress = ctk.CTkProgressBar(
            frame,
            width=360,
            height=18,
            progress_color=THEME_ORANGE,
            fg_color=THEME_DARK_TRACK,
            corner_radius=8,
        )
        self._load_progress.pack(pady=(0, 4))
        self._load_progress.set(0)

        overlay.update_idletasks()
        width, height = 420, 150
        root_x = self.root.winfo_rootx()
        root_y = self.root.winfo_rooty()
        root_w = self.root.winfo_width()
        root_h = self.root.winfo_height()
        pos_x = root_x + max(0, (root_w - width) // 2)
        pos_y = root_y + max(0, (root_h - height) // 2)
        overlay.geometry(f"{width}x{height}+{pos_x}+{pos_y}")

        self._load_overlay = overlay
        self._pump_ui()

    def _update_load_progress(self, value, message=None):
        if not hasattr(self, "_load_progress") or self._load_progress is None:
            return
        self._load_progress.set(min(1.0, max(0.0, value)))
        if message and hasattr(self, "_load_status_label") and self._load_status_label:
            self._load_status_label.configure(text=message)
        self._pump_ui()

    def _hide_load_progress(self):
        if hasattr(self, "_load_overlay") and self._load_overlay:
            try:
                self._load_overlay.attributes("-topmost", False)
                self._load_overlay.grab_release()
            except Exception:
                pass
            self._load_overlay.destroy()
        self._load_overlay = None
        self._load_progress = None
        self._load_status_label = None

    def _reset_page_cache_state(self):
        """Clear per-page build keys after a full UI teardown."""
        self._inventory_built_for_key = None
        self._buffs_built_for_key = None
        self._spells_per_day_built_for_key = None
        self._description_built_for_key = None
        self._feats_built_for_key = None
        self._spells_built_for_key = None
        self._combat_built_for_key = None
        self._combat_summaries_built_for_key = None
        self._domain_preview_built_for_key = None
        self._stats_layout_built_for_key = None
        self._dirty = set()

    def _clear_destroyed_page_widget_refs(self):
        """Drop stale widget references before page frames are destroyed."""
        self.general_feat_combos = []
        self._general_feat_combo_indices = []
        self.bonus_feat_combos = {}
        self.special_ability_combos = {}
        self.asi_combos = {}
        self.extra_ring_combos = []
        self.skill_specialty_combos = {}
        self.domain_combos = []
        self.affliction_vars = {}
        self.daily_use_vars = {}
        self.magic_item_daily_vars = {}
        self.magic_item_charge_combos = {}
        self.rage_switch_widgets = {}
        self.special_feature_form_widgets = {}
        self.movement_mode_widgets = {}
        self.stats_movement_mode_widgets = {}
        for attr in (
            "combat_spell_panel",
            "combat_resist_panel",
            "combat_ac_panel",
            "combat_melee_touch_label",
            "combat_ranged_touch_label",
            "combat_ac_label",
        ):
            setattr(self, attr, None)

    def _destroy_content_pages(self):
        """Remove old page frames so rebuilds do not stack duplicate widgets."""
        self._ui_generation = int(getattr(self, "_ui_generation", 0) or 0) + 1
        self._close_skills_popout()
        self._cancel_pending_ui_work()
        try:
            if self._widget_is_alive(getattr(self, "feats_frame", None)):
                self._sync_feats_widgets_to_data()
        except Exception:
            pass
        self._clear_destroyed_page_widget_refs()
        self._reset_page_cache_state()
        for attr in (
            "stats_frame", "inv_frame", "combat_frame", "spells_frame",
            "buffs_frame", "feats_frame", "description_frame",
        ):
            frame = getattr(self, attr, None)
            if frame is not None:
                try:
                    if frame.winfo_exists():
                        frame.destroy()
                except tk.TclError:
                    pass
                except Exception:
                    pass
                setattr(self, attr, None)
        if hasattr(self, "content"):
            for child in list(self.content.winfo_children()):
                try:
                    if child.winfo_exists():
                        child.destroy()
                except tk.TclError:
                    pass
                except Exception:
                    pass
        self.inventory_row_widgets = []
        for attr in (
            "class_combos", "level_entries", "class_vars", "level_vars",
            "class_name_labels", "class_level_labels", "class_display_frame",
            "class_lock_buttons",
        ):
            setattr(self, attr, [])

    def _rebuild_character_ui(self, show_progress=False, remember_path=None):
        """Rebuild all pages from self.data and refresh the sheet."""
        if show_progress and not getattr(self, "_load_overlay", None):
            self._show_load_progress()
        self._rebuilding_ui = True
        try:
            if show_progress:
                self._update_load_progress(0.16, "Preparing character data...")
            self._normalize_character_data()
            self._last_known_max_hp = None
            self._ability_bonuses_applied = False
            self._destroy_content_pages()
            self._mark_feats_page_stale()
            self._mark_spells_page_stale()
            self._mark_combat_page_stale()
            self.invalidate_caches()
            self.widget_registry = {}

            if show_progress:
                self._update_load_progress(0.28, "Building Stats page...")
            self.build_stats_page()
            self._apply_stats_page_layout(force=True)

            self._migrate_prepared_spells()
            self._migrate_known_spells()
            self._migrate_skill_rank_costs()
            self._migrate_human_bonus_feat()
            self._migrate_custom_magic_item_grants()
            self._sync_magic_item_prepared_spells()
            self._sync_spell_like_prepared_spells()
            self._sync_warlock_invocation_prepared_spells()

            if show_progress:
                self._update_load_progress(0.42, "Building Inventory page...")
            self.build_inventory_page()

            if show_progress:
                self._update_load_progress(0.54, "Building Combat page...")
            self.build_combat_page()

            if show_progress:
                self._update_load_progress(0.66, "Building Spells page...")
            self.build_spells_page()

            if show_progress:
                self._update_load_progress(0.72, "Building Buffs page...")
            self.build_buffs_page()

            if show_progress:
                self._update_load_progress(0.78, "Building Feats & Features page...")
            self.build_feats_page()

            if show_progress:
                self._update_load_progress(0.84, "Building Description page...")
            self.build_description_page()

            if show_progress:
                self._update_load_progress(0.86, "Restoring saved values...")
            for data_key, widget in list(self.widget_registry.items()):
                if self._is_legacy_coin_widget_key(data_key):
                    continue
                value = self._get_widget_saved_value(data_key)
                if value is None:
                    continue
                try:
                    if isinstance(widget, ctk.StringVar):
                        widget.set(str(value))
                    elif hasattr(widget, "set"):
                        widget.set(str(value))
                except Exception as e:
                    print(f"   → Could not restore {data_key}: {e}")

            self._push_feats_data_to_widgets()
            self._apply_coins_to_ui()

            if show_progress:
                self._update_load_progress(0.94, "Refreshing character sheet...")
            self.refresh_inventory(sync_first=False)
            self.refresh_spells_page()
            if self._feats_page_is_stale():
                self.refresh_feats_page()
            elif hasattr(self, "tabview"):
                try:
                    self.refresh_feats_scope("magical_items")
                except Exception:
                    pass
            self._rebuild_feat_cache()
            self.refresh_combat_page()
            self._mark_combat_page_built()
            self.refresh_health_display()
            self._mount_all_content_pages_placed()
            self._mark_all_content_pages_built()
            current_page = getattr(self, "_current_page", "Stats") or "Stats"
            if current_page == "Stats":
                self._apply_stats_page_layout(force=True)
            self._show_page_frame(current_page)
            if current_page == "Combat":
                self.root.after_idle(self._apply_responsive_layout)
            elif current_page == "Description":
                self._ensure_portrait_panel_sized()
            elif current_page == "Feats & Features" and hasattr(self, "update_domain_preview"):
                self.root.after_idle(self.update_domain_preview)

            if remember_path:
                self._remember_character_path(remember_path)
            self._update_window_title()

            if show_progress:
                self._update_load_progress(1.0, "Done!")
                self.root.after(250, self._hide_load_progress)

            print("✅ Character sheet rebuilt successfully")
            return True
        except Exception as e:
            if show_progress:
                self._hide_load_progress()
            messagebox.showerror("Character Error", f"Could not rebuild character sheet:\n{e}")
            return False
        finally:
            if self.refresh_timer is not None:
                try:
                    self.root.after_cancel(self.refresh_timer)
                except tk.TclError:
                    pass
                self.refresh_timer = None
            def _post_load_refresh():
                try:
                    self._push_feats_data_to_widgets()
                    self._rebuild_feat_cache()
                    # End rebuild before derived-stat refresh so final max HP
                    # (e.g. Amulet of Health Con) is known for damage-pool reconciliation.
                    self._rebuilding_ui = False
                    self._perform_refresh(force=True)
                    self._push_feats_data_to_widgets()
                    self._refresh_wielded_weapons_feat_sliders()
                    try:
                        self._mark_all_content_pages_built()
                    except Exception:
                        pass
                finally:
                    self._rebuilding_ui = False
                self._apply_stats_page_layout(force=True)
                self.refresh_health_display()
                self.refresh_xp_display()
                self.refresh_level_up_button()
                self._schedule_post_load_cloud_sync()
                self._cloud_sync_applying_remote = False
                self._skip_post_load_cloud_push = False

            self.root.after_idle(_post_load_refresh)

    def _load_character_from_path(self, file_path, show_progress=False):
        """Load character safely - clears old widget references before rebuilding pages."""
        self._cancel_pending_refresh()
        if show_progress:
            self._show_load_progress()
            self._update_load_progress(0.04, "Preparing to load...")
        try:
            if show_progress:
                self._update_load_progress(0.08, "Reading character file...")
            with open(file_path, "r", encoding="utf-8") as f:
                self.data = json.load(f)
            self._followers_server_cache = {}
            self._invalidate_followers_server_cache()
            self._strip_follower_statblocks_from_data()
            self._normalize_character_data()
            self._ensure_cleric_domain_spells_in_known()

            # Restore saved theme for this character
            theme_name = self.data.get("theme", "Dicey Default")
            if theme_name in getattr(self, "THEMES", {}):
                self.current_theme = theme_name
                self.primary_button_color = self.THEMES[theme_name]["nav"]
                self.primary_hover_color = self.THEMES[theme_name]["hover_nav"]
                self.secondary_button_color = self.THEMES[theme_name].get("reload", self.THEMES[theme_name].get("secondary", "#28a99e"))
                self.secondary_hover_color = self.THEMES[theme_name].get("hover_reload", self.THEMES[theme_name].get("hover_secondary", "#1f7f75"))
                self._apply_theme(theme_name)
            if hasattr(self, "hamburger_sb_var"):
                try:
                    self.hamburger_sb_var.set(bool(self.data.get("sb_portrait", False)))
                except Exception:
                    pass

            # Extract portrait if this data (e.g. previously synced from cloud) carried base64 image
            self._extract_and_save_cloud_portrait()
            self._refresh_sidebar_background()

            print(f"✅ Loaded: {file_path}")
            if show_progress:
                self._pump_ui()
            if not self._rebuild_character_ui(show_progress=show_progress, remember_path=file_path):
                return False
            print("✅ Character loaded successfully with magical item bonuses applied")
            # If the loaded local sheet has a character_id (from previous cloud use or auto-gen),
            # adopt it into the current cloud config so we sync against the correct unique slot.
            if hasattr(self, "cloud_sync") and self.cloud_sync and self.cloud_sync.is_configured():
                cid = self.data.get("character_id", "")
                if cid:
                    self.cloud_sync.config["character_id"] = cid
                    try:
                        self.cloud_sync.save_config({"character_id": cid})
                    except Exception:
                        pass
                self._start_dm_status_polling()
            return True

        except json.JSONDecodeError as e:
            if show_progress:
                self._hide_load_progress()
            messagebox.showerror(
                "Load Error",
                f"Corrupted JSON file!\n\n"
                f"Line {e.lineno}, Column {e.colno}\n"
                f"Message: {e.msg}\n\n"
                "Try creating a new character and saving it again.",
            )
            return False
        except Exception as e:
            if show_progress:
                self._hide_load_progress()
            messagebox.showerror("Load Error", f"Could not load character:\n{e}")
            return False

    def _reload_application(self):
        """Restart the app process so every page and cache starts fresh."""
        self.last_character_path = None
        if self.refresh_timer is not None:
            try:
                self.root.after_cancel(self.refresh_timer)
            except Exception:
                pass
            self.refresh_timer = None
        launch_args = [sys.executable]
        if not getattr(sys, "frozen", False):
            launch_args.extend(sys.argv[1:])
        os.execv(sys.executable, launch_args)

    def new_character(self):
        """Restart the application with a blank default character."""
        save_choice = messagebox.askyesnocancel(
            "New Character",
            "Save your current character before starting a fresh sheet?",
        )
        if save_choice is None:
            return False
        if save_choice and not self.save_character():
            return False

        if not messagebox.askyesno(
            "New Character",
            "Restart now with a blank character sheet?\n\n"
            "The application will reload.",
        ):
            return False

        try:
            if os.path.isfile(LAST_CHARACTER_FILE):
                os.remove(LAST_CHARACTER_FILE)
        except OSError:
            pass

        self._reload_application()
        return True

    def load_character(self):
        """Load character via file dialog."""
        file_path = filedialog.askopenfilename(
            filetypes=[("JSON files", "*.json"), ("All files", "*.*")],
            title="Load Character Sheet",
            initialdir=self._characters_dir(),
        )
        if not file_path:
            return False
        return self._load_character_from_path(file_path, show_progress=True)
    
    def _build_afflictions_panel(self, parent):
        afflictions_frame = ctk.CTkFrame(parent, fg_color="transparent")
        afflictions_frame.pack(fill="x", pady=(16, 0))

        ctk.CTkLabel(
            afflictions_frame,
            text="Afflictions & Conditions",
            font=ctk.CTkFont(size=15, weight="bold"),
        ).pack(anchor="w", pady=(0, 6))
        ctk.CTkLabel(
            afflictions_frame,
            text="Check active conditions to apply 3.5 penalties across the sheet.",
            font=ctk.CTkFont(size=12),
            text_color="#888888",
        ).pack(anchor="w", pady=(0, 8))

        columns_row = ctk.CTkFrame(afflictions_frame, fg_color="transparent")
        columns_row.pack(fill="x")
        columns = []
        for _ in range(3):
            col = ctk.CTkFrame(columns_row, fg_color="transparent")
            col.pack(side="left", fill="both", expand=True, padx=(0, 6))
            columns.append(col)

        saved = self.data.get("afflictions", {})
        per_column = (len(AFFLICTION_ORDER) + 2) // 3
        for index, key in enumerate(AFFLICTION_ORDER):
            col = columns[index // per_column]
            row = ctk.CTkFrame(col, fg_color="transparent")
            row.pack(fill="x", pady=2)

            var = BooleanVar(value=bool(saved.get(key, False)))
            cb = ctk.CTkCheckBox(
                row,
                text=key,
                variable=var,
                width=150,
                command=lambda k=key, v=var: self._toggle_affliction(k, v),
            )
            cb.pack(side="left", anchor="w")
            info_btn = ctk.CTkButton(
                row, text="ℹ", width=26, height=24, fg_color="#666666",
                command=lambda k=key: self.show_affliction_details(k),
            )
            info_btn.pack(side="left", padx=(4, 0))
            self.affliction_vars[key] = var

            tooltip_text = self._get_affliction_tooltip_text(key)
            for widget in (row, cb, info_btn):
                self._bind_hover_tooltip(widget, tooltip_text, wraplength=340)

    def show_affliction_details(self, affliction_name):
        info = AFFLICTION_DEFINITIONS.get(affliction_name)
        if not info:
            messagebox.showinfo("Affliction", "Condition not found.")
            return

        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Condition: {affliction_name}")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=580, min_height=440)

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=24, pady=(8, 20))
        ctk.CTkButton(
            footer, text="Close", width=120, height=36,
            fg_color=getattr(self, 'primary_button_color', '#c77626'), command=popup.destroy,
        ).pack(anchor="e")

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=24, pady=(16, 8))

        ctk.CTkLabel(
            body, text=affliction_name,
            font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        desc_frame = ctk.CTkScrollableFrame(body, height=280)
        desc_frame.pack(fill="both", expand=True)
        ctk.CTkLabel(
            desc_frame,
            text=info.get("description", "No description available."),
            wraplength=480,
            justify="left",
        ).pack(anchor="w", pady=5, padx=4)

        effects = info.get("effects", {})
        effect_summary = self._format_affliction_effects_summary(effects)
        if effect_summary:
            ctk.CTkLabel(
                body,
                text="Applied on sheet: " + effect_summary,
                font=ctk.CTkFont(size=12),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                wraplength=480,
                justify="left",
            ).pack(anchor="w", pady=(8, 0))

    def _build_negative_levels_ui(self, parent):
        """+- box for negative levels (affects HP max/current, attacks, saves, skills)."""
        frame = ctk.CTkFrame(parent, fg_color="transparent")
        frame.pack(fill="x", pady=(8, 0))
        ctk.CTkLabel(frame, text="Negative Levels", font=ctk.CTkFont(size=14, weight="bold")).pack(anchor="w")
        row = ctk.CTkFrame(frame, fg_color="transparent")
        row.pack(fill="x", pady=2)
        self.neg_levels_var = ctk.IntVar(value=self.data.get("negative_levels", 0))
        lbl = ctk.CTkLabel(row, textvariable=self.neg_levels_var, width=40, font=ctk.CTkFont(weight="bold"))
        lbl.pack(side="left")
        def adjust(delta):
            old = self.neg_levels_var.get()
            new = max(0, old + delta)
            self.neg_levels_var.set(new)
            self.data["negative_levels"] = new
            if delta > 0:
                self._apply_lethal_damage(5 * delta)
            self._affliction_penalties_cache = None
            self.refresh_all()
            self._mark_cloud_sync_dirty()
        ctk.CTkButton(row, text="-", width=24, height=22, command=lambda: adjust(-1)).pack(side="left", padx=1)
        ctk.CTkButton(row, text="+", width=24, height=22, command=lambda: adjust(+1)).pack(side="left", padx=1)
        ctk.CTkLabel(row, text=" (-5 max HP, -5 cur HP min1, -1 atk/saves/skills)", font=ctk.CTkFont(size=9), text_color="#888888").pack(side="left", padx=4)

    def _build_ability_damage_ui(self, parent):
        """Mini window: dropdown + value + apply; stores penalty to abilities."""
        frame = ctk.CTkFrame(parent, fg_color="transparent")
        frame.pack(fill="x", pady=(10, 0))
        ctk.CTkLabel(frame, text="Ability Damage", font=ctk.CTkFont(size=14, weight="bold")).pack(anchor="w")
        ctk.CTkLabel(frame, text="Reduces effective ability score (affects mods).", font=ctk.CTkFont(size=10), text_color="#888888").pack(anchor="w")
        row = ctk.CTkFrame(frame, fg_color="transparent")
        row.pack(fill="x", pady=2)
        abilities = ["Strength", "Dexterity", "Constitution", "Intelligence", "Wisdom", "Charisma"]
        self.abil_dmg_var = ctk.StringVar(value="Strength")
        combo = ctk.CTkComboBox(row, values=abilities, variable=self.abil_dmg_var, width=110)
        combo.pack(side="left")
        self.abil_dmg_val = ctk.IntVar(value=1)
        entry = ctk.CTkEntry(row, textvariable=self.abil_dmg_val, width=50)
        entry.pack(side="left", padx=4)
        ctk.CTkButton(row, text="Apply", width=50, fg_color=getattr(self, 'primary_button_color', '#c77626'),
                      command=self._apply_ability_damage).pack(side="left", padx=2)
        ctk.CTkButton(row, text="Clear", width=50, fg_color="#666666",
                      command=self._clear_ability_damage).pack(side="left", padx=2)
        self.abil_dmg_display = ctk.CTkLabel(frame, text="", font=ctk.CTkFont(size=10))
        self.abil_dmg_display.pack(anchor="w", pady=2)
        self._update_ability_damage_display()

    def _apply_ability_damage(self):
        ab = self.abil_dmg_var.get()
        val = self.abil_dmg_val.get() or 0
        dmg = self.data.setdefault("ability_damage", {})
        dmg[ab] = max(0, dmg.get(ab, 0) + val)
        self._update_ability_damage_display()
        self._affliction_penalties_cache = None
        self.refresh_all()
        self._mark_cloud_sync_dirty()
        self._update_ability_name_styles()

    def _clear_ability_damage(self):
        ab = self.abil_dmg_var.get()
        dmg = self.data.setdefault("ability_damage", {})
        dmg[ab] = 0
        self._update_ability_damage_display()
        self._affliction_penalties_cache = None
        self.refresh_all()
        self._mark_cloud_sync_dirty()
        self._update_ability_name_styles()

    def _update_ability_damage_display(self):
        if not hasattr(self, "abil_dmg_display"): return
        dmg = self.data.get("ability_damage", {})
        parts = []
        for ab in ["Strength", "Dexterity", "Constitution", "Intelligence", "Wisdom", "Charisma"]:
            if dmg.get(ab, 0) > 0:
                parts.append(f"{ab[:3]}:{dmg[ab]}")
        text = " | ".join(parts) if parts else "None"
        self.abil_dmg_display.configure(text=f"Current: {text}")

    def build_buffs_page(self):
        """Buffs page: left = add form + current manual effects list (toggle/value/remove); right = reference of active buffs + active spell effects."""
        if not hasattr(self, "buffs_frame") or self.buffs_frame is None:
            self.buffs_frame = ctk.CTkFrame(self.content)
        self.buffs_frame.pack_propagate(True)

        for widget in self.buffs_frame.winfo_children():
            try:
                widget.destroy()
            except Exception:
                pass

        # Header
        top_bar = ctk.CTkFrame(self.buffs_frame)
        top_bar.pack(fill="x", padx=15, pady=10)
        ctk.CTkLabel(
            top_bar, text="Buffs & Magical Effects",
            font=ctk.CTkFont(size=24, weight="bold")
        ).pack(side="left", padx=10)
        ctk.CTkLabel(
            top_bar, text="— quick effects that factor into stats (like spell effects)",
            font=ctk.CTkFont(size=12), text_color="#aaaaaa"
        ).pack(side="left", padx=6)

        # Main two-column
        main_content = ctk.CTkFrame(self.buffs_frame)
        main_content.pack(fill="both", expand=True, padx=15, pady=5)
        main_content.columnconfigure(0, weight=1, uniform="buffs")
        main_content.columnconfigure(1, weight=1, uniform="buffs")
        main_content.rowconfigure(0, weight=1)

        # LEFT: form + list
        left = ctk.CTkFrame(main_content)
        left.grid(row=0, column=0, sticky="nsew", padx=(0, 8), pady=5)
        left.columnconfigure(0, weight=1)
        left.rowconfigure(5, weight=1)

        ctk.CTkLabel(left, text="Add New Buff", font=ctk.CTkFont(size=16, weight="bold")).grid(
            row=0, column=0, sticky="w", padx=8, pady=(4, 6)
        )

        form = ctk.CTkFrame(left, fg_color="transparent")
        form.grid(row=1, column=0, sticky="ew", padx=8, pady=2)

        ctk.CTkLabel(form, text="Name:").pack(side="left", padx=3)
        self.buff_name_var = ctk.StringVar()
        ctk.CTkEntry(form, textvariable=self.buff_name_var, width=150, placeholder_text="e.g. Potion of Bull's Str").pack(side="left", padx=3)

        ctk.CTkLabel(form, text="Type:").pack(side="left", padx=(8, 3))
        dd_vals = self._get_buffs_dropdown_values()
        self.buff_type_combo = ctk.CTkComboBox(form, values=dd_vals, width=170)
        self.buff_type_combo.pack(side="left", padx=3)
        if dd_vals:
            try:
                self.buff_type_combo.set(dd_vals[0])
            except Exception:
                pass

        ctk.CTkLabel(form, text="Bonus Type:").pack(side="left", padx=(8, 3))
        self.buff_bonus_type_combo = ctk.CTkComboBox(form, values=list(BONUS_TYPES), width=105)
        self.buff_bonus_type_combo.pack(side="left", padx=3)
        try:
            self.buff_bonus_type_combo.set("Enhancement")
        except Exception:
            pass

        ctk.CTkLabel(form, text="Value:").pack(side="left", padx=(8, 3))
        self.buff_value_var = ctk.StringVar(value="1")
        ctk.CTkEntry(form, textvariable=self.buff_value_var, width=55).pack(side="left", padx=3)

        ctk.CTkButton(
            form, text="Add", width=55, height=30,
            fg_color=getattr(self, "primary_button_color", "#c77626"),
            command=self._add_buff_from_form
        ).pack(side="left", padx=8)

        ctk.CTkLabel(left, text="Add Spell Buff", font=ctk.CTkFont(size=14, weight="bold")).grid(
            row=2, column=0, sticky="w", padx=8, pady=(8, 2)
        )

        spell_form = ctk.CTkFrame(left, fg_color="transparent")
        spell_form.grid(row=3, column=0, sticky="ew", padx=8, pady=2)

        self.buff_spell_var = ctk.StringVar()
        self.buff_spell_combo = ctk.CTkComboBox(
            spell_form, variable=self.buff_spell_var, values=[], width=220
        )
        self.buff_spell_combo.pack(side="left", padx=3)
        self.buff_spell_combo.bind("<KeyRelease>", self._update_buff_spell_options)
        self.buff_spell_combo.bind("<<ComboboxSelected>>", self._on_buff_spell_cl_selected)

        ctk.CTkLabel(spell_form, text="CL:").pack(side="left", padx=(8, 2))
        self.buff_spell_cl = ctk.CTkEntry(spell_form, placeholder_text="CL", width=50)
        self.buff_spell_cl.pack(side="left", padx=3)

        ctk.CTkButton(
            spell_form, text="Add Spell", width=90, height=30,
            fg_color=getattr(self, "primary_button_color", "#c77626"),
            command=self._add_spell_buff_from_form
        ).pack(side="left", padx=8)

        ctk.CTkLabel(
            left, text="Current Effects (toggle active, adjust value, remove)",
            font=ctk.CTkFont(size=14, weight="bold")
        ).grid(row=4, column=0, sticky="w", padx=8, pady=(10, 4))

        self.buffs_list_scroll = ctk.CTkScrollableFrame(left, height=360)
        self.buffs_list_scroll.grid(row=5, column=0, sticky="nsew", padx=6, pady=2)

        # RIGHT: reference (read-only combined view)
        right = ctk.CTkFrame(main_content)
        right.grid(row=0, column=1, sticky="nsew", padx=(8, 0), pady=5)
        right.columnconfigure(0, weight=1)
        right.rowconfigure(1, weight=1)

        ctk.CTkLabel(
            right, text="Active Effects Reference",
            font=ctk.CTkFont(size=14, weight="bold")
        ).grid(row=0, column=0, sticky="w", padx=8, pady=(4, 4))

        self.buffs_ref_scroll = ctk.CTkScrollableFrame(right, height=400)
        self.buffs_ref_scroll.grid(row=1, column=0, sticky="nsew", padx=6, pady=2)

        # initial population
        self._rebuild_buffs_list()
        self._rebuild_buffs_reference()
        self._mark_buffs_page_built()

    def _add_buff_from_form(self):
        name = (getattr(self, "buff_name_var", None).get() or "").strip() or "Unnamed Buff"
        etype = ""
        if hasattr(self, "buff_type_combo"):
            etype = self.buff_type_combo.get() or ""
        bt = "Enhancement"
        if hasattr(self, "buff_bonus_type_combo"):
            bt = self.buff_bonus_type_combo.get() or "Enhancement"
        try:
            val = int(getattr(self, "buff_value_var", None).get() or "0")
        except Exception:
            val = 0
        if not etype or val == 0:
            try:
                messagebox.showwarning("Buffs", "Pick an effect Type and a non-zero Value (positive for bonus, negative for penalty).")
            except Exception:
                pass
            return
        buffs = self.data.setdefault("buffs", [])
        import uuid as _uuid
        bid = str(_uuid.uuid4())[:8]
        buffs.append({
            "id": bid,
            "name": name,
            "effect_type": etype,
            "bonus_type": bt,
            "value": val,
            "active": True,
        })
        # reset form (keep last type and bonus type)
        if hasattr(self, "buff_name_var"):
            self.buff_name_var.set("")
        if hasattr(self, "buff_value_var"):
            self.buff_value_var.set("1")
        self._schedule_scoped_refresh(skills=True, combat=True)
        self._rebuild_buffs_list()
        self._rebuild_buffs_reference()
        try:
            self._mark_cloud_sync_dirty()
        except Exception:
            pass

    def _add_spell_buff_from_form(self):
        raw_input = (getattr(self, "buff_spell_var", None).get() or "").strip()
        spell = raw_input
        if spell not in self.spells_db:
            try:
                messagebox.showwarning("Buffs", "Select a valid spell from the list.")
            except Exception:
                pass
            return
        spell_info = self.spells_db.get(spell) or {}
        if not spell_info.get("effects"):
            try:
                messagebox.showwarning(
                    "Buffs",
                    f"'{spell}' has no automated effects in the spell database.",
                )
            except Exception:
                pass
            return
        cl_str = ""
        if hasattr(self, "buff_spell_cl"):
            cl_str = self.buff_spell_cl.get().strip()
        try:
            cl = int(cl_str) if cl_str else 0
        except (TypeError, ValueError):
            cl = 0
        if cl <= 0:
            cl = self._parse_caster_level_from_text(raw_input)
        if cl <= 0:
            cl = self._get_effective_cl_for_spell(spell)
        display_name = spell
        if cl and not re.search(r'\bCL\s*\d+', display_name, re.I):
            display_name = f"{spell} CL{cl}"
        import uuid as _uuid
        bid = str(_uuid.uuid4())[:8]
        self.data.setdefault("buffs", []).append({
            "id": bid,
            "source": "spell",
            "spell_name": spell,
            "cl": cl,
            "name": display_name,
            "active": True,
        })
        if hasattr(self, "buff_spell_var"):
            self.buff_spell_var.set("")
        if hasattr(self, "buff_spell_combo"):
            self.buff_spell_combo.configure(values=[])
        if hasattr(self, "buff_spell_cl"):
            self.buff_spell_cl.delete(0, "end")
        self._schedule_scoped_refresh(skills=True, combat=True)
        self._rebuild_buffs_list()
        self._rebuild_buffs_reference()
        try:
            self._mark_cloud_sync_dirty()
        except Exception:
            pass

    def _update_buff_spell_options(self, event=None):
        current = getattr(self, "buff_spell_var", ctk.StringVar()).get()
        text = current.strip().lower()
        if len(text) < 3:
            if hasattr(self, "buff_spell_combo"):
                self.buff_spell_combo.configure(values=[])
            return
        matches = [s for s in sorted(self.spells_db.keys()) if text in s.lower()][:25]
        if hasattr(self, "buff_spell_combo"):
            self.buff_spell_combo.configure(values=matches)
            self.buff_spell_combo.set(current)

    def _on_buff_spell_cl_selected(self, event=None):
        spell = (getattr(self, "buff_spell_var", None).get() or "").strip()
        if spell and hasattr(self, "buff_spell_cl"):
            try:
                cl = self._get_effective_cl_for_spell(spell)
                self.buff_spell_cl.delete(0, "end")
                self.buff_spell_cl.insert(0, str(cl))
            except Exception:
                pass

    def _format_spell_buff_summary(self, buff):
        spell_name = str(buff.get("spell_name") or "").strip()
        if not spell_name:
            return "[spell]"
        try:
            cl = int(buff.get("cl") or 0)
        except (TypeError, ValueError):
            cl = 0
        if cl <= 0:
            cl = self._parse_caster_level_from_text(buff.get("name", ""))
        if cl <= 0:
            cl = self._get_effective_cl_for_spell(spell_name)
        spell = self.spells_db.get(spell_name) or {}
        raw_effects = spell.get("effects") or {}
        if not raw_effects:
            return "[spell|no effects]"
        resolved = self._resolve_spell_effects_for_caster_level(dict(raw_effects), spell_name, cl=cl)
        norm = self._normalize_spell_effects(resolved)
        parts = []
        for key, val in list(norm.items())[:4]:
            if key in ("ability_enh", "ability_inherent") and isinstance(val, dict):
                for ab, av in val.items():
                    parts.append(f"{ab[:3]}{int(av):+d}")
            elif isinstance(val, (int, float)):
                parts.append(f"{int(val):+d}")
            elif isinstance(val, str):
                parts.append(val[:12])
        return "[spell|" + (", ".join(parts) if parts else "active") + "]"

    def _rebuild_buffs_list(self):
        if not hasattr(self, "buffs_list_scroll"):
            return
        for w in self.buffs_list_scroll.winfo_children():
            try:
                w.destroy()
            except Exception:
                pass
        buffs = self.data.setdefault("buffs", [])
        if not buffs:
            ctk.CTkLabel(self.buffs_list_scroll, text="(no buffs added yet — use form above)", text_color="#888888").pack(pady=12)
            self._mark_buffs_page_built()
            return
        for idx, b in enumerate(buffs):
            row = ctk.CTkFrame(self.buffs_list_scroll)
            row.pack(fill="x", padx=2, pady=1)

            active = bool(b.get("active", True))
            var = ctk.BooleanVar(value=active)

            def _mk_toggle(i=idx, v=var):
                def _t():
                    self.data.setdefault("buffs", [])[i]["active"] = bool(v.get())
                    self._schedule_scoped_refresh(skills=True, combat=True)
                    self._rebuild_buffs_reference()
                    try:
                        self._mark_cloud_sync_dirty()
                    except Exception:
                        pass
                return _t

            cb = ctk.CTkCheckBox(row, text="", variable=var, command=_mk_toggle(), width=18)
            cb.pack(side="left", padx=(4, 2))

            nm = str(b.get("name", ""))[:28]
            if b.get("source") == "spell":
                detail = self._format_spell_buff_summary(b)
                ctk.CTkLabel(row, text=f"{nm} {detail}", anchor="w", width=300).pack(side="left", padx=3)
            else:
                et = str(b.get("effect_type", ""))[:20]
                bt = str(b.get("bonus_type") or "Enhancement")[:12]
                ctk.CTkLabel(row, text=f"{nm} [{et}|{bt}]", anchor="w", width=230).pack(side="left", padx=3)

                val = int(b.get("value", 0) or 0)
                ctk.CTkLabel(row, text=f"{val:+d}" if val else "0", width=42, anchor="e").pack(side="left", padx=2)

                def _mk_adj(i=idx, d=0):
                    def _a():
                        bl = self.data.setdefault("buffs", [])
                        bl[i]["value"] = int(bl[i].get("value", 0) or 0) + d
                        self._schedule_scoped_refresh(skills=True, combat=True)
                        self._rebuild_buffs_list()
                        self._rebuild_buffs_reference()
                        try:
                            self._mark_cloud_sync_dirty()
                        except Exception:
                            pass
                    return _a

                ctk.CTkButton(row, text="–", width=22, height=20, command=_mk_adj(d=-1)).pack(side="left", padx=1)
                ctk.CTkButton(row, text="+", width=22, height=20, command=_mk_adj(d=+1)).pack(side="left", padx=1)

            def _mk_rem(i=idx):
                def _r():
                    bl = self.data.setdefault("buffs", [])
                    try:
                        nm = bl[i].get("name", "buff")
                        if messagebox.askyesno("Remove Buff", f"Remove '{nm}'?"):
                            del bl[i]
                            self._schedule_scoped_refresh(skills=True, combat=True)
                            self._rebuild_buffs_list()
                            self._rebuild_buffs_reference()
                            try:
                                self._mark_cloud_sync_dirty()
                            except Exception:
                                pass
                    except Exception:
                        pass
                return _r

            ctk.CTkButton(row, text="✕", width=22, height=20, fg_color="#8B0000", hover_color="#5C0000",
                          command=_mk_rem()).pack(side="left", padx=6)
        self._mark_buffs_page_built()

    def _rebuild_buffs_reference(self):
        if not hasattr(self, "buffs_ref_scroll"):
            return
        for w in self.buffs_ref_scroll.winfo_children():
            try:
                w.destroy()
            except Exception:
                pass

        if not hasattr(self, "buffs_ref_ui"):
            self.buffs_ref_ui = {}
        if not hasattr(self, "buffs_ref_expanded"):
            self.buffs_ref_expanded = {"manual_buffs": True, "spells": True}

        self.buffs_ref_ui = {}

        buffs = self.data.get("buffs", []) or []
        active_b = [b for b in buffs if b.get("active")]

        # === Category: Active Manual Buffs ===
        cat = "manual_buffs"
        header_row = ctk.CTkFrame(self.buffs_ref_scroll, fg_color="transparent")
        header_row.pack(anchor="w", padx=6, pady=(6, 2))

        expanded = self.buffs_ref_expanded.get(cat, True)
        btn_text = "−" if expanded else "+"
        toggle_btn = ctk.CTkButton(
            header_row,
            text=btn_text,
            width=20,
            height=20,
            font=ctk.CTkFont(size=11, weight="bold"),
            fg_color="#2a2a2a",
            hover_color="#3a3a3a",
            text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
            command=lambda c=cat: self._toggle_buffs_ref_category(c)
        )
        toggle_btn.pack(side="left", padx=(0, 5))

        ctk.CTkLabel(
            header_row, text="Active Manual Buffs",
            font=ctk.CTkFont(size=13, weight="bold"),
            text_color=getattr(self, 'primary_button_color', THEME_ORANGE)
        ).pack(side="left")

        container = ctk.CTkFrame(self.buffs_ref_scroll, fg_color="transparent")
        if expanded:
            container.pack(fill="x", padx=4, pady=2)

        self.buffs_ref_ui[cat] = {
            'header_row': header_row,
            'container': container,
            'toggle_btn': toggle_btn
        }

        # populate manual buffs
        if active_b:
            for b in active_b:
                brow = ctk.CTkFrame(container, fg_color="#2A2A2A")
                brow.pack(fill="x", pady=1, padx=4)
                if b.get("source") == "spell":
                    summary = self._format_spell_buff_summary(b)
                    lbl = ctk.CTkLabel(
                        brow,
                        text=f"• {b.get('name', '?')} {summary}",
                        font=ctk.CTkFont(size=11),
                        anchor="w",
                    )
                else:
                    v = int(b.get("value", 0) or 0)
                    vs = f"{v:+d}" if v else "0"
                    et = b.get("effect_type", "?")
                    bt = b.get("bonus_type") or "Enhancement"
                    lbl = ctk.CTkLabel(
                        brow,
                        text=f"• {b.get('name','?')} [{et}|{bt}] {vs}",
                        font=ctk.CTkFont(size=11),
                        anchor="w"
                    )
                lbl.pack(side="left", padx=4, pady=2)
        else:
            ctk.CTkLabel(
                container, text="(none active)", text_color="#888888",
                font=ctk.CTkFont(size=11)
            ).pack(anchor="w", padx=8, pady=2)

        # === Category: Active Spells ===
        cat = "spells"
        header_row = ctk.CTkFrame(self.buffs_ref_scroll, fg_color="transparent")
        header_row.pack(anchor="w", padx=6, pady=(10, 2))

        expanded = self.buffs_ref_expanded.get(cat, True)
        btn_text = "−" if expanded else "+"
        toggle_btn = ctk.CTkButton(
            header_row,
            text=btn_text,
            width=20,
            height=20,
            font=ctk.CTkFont(size=11, weight="bold"),
            fg_color="#2a2a2a",
            hover_color="#3a3a3a",
            text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
            command=lambda c=cat: self._toggle_buffs_ref_category(c)
        )
        toggle_btn.pack(side="left", padx=(0, 5))

        ctk.CTkLabel(
            header_row, text="Active Spells",
            font=ctk.CTkFont(size=13, weight="bold"),
            text_color=getattr(self, 'primary_button_color', THEME_ORANGE)
        ).pack(side="left")

        container = ctk.CTkFrame(self.buffs_ref_scroll, fg_color="transparent")
        if expanded:
            container.pack(fill="x", padx=4, pady=2)

        self.buffs_ref_ui[cat] = {
            'header_row': header_row,
            'container': container,
            'toggle_btn': toggle_btn
        }

        # populate active spells - just spell + effect total (no effect names in main text)
        # tooltip (after ~1s hover) shows full details + buff type
        spell_count = 0
        for sname in self._iter_active_spell_names():
            spell_count += 1
            info = self.spells_db.get(sname, {})
            raw_eff = info.get("effects") or {}
            eff = self._resolve_spell_effects_for_caster_level(dict(raw_eff), sname)

            srow = ctk.CTkFrame(container, fg_color="#2A2A2A")
            srow.pack(fill="x", pady=1, padx=4)

            if not eff:
                lbl_text = f"• {sname} (no numeric bonuses listed)"
                lbl = ctk.CTkLabel(srow, text=lbl_text, font=ctk.CTkFont(size=11))
                lbl.pack(side="left", padx=4, pady=2)
                self._bind_hover_tooltip(lbl, f"{sname}\n\nNo numeric bonuses listed for this spell.", delay_ms=1000)
                continue

            # build parts but strip effect names for main display (just the totals)
            parts = []
            for k, v in list(eff.items())[:5]:
                if k in ("ability_enh", "ability_inherent") and isinstance(v, dict):
                    for ab, av in v.items():
                        parts.append(f"{ab[:3]}{av:+d}")
                elif isinstance(v, (int, float)):
                    parts.append(f"{int(v):+d}")  # just total, omit effect name k
                elif isinstance(v, str) and any(c in v.lower() for c in 'd'):
                    parts.append(v)  # the die total
                else:
                    parts.append(str(v))
            total_str = ', '.join(parts) if parts else '(see spell)'
            lbl = ctk.CTkLabel(srow, text=f"• {sname}: {total_str}", font=ctk.CTkFont(size=11))
            lbl.pack(side="left", padx=4, pady=2)

            # tooltip after 1s: full effect totals + buff type
            tt_parts = []
            for k, v in eff.items():
                if k in ("ability_enh", "ability_inherent") and isinstance(v, dict):
                    for ab, av in v.items():
                        tt_parts.append(f"{k} {ab}: {av:+d}")
                else:
                    tt_parts.append(f"{k}: {v}")
            tooltip = f"{sname}\n\nEffect totals:\n" + "\n".join(f"  {p}" for p in tt_parts)
            tooltip += "\n\n(Buff type: spell-granted / see full spell for details)"
            self._bind_hover_tooltip(lbl, tooltip, delay_ms=1000, wraplength=320)

        if spell_count == 0:
            ctk.CTkLabel(
                container, text="(no active spells)", text_color="#888888",
                font=ctk.CTkFont(size=11)
            ).pack(anchor="w", padx=8, pady=2)

    def _toggle_buffs_ref_category(self, cat):
        """Toggle collapse/expand for one of the categories (manual_buffs or spells) in the Active Effects Reference.
        In-place pack_forget / re-pack (after header) to match Prepared spells level toggle style.
        """
        if not hasattr(self, "buffs_ref_expanded"):
            self.buffs_ref_expanded = {"manual_buffs": True, "spells": True}
        expanded = not self.buffs_ref_expanded.get(cat, True)
        self.buffs_ref_expanded[cat] = expanded

        if hasattr(self, "buffs_ref_ui") and cat in self.buffs_ref_ui:
            ui = self.buffs_ref_ui[cat]
            if ui.get('toggle_btn'):
                ui['toggle_btn'].configure(text="−" if expanded else "+")
            container = ui.get('container')
            header = ui.get('header_row')
            if container:
                if expanded:
                    container.pack_forget()
                    if header:
                        container.pack(fill="x", padx=4, pady=2, after=header)
                    else:
                        container.pack(fill="x", padx=4, pady=2)
                else:
                    container.pack_forget()

    def build_feats_page(self):
        """Build Feats & Features page - now safely initializes dicts + uses register_widget"""
        if not hasattr(self, 'feats_frame') or self.feats_frame is None:
            self.feats_frame = ctk.CTkFrame(self.content)

        # Clear old content
        for widget in self.feats_frame.winfo_children():
            widget.destroy()

        # === Initialize storage (critical for load) ===
        self.special_ability_combos = {}
        self.bonus_feat_combos = {}
        self.domain_combos = []
        self.domain_powers_panel = None
        self.domain_spells_panel = None
        self.daily_use_vars = {}
        self.magic_item_daily_vars = {}
        self.magic_item_charge_combos = {}
        self.asi_combos = {}
        self.affliction_vars = {}
        self.neg_levels_var = None
        self.abil_dmg_var = None
        self.abil_dmg_val = None
        self.abil_dmg_display = None
        self.rage_switch_widgets = {}
        self.special_feature_form_widgets = {}
        self.extra_ring_combos = []
        self.feat_spec_frames = {}
        self.feat_spec_combos = {}
        self.feat_spec_layouts = {}
        self.feat_row_parents = {}
        self.data.setdefault("bonus_feats", {})
        self.data.setdefault("feat_specs", {})
        self.data.setdefault("magic_item_daily_uses", {})
        self.data.setdefault("magic_item_charges", {})
        self.data.setdefault("custom_magic_items", [])
        self.data.setdefault("special_abilities", {})
        self.data.setdefault("general_feats", [])
        self.data.setdefault("daily_feature_uses", {})
        self.data.setdefault("ability_score_improvements", {})
        self.data.setdefault("afflictions", {})
        self.data.setdefault("class_feature_state", {})
        self.data.setdefault("negative_levels", 0)
        self.data.setdefault("ability_damage", {"Strength": 0, "Dexterity": 0, "Constitution": 0, "Intelligence": 0, "Wisdom": 0, "Charisma": 0})
        self.data.setdefault("feat_options", {"extra_rings": ["", ""]})
        self.data.setdefault("custom_features", [])  # user-added features with name, description, per_day; shown on Racial/Class/Magical tabs

        # === TOP BAR ===
        top_bar = ctk.CTkFrame(self.feats_frame, height=45)
        top_bar.pack(fill="x", padx=15, pady=6)

        ctk.CTkLabel(top_bar, text="Feats & Features", 
                     font=ctk.CTkFont(size=20, weight="bold")).pack(side="left", padx=10)
        
        ctk.CTkButton(top_bar, text="🔄 Refresh Feats & Features", 
                      fg_color=getattr(self, 'secondary_button_color', THEME_TEAL), hover_color=getattr(self, 'secondary_hover_color', '#1f7f75'), width=240, height=35,
                      command=self.refresh_feats_page).pack(side="right", padx=15)

        # === MAIN CONTENT ===
        main_content = ctk.CTkFrame(self.feats_frame)
        main_content.pack(fill="both", expand=True, padx=15, pady=6)

        # LEFT SIDE: General Feats + status panels (scoped refresh targets)
        self.feats_left_frame = ctk.CTkFrame(main_content)
        self.feats_left_frame.pack(side="left", fill="both", expand=True, padx=(0, 8))

        self.feats_general_frame = ctk.CTkFrame(self.feats_left_frame, fg_color="transparent")
        self.feats_general_frame.pack(fill="x")

        self.feats_status_frame = ctk.CTkFrame(self.feats_left_frame, fg_color="transparent")
        self.feats_status_frame.pack(fill="x")

        self._build_feats_general_column(self.feats_general_frame)
        self._build_feats_status_panel(self.feats_status_frame)

        # RIGHT SIDE: Class tabs
        right_frame = ctk.CTkFrame(main_content)
        right_frame.pack(side="right", fill="both", expand=True)

        self.tabview = ctk.CTkTabview(right_frame)
        self.tabview.pack(fill="both", expand=True)

        # Build class tabs first
        for cls_name, class_level in self._get_class_level_slots():
            if cls_name != "None" and class_level > 0 and cls_name in self.classes_db:
                self.tabview.add(cls_name)
                self.build_class_features_tab(cls_name, class_level)

        if self._has_extra_rings_feat():
            self.tabview.add("Feat Options")
            self.build_feat_options_tab()

        self.tabview.add("Magical Items")
        self._sync_magic_item_prepared_spells()
        self.build_magical_items_tab()

        # Racial tab at the end, after Magical Items
        self.tabview.add("Racial")
        self.build_racial_tab()

        campaign_tab = self._get_campaign_homebrew_tab_name()
        if campaign_tab and self._has_campaign_homebrew_features():
            self.tabview.add(campaign_tab)
            self.build_campaign_homebrew_tab(campaign_tab)

        print("✅ Feats & Features page built with register_widget (auto-save)")
        self._mark_feats_page_built()

    def show_feat_details(self, feat_name, slot_key=None):
        """Popup showing full description and prerequisites from feats.json"""
        db_key = self._resolve_feat_db_key(feat_name)
        if not db_key:
            messagebox.showinfo("Feat Info", "No feat selected or feat not found.")
            return

        feat = self.feats_db[db_key]
        prereq = feat.get("prerequisites", "None")
        desc = feat.get("description", "No description available.")
        base_name, chosen_spec = self._split_feat_spec_from_name(feat_name)
        if not chosen_spec and slot_key and base_name == db_key:
            chosen_spec = self._get_feat_spec(slot_key)

        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Feat: {db_key}")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=620, min_height=480)

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=24, pady=(8, 20))
        ctk.CTkButton(
            footer, text="Close", width=120, height=36,
            fg_color=getattr(self, 'primary_button_color', '#c77626'), command=popup.destroy,
        ).pack(anchor="e")

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=24, pady=(16, 8))

        ctk.CTkLabel(body, text=db_key, font=ctk.CTkFont(size=18, weight="bold")).pack(anchor="w", pady=(0, 8))
        if chosen_spec and base_name == db_key:
            ctk.CTkLabel(
                body, text=f"Chosen: {chosen_spec}",
                font=ctk.CTkFont(size=13), text_color="#aaaaaa",
            ).pack(anchor="w", pady=(0, 6))
        ctk.CTkLabel(
            body, text=f"Prerequisites: {prereq}",
            font=ctk.CTkFont(size=14), text_color="#c77626",
        ).pack(anchor="w", pady=(0, 10))

        desc_frame = ctk.CTkScrollableFrame(body, height=300)
        desc_frame.pack(fill="both", expand=True)
        ctk.CTkLabel(desc_frame, text=desc, wraplength=500, justify="left").pack(anchor="w", pady=5, padx=4)
        
    def show_spell_details(self, spell_name, preferred_caster=None, cl=None):
        """Popup showing full spell description (like feats)"""
        if not spell_name or spell_name not in self.spells_db:
            messagebox.showinfo("Spell Info", "No spell selected or spell not found.")
            return

        info = self.spells_db[spell_name]
        lvl = info.get("level", "?")
        classes_str = ", ".join(self._get_spell_classes(info)) or "—"
        if cl is None:
            cl = self._get_effective_cl_for_spell(spell_name, preferred_caster)
        desc = self._get_formatted_spell_description(spell_name, preferred_caster, cl) or info.get("description", "No description available.")
        if cl > 0:
            caster_note = f" ({preferred_caster})" if preferred_caster else ""
            desc = f"(CL {cl}{caster_note})\n\n{desc}"

        # Material component (if present)
        mat = info.get("material_component", {})
        mat_text = ""
        if mat.get("name"):
            mat_text = f"\n\nMaterial Component: {mat['name']} (cost {mat.get('cost', 0)} gp)"

        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Spell: {spell_name}")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=740, min_height=620)

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=24, pady=(8, 20))
        ctk.CTkButton(
            footer, text="Close", width=120, height=36,
            fg_color=getattr(self, 'primary_button_color', '#c77626'), command=popup.destroy,
        ).pack(anchor="e")

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=24, pady=(16, 8))

        ctk.CTkLabel(
            body, text=f"{spell_name} (Level {lvl})",
            font=ctk.CTkFont(size=20, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))
        ctk.CTkLabel(
            body, text=f"Classes: {classes_str}",
            font=ctk.CTkFont(size=14), text_color="#c77626",
        ).pack(anchor="w", pady=(0, 10))

        desc_frame = ctk.CTkScrollableFrame(body, height=400)
        desc_frame.pack(fill="both", expand=True)
        ctk.CTkLabel(
            desc_frame, text=desc + mat_text,
            wraplength=640, justify="left",
        ).pack(anchor="w", pady=5, padx=4)
 
    def _save_general_feat(self, combo_index, value):
        if getattr(self, "_rebuilding_ui", False):
            return
        stripped = value.strip() if value else ""
        base, legacy_spec = self._normalize_feat_selection(stripped)
        if base and base not in self.feats_db and base not in getattr(self, "epic_feats_db", {}):
            return
        if getattr(self, "_feats_page_refreshing", False) and not base:
            return
        feats = self.data.setdefault("general_feats", [])
        while len(feats) <= combo_index:
            feats.append("")
        old_value = str(feats[combo_index] or "").strip() if combo_index < len(feats) else ""
        if base == old_value:
            return
        feats[combo_index] = base
        self.data[f"general_feat_{combo_index}"] = base
        slot_key = f"general_feat_{combo_index}"
        if legacy_spec and not self._get_feat_spec(slot_key):
            self._save_feat_spec(slot_key, legacy_spec, refresh_combat=False)
        if combo_index == 0 and self.data.get("race") == "Human":
            self.data["human_bonus_feat"] = base
        new_value = feats[combo_index]
        self._on_feat_spec_feat_changed(slot_key, new_value)
        self.root.after_idle(
            lambda ov=old_value, nv=new_value: self._apply_general_feat_side_effects(ov, nv)
        )

    def _apply_general_feat_side_effects(self, old_value, new_value):
        if getattr(self, "_switching_page", False) or self._focus_is_navigation():
            return
        old_value = str(old_value or "").strip()
        new_value = str(new_value or "").strip()
        if old_value == new_value:
            return
        scopes = self._feat_selection_refresh_scopes(old_value, new_value)
        if scopes:
            self.invalidate_caches()
            self._rebuild_feat_cache(sync_widgets=False)
            self.root.after(50, lambda s=scopes: self.refresh_feats_scope(*s))
        else:
            self._rebuild_feat_cache(sync_widgets=False)
            if self._feat_needs_spec_picker(new_value) or self._feat_needs_spec_picker(old_value):
                self.invalidate_caches(combat=True)
                if hasattr(self, "combat_frame"):
                    self._mark_combat_page_stale()
        if new_value in {"Extra Rings", "Forge Ring"} or old_value in {"Extra Rings", "Forge Ring"}:
            self.invalidate_caches()
            self.refresh_all()
        if scopes or new_value in {"Extra Rings", "Forge Ring"} or old_value in {"Extra Rings", "Forge Ring"}:
            self._sync_animal_companion()
            self._sync_familiar()
            self._sync_paladin_mount()

    def _save_ability_score_improvement(self, milestone, value):
        self.data.setdefault("ability_score_improvements", {})[str(milestone)] = (
            value.strip() if value else ""
        )
        self.refresh_all()

    def _build_feats_general_column(self, parent):
        """Left column: general feat slots (read-only) and ASI dropdowns."""
        self.general_feat_combos = []
        self._general_feat_combo_indices = []
        self.asi_combos = {}

        total_hd = self._get_total_hit_dice()
        feat_title = f"General Feats (Total HD: {total_hd})"
        if self._is_epic_character():
            feat_title += f"  —  Epic feats available ({len(self.epic_feats_db)})"
        ctk.CTkLabel(
            parent, text=feat_title,
            font=ctk.CTkFont(size=17, weight="bold"),
        ).pack(anchor="w", pady=(0, 4))
        ctk.CTkLabel(
            parent,
            text="Feats are chosen in the Character Creation wizard (or when leveling up).",
            font=ctk.CTkFont(size=12),
            text_color="#888888",
            wraplength=520,
            justify="left",
        ).pack(anchor="w", pady=(0, 8))

        feat_levels = self._get_general_feat_milestones(total_hd)
        idx = 1 if self.data.get("race") == "Human" else 0

        for lvl in feat_levels:
            if total_hd < lvl:
                continue
            slot_key = f"general_feat_{idx}"
            feat_name = self._get_general_feat_slot_value(idx)
            row = self._build_feat_readonly_row(
                parent,
                slot_key,
                feat_name,
                f"HD {lvl} Feat:",
            )
            self._register_feat_row_parent(slot_key, row)
            idx += 1

        asi_frame = ctk.CTkFrame(parent, fg_color="transparent")
        asi_frame.pack(fill="x", pady=(14, 0))
        ctk.CTkLabel(
            asi_frame,
            text="Ability Score Improvements (+1 every 4 HD)",
            font=ctk.CTkFont(size=15, weight="bold"),
        ).pack(anchor="w", pady=(0, 6))

        saved_asi = self.data.get("ability_score_improvements", {})
        asi_options = [""] + list(ABILITY_NAMES)
        asi_shown = 0
        for milestone in self._get_asi_milestones(total_hd):
            row = ctk.CTkFrame(asi_frame, fg_color="transparent")
            row.pack(fill="x", pady=1)
            ctk.CTkLabel(
                row,
                text=f"Level {milestone} (+1):",
                font=ctk.CTkFont(weight="bold"),
                width=180,
            ).pack(side="left", padx=(0, 8))
            combo = ctk.CTkComboBox(
                row,
                values=asi_options,
                width=280,
                command=lambda val, m=milestone: self._save_ability_score_improvement(m, val),
            )
            combo.set(saved_asi.get(str(milestone), ""))
            combo.pack(side="left", pady=1)
            self.asi_combos[milestone] = combo
            asi_shown += 1

        if asi_shown == 0:
            ctk.CTkLabel(
                asi_frame,
                text="Reach level 4 to gain your first ability score improvement.",
                font=ctk.CTkFont(size=12),
                text_color="#888888",
            ).pack(anchor="w", padx=4)

    def _build_feats_status_panel(self, parent):
        """Left column: afflictions, negative levels, ability damage."""
        self.affliction_vars = {}
        self.neg_levels_var = None
        self.abil_dmg_var = None
        self.abil_dmg_val = None
        self.abil_dmg_display = None
        self._build_afflictions_panel(parent)
        self._build_negative_levels_ui(parent)
        self._build_ability_damage_ui(parent)

    def _rebuild_feats_general_column(self):
        if not getattr(self, "feats_general_frame", None):
            return
        try:
            if not self.feats_general_frame.winfo_exists():
                return
        except tk.TclError:
            return
        for widget in self.feats_general_frame.winfo_children():
            widget.destroy()
        self._build_feats_general_column(self.feats_general_frame)

    def _rebuild_feats_status_panel(self):
        if not getattr(self, "feats_status_frame", None):
            return
        try:
            if not self.feats_status_frame.winfo_exists():
                return
        except tk.TclError:
            return
        for widget in self.feats_status_frame.winfo_children():
            widget.destroy()
        self._build_feats_status_panel(self.feats_status_frame)

    def _feats_tab_exists(self, tab_name):
        if not hasattr(self, "tabview"):
            return False
        try:
            self.tabview.tab(tab_name)
            return True
        except Exception:
            return False

    def _feat_selection_refresh_scopes(self, old_value, new_value):
        """Scopes needed after a feat dropdown change; full rebuild when tab structure changes."""
        feat_refresh_triggers = {"Extra Rings", "Forge Ring"}
        if (
            new_value in feat_refresh_triggers
            or old_value in feat_refresh_triggers
        ):
            return ("full",)
        if (
            new_value in DAILY_USE_FEATS
            or old_value in DAILY_USE_FEATS
        ):
            return ("class_tabs",)
        return ()

    def _refresh_feats_custom_feature_categories(self, categories):
        scopes = []
        for cat in categories:
            if not cat:
                continue
            if cat == "racial":
                scopes.append("racial")
            elif cat == "magic_item":
                scopes.append("magical_items")
            elif cat == self._get_campaign_homebrew_tab_name():
                scopes.append("campaign_homebrew")
            elif self._feats_tab_exists(cat):
                scopes.append(cat)
            else:
                self.refresh_feats_scope("full")
                return
        if scopes:
            self.refresh_feats_scope(*dict.fromkeys(scopes))

    def refresh_feats_scope(self, *scopes):
        """Tiered feats refresh — rebuild only the requested sections."""
        if not scopes:
            scopes = ("full",)
        if "full" in scopes or self._feats_page_is_stale():
            self.refresh_feats_page()
            return

        if not hasattr(self, "feats_frame") or self.feats_frame is None:
            self.build_feats_page()
            return

        try:
            self._sync_feats_widgets_to_data()
        except Exception:
            pass

        scope_set = set(scopes)

        if "domain" in scope_set:
            self.update_domain_preview()
            scope_set.discard("domain")

        if "left" in scope_set:
            self._rebuild_feats_general_column()
            scope_set.discard("left")

        if "afflictions" in scope_set:
            self._rebuild_feats_status_panel()
            scope_set.discard("afflictions")

        if "racial" in scope_set:
            if self._feats_tab_exists("Racial"):
                try:
                    self.build_racial_tab()
                except Exception:
                    self.refresh_feats_page()
                    return
            scope_set.discard("racial")

        if "magical_items" in scope_set:
            if self._feats_tab_exists("Magical Items"):
                try:
                    self._sync_magic_item_prepared_spells()
                    self.build_magical_items_tab()
                except Exception:
                    self.refresh_feats_page()
                    return
            scope_set.discard("magical_items")

        if "feat_options" in scope_set:
            if self._feats_tab_exists("Feat Options") and self._has_extra_rings_feat():
                try:
                    self.build_feat_options_tab()
                except Exception:
                    self.refresh_feats_page()
                    return
            scope_set.discard("feat_options")

        if "class_tabs" in scope_set:
            for cls_name, class_level in self._get_class_level_slots():
                if cls_name != "None" and class_level > 0 and cls_name in self.classes_db:
                    if self._feats_tab_exists(cls_name):
                        try:
                            self.build_class_features_tab(cls_name, class_level)
                        except Exception:
                            self.refresh_feats_page()
                            return
            scope_set.discard("class_tabs")

        if "campaign_homebrew" in scope_set:
            tab_name = self._get_campaign_homebrew_tab_name()
            if tab_name and self._feats_tab_exists(tab_name):
                try:
                    self.build_campaign_homebrew_tab(tab_name)
                except Exception:
                    self.refresh_feats_page()
                    return
            scope_set.discard("campaign_homebrew")

        for scope in list(scope_set):
            rebuilt = False
            for cls_name, class_level in self._get_class_level_slots():
                if cls_name == scope and class_level > 0 and cls_name in self.classes_db:
                    if self._feats_tab_exists(cls_name):
                        try:
                            self.build_class_features_tab(cls_name, class_level)
                            rebuilt = True
                        except Exception:
                            self.refresh_feats_page()
                            return
                    break
            scope_set.discard(scope)
            if not rebuilt:
                self.refresh_feats_page()
                return

    def save_special_ability(self, key, value):
        """Save the chosen special ability so it survives refresh"""
        self.data.setdefault("special_abilities", {})[key] = value.strip() if value else ""
 
    def build_feat_options_tab(self):
        tab = self.tabview.tab("Feat Options")
        for widget in tab.winfo_children():
            widget.destroy()
        scroll = ctk.CTkScrollableFrame(tab)
        scroll.pack(fill="both", expand=True, padx=10, pady=10)

        ctk.CTkLabel(
            scroll,
            text="Feat Options",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        if self._has_extra_rings_feat():
            ring_frame = ctk.CTkFrame(scroll, fg_color="#2F2F2F")
            ring_frame.pack(fill="x", pady=(0, 10), padx=2)

            ctk.CTkLabel(
                ring_frame,
                text="Extra Rings",
                font=ctk.CTkFont(size=14, weight="bold"),
                text_color=THEME_ORANGE,
            ).pack(anchor="w", padx=12, pady=(10, 4))
            ctk.CTkLabel(
                ring_frame,
                text="Two additional ring slots from the Extra Rings feat.",
                font=ctk.CTkFont(size=12),
                text_color="#888888",
                wraplength=620,
                justify="left",
            ).pack(anchor="w", padx=12, pady=(0, 8))

            saved_rings = self._normalize_extra_ring_data()
            ring_options = self._get_extra_ring_options()
            self.extra_ring_combos = []

            for index, label in enumerate(("Ring 3:", "Ring 4:")):
                row = ctk.CTkFrame(ring_frame, fg_color="transparent")
                row.pack(fill="x", padx=12, pady=(0, 10))

                ctk.CTkLabel(
                    row, text=label, font=ctk.CTkFont(weight="bold"), width=70,
                ).pack(side="left", padx=(0, 8))
                combo = ctk.CTkComboBox(
                    row,
                    values=ring_options,
                    width=280,
                    command=lambda val, i=index: self._on_extra_ring_changed(i, val),
                )
                combo.set(saved_rings[index] if index < len(saved_rings) else "")
                combo.bind(
                    "<FocusOut>",
                    lambda _e, i=index, c=combo: self._on_extra_ring_changed(i, c.get()),
                    add="+",
                )
                combo.pack(side="left", padx=4)
                self.extra_ring_combos.append(combo)
                self.register_widget(f"extra_ring_{index}", combo)
        else:
            ctk.CTkLabel(
                scroll,
                text="No feat options are available for your current feats.",
                font=ctk.CTkFont(size=12),
                text_color="#888888",
            ).pack(anchor="w", padx=4, pady=8)

    def _build_magical_items_scroll_content(
        self,
        scroll,
        *,
        inventory_items,
        custom_items=None,
        custom_features=None,
        empty_message,
    ):
        custom_items = custom_items or []
        custom_features = custom_features or []
        has_content = bool(inventory_items or custom_items or custom_features)

        if inventory_items:
            ctk.CTkLabel(
                scroll, text="Inventory Items",
                font=ctk.CTkFont(size=14, weight="bold"),
                text_color=THEME_ORANGE,
            ).pack(anchor="w", pady=(4, 6))
            for item in inventory_items:
                self._build_magic_item_feature_card(scroll, item)

        if custom_items:
            ctk.CTkLabel(
                scroll, text="Custom Items",
                font=ctk.CTkFont(size=14, weight="bold"),
                text_color=THEME_ORANGE,
            ).pack(anchor="w", pady=(12, 6))
            for item in custom_items:
                self._build_magic_item_feature_card(scroll, item)

        if custom_features:
            ctk.CTkLabel(
                scroll, text="Custom Features",
                font=ctk.CTkFont(size=14, weight="bold"),
                text_color=THEME_ORANGE,
            ).pack(anchor="w", pady=(12, 6))
            for item in custom_features:
                self._build_magic_item_feature_card(scroll, item)

        if not has_content:
            ctk.CTkLabel(
                scroll,
                text=empty_message,
                font=ctk.CTkFont(size=13),
                text_color="#888888",
                wraplength=650,
                justify="left",
            ).pack(anchor="w", padx=4, pady=8)

    def build_magical_items_tab(self):
        tab = self.tabview.tab("Magical Items")
        for widget in tab.winfo_children():
            widget.destroy()

        header_row = ctk.CTkFrame(tab, fg_color="transparent")
        header_row.pack(fill="x", padx=10, pady=(10, 4))
        ctk.CTkLabel(
            header_row, text="Magical Items",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(side="left")
        primary = getattr(self, "primary_button_color", THEME_ORANGE)
        hover_primary = getattr(self, "primary_hover_color", "#a56b32")
        header_actions = ctk.CTkFrame(header_row, fg_color="transparent")
        header_actions.pack(side="right")
        ctk.CTkButton(
            header_actions, text="+ Feature", width=88, height=28,
            fg_color=getattr(self, "secondary_button_color", THEME_TEAL),
            hover_color=getattr(self, "secondary_hover_color", "#1f7f75"),
            command=lambda: self._open_custom_feature_dialog("magic_item"),
        ).pack(side="right", padx=(6, 0))
        ctk.CTkButton(
            header_actions, text="+ Item", width=72, height=28,
            fg_color=primary, hover_color=hover_primary,
            command=self._open_add_custom_magic_item_popup,
        ).pack(side="right")

        sub_tabview = ctk.CTkTabview(tab)
        sub_tabview.pack(fill="both", expand=True, padx=10, pady=(0, 10))
        self._magical_items_sub_tabview = sub_tabview

        arms_tab = sub_tabview.add("Arms & Armor")
        wondrous_tab = sub_tabview.add("Wondrous")

        inventory_items = self._get_inventory_magic_item_features()
        arms_items = [
            item for item in inventory_items if self._magic_item_is_arms_and_armor(item)
        ]
        wondrous_inventory = [
            item for item in inventory_items if not self._magic_item_is_arms_and_armor(item)
        ]
        custom_items = self._get_custom_magic_items()
        custom_arms_items = [
            item for item in custom_items if self._magic_item_is_arms_and_armor(item)
        ]
        custom_wondrous_items = [
            item for item in custom_items if not self._magic_item_is_arms_and_armor(item)
        ]
        custom_features = self._get_magic_item_custom_features()

        arms_scroll = ctk.CTkScrollableFrame(arms_tab)
        arms_scroll.pack(fill="both", expand=True, padx=10, pady=10)
        self._build_magical_items_scroll_content(
            arms_scroll,
            inventory_items=arms_items,
            custom_items=custom_arms_items,
            empty_message=(
                "No magical weapons, armor, or shields. Assign gear on the Inventory page "
                "and use the ✦ wizard to enchant them, or use + Item to add a custom one."
            ),
        )

        wondrous_scroll = ctk.CTkScrollableFrame(wondrous_tab)
        wondrous_scroll.pack(fill="both", expand=True, padx=10, pady=10)
        self._build_magical_items_scroll_content(
            wondrous_scroll,
            inventory_items=wondrous_inventory,
            custom_items=custom_wondrous_items,
            custom_features=custom_features,
            empty_message=(
                "No wondrous magical items. Equip items on the Inventory page "
                "or use + to create a custom item."
            ),
        )

        self._mark_magical_items_tab_built()

    def build_racial_tab(self):
        tab = self.tabview.tab("Racial")
        for widget in tab.winfo_children():
            widget.destroy()
        race = self.data.get("race", "Human")
        if hasattr(self, "race_var"):
            race = self.race_var.get().strip() or race
        race_data = self.races.get(race, {})
        features = race_data.get("features", "No special racial features.")

        scroll = ctk.CTkScrollableFrame(tab)
        scroll.pack(fill="both", expand=True, padx=10, pady=10)

        # + button at top right for adding custom features (no header text)
        plus_row = ctk.CTkFrame(scroll, fg_color="transparent")
        plus_row.pack(fill="x", padx=10, pady=(0, 4))
        primary = getattr(self, 'primary_button_color', '#c77626')
        hover_primary = getattr(self, 'primary_hover_color', '#a56b32')
        ctk.CTkButton(
            plus_row, text="+", width=30, height=28,
            fg_color=primary, hover_color=hover_primary,
            command=lambda: self._open_custom_feature_dialog("racial")
        ).pack(side="right")

        ctk.CTkLabel(
            scroll, text=f"{race} Racial Features",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        ability_lines = []
        for ability_name in ABILITY_NAMES:
            mod = race_data.get(ABILITY_SHORT[ability_name], 0)
            if mod:
                sign = "+" if mod > 0 else ""
                ability_lines.append(f"{ability_name} {sign}{mod}")
        if ability_lines:
            ctk.CTkLabel(
                scroll,
                text="Ability Adjustments: " + ", ".join(ability_lines),
                font=ctk.CTkFont(size=13, weight="bold"),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                wraplength=650,
                justify="left",
            ).pack(anchor="w", pady=(0, 6))

        size = race_data.get("size", self.data.get("size", "Medium"))
        speed = race_data.get("speed")
        if speed:
            ctk.CTkLabel(
                scroll, text=f"Size: {size}  |  Base Speed: {speed} ft.",
                font=ctk.CTkFont(size=13),
                wraplength=650, justify="left",
            ).pack(anchor="w", pady=(0, 8))

        age_ranges_text = self._format_race_age_ranges(race)
        if age_ranges_text:
            ctk.CTkLabel(
                scroll,
                text=age_ranges_text,
                font=ctk.CTkFont(size=13),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                wraplength=650,
                justify="left",
            ).pack(anchor="w", pady=(0, 8))

        hd_info = race_data.get("racial_hit_dice")
        if hd_info:
            hd_count = int(hd_info.get("count", 0) or 0)
            hd_die = int(hd_info.get("die", 8) or 8)
            hd_type = hd_info.get("type", "humanoid")
            racial_saves = self._get_racial_save_bonuses()
            racial_skill_pts = self._get_racial_hd_skill_points()
            racial_class_skills = ", ".join(sorted(self._get_racial_hd_class_skills()))
            la = self._get_racial_level_adjustment(race)
            hd_lines = [
                f"Racial Hit Dice: {hd_count}d{hd_die} {hd_type}",
                (
                    f"BAB +{hd_info.get('bab', 0)}  |  "
                    f"Fort +{racial_saves['fort']}, Ref +{racial_saves['ref']}, "
                    f"Will +{racial_saves['will']}"
                ),
                f"One-time racial skill points: {racial_skill_pts} (6 × [2 + Int mod])",
            ]
            if racial_class_skills:
                hd_lines.append(f"Racial class skills: {racial_class_skills}")
            if la:
                hd_lines.append(f"Level adjustment: +{la}")
            ecl, ecl_detail = self._format_ecl_breakdown()
            hd_lines.append(f"Effective character level: {ecl} ({ecl_detail})")
            ctk.CTkLabel(
                scroll,
                text="\n".join(hd_lines),
                font=ctk.CTkFont(size=13),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                wraplength=650,
                justify="left",
            ).pack(anchor="w", pady=(0, 8))

        ctk.CTkLabel(
            scroll, text=features, wraplength=650, justify="left",
        ).pack(anchor="w", pady=(0, 10))

        if race == "Human":
            human_bonus = self._get_human_bonus_feat()
            feat_row = ctk.CTkFrame(scroll, fg_color="#2F2F2F")
            feat_row.pack(fill="x", pady=(8, 4), padx=2)
            ctk.CTkLabel(
                feat_row, text="Level 1 Bonus Feat (Human):",
                font=ctk.CTkFont(size=14, weight="bold"),
            ).pack(anchor="w", padx=12, pady=(10, 4))
            combo_row = ctk.CTkFrame(feat_row, fg_color="transparent")
            combo_row.pack(fill="x", padx=12, pady=(0, 10))
            self._build_feat_readonly_row(
                combo_row,
                "general_feat_0",
                human_bonus,
                "",
                pack=False,
            ).pack(fill="x")
            self._register_feat_row_parent("general_feat_0", combo_row)

        # Render any custom racial features (no header, + button is at top right)
        customs = [f for f in self.data.get("custom_features", []) if f.get("category") == "racial"]
        for cf in customs:
            try:
                global_idx = self.data.get("custom_features", []).index(cf)
            except ValueError:
                global_idx = -1
            if global_idx >= 0:
                self._build_custom_feature_card(scroll, cf, "racial", global_idx)

    def build_class_features_tab(self, cls_name, class_level):
        """Show features up to this class's level - FIXED domain restore + REAL-TIME preview"""
        tab = self.tabview.tab(cls_name)
        for widget in tab.winfo_children():
            widget.destroy()
        scroll = ctk.CTkScrollableFrame(tab)
        scroll.pack(fill="both", expand=True, padx=10, pady=10)

        # + button at top right for adding custom features (no header text)
        plus_row = ctk.CTkFrame(scroll, fg_color="transparent")
        plus_row.pack(fill="x", padx=10, pady=(0, 4))
        primary = getattr(self, 'primary_button_color', '#c77626')
        hover_primary = getattr(self, 'primary_hover_color', '#a56b32')
        ctk.CTkButton(
            plus_row, text="+", width=30, height=28,
            fg_color=primary, hover_color=hover_primary,
            command=lambda c=cls_name: self._open_custom_feature_dialog(c)
        ).pack(side="right")
        
        ctk.CTkLabel(scroll, text=f"{cls_name} Features (level {class_level})",
                     font=ctk.CTkFont(size=16, weight="bold")).pack(anchor="w", pady=5)
        
        features_dict = self.classes_db.get(cls_name, {}).get("features", {})
        
        best_features = {}
        for level_str in sorted(features_dict.keys(), key=int):
            level = int(level_str)
            if level > class_level:
                continue
            for feat in features_dict[level_str]:
                key = self._class_feature_dedupe_key(feat)
                if not key:
                    continue
                if key not in best_features or level > best_features[key][0]:
                    best_features[key] = (level, feat)
        
        for _feature_key, (level, feat) in best_features.items():
            name = feat.get("name", _feature_key)
            desc = feat.get("description", "")
            frame = ctk.CTkFrame(scroll, fg_color="#2F2F2F")
            frame.pack(fill="x", pady=10, padx=8)

            title_row = ctk.CTkFrame(frame, fg_color="transparent")
            title_row.pack(fill="x", padx=15, pady=(12, 4))
            ctk.CTkLabel(
                title_row, text=name, font=ctk.CTkFont(size=14, weight="bold"),
            ).pack(side="left", anchor="w")
            override_key = self._class_feature_description_override_key(cls_name, name)
            self._build_feature_description_edit_button(
                title_row, override_key, name, desc,
            ).pack(side="right", padx=(4, 0))

            ctk.CTkLabel(frame, text=desc, wraplength=540, justify="left").pack(
                anchor="w", padx=15, pady=(0, 4))

            granted_spell = (feat.get("granted_spell") or "").strip()
            if granted_spell:
                at_will_note = " (at will)" if feat.get("at_will") else ""
                ctk.CTkLabel(
                    frame,
                    text=f"Granted spell: {granted_spell}{at_will_note}",
                    font=ctk.CTkFont(size=12, weight="bold"),
                    text_color=THEME_TEAL,
                    wraplength=540,
                    justify="left",
                ).pack(anchor="w", padx=15, pady=(0, 4))

            custom_desc = self._get_feature_description_override(override_key)
            if custom_desc:
                ctk.CTkLabel(
                    frame,
                    text=custom_desc,
                    wraplength=540,
                    justify="left",
                    font=ctk.CTkFont(size=12),
                    text_color=getattr(self, "secondary_button_color", THEME_TEAL),
                ).pack(anchor="w", padx=15, pady=(0, 4))
                for dice in self._extract_simple_dice_from_description(custom_desc):
                    dice_lbl = ctk.CTkLabel(
                        frame, text=f"({dice})",
                        font=ctk.CTkFont(size=11, weight="bold"),
                        text_color="#66b3ff",
                        fg_color="#1a2a3a",
                        corner_radius=4,
                        cursor="hand2",
                    )
                    dice_lbl.pack(anchor="w", padx=15, pady=(2, 4))
                    builder = lambda d=dice, lbl=name: self._format_talespire_roll(lbl, [d])
                    self._bind_talespire_click(dice_lbl, builder)

                override_abilities = self._get_custom_magic_item_abilities(
                    name, {"description": custom_desc},
                )
                granted_spells = override_abilities.get("granted_spells") or []
                if granted_spells:
                    spell_text = ", ".join(granted_spells)
                    ctk.CTkLabel(
                        frame,
                        text=f"Granted spell{'s' if len(granted_spells) != 1 else ''}: {spell_text}",
                        font=ctk.CTkFont(size=12, weight="bold"),
                        text_color=THEME_TEAL,
                        wraplength=540,
                        justify="left",
                    ).pack(anchor="w", padx=15, pady=(0, 4))
                uses_per_day = int(override_abilities.get("uses_per_day") or 0)
                if uses_per_day > 0:
                    tracker_key = f"class_feature|{cls_name}|{name}"
                    self._build_magic_item_daily_tracker(frame, tracker_key, uses_per_day)
                max_charges = int(override_abilities.get("max_charges") or 0)
                if max_charges > 0:
                    tracker_key = f"class_feature|{cls_name}|{name}"
                    self._build_magic_item_charge_tracker(frame, tracker_key, max_charges)

            ctk.CTkLabel(frame, text="", height=4).pack(anchor="w")

            # Animal companion selection UI (SRD list, factors effective level + Improved feats)
            if name == "Animal Companion" and cls_name in ("Druid", "Ranger"):
                self._build_animal_companion_selector(frame, cls_name)

            # Familiar selection for Sorcerer/Wizard (and similar arcane classes)
            if name == "Familiar" and cls_name in ("Sorcerer", "Wizard"):
                self._build_familiar_selector(frame, cls_name)

            if name == "Special Mount" and cls_name == "Paladin":
                self._build_paladin_mount_selector(frame)

            if self._should_show_daily_tracker(feat):
                self._build_daily_use_tracker(frame, cls_name, name, feat, class_level)

            if feat.get("rage_toggle"):
                self._build_rage_active_toggle(frame, cls_name, name)

            if feat.get("fast_healing_toggle") and cls_name == "Warlock":
                self._build_fiendish_resilience_toggle(frame, feat)

            if feat.get("eldritch_blast") and cls_name == "Warlock":
                self._build_warlock_blast_modifier_picker(frame)

            if feat.get("invocation_picker") and cls_name == "Warlock":
                self._build_warlock_invocation_picker(frame)

            if feat.get("energy_resistance_picker") and cls_name == "Warlock":
                self._build_warlock_energy_resistance_picker(frame, feat)

            if feat.get("wild_shape_toggle"):
                self._build_wild_shape_form_selector(frame)
                self._build_wild_shape_active_toggle(frame, cls_name, name)
                self._build_wild_shape_qualities_widget(frame)
            
            # === CLERIC DOMAIN DROPDOWNS ===
            if feat.get("is_domain_choice"):
                domains = self.data.setdefault("domains", ["", ""])
                if len(domains) < 2:
                    domains.extend([""] * (2 - len(domains)))
                    self.data["domains"] = domains

                domain_row = ctk.CTkFrame(frame, fg_color="transparent")
                domain_row.pack(fill="x", padx=15, pady=(8, 4))

                for index, label in enumerate(("Domain 1:", "Domain 2:")):
                    col = ctk.CTkFrame(domain_row, fg_color="transparent")
                    col.pack(side="left", fill="x", expand=True, padx=(0 if index == 0 else 8, 0))
                    ctk.CTkLabel(
                        col, text=label, font=ctk.CTkFont(size=14, weight="bold"),
                    ).pack(anchor="w", pady=(0, 4))
                    saved = domains[index] if domains[index] else self.data.get(f"domain_{index}", "")
                    combo = ctk.CTkComboBox(
                        col,
                        values=self.domain_list,
                        width=280,
                        command=lambda val, i=index: self._on_domain_selected(i, val),
                    )
                    combo.set(saved)
                    combo.bind(
                        "<FocusOut>",
                        lambda _e, i=index, c=combo: self._on_domain_selected(i, c.get()),
                    )
                    self.register_widget(f"domain_{index}", combo)
                    combo.pack(anchor="w", pady=(0, 4))
                    self.domain_combos.append(combo)

                self.domain_preview_frame = ctk.CTkFrame(frame, fg_color="#1F1F1F")
                self.domain_preview_frame.pack(fill="x", pady=8, padx=15)

                preview_columns = ctk.CTkFrame(self.domain_preview_frame, fg_color="transparent")
                preview_columns.pack(fill="both", expand=True, padx=8, pady=8)

                self.domain_powers_panel = ctk.CTkScrollableFrame(
                    preview_columns, fg_color="#2a2a2a", height=200,
                )
                self.domain_powers_panel.pack(side="left", fill="both", expand=True, padx=(0, 4))

                self.domain_spells_panel = ctk.CTkScrollableFrame(
                    preview_columns, fg_color="#2a2a2a", height=200,
                )
                self.domain_spells_panel.pack(side="left", fill="both", expand=True, padx=(4, 0))

                self.root.after(50, self.update_domain_preview)

            if feat.get("is_bonus_feat"):
                key = f"{cls_name}_{level}_bonus"
                saved_value = self.data.setdefault("bonus_feats", {}).get(key, "")
                pool = feat.get("bonus_feat_pool", "")
                pool_label = f" ({pool} bonus feats)" if pool else ""
                ctk.CTkLabel(
                    frame,
                    text=f"Choose bonus feat{pool_label}:",
                    font=ctk.CTkFont(size=12, weight="bold"),
                ).pack(anchor="w", padx=15, pady=(4, 0))
                feat_values = self._get_bonus_feat_options(pool)

                bonus_feat_row = ctk.CTkFrame(frame, fg_color="transparent")
                bonus_feat_row.pack(fill="x", padx=15, pady=8)
                self._build_feat_readonly_row(
                    bonus_feat_row,
                    key,
                    saved_value,
                    "Selected:",
                    pack=False,
                ).pack(fill="x")
                self._register_feat_row_parent(key, bonus_feat_row)

            if feat.get("is_choice"):
                key = f"{cls_name}_{level}"
                saved_value = self.data.setdefault("special_abilities", {}).get(key, "")
                choice_values = [""] + feat.get("choices", [])

                combo = ctk.CTkComboBox(
                    frame, values=choice_values, width=300,
                    command=lambda val, k=key: self.save_special_ability(k, val),
                )
                combo.set(saved_value)
                combo.bind("<FocusOut>", lambda e, k=key, c=combo: self.save_special_ability(k, c.get()))
                self.register_widget(key, combo)
                self.special_ability_combos[key] = combo
                combo.pack(pady=8, padx=15)

            if name == "Flurry of Blows" and cls_name == "Monk":
                self._build_monk_flurry_ui(frame, cls_name, level)

            if name == "Wholeness of Body" and cls_name == "Monk":
                monk_lvl = self._get_class_level("Monk")
                wis_mod = max(0, self._effective_ability_mod("Wisdom"))
                max_h = monk_lvl * wis_mod
                self._build_healing_pool_ui(frame, "Monk", "wholeness", max_h)

            if name == "Lay on Hands" and cls_name == "Paladin":
                pal_lvl = self._get_class_level("Paladin")
                cha_mod = max(0, self._effective_ability_mod("Charisma"))
                max_h = pal_lvl * cha_mod
                self._build_healing_pool_ui(frame, "Paladin", "lay_on_hands", max_h)

        # Render any custom features for this class (no header; + button is at top right)
        customs = [f for f in self.data.get("custom_features", []) if f.get("category") == cls_name]
        for cf in customs:
            try:
                gidx = self.data.get("custom_features", []).index(cf)
            except ValueError:
                gidx = -1
            if gidx >= 0:
                self._build_custom_feature_card(scroll, cf, cls_name, gidx)

    def _build_monk_flurry_ui(self, parent, cls_name, level):
        state = self.data.setdefault("class_feature_state", {})
        row1 = ctk.CTkFrame(parent, fg_color="transparent")
        row1.pack(fill="x", padx=15, pady=4)
        ctk.CTkLabel(row1, text="Flurry to-hit Ability:", width=140).pack(side="left")
        tohit_var = ctk.StringVar(value=state.get("monk_flurry_tohit_ability", "Strength"))
        tohit_combo = ctk.CTkComboBox(row1, values=list(ABILITY_NAMES), width=120, variable=tohit_var,
            command=lambda v: self._save_monk_flurry_choice("tohit_ability", v))
        tohit_combo.pack(side="left", padx=4)
        ctk.CTkLabel(row1, text="toHit Bonus:", width=80).pack(side="left", padx=(10, 0))
        tohit_b_var = ctk.IntVar(value=state.get("monk_flurry_tohit_bonus", 0))
        tohit_b_entry = ctk.CTkEntry(row1, textvariable=tohit_b_var, width=50)
        tohit_b_entry.pack(side="left", padx=2)
        tohit_b_entry.bind("<FocusOut>", lambda e: self._save_monk_flurry_choice("tohit_bonus", tohit_b_var.get()))

        row2 = ctk.CTkFrame(parent, fg_color="transparent")
        row2.pack(fill="x", padx=15, pady=4)
        ctk.CTkLabel(row2, text="Flurry damage Ability:", width=140).pack(side="left")
        dmg_var = ctk.StringVar(value=state.get("monk_flurry_damage_ability", "Strength"))
        dmg_combo = ctk.CTkComboBox(row2, values=list(ABILITY_NAMES), width=120, variable=dmg_var,
            command=lambda v: self._save_monk_flurry_choice("damage_ability", v))
        dmg_combo.pack(side="left", padx=4)
        ctk.CTkLabel(row2, text="Dmg Bonus:", width=80).pack(side="left", padx=(10, 0))
        dmg_b_var = ctk.IntVar(value=state.get("monk_flurry_damage_bonus", 0))
        dmg_b_entry = ctk.CTkEntry(row2, textvariable=dmg_b_var, width=50)
        dmg_b_entry.pack(side="left", padx=2)
        dmg_b_entry.bind("<FocusOut>", lambda e: self._save_monk_flurry_choice("damage_bonus", dmg_b_var.get()))

        ctk.CTkLabel(parent, text="Note: Uses Monk table base bonuses + chosen ability mod + bonuses. Unarmed damage die scales with level (Medium).", 
                     font=ctk.CTkFont(size=10), text_color="#888888").pack(anchor="w", padx=15, pady=(0, 4))

    def _save_monk_flurry_choice(self, key, val):
        state = self.data.setdefault("class_feature_state", {})
        state[f"monk_flurry_{key}"] = val
        self._mark_cloud_sync_dirty()
        if hasattr(self, "combat_frame") and getattr(self, "combat_frame", None) and self._is_page_active("Combat"):
            try:
                self.refresh_combat_page()
            except Exception:
                pass

    def _build_healing_pool_ui(self, parent, cls_name, pool_name, max_val):
        state = self.data.setdefault("class_feature_state", {})
        rem_key = f"{cls_name.lower()}_{pool_name}_remaining"
        remaining = int(state.get(rem_key, max_val))
        if remaining > max_val or remaining < 0:
            remaining = max(0, min(max_val, remaining))
            state[rem_key] = remaining

        row = ctk.CTkFrame(parent, fg_color="transparent")
        row.pack(fill="x", padx=15, pady=4)

        ctk.CTkLabel(row, text=f"{pool_name.replace('_', ' ').title()} remaining:", width=170).pack(side="left")
        rem_var = ctk.IntVar(value=remaining)
        rem_lbl = ctk.CTkLabel(row, textvariable=rem_var, width=50, font=ctk.CTkFont(weight="bold", size=13))
        rem_lbl.pack(side="left")
        ctk.CTkLabel(row, text=f" / {max_val}").pack(side="left", padx=2)

        def adjust(delta):
            new_val = max(0, min(max_val, rem_var.get() + delta))
            rem_var.set(new_val)
            state[rem_key] = new_val
            self._mark_cloud_sync_dirty()

        ctk.CTkButton(row, text="-", width=24, height=22, command=lambda: adjust(-1)).pack(side="left", padx=1)
        ctk.CTkButton(row, text="+", width=24, height=22, command=lambda: adjust(+1)).pack(side="left", padx=1)

    def _sync_domains_from_combos(self):
        domains = list(self.data.setdefault("domains", ["", ""]))
        while len(domains) < 2:
            domains.append("")
        for index, combo in enumerate(getattr(self, "domain_combos", [])):
            try:
                if not combo.winfo_exists():
                    continue
                value = combo.get().strip()
            except Exception:
                continue
            domains[index] = value
            self.data[f"domain_{index}"] = value
        self.data["domains"] = domains

    def _get_cleric_level(self):
        return self._get_class_level_total("Cleric")

    def _get_class_level_total(self, cls_name):
        return sum(
            lvl for cls, lvl in self._get_class_level_slots() if cls == cls_name
        )

    def _get_selected_domains(self):
        self._sync_domains_from_combos()
        domains = list(self.data.get("domains", ["", ""]))
        while len(domains) < 2:
            domains.append("")
        for index in range(2):
            if not domains[index]:
                flat = self.data.get(f"domain_{index}", "")
                if flat:
                    domains[index] = str(flat).strip()
        return domains

    def _on_domain_selected(self, index, value):
        self.save_domain(index, value)
        self.update_domain_preview()

    def save_domain(self, index, value):
        """Save domain choice and immediately refresh the preview."""
        domains = self.data.setdefault("domains", ["", ""])
        while len(domains) < 2:
            domains.append("")
        domains[index] = value.strip()
        self.data["domains"] = domains
        self.data[f"domain_{index}"] = value.strip()
        self._ensure_cleric_domain_spells_in_known()
        self.refresh_all()

    def _clear_domain_panel(self, panel):
        for widget in panel.winfo_children():
            widget.destroy()

    def update_domain_preview(self):
        """Side-by-side preview: granted powers (left) and domain spells (right)."""
        if not getattr(self, "domain_powers_panel", None) or not getattr(self, "domain_spells_panel", None):
            return
        try:
            if not self.domain_powers_panel.winfo_exists() or not self.domain_spells_panel.winfo_exists():
                return
        except Exception:
            return

        self._clear_domain_panel(self.domain_powers_panel)
        self._clear_domain_panel(self.domain_spells_panel)

        ctk.CTkLabel(
            self.domain_powers_panel, text="Granted Powers",
            font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626",
        ).pack(anchor="w", padx=10, pady=(8, 6))
        ctk.CTkLabel(
            self.domain_spells_panel, text="Domain Spells",
            font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626",
        ).pack(anchor="w", padx=10, pady=(8, 6))

        domains = self._get_selected_domains()
        selected = [
            (index, name) for index, name in enumerate(domains)
            if name and name in self.cleric_domains
        ]

        if not selected:
            placeholder = "Select domains above to see details here."
            ctk.CTkLabel(
                self.domain_powers_panel, text=placeholder,
                text_color="#888888", wraplength=250, justify="left",
                font=ctk.CTkFont(size=12, slant="italic"),
            ).pack(anchor="w", padx=10, pady=12)
            ctk.CTkLabel(
                self.domain_spells_panel, text=placeholder,
                text_color="#888888", wraplength=250, justify="left",
                font=ctk.CTkFont(size=12, slant="italic"),
            ).pack(anchor="w", padx=10, pady=12)
            self._mark_domain_preview_built()
            return

        for index, dom_name in selected:
            dom = self.cleric_domains[dom_name]

            power_card = ctk.CTkFrame(self.domain_powers_panel, fg_color="#333333")
            power_card.pack(fill="x", pady=4, padx=8)
            ctk.CTkLabel(
                power_card, text=f"Domain {index + 1}: {dom_name}",
                font=ctk.CTkFont(size=12, weight="bold"), text_color="#c77626",
            ).pack(anchor="w", padx=10, pady=(8, 4))
            ctk.CTkLabel(
                power_card, text=dom["granted_power"],
                wraplength=250, justify="left",
            ).pack(anchor="w", padx=10, pady=(0, 10))

            spell_card = ctk.CTkFrame(self.domain_spells_panel, fg_color="#333333")
            spell_card.pack(fill="x", pady=4, padx=8)
            ctk.CTkLabel(
                spell_card, text=f"Domain {index + 1}: {dom_name}",
                font=ctk.CTkFont(size=12, weight="bold"), text_color="#c77626",
            ).pack(anchor="w", padx=10, pady=(8, 4))
            max_d_lvl = self._get_max_castable_spell_level("Cleric") if self._get_cleric_level() > 0 else 9
            for lvl in range(1, max_d_lvl + 1):
                spell = dom["spells"][lvl - 1]
                ctk.CTkLabel(
                    spell_card, text=f"{lvl}: {spell}",
                    wraplength=250, justify="left",
                ).pack(anchor="w", padx=10, pady=1)
            ctk.CTkLabel(spell_card, text="").pack(pady=4)
        self._mark_domain_preview_built()

    def save_bonus_feat(self, key, value):
        """Save the chosen bonus feat so it survives refresh"""
        if getattr(self, "_rebuilding_ui", False):
            return
        stripped = value.strip() if value else ""
        base, legacy_spec = self._normalize_feat_selection(stripped)
        if getattr(self, "_feats_page_refreshing", False) and not base:
            return
        old_value = str(self.data.setdefault("bonus_feats", {}).get(key, "") or "").strip()
        new_value = base
        if new_value == old_value:
            return
        self.data["bonus_feats"][key] = new_value
        if legacy_spec and not self._get_feat_spec(key):
            self._save_feat_spec(key, legacy_spec, refresh_combat=False)
        self._on_feat_spec_feat_changed(key, new_value)
        self.root.after_idle(
            lambda ov=old_value, nv=new_value: self._apply_bonus_feat_side_effects(ov, nv)
        )

    def _apply_bonus_feat_side_effects(self, old_value, new_value):
        if getattr(self, "_switching_page", False) or self._focus_is_navigation():
            return
        old_value = str(old_value or "").strip()
        new_value = str(new_value or "").strip()
        if old_value == new_value:
            return
        scopes = self._feat_selection_refresh_scopes(old_value, new_value)
        if scopes:
            self.invalidate_caches()
            self._rebuild_feat_cache(sync_widgets=False)
            self.root.after(50, lambda s=scopes: self.refresh_feats_scope(*s))
        else:
            self._rebuild_feat_cache(sync_widgets=False)
            if self._feat_needs_spec_picker(new_value) or self._feat_needs_spec_picker(old_value):
                self.invalidate_caches(combat=True)
                if hasattr(self, "combat_frame"):
                    self._mark_combat_page_stale()
        if new_value in {"Extra Rings", "Forge Ring"} or old_value in {"Extra Rings", "Forge Ring"}:
            self.invalidate_caches()
            self.refresh_all()
        if scopes or new_value in {"Extra Rings", "Forge Ring"} or old_value in {"Extra Rings", "Forge Ring"}:
            self._sync_animal_companion()
            self._sync_familiar()
            self._sync_paladin_mount()

    def _end_feats_page_refresh(self):
        self._feats_page_refreshing = False

    def refresh_feats_page(self):
        """Refresh feats page - domains now restore correctly"""
        if not hasattr(self, 'feats_frame') or self.feats_frame is None:
            self.build_feats_page()
            return

        self._feats_page_refreshing = True
        self._sync_animal_companion()
        self._sync_familiar()
        self._sync_paladin_mount()
        try:
            self._push_feats_data_to_widgets()
            self._sync_feats_widgets_to_data()
            self._sync_general_feat_registry_keys()

            for widget in self.feats_frame.winfo_children():
                widget.destroy()

            self.build_feats_page()
            self._mark_feats_page_built()
        finally:
            self.root.after_idle(self._end_feats_page_refresh)
        print("✅ Feats & Features refreshed (domains restored)")

        # Force domain preview after rebuild
        if hasattr(self, 'update_domain_preview'):
            self.root.after(300, self.update_domain_preview)
        
    def _get_total_character_level(self):
        if self._class_ui_ready():
            total = 0
            for i in range(3):
                try:
                    total += int(self.level_vars[i].get() or 0)
                except (TypeError, ValueError, tk.TclError, IndexError, AttributeError):
                    continue
            return total
        return sum(int(level or 0) for level in self.data.get("levels", []))

    def _get_total_hit_dice(self):
        """Total HD for feat/ASI progression: class levels plus racial hit dice plus generic HD."""
        return (
            self._get_total_character_level()
            + self._get_racial_hit_dice_count()
            + self._get_generic_hd_count()
        )

    def _parse_xp_value(self, raw):
        """Coerce saved/cloud/widget XP to a non-negative int (handles floats and '12,000' strings)."""
        if raw is None or isinstance(raw, bool):
            return 0
        if isinstance(raw, int):
            return max(0, raw)
        if isinstance(raw, float):
            return max(0, int(raw))
        text = str(raw).replace(",", "").strip()
        if not text:
            return 0
        try:
            return max(0, int(text))
        except ValueError:
            try:
                return max(0, int(float(text)))
            except (TypeError, ValueError):
                return 0

    def _get_current_xp(self):
        if hasattr(self, "xp_var"):
            try:
                return self._parse_xp_value(self.xp_var.get())
            except (tk.TclError, AttributeError):
                pass
        return self._parse_xp_value(self.data.get("xp", 0))

    def _set_current_xp(self, xp):
        xp = self._parse_xp_value(xp)
        self.data["xp"] = xp
        if hasattr(self, "xp_var"):
            self.xp_var.set(str(xp))
        if hasattr(self, "xp_combo"):
            self.xp_combo.configure(values=self._xp_combobox_values())

    def _get_max_level_for_xp(self, xp=None):
        xp = self._get_current_xp() if xp is None else max(0, int(xp or 0))
        if xp < XP_LEVEL_THRESHOLDS[-1]:
            max_level = 1
            for index, threshold in enumerate(XP_LEVEL_THRESHOLDS):
                if xp >= threshold:
                    max_level = index + 1
            return max_level
        epic_xp = xp - XP_LEVEL_THRESHOLDS[-1]
        return 20 + epic_xp // EPIC_XP_PER_LEVEL

    def _xp_required_for_level(self, level):
        level = int(level or 1)
        if level < 1:
            return 0
        if level <= len(XP_LEVEL_THRESHOLDS):
            return XP_LEVEL_THRESHOLDS[level - 1]
        return XP_LEVEL_THRESHOLDS[-1] + (level - len(XP_LEVEL_THRESHOLDS)) * EPIC_XP_PER_LEVEL

    def _xp_to_next_level(self):
        ecl = self._get_effective_character_level()
        return self._xp_required_for_level(ecl + 1)

    def _per_level_entry_value(self, raw):
        try:
            return int(str(raw).replace(",", "").strip() or 0)
        except (TypeError, ValueError):
            return 0

    def _is_per_level_row_incomplete(self, hit_die_roll, skill_points):
        return (
            self._per_level_entry_value(hit_die_roll) <= 0
            or self._per_level_entry_value(skill_points) <= 0
        )

    def _has_missing_per_level_health_data(self):
        ui_level = self._get_total_character_level()
        committed = self._get_committed_health_level()
        levels_to_check = min(max(ui_level, committed), 20)
        if ui_level > 0 and committed < min(ui_level, 20):
            return True
        if committed <= 0 and ui_level > 0:
            return True
        rolls = self.data["health"].get("hit_dice_rolls", [])
        skill_pts = self.data["health"].get("skill_points_per_level", [])
        for i in range(levels_to_check):
            roll = rolls[i] if i < len(rolls) else 0
            sp = skill_pts[i] if i < len(skill_pts) else 0
            if self._is_per_level_row_incomplete(roll, sp):
                return True
        return False

    def _can_level_up(self):
        return self._get_effective_character_level() < self._get_max_level_for_xp()

    def _should_show_level_up_button(self):
        return self._can_level_up() or self._has_missing_per_level_health_data()

    def _xp_combobox_values(self):
        current = str(self._get_current_xp())
        milestones = [str(threshold) for threshold in XP_LEVEL_THRESHOLDS if threshold > 0]
        max_level = max(
            self._get_max_level_for_xp(),
            self._get_effective_character_level(),
            EPIC_CHARACTER_LEVEL,
        )
        for level in range(EPIC_CHARACTER_LEVEL, min(max_level + 4, 41)):
            milestones.append(str(self._xp_required_for_level(level)))
        values = []
        for item in [current, *milestones]:
            if item not in values:
                values.append(item)
        return values

    def _on_xp_combo_changed(self, _choice=None):
        xp = self._parse_xp_value(self.xp_var.get())
        self._set_current_xp(xp)
        self._sync_xp_to_data()
        self.refresh_level_up_button()
        self._schedule_priority_cloud_push(delay_ms=500)

    def refresh_xp_display(self):
        if not hasattr(self, "xp_var"):
            return
        xp = self._parse_xp_value(self.data.get("xp", 0))
        self.data["xp"] = xp
        self.xp_var.set(str(xp))
        if hasattr(self, "xp_combo"):
            self.xp_combo.configure(values=self._xp_combobox_values())

    def _format_hd_summary_text(self):
        char_level = self._get_total_character_level()
        total_hd = self._get_total_hit_dice()
        if total_hd <= 0 and char_level <= 0:
            return None
        parts = []
        if total_hd > 0:
            parts.append(f"HD: {total_hd}")
        if char_level >= EPIC_CHARACTER_LEVEL:
            parts.append(f"Epic {char_level}")
        elif char_level > 0:
            parts.append(f"Lvl {char_level}")
        return "  |  ".join(parts) if parts else None

    def _refresh_hd_summary_label(self):
        if not hasattr(self, "hd_summary_label"):
            return
        text = self._format_hd_summary_text()
        if text:
            self.hd_summary_label.configure(text=text)
            self._safe_pack(self.hd_summary_label, side="left", padx=(12, 0))
        else:
            self._safe_pack_forget(self.hd_summary_label)

    def refresh_level_up_button(self):
        btn = getattr(self, "level_up_btn", None)
        if not self._widget_is_alive(btn):
            return
        self._refresh_hd_summary_label()
        if self._should_show_level_up_button():
            self._safe_pack(btn, side="right")
        else:
            self._safe_pack_forget(btn)

    def _bind_classes_levels_ctrl_shift_click(self, *widgets):
        """Ctrl+Shift+click Classes & Levels opens hit dice / skill points manager."""
        bound = getattr(self, "_classes_levels_ctrl_shift_bound", None)
        if bound is None:
            self._classes_levels_ctrl_shift_bound = set()

        def on_click(event):
            if (event.state & 0x0005) != 0x0005:
                return
            self.open_health_manager()
            return "break"

        for widget in widgets:
            if widget is None or not self._widget_is_alive(widget):
                continue
            widget_id = id(widget)
            if widget_id in self._classes_levels_ctrl_shift_bound:
                continue
            widget.bind("<Button-1>", on_click, add="+")
            self._classes_levels_ctrl_shift_bound.add(widget_id)

        title = getattr(self, "classes_levels_title_label", None)
        if title and hasattr(self, "_bind_hover_tooltip"):
            self._bind_hover_tooltip(
                title,
                "Ctrl+Shift+click to open Hit Dice & Skill Points per Level.",
                wraplength=300,
            )

    def open_level_up_entry(self):
        """Blue +: level-up wizard when XP allows, else health manager for missing per-level data."""
        if self._can_level_up():
            self.open_level_up_wizard()
        elif self._has_missing_per_level_health_data():
            self.open_health_manager()
        else:
            messagebox.showinfo(
                "Level Up",
                "You do not have enough XP to advance, and per-level health data is complete.",
                parent=self.root,
            )

    def open_level_up_wizard(self):
        if not HAS_LEVEL_UP_WIZARD or LevelUpWizard is None:
            messagebox.showwarning(
                "Level Up",
                "Level-up wizard is not available (level_up_wizard.py missing).",
                parent=self.root,
            )
            return
        if not self._can_level_up():
            messagebox.showinfo(
                "Level Up",
                "You do not have enough XP to gain another level.",
                parent=self.root,
            )
            return

        def on_complete(result):
            if apply_level_up_to_sheet(self, result):
                messagebox.showinfo(
                    "Level Up",
                    f"{result.get('class_name', 'Character')} advanced to level "
                    f"{result.get('new_class_level', '?')}.",
                    parent=self.root,
                )

        LevelUpWizard(self, on_complete=on_complete)

    def open_add_xp_popup(self):
        popup = ctk.CTkToplevel(self.root)
        popup.title("Add Experience")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=440, min_height=300)

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=20, pady=16)

        ctk.CTkLabel(
            body, text="Add Experience Points",
            font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        current_xp = self._get_current_xp()
        class_level = self._get_total_character_level()
        ecl, ecl_detail = self._format_ecl_breakdown()
        max_level = self._get_max_level_for_xp(current_xp)
        next_xp = self._xp_to_next_level()
        info_lines = [
            f"Current XP: {current_xp:,}",
            f"Class levels: {class_level}",
        ]
        if ecl != class_level:
            info_lines.append(f"Effective character level (ECL): {ecl} ({ecl_detail})")
        la = self._get_racial_level_adjustment()
        if la:
            info_lines.append(f"Level adjustment: +{la}")
        info_lines.append(f"XP supports up to ECL: {max_level}")
        if next_xp is not None:
            remaining = max(0, next_xp - current_xp)
            info_lines.append(f"Next ECL at {next_xp:,} XP ({remaining:,} remaining)")
        ctk.CTkLabel(
            body, text="\n".join(info_lines), justify="left", text_color="#aaaaaa",
        ).pack(anchor="w", pady=(0, 12))

        amount_row = ctk.CTkFrame(body, fg_color="transparent")
        amount_row.pack(fill="x", pady=(0, 8))
        ctk.CTkLabel(amount_row, text="Amount:", width=70, anchor="w").pack(side="left")
        amount_var = ctk.StringVar(value="100")
        amount_combo = ctk.CTkComboBox(
            amount_row, values=list(XP_QUICK_ADD_OPTIONS), variable=amount_var, width=140,
        )
        amount_combo.pack(side="left", padx=(8, 0))

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=20, pady=(0, 16))

        def apply_xp():
            try:
                added = max(0, int(amount_var.get().replace(",", "").strip() or 0))
            except ValueError:
                messagebox.showerror("Add XP", "Enter a valid XP amount.", parent=popup)
                return
            self._set_current_xp(current_xp + added)
            self._sync_xp_to_data()
            self.refresh_level_up_button()
            self.refresh_all()
            self._schedule_priority_cloud_push(delay_ms=500)
            popup.destroy()

        ctk.CTkButton(
            footer, text="Add XP", width=120, fg_color=THEME_ORANGE, command=apply_xp,
        ).pack(side="right")
        ctk.CTkButton(
            footer, text="Cancel", width=100, fg_color="#666666", command=popup.destroy,
        ).pack(side="right", padx=(0, 8))

    def _get_general_feat_milestones(self, total_hd):
        """1st-level feat plus one every 3 HD (continues into epic)."""
        milestones = [1]
        milestones.extend(range(3, total_hd + 1, 3))
        return milestones

    def _get_asi_milestones(self, total_hd):
        """+1 ability every 4 HD (continues into epic)."""
        return list(range(4, total_hd + 1, 4))

    def _get_ability_score_improvement_bonus(self, ability_name):
        """+1 per ASI milestone where this ability was chosen (every 4 HD)."""
        total_hd = self._get_total_hit_dice()
        choices = self.data.get("ability_score_improvements", {})
        bonus = 0
        for milestone in self._get_asi_milestones(total_hd):
            if choices.get(str(milestone)) == ability_name:
                bonus += 1
        return bonus

    def _sync_health_per_level_rows_to_character_level(self):
        """Resize per-level HP/SP rows to match UI level — only via the level-up manager."""
        total_level = self._get_total_character_level()
        health = self.data.setdefault("health", {})
        rolls = list(health.get("hit_dice_rolls", []))
        skill_pts = list(health.get("skill_points_per_level", []))

        while len(rolls) < total_level:
            rolls.append(0)
        while len(skill_pts) < total_level:
            skill_pts.append(0)

        health["hit_dice_rolls"] = rolls[:total_level]
        health["skill_points_per_level"] = skill_pts[:total_level]
        # Ensure generic HD rolls list matches current count (non-class HD)
        self._ensure_generic_hd_rolls()
        return total_level

    def _constitution_mod_for_hp_baseline(self):
        """Con mod from sheet base stats only (no item/spell/buff ability enhancement)."""
        ab = "Constitution"
        try:
            base = int(self.data["abilities"][ab].get("base", 10) or 10)
        except (TypeError, ValueError, KeyError):
            base = 10
        racial = 0
        try:
            race_name = self._get_current_race()
            racial = int(self.races.get(race_name, {}).get(ABILITY_SHORT[ab], 0) or 0)
        except Exception:
            racial = 0
        misc = int(self.data["abilities"][ab].get("misc", 0) or 0)
        asi = self._get_ability_score_improvement_bonus(ab)
        age_mod = self._get_age_ability_mod(ab)
        score = base + racial + misc + asi + age_mod
        dmg = int(self.data.get("ability_damage", {}).get(ab, 0) or 0)
        score = max(0, score - dmg)
        return (score - 10) // 2

    def _calculate_max_hp_for_con_mod(self, con_mod):
        """Max HP for an explicit Con modifier (shared by calculate_max_hp and freeze correction)."""
        try:
            rolls = self.data["health"].get("hit_dice_rolls", [])
            committed_levels = len(rolls)
            rolls_sum = sum(
                self._effective_hit_die_roll_value(idx, roll)
                for idx, roll in enumerate(rolls)
            )
            feat_hp = self.get_feat_bonuses().get("hp_bonus", 0)
            spell_hp = self.get_spell_bonuses().get("max_hp_bonus", 0)
            racial_hp = self._get_racial_hd_hp_bonus()
            generic_hp = self._get_generic_hd_hp_bonus()
            neg_levels = int(self.data.get("negative_levels", 0) or 0)
            max_hp = (
                rolls_sum
                + (int(con_mod) * committed_levels)
                + feat_hp
                + spell_hp
                + racial_hp
                + generic_hp
                - (5 * neg_levels)
            )
            class_level = self._get_total_character_level()
            if class_level <= 0 and committed_levels <= 0:
                return max(0, max_hp)
            return max(1, max_hp)
        except Exception:
            if self._get_total_character_level() <= 0:
                return 0
            return 10

    def calculate_max_hp(self):
        """Max HP = hit dice rolls + (Con mod × committed levels) + feat bonus + active spell max HP."""
        return self._calculate_max_hp_for_con_mod(self._effective_ability_mod("Constitution"))

    def _init_health_data(self):
        health = self.data.setdefault("health", {})
        if "current_hp" in self.data:
            flat_hp = self.data.get("current_hp")
            if flat_hp not in (None, ""):
                try:
                    flat_int = int(flat_hp)
                except (TypeError, ValueError):
                    flat_int = None
                if flat_int is not None:
                    try:
                        health_int = int(health.get("current_hp", 0) or 0)
                    except (TypeError, ValueError):
                        health_int = 0
                    # Never let a stale flat widget value of 0 wipe a real health.current_hp.
                    if flat_int != 0 or health_int == 0:
                        health["current_hp"] = flat_int
        health.setdefault("current_hp", 0)
        health.setdefault("temp_hp", 0)
        health.setdefault("lethal_damage_taken", 0)
        health.setdefault("nonlethal_damage_taken", 0)
        health.setdefault("death_threshold", -10)
        health.setdefault("generic_hd_count", 0)
        health.setdefault("generic_hd_rolls", [])
        health.setdefault("level_adjustment", 0)
        health.setdefault("racial_hd_hp", 0)
        self.data.setdefault("spell_temp_hp", {})

    def _get_death_threshold(self):
        return int(self.data.get("health", {}).get("death_threshold", -10))

    def _health_damage_pools_can_reconcile(self):
        """True once ability totals include item/spell bonuses (Con affects max HP)."""
        if getattr(self, "_rebuilding_ui", False):
            return False
        if not hasattr(self, "ability_vars"):
            return False
        return bool(getattr(self, "_ability_bonuses_applied", False))

    def _get_stored_display_hp(self):
        """Best-effort display HP from saved JSON (cache only — pools are authoritative)."""
        health = self.data.get("health") or {}
        parsed = []
        for raw in (health.get("current_hp"), self.data.get("current_hp")):
            if raw in (None, ""):
                continue
            try:
                parsed.append(int(raw))
            except (TypeError, ValueError):
                continue
        if not parsed:
            return None
        positive = [value for value in parsed if value > 0]
        if positive:
            return max(positive)
        return parsed[0]

    def _clamp_lethal_damage_taken_value(self, value, max_hp=None):
        if max_hp is None:
            max_hp = self.calculate_max_hp()
        floor = self._get_death_threshold()
        max_taken = max(0, int(max_hp) - floor)
        return max(0, min(int(value or 0), max_taken))

    def _correct_frozen_lethal_pool_after_con_bonus(self, max_hp, lethal_taken, nl, stored_display):
        """Undo lethal inflation that froze display HP when Con item bonuses raised max HP."""
        if lethal_taken <= 0:
            return lethal_taken
        if stored_display is None:
            stored_display = max_hp - lethal_taken - nl
        frozen_lethal = max(0, max_hp - stored_display - nl)
        if lethal_taken != frozen_lethal:
            return lethal_taken
        try:
            baseline_max = self._calculate_max_hp_for_con_mod(
                self._constitution_mod_for_hp_baseline(),
            )
        except Exception:
            return lethal_taken
        con_bonus_delta = int(max_hp) - int(baseline_max)
        if con_bonus_delta <= 0:
            return lethal_taken
        corrected = lethal_taken - con_bonus_delta
        if corrected < 0:
            return lethal_taken
        corrected_display = max_hp - corrected - nl
        if corrected_display == stored_display + con_bonus_delta:
            return corrected
        return lethal_taken

    def _reconcile_health_damage_pools(self):
        """Migrate legacy HP fields or fix pools after max HP is fully calculated."""
        if not self._health_damage_pools_can_reconcile():
            return
        health = self.data.setdefault("health", {})
        nl = self._sanitize_nonlethal_damage(
            health.get("nonlethal_damage_taken", health.get("nonlethal_damage", 0)),
        )
        health["nonlethal_damage_taken"] = nl
        health["nonlethal_damage"] = nl

        try:
            max_hp = int(self.calculate_max_hp() or 0)
        except Exception:
            max_hp = 0
        if max_hp <= 0:
            return

        try:
            lethal_taken = max(0, int(health.get("lethal_damage_taken", 0) or 0))
        except (TypeError, ValueError):
            lethal_taken = 0

        stored_display = self._get_stored_display_hp()
        floor = self._get_death_threshold()

        if health.get("_damage_pools_v2") and lethal_taken > 0:
            if not health.get("_con_freeze_corrected"):
                corrected = self._correct_frozen_lethal_pool_after_con_bonus(
                    max_hp, lethal_taken, nl, stored_display,
                )
                if corrected != lethal_taken:
                    lethal_taken = corrected
                    health["_con_freeze_corrected"] = True
            health["lethal_damage_taken"] = self._clamp_lethal_damage_taken_value(
                lethal_taken, max_hp,
            )
            health["_damage_reconcile_max_hp"] = max_hp
            return

        if not health.get("_damage_pools_v2"):
            stored_damage = 0
            try:
                stored_damage = max(0, int(health.pop("damage", 0) or 0))
            except (TypeError, ValueError):
                stored_damage = 0
            if stored_display is not None and stored_display > 0 and stored_display < max_hp - nl:
                lethal_taken = max(0, max_hp - stored_display - nl)
            elif stored_display == 0 and nl > 0:
                lethal_taken = max(0, max_hp - nl)
            elif stored_damage > 0:
                lethal_taken = stored_damage
            elif lethal_taken > 0:
                pass
            elif stored_display is not None and stored_display >= max_hp - nl:
                lethal_taken = 0
            health["lethal_damage_taken"] = self._clamp_lethal_damage_taken_value(
                lethal_taken, max_hp,
            )
            health["_damage_pools_v2"] = True
        health["_damage_reconcile_max_hp"] = max_hp

    def _get_lethal_damage_taken(self):
        self._init_health_data()
        try:
            return max(0, int(self.data["health"].get("lethal_damage_taken", 0) or 0))
        except (TypeError, ValueError):
            return 0

    def _set_lethal_damage_taken(self, value):
        self._init_health_data()
        self.data["health"]["lethal_damage_taken"] = self._clamp_lethal_damage_taken_value(value)

    def _get_nonlethal_damage_taken(self):
        self._init_health_data()
        return self._sanitize_nonlethal_damage(
            self.data["health"].get(
                "nonlethal_damage_taken",
                self.data["health"].get("nonlethal_damage", 0),
            ),
        )

    def _set_nonlethal_damage_taken(self, value):
        value = self._sanitize_nonlethal_damage(value)
        self._init_health_data()
        self.data["health"]["nonlethal_damage_taken"] = value
        self.data["health"]["nonlethal_damage"] = value

    def _get_lethal_hp_remaining(self, max_hp=None):
        if max_hp is None:
            max_hp = self.calculate_max_hp()
        return int(max_hp) - self._get_lethal_damage_taken()

    def _compute_display_hp(self, max_hp=None):
        """HP shown on the sheet: max − lethal_damage_taken − nonlethal_damage_taken."""
        if max_hp is None:
            max_hp = self.calculate_max_hp()
        return (
            int(max_hp)
            - self._get_lethal_damage_taken()
            - self._get_nonlethal_damage_taken()
        )

    def _update_hp_display_cache(self):
        display = self._compute_display_hp()
        self.data.setdefault("health", {})["current_hp"] = display
        self.data["current_hp"] = display
        if hasattr(self, "current_hp_var"):
            try:
                self.current_hp_var.set(str(display))
            except Exception:
                pass

    def _sync_health_damage_pools_to_data(self):
        """Persist computed display HP alongside damage pools (pools are authoritative)."""
        if self._should_skip_widget_to_data_sync():
            return
        self._init_health_data()
        self._reconcile_health_damage_pools()
        health = self.data.setdefault("health", {})
        health["lethal_damage_taken"] = self._get_lethal_damage_taken()
        health["nonlethal_damage_taken"] = self._get_nonlethal_damage_taken()
        health["nonlethal_damage"] = health["nonlethal_damage_taken"]
        self._update_hp_display_cache()

    def _apply_lethal_damage(self, amount):
        """Damage temp HP first, then add to lethal_damage_taken."""
        amount = max(0, int(amount or 0))
        if amount <= 0:
            return
        temp_hp = self._get_temp_hp_value()
        if temp_hp > 0:
            absorbed = min(temp_hp, amount)
            self._set_temp_hp_value(temp_hp - absorbed)
            amount -= absorbed
        if amount > 0:
            self._set_lethal_damage_taken(self._get_lethal_damage_taken() + amount)

    def _apply_nonlethal_damage(self, amount):
        amount = max(0, int(amount or 0))
        if amount <= 0:
            return
        self._set_nonlethal_damage_taken(self._get_nonlethal_damage_taken() + amount)

    def _apply_healing(self, amount):
        """Clear nonlethal damage taken, then lethal damage taken. Temp HP is unchanged."""
        amount = max(0, int(amount or 0))
        if amount <= 0:
            return
        remaining = amount
        nonlethal = self._get_nonlethal_damage_taken()
        if nonlethal > 0:
            healed_nl = min(nonlethal, remaining)
            self._set_nonlethal_damage_taken(nonlethal - healed_nl)
            remaining -= healed_nl
        if remaining > 0:
            self._set_lethal_damage_taken(self._get_lethal_damage_taken() - remaining)

    def _is_character_dead(self, current_hp=None):
        lethal_remaining = (
            int(current_hp)
            if current_hp is not None
            else self._get_lethal_hp_remaining()
        )
        return lethal_remaining <= self._get_death_threshold()

    def _is_character_dying(self, current_hp=None):
        """Dying from lethal HP only (-9 through -1). Nonlethal alone never causes dying."""
        lethal_remaining = (
            int(current_hp)
            if current_hp is not None
            else self._get_lethal_hp_remaining()
        )
        floor = self._get_death_threshold()
        return lethal_remaining < 0 and lethal_remaining > floor

    def _is_character_staggered(self, current_hp=None, nonlethal=None):
        """Staggered at 0 lethal HP, or when nonlethal equals remaining lethal HP."""
        lethal_remaining = (
            int(current_hp)
            if current_hp is not None
            else self._get_lethal_hp_remaining()
        )
        if nonlethal is None:
            nonlethal = self._get_nonlethal_damage()
        if lethal_remaining == 0:
            return True
        return lethal_remaining > 0 and nonlethal > 0 and nonlethal >= lethal_remaining

    def _is_character_unconscious_from_nonlethal(self, current_hp=None, nonlethal=None):
        """Unconscious when nonlethal drives effective HP to death threshold or below."""
        lethal_remaining = (
            int(current_hp)
            if current_hp is not None
            else self._get_lethal_hp_remaining()
        )
        if nonlethal is None:
            nonlethal = self._get_nonlethal_damage()
        floor = self._get_death_threshold()
        if lethal_remaining <= floor:
            return False
        return (int(lethal_remaining) - int(nonlethal)) <= floor

    def _drop_wielded_weapons(self):
        """Move every wielded inventory weapon to dropped."""
        changed = False
        was_rebuilding = getattr(self, "_rebuilding_ui", False)
        self._rebuilding_ui = True
        try:
            for idx, weapon in enumerate(self.data.get("weapons", [])):
                if str(weapon.get("status", "")).strip().lower() != "wielded":
                    continue
                weapon["status"] = "dropped"
                changed = True
                if hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
                    try:
                        combo = self.weapon_vars[idx].get("status_combo")
                        if combo is not None:
                            combo.set("dropped")
                        else:
                            self.weapon_vars[idx]["status"].set("dropped")
                    except Exception:
                        pass
        finally:
            self._rebuilding_ui = was_rebuilding
        if changed:
            self._affliction_penalties_cache = None
            try:
                self.invalidate_caches()
            except Exception:
                pass
            if hasattr(self, "_refresh_wielded_weapons_feat_sliders"):
                try:
                    self._refresh_wielded_weapons_feat_sliders()
                except Exception:
                    pass

    def _apply_death_theme(self, active, restore_theme=None):
        """Grey death theme while dead; restore the character's chosen theme when revived."""
        if active:
            if not getattr(self, "_death_theme_active", False):
                health = self.data.setdefault("health", {})
                health["theme_before_death"] = self.data.get("theme", "Dicey Default")
            self._death_theme_active = True
            if DEATH_THEME_NAME in getattr(self, "THEMES", {}):
                self._apply_theme(DEATH_THEME_NAME)
            if hasattr(self, "sidebar_bg_canvas"):
                try:
                    self.sidebar_bg_canvas.configure(bg="#2a2a2a")
                except Exception:
                    pass
            return
        self._death_theme_active = False
        health = self.data.setdefault("health", {})
        theme_name = (
            restore_theme
            or health.pop("theme_before_death", None)
            or self.data.get("theme", "Dicey Default")
        )
        if theme_name == DEATH_THEME_NAME:
            theme_name = "Dicey Default"
        if theme_name in getattr(self, "THEMES", {}):
            self.current_theme = theme_name
            colors = self.THEMES[theme_name]
            self.primary_button_color = colors["nav"]
            self.primary_hover_color = colors.get("hover_nav", colors["nav"])
            self.secondary_button_color = colors.get("reload", colors.get("secondary", "#28a99e"))
            self.secondary_hover_color = colors.get("hover_reload", colors.get("hover_secondary", "#1f7f75"))
            self._apply_theme(theme_name)
        if hasattr(self, "sidebar_bg_canvas"):
            try:
                self._refresh_sidebar_background()
            except Exception:
                pass

    def _refresh_death_skull_overlay(self):
        """Large skull over the sidebar background while the character is dead."""
        if not hasattr(self, "sidebar_bg_canvas"):
            return
        canvas = self.sidebar_bg_canvas
        try:
            if not canvas.winfo_exists():
                return
        except tk.TclError:
            return
        canvas.delete("death_skull")
        if not self._is_character_dead():
            return
        try:
            canvas.update_idletasks()
            width = max(10, canvas.winfo_width())
            height = max(10, canvas.winfo_height())
            font_size = max(72, min(160, int(min(width, height) * 0.45)))
            canvas.create_text(
                width // 2,
                height // 2,
                text="☠",
                font=("Segoe UI Symbol", font_size, "bold"),
                fill="#5a5a5a",
                tags="death_skull",
            )
            canvas.tag_raise("death_skull")
        except Exception as exc:
            print(f"Death skull overlay error: {exc}")

    def _apply_hp_condition_effects(self):
        """Auto afflictions, weapon drops, and death visuals from current HP."""
        if not hasattr(self, "data"):
            return
        self._init_health_data()
        health = self.data.setdefault("health", {})
        auto = health.setdefault("auto_afflictions", {})
        lethal_remaining = self._get_lethal_hp_remaining()
        was_dead = bool(health.get("was_dead", False))
        nonlethal = self._get_nonlethal_damage()
        is_dead = self._is_character_dead(lethal_remaining)
        is_dying = self._is_character_dying(lethal_remaining)
        is_nl_unconscious = self._is_character_unconscious_from_nonlethal(lethal_remaining, nonlethal)
        is_staggered = self._is_character_staggered(lethal_remaining, nonlethal)
        if is_nl_unconscious:
            is_staggered = False

        if is_dead:
            health["was_dead"] = True
            self._apply_death_theme(True)
        else:
            if was_dead:
                self._apply_death_theme(False)
            health["was_dead"] = False
            self._refresh_death_skull_overlay()

        needs_helpless_prone = is_dying or is_nl_unconscious
        if needs_helpless_prone:
            entering_down = (
                (is_dying and not auto.get("dying"))
                or (is_nl_unconscious and not auto.get("nonlethal_unconscious"))
            )
            if is_dying:
                auto["dying"] = True
            if is_nl_unconscious:
                auto["nonlethal_unconscious"] = True
            if not auto.get("helpless"):
                self._set_affliction_active("Helpless", True)
                auto["helpless"] = True
            if not auto.get("prone"):
                self._set_affliction_active("Prone", True)
                auto["prone"] = True
            if entering_down:
                self._drop_wielded_weapons()
        else:
            if auto.pop("dying", False):
                pass
            if auto.pop("nonlethal_unconscious", False):
                pass
            if auto.pop("helpless", False):
                self._set_affliction_active("Helpless", False)
            if auto.pop("prone", False):
                self._set_affliction_active("Prone", False)

        if is_staggered:
            entering_staggered = not auto.get("staggered")
            if not auto.get("staggered"):
                self._set_affliction_active("Staggered", True)
                auto["staggered"] = True
            if entering_staggered:
                self._drop_wielded_weapons()
        else:
            if auto.pop("staggered", False):
                self._set_affliction_active("Staggered", False)

        if is_dead:
            self._refresh_death_skull_overlay()

        self._affliction_penalties_cache = None

    def _sync_health_to_data(self):
        self._sync_health_damage_pools_to_data()

    def _heal_character_to_full(self):
        """Clear damage pools and temporary HP."""
        self._init_health_data()
        health = self.data.setdefault("health", {})
        health["lethal_damage_taken"] = 0
        health["nonlethal_damage_taken"] = 0
        health["nonlethal_damage"] = 0
        health["temp_hp"] = 0
        self._last_known_max_hp = self.calculate_max_hp()
        self.refresh_health_display()

    def _sync_xp_to_data(self):
        try:
            xp = self._parse_xp_value(self.xp_var.get())
        except (tk.TclError, AttributeError):
            xp = self._parse_xp_value(self.data.get("xp", 0))
        self.data["xp"] = xp

    def _get_current_hp_value(self):
        return self._compute_display_hp()

    def _get_temp_hp_value(self):
        return max(0, int(self.data.get("health", {}).get("temp_hp", 0) or 0))

    def _sanitize_nonlethal_damage(self, value):
        """Nonlethal is always a positive pool — never negative lethal HP."""
        try:
            return max(0, abs(int(value or 0)))
        except (TypeError, ValueError):
            return 0

    def _get_nonlethal_damage(self):
        return self._get_nonlethal_damage_taken()

    def _get_effective_hp_value(self, current=None, nonlethal=None):
        """Effective HP after nonlethal (equals display HP with damage-pool model)."""
        if current is None and nonlethal is None:
            return self._compute_display_hp()
        lethal_remaining = (
            int(current) if current is not None else self._get_lethal_hp_remaining()
        )
        if nonlethal is None:
            nonlethal = self._get_nonlethal_damage()
        return int(lethal_remaining) - int(nonlethal)

    def _set_nonlethal_damage(self, value, *, refresh=True):
        self._set_nonlethal_damage_taken(value)
        if refresh and hasattr(self, "nonlethal_hp_label"):
            if value > 0:
                self.nonlethal_hp_label.configure(text=f"Nonlethal: (-{value})")
            else:
                self.nonlethal_hp_label.configure(text="Nonlethal: —")

    def _set_temp_hp_value(self, value):
        value = max(0, int(value or 0))
        self.data.setdefault("health", {})["temp_hp"] = value
        if hasattr(self, "temp_hp_label"):
            self.temp_hp_label.configure(text=str(value))
        self._schedule_priority_cloud_push(delay_ms=500)

    def _get_caster_level(self):
        return max(1, self._get_total_character_level())

    def _get_active_spell_temp_hp_values(self):
        values = []
        for entry in self.data.get("prepared_spells", []):
            entry_key = self._prepared_entry_key(entry)
            if self.data.get("spell_states", {}).get(entry_key) != "Active":
                continue
            stored = self.data.get("spell_temp_hp", {}).get(entry_key)
            if stored is not None:
                values.append(int(stored or 0))
            else:
                spell_name = self._normalize_prepared_entry(entry)["spell"]
                raw_effects = self.spells_db.get(spell_name, {}).get("effects", {}) or {}
                effects = self._resolve_spell_effects_for_caster_level(dict(raw_effects), spell_name)
                if effects.get("temp_hp") is not None:
                    values.append(int(effects["temp_hp"]))
        return values

    def _get_spell_skill_choice_options(self):
        return sorted({skill_name for skill_name, _ in self.all_skills})

    def _prompt_spell_skill_choice(self, spell_name, choice_cfg):
        skills = self._get_spell_skill_choice_options()
        if not skills:
            return None

        result = {"skill": None}
        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Skill Bonus — {spell_name}")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=460, min_height=240)

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=20, pady=(16, 8))

        prompt = choice_cfg.get(
            "prompt", "Choose which skill receives the spell bonus",
        )
        ctk.CTkLabel(body, text=prompt, wraplength=380, justify="left").pack(anchor="w")

        if choice_cfg.get("bonus_per_caster_level"):
            bonus_amount = self._get_caster_level_for_spell(spell_name)
            bonus_text = f"Bonus: +{bonus_amount} (caster level)"
        else:
            bonus_text = f"Bonus: +{int(choice_cfg.get('bonus', 1) or 1)}"
        ctk.CTkLabel(
            body, text=bonus_text, text_color="#c77626",
            font=ctk.CTkFont(weight="bold"),
        ).pack(anchor="w", pady=(8, 10))

        skill_var = ctk.StringVar(value=skills[0])
        ctk.CTkComboBox(
            body, values=skills, variable=skill_var, width=360,
        ).pack(anchor="w")

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=20, pady=(8, 16))

        def confirm():
            result["skill"] = skill_var.get().strip()
            popup.destroy()

        def cancel():
            popup.destroy()

        ctk.CTkButton(
            footer, text="Cancel", width=100, fg_color="#666666", command=cancel,
        ).pack(side="right", padx=(8, 0))
        ctk.CTkButton(
            footer, text="OK", width=100, fg_color=getattr(self, 'primary_button_color', '#c77626'), command=confirm,
        ).pack(side="right")

        popup.wait_window()
        return result["skill"]

    def _apply_spell_skill_on_activate(self, entry_key, spell_name):
        raw_effects = self.spells_db.get(spell_name, {}).get("effects", {}) or {}
        effects = self._resolve_spell_effects_for_caster_level(dict(raw_effects), spell_name)
        choice_cfg = effects.get("skill_bonus_choice")
        if not choice_cfg:
            return True
        if self.data.get("spell_skill_choices", {}).get(entry_key):
            return True
        chosen_skill = self._prompt_spell_skill_choice(spell_name, choice_cfg)
        if not chosen_skill:
            return False
        self.data.setdefault("spell_skill_choices", {})[entry_key] = chosen_skill
        return True

    def _prompt_spell_temp_hp(self, spell_name, effects):
        hint = effects.get("temp_hp_prompt")
        if not hint:
            parts = []
            if effects.get("temp_hp_roll"):
                parts.append(effects["temp_hp_roll"])
            if effects.get("temp_hp_per_level"):
                parts.append(f"+{effects['temp_hp_per_level']}/level")
            if effects.get("temp_hp_bonus"):
                parts.append(f"+{effects['temp_hp_bonus']}")
            if effects.get("temp_hp_max"):
                parts.append(f"(max +{effects['temp_hp_max']})")
            hint = "Enter temporary HP gained"
            if parts:
                hint += f" ({', '.join(parts)})"
        return self._prompt_for_int(
            f"Temporary HP — {spell_name}",
            hint,
            default=0,
            minvalue=0,
            maxvalue=999,
        )

    def _apply_spell_health_on_activate(self, entry_key, spell_name):
        spell = self.spells_db.get(spell_name, {})
        raw_effects = spell.get("effects", {}) or {}
        effects = self._resolve_spell_effects_for_caster_level(dict(raw_effects), spell_name)
        if not effects:
            return

        amount = None
        if effects.get("temp_hp") is not None:
            amount = int(effects["temp_hp"])
        elif any(
            key in effects
            for key in (
                "temp_hp_roll", "temp_hp_per_level", "temp_hp_bonus",
                "temp_hp_variable", "temp_hp_prompt",
            )
        ):
            if entry_key in self.data.get("spell_temp_hp", {}):
                amount = int(self.data["spell_temp_hp"][entry_key])
            else:
                amount = self._prompt_spell_temp_hp(spell_name, effects)

        if amount is None or amount <= 0:
            return

        self.data.setdefault("spell_temp_hp", {})[entry_key] = amount
        # "temp_hp" effect from activating a prepared spell sets (changes) the total Temp HP to the effect value
        self._set_temp_hp_value(amount)

    def _iter_class_daily_feature_trackers(self):
        for cls_name, class_level in self._get_class_level_slots():
            if class_level <= 0 or cls_name in (None, "None", ""):
                continue
            if cls_name not in self.classes_db:
                continue

            features_dict = self.classes_db[cls_name].get("features", {})
            best_features = {}
            for level_str in sorted(features_dict.keys(), key=int):
                level = int(level_str)
                if level > class_level:
                    continue
            for feat in features_dict[level_str]:
                    key = self._class_feature_dedupe_key(feat)
                    if not key:
                        continue
                    if key not in best_features or level > best_features[key][0]:
                        best_features[key] = (level, feat)

            for key, (_level, feat) in best_features.items():
                if not self._should_show_daily_tracker(feat):
                    continue
                use_count = self._compute_daily_use_count(cls_name, class_level, feat)
                if use_count > 0:
                    yield self._get_daily_tracker_key(cls_name, key), use_count

    def _reset_prepared_spells_for_rest(self):
        for entry in self.data.get("prepared_spells", []):
            entry_key = self._prepared_entry_key(entry)
            self.data.setdefault("spell_states", {})[entry_key] = "Ready"
            self.data.get("spell_temp_hp", {}).pop(entry_key, None)
            self.data.get("spell_skill_choices", {}).pop(entry_key, None)
            # Reset Eternal Wand daily uses (3/day recharges on rest)
            if (entry.get("consumable_type") or "").lower().replace("_", " ") == "eternal wand":
                entry["eternal_uses"] = [False, False, False]
        self.data["pending_prepared_spells"] = []
        self.data["combat_spell_attacks"] = []
        # Mark combat summaries stale so the Spells section is cleared on next view/build
        self._mark_combat_page_stale()
        # Reset any visible sword buttons to non-active (dim) state without rebuilding prepared list
        if hasattr(self, "prepared_widgets"):
            for ek, w in list(getattr(self, "prepared_widgets", {}).items()):
                self._set_sword_active(w.get("sword_btn"), False)

    def _reset_all_daily_abilities_for_rest(self):
        seen_daily = set()
        for key, use_count in self._iter_class_daily_feature_trackers():
            self._reset_daily_uses(key, use_count)
            seen_daily.add(key)
        for key, states in list(self.data.get("daily_feature_uses", {}).items()):
            if key not in seen_daily and states:
                self._reset_daily_uses(key, len(states))

        seen_magic = set()
        for item in self._get_all_magic_item_features():
            uses_per_day = int(item["abilities"].get("uses_per_day") or 0)
            if uses_per_day > 0:
                self._reset_magic_item_daily_uses(item["key"], uses_per_day)
                seen_magic.add(item["key"])
        for key, states in list(self.data.get("magic_item_daily_uses", {}).items()):
            if key not in seen_magic and states:
                self._reset_magic_item_daily_uses(key, len(states))

        # Reset Monk Wholeness and Paladin Lay on Hands pools on rest (using current level * mod)
        state = self.data.setdefault("class_feature_state", {})
        monk_lvl = self._get_class_level("Monk")
        if monk_lvl > 0:
            wis_mod = max(0, self._effective_ability_mod("Wisdom"))
            state["monk_wholeness_remaining"] = monk_lvl * wis_mod
        pal_lvl = self._get_class_level("Paladin")
        if pal_lvl > 0:
            cha_mod = max(0, self._effective_ability_mod("Charisma"))
            state["paladin_lay_on_hands_remaining"] = pal_lvl * cha_mod

        # Clear temporary per-weapon overrides in Attack Summaries (Enh/Threat/Damage boxes)
        # These are session-only and reset on rest
        combat = self.data.setdefault("combat", {})
        wcfgs = combat.setdefault("weapons", {})
        for cfg in wcfgs.values():
            if isinstance(cfg, dict):
                cfg["temp_enh"] = 0
                cfg["temp_threat"] = ""
                cfg["temp_damage"] = 0
                cfg["defend_amount"] = 0

    def _apply_rest_effects(self):
        """Core rest mechanics shared by voluntary and DM-forced rest."""
        self._reset_prepared_spells_for_rest()
        self._set_spell_prep_after_rest_available(True)
        self._reset_all_daily_abilities_for_rest()
        self._deactivate_rage_for_rest()
        self._deactivate_wild_shape_for_rest()
        self._clear_fatigue_for_rest()

        dmg = self.data.setdefault("ability_damage", {})
        for ab in list(dmg.keys()):
            dmg[ab] = max(0, dmg[ab] - 1)
        if hasattr(self, "abil_dmg_display"):
            try:
                self._update_ability_damage_display()
            except Exception:
                pass

        self._update_ability_name_styles()

        healing = self._get_total_character_level()
        if healing > 0:
            self.apply_hp_delta(healing)

        self.invalidate_caches()
        self.refresh_spells_page()
        self.refresh_feats_scope("class_tabs")
        self.refresh_all()

    def perform_rest(self):
        if not messagebox.askyesno(
            "Rest",
            "Take a rest?\n\n"
            "• Prepared spells return to Ready\n"
            "• Memorize / Meditate for Spells becomes available once\n"
            "• Regain HP equal to your character level\n"
            "• Remove Fatigued and Exhausted\n"
            "• End Rage and Wild Shape\n"
            "• Reset per-day class abilities and magical item uses\n"
            "• Reset Eternal Wand 3/day uses",
            parent=self.root,
        ):
            return
        self._apply_rest_effects()

    def _perform_forced_rest(self):
        """Apply DM-forced rest silently (no confirmation popup)."""
        self._apply_rest_effects()
        self._cloud_sync_dirty = True
        self._schedule_priority_cloud_push(delay_ms=500)

    def apply_hp_delta(self, delta):
        """Apply healing or lethal damage using damage-taken pools."""
        if delta == 0:
            return
        if delta < 0:
            self._apply_lethal_damage(-delta)
        else:
            self._apply_healing(delta)
        self._update_hp_display_cache()
        self.refresh_health_display()
        self._schedule_priority_cloud_push(delay_ms=500)

    def increment_current_hp(self):
        self.apply_hp_delta(1)

    def decrement_current_hp(self):
        self.apply_hp_delta(-1)

    def increment_temp_hp(self):
        self._set_temp_hp_value(self._get_temp_hp_value() + 1)

    def decrement_temp_hp(self):
        self._set_temp_hp_value(self._get_temp_hp_value() - 1)

    def _prompt_set_temp_hp(self):
        """Dark-mode popup to set the exact Temp HP total by typing a number."""
        current = self._get_temp_hp_value()

        popup = ctk.CTkToplevel(self.root)
        popup.title("Set Temp HP")
        popup.resizable(False, False)
        popup.configure(fg_color=THEME_DARK_BG)
        popup.transient(self.root)
        popup.grab_set()

        body = ctk.CTkFrame(popup, fg_color=THEME_DARK_BG)
        body.pack(fill="both", expand=True, padx=20, pady=(16, 8))

        primary = getattr(self, "primary_button_color", THEME_ORANGE)
        ctk.CTkLabel(
            body,
            text="Set Temp HP",
            font=ctk.CTkFont(size=18, weight="bold"),
            text_color=primary,
        ).pack(anchor="w", pady=(0, 6))
        ctk.CTkLabel(
            body,
            text=f"Enter new temporary HP total:\n(current: {current})",
            wraplength=300,
            justify="left",
            text_color="#cccccc",
        ).pack(anchor="w", pady=(0, 10))

        var = ctk.StringVar(value=str(current))
        entry = ctk.CTkEntry(body, textvariable=var, width=120)
        entry.pack(anchor="w", pady=(0, 4))
        entry.focus_set()
        try:
            entry.select_range(0, "end")
        except Exception:
            pass

        error_label = ctk.CTkLabel(body, text="", text_color="#ff6666", wraplength=280, justify="left")
        error_label.pack(anchor="w", pady=(0, 4))

        def on_ok():
            try:
                val = int(var.get().strip())
            except (ValueError, TypeError):
                error_label.configure(text="Enter a valid whole number.")
                return
            if val < 0:
                error_label.configure(text="Value must be at least 0.")
                return
            self._set_temp_hp_value(max(0, val))
            popup.destroy()

        def on_cancel():
            popup.destroy()

        entry.bind("<Return>", lambda _e: on_ok())
        entry.bind("<Escape>", lambda _e: on_cancel())
        popup.bind("<Escape>", lambda _e: on_cancel())

        btnf = ctk.CTkFrame(body, fg_color="transparent")
        btnf.pack(anchor="w", pady=(10, 0))
        ctk.CTkButton(
            btnf,
            text="OK",
            width=80,
            fg_color=primary,
            hover_color=getattr(self, "primary_hover_color", "#a85f1f"),
            command=on_ok,
        ).pack(side="left", padx=(0, 8))
        ctk.CTkButton(
            btnf,
            text="Cancel",
            width=80,
            fg_color="#555555",
            command=on_cancel,
        ).pack(side="left")

        self._size_and_center_popup_to_content(popup, min_width=340, min_height=200)
        self.root.wait_window(popup)

    def _parse_hp_delta_amount(self, *, show_error=True):
        raw = ""
        if hasattr(self, "hp_delta_var"):
            raw = self.hp_delta_var.get().strip()
        if not raw:
            if show_error:
                messagebox.showerror("Error", "Enter a number to apply.")
            return None
        try:
            amount = abs(int(raw))
        except ValueError:
            if show_error:
                messagebox.showerror("Error", "Enter a valid whole number (e.g. 8).")
            return None
        if amount <= 0:
            if show_error:
                messagebox.showerror("Error", "Enter a non-zero amount.")
            return None
        return amount

    def apply_lethal_damage_from_entry(self):
        amount = self._parse_hp_delta_amount()
        if amount is None:
            return
        self._apply_lethal_damage(amount)
        self._update_hp_display_cache()
        self.refresh_health_display()
        self._schedule_priority_cloud_push(delay_ms=500)
        self._reset_hp_delta_mitigation_used()

    def apply_nonlethal_damage_from_entry(self):
        """Add to nonlethal_damage_taken (display HP drops via damage-pool math)."""
        amount = self._parse_hp_delta_amount()
        if amount is None:
            return
        self._apply_nonlethal_damage(amount)
        self._update_hp_display_cache()
        self.refresh_health_display()
        self._schedule_priority_cloud_push(delay_ms=500)
        self._reset_hp_delta_mitigation_used()

    def heal_nonlethal_by_level(self):
        """Reduce nonlethal damage by the character's total level."""
        level = max(1, int(self._get_total_character_level() or 1))
        nonlethal = self._get_nonlethal_damage()
        if nonlethal <= 0:
            return
        self._set_nonlethal_damage(max(0, nonlethal - level), refresh=False)
        self.refresh_health_display()
        self._schedule_priority_cloud_push(delay_ms=500)

    def _health_widget_icon(self, filename, *, size=32):
        if HAS_HEALTH_UI_ICONS and load_grey_health_icon:
            return load_grey_health_icon(HEALTH_ASSETS_DIR, filename, size=size)
        return None

    def apply_heal_from_entry(self):
        amount = self._parse_hp_delta_amount()
        if amount is None:
            return
        self._apply_healing(amount)
        self._update_hp_display_cache()
        self.refresh_health_display()
        self._schedule_priority_cloud_push(delay_ms=500)
        self._reset_hp_delta_mitigation_used()

    def _increment_hp_delta_amount(self):
        current = self._get_hp_delta_combo_int() or 0
        self._set_hp_delta_combo_int(max(0, current) + 1)
        self._on_hp_delta_amount_changed()

    def _decrement_hp_delta_amount(self):
        current = self._get_hp_delta_combo_int() or 0
        self._set_hp_delta_combo_int(max(0, current - 1))
        self._on_hp_delta_amount_changed()

    def _on_hp_delta_amount_changed(self, _value=None):
        if not hasattr(self, "hp_delta_var"):
            return
        current = self.hp_delta_var.get().strip()
        last = getattr(self, "_hp_delta_combo_last", None)
        if last is not None and current != last:
            self._reset_hp_delta_mitigation_used()
        self._hp_delta_combo_last = current

    def _reset_hp_delta_mitigation_used(self):
        if not getattr(self, "_hp_delta_mitigation_used", None):
            self._hp_delta_mitigation_used = set()
        else:
            self._hp_delta_mitigation_used.clear()
        if hasattr(self, "defenses_scroll"):
            self.refresh_defenses()
        elif hasattr(self, "elemental_resistance_widgets"):
            self.refresh_elemental_resistance_display()

    def _get_hp_delta_combo_int(self):
        if hasattr(self, "hp_delta_var"):
            raw = self.hp_delta_var.get().strip()
        elif hasattr(self, "hp_delta_combo"):
            raw = self.hp_delta_combo.get().strip()
        else:
            return None
        if not raw:
            return None
        try:
            return int(raw)
        except ValueError:
            return None

    def _set_hp_delta_combo_int(self, value):
        text = str(max(0, int(value or 0)))
        if hasattr(self, "hp_delta_var"):
            self.hp_delta_var.set(text)
        elif hasattr(self, "hp_delta_combo"):
            self.hp_delta_combo.set(text)
        self._hp_delta_combo_last = text

    def _is_hp_delta_mitigation_used(self, source_key):
        return source_key in getattr(self, "_hp_delta_mitigation_used", set())

    def _mark_hp_delta_mitigation_used(self, source_key):
        used = getattr(self, "_hp_delta_mitigation_used", None)
        if used is None:
            used = set()
            self._hp_delta_mitigation_used = used
        used.add(source_key)

    def _mitigate_hp_delta_combo_by(self, amount, source_key):
        """Apply resistance/DR to pending lethal damage in the HP amount field (once per source)."""
        if self._is_hp_delta_mitigation_used(source_key):
            return False
        current = self._get_hp_delta_combo_int()
        if current is None or current <= 0:
            return False
        if amount is None or amount <= 0:
            return False
        self._set_hp_delta_combo_int(max(0, current - amount))
        self._mark_hp_delta_mitigation_used(source_key)
        if hasattr(self, "defenses_scroll"):
            self.refresh_defenses()
        elif hasattr(self, "elemental_resistance_widgets"):
            self.refresh_elemental_resistance_display()
        return True

    def _apply_elemental_resistance_to_hp_delta(self, element_key):
        results, _tooltips = self._get_elemental_resistance_breakdown()
        state = results.get(element_key)
        if not state:
            return
        current = self._get_hp_delta_combo_int()
        if current is None or current <= 0:
            return
        source_key = f"resist:{element_key}"
        if self._is_hp_delta_mitigation_used(source_key):
            return
        if state.get("immunity"):
            amount = current
        else:
            amount = state.get("value")
            if amount is None or amount <= 0:
                return
        self._mitigate_hp_delta_combo_by(amount, source_key)

    def _apply_dr_to_hp_delta(self, entry):
        if str(entry.get("type", "")).strip().lower() != "dr":
            return
        amount = self._parse_resistance_numeric_value(entry.get("value"))
        if amount is None or amount <= 0:
            return
        label = self._format_defense_entry_label(entry)
        self._mitigate_hp_delta_combo_by(amount, f"dr:{label}")

    def refresh_health_display(self):
        """Update the HP display on the Stats page from damage-taken pools."""
        if not hasattr(self, "current_hp_var"):
            return

        self._init_health_data()
        pools_ready = self._health_damage_pools_can_reconcile()
        if pools_ready:
            self._reconcile_health_damage_pools()
        max_hp = self.calculate_max_hp()
        temp_hp = self._get_temp_hp_value()
        floor = self._get_death_threshold()

        rage_snapshot = getattr(self, "_rage_end_hp_snapshot", None)
        if rage_snapshot is not None:
            # Barbarian rage end: keep displayed HP fixed when max drops from lost Con.
            display = int(rage_snapshot)
            nonlethal = self._get_nonlethal_damage_taken()
            self._set_lethal_damage_taken(max(0, max_hp - display - nonlethal))
            self._rage_end_hp_snapshot = None

        if pools_ready:
            display = self._compute_display_hp(max_hp)
        else:
            stored_hp = self._get_stored_display_hp()
            display = (
                stored_hp
                if stored_hp is not None
                else self._compute_display_hp(max_hp)
            )
        lethal_remaining = self._get_lethal_hp_remaining(max_hp)
        nonlethal = self._get_nonlethal_damage_taken()
        if pools_ready:
            self._update_hp_display_cache()
        elif hasattr(self, "current_hp_var"):
            try:
                self.current_hp_var.set(str(display))
            except Exception:
                pass
        self._last_known_max_hp = max_hp

        is_dead = lethal_remaining <= floor
        is_nl_unconscious = self._is_character_unconscious_from_nonlethal(lethal_remaining, nonlethal)
        effective_hp = lethal_remaining - nonlethal

        if is_dead:
            self.current_hp_label.configure(
                text="☠", font=ctk.CTkFont(size=34, weight="bold"), text_color="#b83232",
            )
        elif is_nl_unconscious:
            self.current_hp_label.configure(
                text=f"{effective_hp}/{max_hp}",
                font=ctk.CTkFont(size=28, weight="bold"),
                text_color="#9aa3b2",
            )
        else:
            self.current_hp_label.configure(
                text=f"{display}/{max_hp}",
                font=ctk.CTkFont(size=28, weight="bold"),
                text_color=("#DCE4EE", "#DCE4EE"),
            )

        max_note = f"Max: {max_hp}"
        active_spell_temps = self._get_active_spell_temp_hp_values()
        if active_spell_temps:
            max_note += "  (includes active spell bonuses)"
        self.max_hp_label.configure(text=max_note)

        if hasattr(self, "fast_healing_label"):
            fh = _warlock_support.get_active_fast_healing(self) if HAS_WARLOCK_SUPPORT else 0
            if fh > 0:
                self.fast_healing_label.configure(text=f"Fast Healing {fh} (Fiendish Resilience)")
            else:
                self.fast_healing_label.configure(text="")

        if hasattr(self, "temp_hp_label"):
            self.temp_hp_label.configure(text=str(temp_hp))

        self._set_nonlethal_damage(nonlethal, refresh=True)

        self._apply_hp_condition_effects()
        self._refresh_affliction_status_label()

    def _parse_hit_die_sides(self, hit_die):
        text = str(hit_die or "").strip().lower()
        match = re.search(r"d(\d+)", text)
        if match:
            return int(match.group(1))
        try:
            return int(text)
        except (TypeError, ValueError):
            return 0

    def _get_first_class_hit_die_sides(self):
        """Hit die sides for the first class with levels (used for level-1 max HD rule)."""
        for cls_name, lvl in self._get_class_level_slots():
            if not cls_name or cls_name == "None" or int(lvl or 0) <= 0:
                continue
            cls_info = (getattr(self, "classes_db", None) or {}).get(cls_name, {})
            sides = self._parse_hit_die_sides(cls_info.get("hit_die"))
            if sides:
                return sides
        return 0

    def _effective_hit_die_roll_value(self, level_index, roll_value):
        """Apply 3.5 rule: a character's first class HD is always maximum."""
        try:
            roll = int(roll_value or 0)
        except (TypeError, ValueError):
            roll = 0
        if level_index != 0 or roll <= 0:
            return roll
        class_max = self._get_first_class_hit_die_sides()
        if class_max:
            return max(roll, class_max)
        return roll

    def _show_fixed_hd_roll_popup(self, die_sides, level_num, roll_var):
        group = {
            "display": f"1d{die_sides}",
            "rolls": [die_sides],
            "modifier": 0,
            "total": die_sides,
            "min_total": die_sides,
            "max_total": die_sides,
        }
        label = f"L{level_num} HD (max)" if level_num == 1 else f"L{level_num} HD"
        roll_result = {
            "label": label,
            "formula": f"1d{die_sides}",
            "groups": [group],
            "result_text": str(die_sides),
        }

        def _apply_roll_result(_roll_result):
            if roll_var is not None:
                roll_var.set(str(die_sides))

        self._show_local_dice_roll_popup(roll_result, on_complete=_apply_roll_result)

    def _roll_hd_die_for_level(self, roll_var, sides, level_num):
        """Roll 1d{sides} for a class level HD entry and insert the result when the roll finishes."""
        try:
            die_sides = int(sides)
        except (TypeError, ValueError):
            return
        if die_sides not in (4, 6, 8, 10, 12):
            return
        if level_num == 1:
            self._show_fixed_hd_roll_popup(die_sides, level_num, roll_var)
            return

        character = self._get_talespire_character_name()
        roll_text = f"!{character} L{level_num} HD: 1d{die_sides}"

        def _apply_roll_result(roll_result):
            groups = (roll_result or {}).get("groups") or []
            if groups:
                total = int(groups[0].get("total", 0) or 0)
            else:
                try:
                    total = int(str((roll_result or {}).get("result_text", "0")).strip() or 0)
                except (TypeError, ValueError):
                    total = 0
            if total > 0 and roll_var is not None:
                roll_var.set(str(total))

        self._begin_local_dice_roll(roll_text, on_complete=_apply_roll_result)

    def open_health_manager(self):
        """Popup window for editing hit dice rolls AND skill points per level"""
        total_level = self._sync_health_per_level_rows_to_character_level()

        popup = ctk.CTkToplevel(self.root)
        popup.title("Health & Skill Points - Per Level")
        popup.grab_set()
        self._center_popup_on_root(popup, 920, 720)  # taller for many per-level rows on high-level characters

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=20, pady=(16, 8))

        title_row = ctk.CTkFrame(body, fg_color="transparent")
        title_row.pack(fill="x", pady=(0, 4))
        ctk.CTkLabel(
            title_row, text="Hit Dice Rolls & Skill Points per Level",
            font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(side="left")
        ctk.CTkLabel(
            body,
            text=f"Rows match your current character level ({total_level}).",
            text_color="#aaaaaa",
        ).pack(anchor="w", pady=(0, 4))

        # Informational text only (per user request): show class base skill points from Classes & Levels widget.
        # This is reference only; the boxes below are the final/actual skill points for each level.
        class_bases = self._get_current_class_skill_point_bases()
        if class_bases:
            base_text = "Class skill points per level (from Classes & Levels): " + ", ".join(
                f"{c}: {s}" for c, s in class_bases
            ) + " (first level is usually ×4; add Int mod yourself if desired when filling boxes)."
            ctk.CTkLabel(
                body,
                text=base_text,
                text_color="#888888",
                wraplength=700,
                justify="left",
            ).pack(anchor="w", pady=(0, 10))
        else:
            ctk.CTkLabel(
                body,
                text="No classes/levels set yet. Set classes on the Stats page for reference values.",
                text_color="#888888",
            ).pack(anchor="w", pady=(0, 10))

        # Level Adjustment and Racial HD (manual) — collapsed by default
        extra_frame = ctk.CTkFrame(body, fg_color="#2F2F2F", height=30)
        extra_frame.pack(fill="x", padx=5, pady=(0, 10))
        extra_frame.pack_propagate(False)
        la_section_expanded = {"value": False}
        extra_content = ctk.CTkFrame(extra_frame, fg_color="transparent")

        la_title_btn = ctk.CTkButton(
            extra_frame,
            text="▸ Manual Level adjustments",
            height=28,
            fg_color="#2F2F2F",
            hover_color="#3a3a3a",
            anchor="w",
            font=ctk.CTkFont(size=13, weight="bold"),
            text_color=getattr(self, "primary_button_color", THEME_ORANGE),
        )
        la_title_btn.pack(fill="x", padx=8, pady=1)

        la_row = ctk.CTkFrame(extra_content, fg_color="transparent")
        la_row.pack(fill="x", padx=12, pady=(8, 2))
        ctk.CTkLabel(la_row, text="Level Adjustment (manual / additional to racial LA):", width=320, anchor="w",
                     font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626").pack(side="left")
        self.level_adj_var = ctk.StringVar(
            value=str(self.data.get("health", {}).get("level_adjustment", 0) or 0)
        )
        ctk.CTkEntry(la_row, textvariable=self.level_adj_var, width=60).pack(side="left", padx=8)
        ctk.CTkLabel(la_row, text="(added to ECL; does not add HD or HP)", text_color="#888888").pack(side="left", padx=4)

        rhd_row = ctk.CTkFrame(extra_content, fg_color="transparent")
        rhd_row.pack(fill="x", padx=12, pady=(2, 8))
        ctk.CTkLabel(rhd_row, text="Racial HD (manual, can be 0):", width=200, anchor="w",
                     font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626").pack(side="left")
        ctk.CTkLabel(rhd_row, text="HD count (xCon):", font=ctk.CTkFont(size=11)).pack(side="left", padx=4)
        self.generic_hd_count_var = ctk.StringVar(  # keep original var name for rolls UI / trace compatibility
            value=str(self.data.get("health", {}).get("generic_hd_count", 0) or 0)
        )
        ctk.CTkEntry(rhd_row, textvariable=self.generic_hd_count_var, width=50).pack(side="left", padx=4)
        ctk.CTkLabel(rhd_row, text="+HP derived:", font=ctk.CTkFont(size=11)).pack(side="left", padx=4)
        self.racial_hd_hp_var = ctk.StringVar(
            value=str(self.data.get("health", {}).get("racial_hd_hp", 0) or 0)
        )
        ctk.CTkEntry(rhd_row, textvariable=self.racial_hd_hp_var, width=50).pack(side="left", padx=4)

        # Generic HD rolls (dynamic like racial)
        self.generic_hd_roll_widgets = []
        self.generic_hd_rolls_frame = ctk.CTkFrame(extra_content, fg_color="transparent")
        self.generic_hd_rolls_frame.pack(fill="x", padx=12, pady=(0, 6))

        def _set_la_section_expanded(expanded):
            la_section_expanded["value"] = bool(expanded)
            if la_section_expanded["value"]:
                extra_content.pack(fill="x", padx=0, pady=(0, 4))
                extra_frame.pack_propagate(True)
                la_title_btn.configure(text="▾ Manual Level adjustments")
                self._rebuild_generic_hd_rolls_ui()
            else:
                extra_content.pack_forget()
                extra_frame.pack_propagate(False)
                extra_frame.configure(height=30)
                la_title_btn.configure(text="▸ Manual Level adjustments")

        la_title_btn.configure(command=lambda: _set_la_section_expanded(not la_section_expanded["value"]))

        # trace to rebuild rolls UI when count changes
        self.generic_hd_count_var.trace_add(
            "write",
            lambda *_: self._rebuild_generic_hd_rolls_ui() if la_section_expanded["value"] else None,
        )

        hd_info = self._get_racial_hit_dice_info()
        racial_hd_count = self._get_racial_hit_dice_count()
        self.racial_hd_roll_widgets = []
        racial_hd_frame = None
        if hd_info and racial_hd_count > 0:
            racial_hd_frame = ctk.CTkFrame(body, fg_color="#2F2F2F")
            racial_hd_frame.pack(fill="x", padx=5, pady=(0, 10))
            hd_die = int(hd_info.get("die", 8) or 8)
            ctk.CTkLabel(
                racial_hd_frame,
                text=(
                    f"Racial Hit Dice ({racial_hd_count}d{hd_die}): enter each die roll. "
                    f"Max HP also gains Con mod × {racial_hd_count} from racial HD."
                ),
                font=ctk.CTkFont(size=13, weight="bold"),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                wraplength=700,
                justify="left",
            ).pack(anchor="w", padx=12, pady=(10, 6))
            rolls_row = ctk.CTkFrame(racial_hd_frame, fg_color="transparent")
            rolls_row.pack(fill="x", padx=12, pady=(0, 10))
            racial_rolls = self._ensure_racial_hd_rolls()
            for die_index in range(racial_hd_count):
                ctk.CTkLabel(
                    rolls_row, text=f"HD {die_index + 1}:", width=52, anchor="w",
                ).pack(side="left", padx=(0, 4))
                roll_value = racial_rolls[die_index] if die_index < len(racial_rolls) else 0
                roll_var = ctk.StringVar(value=str(roll_value))
                ctk.CTkEntry(rolls_row, textvariable=roll_var, width=56).pack(side="left", padx=(0, 10))
                self.racial_hd_roll_widgets.append(roll_var)
            racial_skill_pts = self._get_racial_hd_skill_points()
            ctk.CTkLabel(
                racial_hd_frame,
                text=(
                    f"Racial skill points (one-time reference): {racial_skill_pts} "
                    f"[6 × (2 + Int mod) for some races]. Enter any one-time racial points "
                    f"into the Level 1 skill points box below if you want them in your available pool."
                ),
                text_color="#aaaaaa",
                wraplength=700,
                justify="left",
            ).pack(anchor="w", padx=12, pady=(0, 10))

        header = ctk.CTkFrame(body, fg_color="#2F2F2F")
        header.pack(fill="x", padx=5, pady=(0, 6))
        ctk.CTkLabel(
            header, text="Level", width=70,
            font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626",
        ).pack(side="left", padx=(8, 0), pady=8)
        ctk.CTkLabel(
            header, text="Hit Die Roll (or roll)", width=250,
            font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626",
        ).pack(side="left", padx=8, pady=8)
        ctk.CTkLabel(
            header, text="Skill Points", width=150,
            font=ctk.CTkFont(size=13, weight="bold"), text_color="#c77626",
        ).pack(side="left", padx=8, pady=8)

        first_hd_max = self._get_first_class_hit_die_sides()
        first_hd_note = (
            "Level 1 HD is always maximum"
            + (f" (d{first_hd_max} for your first class)." if first_hd_max else ".")
        )
        ctk.CTkLabel(
            body,
            text=first_hd_note,
            text_color="#888888",
            wraplength=700,
            justify="left",
        ).pack(anchor="w", pady=(0, 6))

        scroll = ctk.CTkScrollableFrame(body, height=320)
        scroll.pack(fill="both", expand=True)

        self.hp_roll_widgets = []
        self.skill_points_widgets = []

        def rebuild_lists():
            for widget in scroll.winfo_children():
                widget.destroy()
            self.hp_roll_widgets.clear()
            self.skill_points_widgets.clear()

            level_count = self._sync_health_per_level_rows_to_character_level()
            rolls = self.data["health"].get("hit_dice_rolls", [])
            skill_pts = self.data["health"].get("skill_points_per_level", [])

            if level_count == 0:
                ctk.CTkLabel(
                    scroll,
                    text="Set your character level on the Stats page to edit per-level health and skill points.",
                    text_color="#888888", wraplength=640, justify="left",
                ).pack(anchor="w", padx=8, pady=16)
                return

            def update_row_highlight(row_frame, roll_var, sp_var):
                incomplete = self._is_per_level_row_incomplete(roll_var.get(), sp_var.get())
                row_frame.configure(
                    fg_color=THEME_ROSE_ROW if incomplete else "transparent",
                )

            for i in range(level_count):
                roll = rolls[i] if i < len(rolls) else 0
                sp = skill_pts[i] if i < len(skill_pts) else 0
                row_incomplete = self._is_per_level_row_incomplete(roll, sp)
                row = ctk.CTkFrame(
                    scroll,
                    fg_color=THEME_ROSE_ROW if row_incomplete else "transparent",
                )
                row.pack(fill="x", pady=3, padx=5)

                level_label = f"{i + 1}"
                if i == 0:
                    level_label = "1 (max HD)"
                ctk.CTkLabel(row, text=level_label, width=70, anchor="w").pack(side="left")

                roll_var = ctk.StringVar(value=str(roll))
                ctk.CTkEntry(row, textvariable=roll_var, width=56).pack(side="left", padx=(8, 4))
                self.hp_roll_widgets.append(roll_var)

                dice_btns = ctk.CTkFrame(row, fg_color="transparent")
                dice_btns.pack(side="left", padx=(0, 12))
                secondary = getattr(self, "secondary_button_color", THEME_TEAL)
                secondary_hover = getattr(self, "secondary_hover_color", "#1f7f75")
                for die_sides in (4, 6, 8, 10, 12):
                    ctk.CTkButton(
                        dice_btns,
                        text=f"d{die_sides}",
                        width=34,
                        height=22,
                        font=ctk.CTkFont(size=10, weight="bold"),
                        fg_color="#444444",
                        hover_color=secondary_hover,
                        command=lambda s=die_sides, rv=roll_var, lv=i + 1: self._roll_hd_die_for_level(rv, s, lv),
                    ).pack(side="left", padx=1)

                sp_var = ctk.StringVar(value=str(sp))
                ctk.CTkEntry(row, textvariable=sp_var, width=80).pack(side="left", padx=8)
                self.skill_points_widgets.append(sp_var)

                roll_var.trace_add("write", lambda *_a, r=row, rv=roll_var, sv=sp_var: update_row_highlight(r, rv, sv))
                sp_var.trace_add("write", lambda *_a, r=row, rv=roll_var, sv=sp_var: update_row_highlight(r, rv, sv))

        def save_and_close():
            new_rolls = []
            for var in self.hp_roll_widgets:
                try:
                    new_rolls.append(int(var.get() or 0))
                except Exception:
                    new_rolls.append(0)
            new_skill_pts = []
            for var in self.skill_points_widgets:
                try:
                    new_skill_pts.append(int(var.get() or 0))
                except Exception:
                    new_skill_pts.append(0)

            total = self._sync_health_per_level_rows_to_character_level()
            if new_rolls:
                new_rolls[0] = self._effective_hit_die_roll_value(0, new_rolls[0])
            self.data["health"]["hit_dice_rolls"] = new_rolls[:total]
            self.data["health"]["skill_points_per_level"] = new_skill_pts[:total]
            if getattr(self, "racial_hd_roll_widgets", None):
                new_racial_rolls = []
                for var in self.racial_hd_roll_widgets:
                    try:
                        new_racial_rolls.append(int(var.get() or 0))
                    except Exception:
                        new_racial_rolls.append(0)
                self.data["health"]["racial_hd_rolls"] = new_racial_rolls

            # Save level adj + racial HD (count + manual +hp) + rolls + LA (from top boxes)
            try:
                gen_count = max(0, int(getattr(self, "generic_hd_count_var", ctk.StringVar(value="0")).get() or 0))
            except Exception:
                gen_count = 0
            self.data["health"]["generic_hd_count"] = gen_count  # stored in generic for total HD / rolls compatibility
            try:
                rh_hp = max(0, int(getattr(self, "racial_hd_hp_var", ctk.StringVar(value="0")).get() or 0))
            except Exception:
                rh_hp = 0
            self.data["health"]["racial_hd_hp"] = rh_hp
            if getattr(self, "generic_hd_roll_widgets", None):
                new_gen_rolls = []
                for var in self.generic_hd_roll_widgets:
                    try:
                        new_gen_rolls.append(int(var.get() or 0))
                    except Exception:
                        new_gen_rolls.append(0)
                self.data["health"]["generic_hd_rolls"] = new_gen_rolls[:gen_count]
            try:
                man_la = max(0, int(getattr(self, "level_adj_var", ctk.StringVar(value="0")).get() or 0))
            except Exception:
                man_la = 0
            self.data["health"]["level_adjustment"] = man_la

            self.invalidate_caches()
            self.refresh_health_display()
            self.refresh_level_up_button()
            self.refresh_all()
            popup.destroy()

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=20, pady=(8, 20))

        footer_skill_text = (
            "Available skill ranks = sum of the Skill Points boxes you enter above. "
            "No Intelligence or other modifiers are auto-added (enter the final numbers you have). "
            "Class base values are shown above for reference only."
        )
        ctk.CTkLabel(
            footer,
            text=footer_skill_text,
            text_color="#888",
            wraplength=700,
            justify="left",
        ).pack(anchor="w")

        ctk.CTkButton(
            title_row, text="Save & Close", width=140, height=36,
            fg_color=getattr(self, 'primary_button_color', '#c77626'), command=save_and_close,
        ).pack(side="right")

        rebuild_lists()

    def _update_skill_points_label(self):
        if hasattr(self, "skill_points_label") and self._widget_is_alive(self.skill_points_label):
            try:
                self.skill_points_label.configure(text="Skills")
            except tk.TclError:
                pass

    def calculate_skill_points(self):
        """Calculate skill points spent vs available.

        Spent uses the actual rank in each Stats rank box (or saved data) times the
        per-skill purchase cost locked when ranks were first bought (1 class / 2 cross).
        Available is the sum of per-level skill point grants from creation/level-up.
        """
        try:
            skill_pts_list = self.data["health"].get("skill_points_per_level", [])
            total_available = sum(int(sp or 0) for sp in skill_pts_list)

            spent = 0
            for skill_key in self._iter_character_skill_keys():
                rank = self._get_skill_rank_value(skill_key)
                if rank <= 0:
                    continue
                step = self._get_skill_rank_step(skill_key)
                if step > 0:
                    spent += int(round(rank / step))

            return spent, total_available
        except Exception as e:
            print(f"Skill points calc error: {e}")
            return 0, 0

    # ===================== DEFENSES / RESISTANCES =====================
    def _get_defense_type_options(self):
        options = list(DEFENSE_TYPE_DEFAULTS)
        seen = {opt.casefold() for opt in options}
        for dtype in self.data.get("defense_type_options", []):
            text = str(dtype).strip()
            if text and text.casefold() not in seen:
                options.append(text)
                seen.add(text.casefold())
        for entry in self.data.get("defenses", []):
            text = str(entry.get("type", "")).strip()
            if text and text.casefold() not in seen:
                options.append(text)
                seen.add(text.casefold())
        return options

    def _configure_editable_defense_type_combo(self, combo):
        try:
            combo._entry.configure(state="normal")
        except Exception:
            pass

    def _remember_defense_type(self, dtype):
        text = str(dtype or "").strip()
        if not text:
            return
        if text not in DEFENSE_TYPE_DEFAULTS:
            extras = self.data.setdefault("defense_type_options", [])
            if text not in extras:
                extras.append(text)
        if hasattr(self, "def_type_combo"):
            current = self.def_type_combo.get()
            self.def_type_combo.configure(values=self._get_defense_type_options())
            self._configure_editable_defense_type_combo(self.def_type_combo)
            self.def_type_combo.set(current or text)

    def _iter_defense_entries(self):
        for entry in self._get_class_defense_entries():
            yield entry
        for entry in self.data.get("defenses", []):
            yield entry

    def _match_elemental_resistance_key(self, desc):
        desc_lower = str(desc or "").strip().lower()
        if not desc_lower:
            return None
        for element_key, keywords in ELEMENTAL_RESISTANCE_KEYWORDS.items():
            if any(keyword in desc_lower for keyword in keywords):
                return element_key
        return None

    def _parse_resistance_numeric_value(self, value):
        text = str(value or "").strip()
        if not text:
            return None
        match = re.search(r"\d+", text)
        if not match:
            return None
        try:
            return int(match.group())
        except ValueError:
            return None

    def _format_defense_entry_label(self, entry):
        return f"{entry.get('type', '')} {entry.get('value', '')} {entry.get('desc', '')}".strip()

    def _get_elemental_resistance_breakdown(self):
        results = {
            element_key: {
                "value": None,
                "immunity": False,
                "sources": [],
            }
            for element_key, _icon, _label, _color in ELEMENTAL_RESISTANCE_DEFS
        }

        for entry in self._iter_defense_entries():
            dtype = str(entry.get("type", "")).strip().lower()
            if dtype not in ("resistance", "immunity"):
                continue
            element_key = self._match_elemental_resistance_key(entry.get("desc", ""))
            if not element_key:
                element_key = self._match_elemental_resistance_key(entry.get("value", ""))
            if not element_key:
                continue

            label = self._format_defense_entry_label(entry)
            state = results[element_key]
            state["sources"].append(label)
            if dtype == "immunity":
                state["immunity"] = True
                continue

            amount = self._parse_resistance_numeric_value(entry.get("value"))
            if amount is None:
                continue
            if state["value"] is None or amount > state["value"]:
                state["value"] = amount

        tooltips = {}
        for element_key, _icon, label, _color in ELEMENTAL_RESISTANCE_DEFS:
            state = results[element_key]
            if state["immunity"]:
                display = "∞"
            elif state["value"] is not None:
                display = str(state["value"])
            else:
                display = ""

            tooltip_lines = [label]
            if state["sources"]:
                tooltip_lines.append("")
                tooltip_lines.extend(state["sources"])
            else:
                tooltip_lines.append("No matching entries in Defenses.")
            tooltips[element_key] = {
                "display": display,
                "active": bool(state["immunity"] or state["value"] is not None),
                "tooltip": "\n".join(tooltip_lines),
            }

        return results, tooltips

    def _build_elemental_resistance_panel(self, parent):
        ctk.CTkLabel(
            parent, text="Resistances",
            font=ctk.CTkFont(size=18, weight="bold"),
            anchor="center",
        ).pack(fill="x", padx=8, pady=(8, 6))

        grid = ctk.CTkFrame(parent, fg_color="transparent")
        grid.pack(fill="both", expand=True, padx=4, pady=(0, 8))
        for col_idx in range(2):
            grid.columnconfigure(col_idx, weight=1, uniform="element_resist")
        for row_idx in range(3):
            grid.rowconfigure(row_idx, weight=1)

        self.elemental_resistance_widgets = {}
        self._elemental_resistance_tooltips = {}

        for idx, (element_key, icon, label, color) in enumerate(ELEMENTAL_RESISTANCE_DEFS):
            row_idx = idx // 2
            col_idx = idx % 2
            colspan = 2 if idx == len(ELEMENTAL_RESISTANCE_DEFS) - 1 else 1
            cell = ctk.CTkFrame(grid, fg_color="transparent", cursor="hand2")
            cell.grid(
                row=row_idx,
                column=col_idx,
                columnspan=colspan,
                padx=2,
                pady=4,
                sticky="nsew",
            )

            icon_slot = ctk.CTkFrame(
                cell,
                fg_color="transparent",
                width=ELEMENTAL_RESISTANCE_ICON_SIZE,
                height=ELEMENTAL_RESISTANCE_ICON_SIZE,
            )
            icon_slot.pack(anchor="center")
            icon_slot.pack_propagate(False)

            icon_lbl = ctk.CTkLabel(
                icon_slot,
                text=icon,
                font=ctk.CTkFont(size=22),
                text_color=THEME_GREY,
                cursor="hand2",
                width=ELEMENTAL_RESISTANCE_ICON_SIZE,
                height=ELEMENTAL_RESISTANCE_ICON_SIZE,
                anchor="center",
            )
            icon_lbl.place(relx=0.5, rely=0.5, anchor="center")

            value_lbl = ctk.CTkLabel(
                cell,
                text="",
                font=ctk.CTkFont(size=13, weight="bold"),
                text_color=THEME_ORANGE,
                cursor="hand2",
                anchor="center",
            )
            value_lbl.pack(anchor="center", pady=(1, 0))

            self.elemental_resistance_widgets[element_key] = {
                "cell": cell,
                "icon": icon_lbl,
                "value": value_lbl,
                "label": label,
                "color": color,
            }
            for widget in (cell, icon_slot, icon_lbl, value_lbl):
                self._bind_elemental_resistance_hover(widget, element_key)
                self._bind_elemental_resistance_click(widget, element_key)

    def _bind_elemental_resistance_click(self, widget, element_key):
        widget.bind(
            "<Button-1>",
            lambda _e, key=element_key: self._apply_elemental_resistance_to_hp_delta(key),
            add="+",
        )

    def _bind_elemental_resistance_hover(self, widget, element_key):
        def on_enter(_event):
            text = self._elemental_resistance_tooltips.get(element_key, "")
            if not text:
                return
            self._cancel_hover_tooltip()
            self._hover_tooltip_widget = widget
            self._hover_tooltip_after_id = self.root.after(
                300,
                lambda: self._display_hover_tooltip(widget, text, 260),
            )

        def on_leave(_event):
            self._cancel_hover_tooltip()

        widget.bind("<Enter>", on_enter)
        widget.bind("<Leave>", on_leave)

    def refresh_elemental_resistance_display(self):
        if not hasattr(self, "elemental_resistance_widgets"):
            return
        try:
            _results, tooltips = self._get_elemental_resistance_breakdown()
            for element_key, widgets in self.elemental_resistance_widgets.items():
                icon_widget = widgets.get("icon")
                value_widget = widgets.get("value")
                if not self._widget_is_alive(icon_widget) or not self._widget_is_alive(value_widget):
                    continue
                info = tooltips.get(element_key, {})
                display = info.get("display", "")
                active = bool(info.get("active"))
                tooltip = info.get("tooltip", "")
                self._elemental_resistance_tooltips[element_key] = tooltip

                used = self._is_hp_delta_mitigation_used(f"resist:{element_key}")
                if active and not used:
                    icon_widget.configure(text_color=widgets["color"])
                    value_widget.configure(text=display, text_color=widgets["color"])
                elif active and used:
                    icon_widget.configure(text_color=THEME_GREY)
                    value_widget.configure(text=display, text_color=THEME_GREY)
                else:
                    icon_widget.configure(text_color=THEME_GREY)
                    value_widget.configure(text="", text_color=THEME_GREY)
        except tk.TclError:
            pass
        except Exception as exc:
            print(f"Elemental resistance display error: {exc}")
        self._refresh_combat_footer_resistances()

    def _refresh_combat_footer_resistances(self):
        panel = getattr(self, "combat_resist_panel", None)
        if not self._widget_is_alive(panel):
            return
        try:
            if not hasattr(self, "_elemental_resistance_tooltips"):
                self._elemental_resistance_tooltips = {}
            for widget in panel.winfo_children():
                widget.destroy()

            _results, tooltips = self._get_elemental_resistance_breakdown()
            active_elements = []
            for element_key, icon, label, color in ELEMENTAL_RESISTANCE_DEFS:
                info = tooltips.get(element_key, {})
                if not info.get("active"):
                    continue
                self._elemental_resistance_tooltips[element_key] = info.get("tooltip", "")
                active_elements.append((element_key, icon, label, color, info.get("display", "")))

            if not active_elements:
                return

            # Center the resistance row both horizontally (in the middle of the bar via the
            # middle panel) and vertically within the fixed 55px footer.
            panel.grid_rowconfigure(0, weight=1)
            panel.grid_columnconfigure(0, weight=1)

            row = ctk.CTkFrame(panel, fg_color="transparent")
            row.grid(row=0, column=0, sticky="ns")  # span height; width controlled by content

            # Make the single inner row take available height so the content can center vertically too
            row.grid_rowconfigure(0, weight=1)

            # Horizontal centering for the elemental resistance group:
            # weighted spacer columns on left (0) and right (2) push the tight content group
            # (column 1) into the exact horizontal center of the middle section.
            row.grid_columnconfigure(0, weight=1)
            row.grid_columnconfigure(2, weight=1)

            content = ctk.CTkFrame(row, fg_color="transparent")
            content.grid(row=0, column=1, sticky="")  # natural size, centered by spacers (horiz + vert)

            for element_key, icon, label, color, display in active_elements:
                cell = ctk.CTkFrame(content, fg_color="transparent", cursor="hand2")
                cell.pack(side="left", padx=6)

                icon_slot = ctk.CTkFrame(
                    cell,
                    fg_color="transparent",
                    width=COMBAT_ELEMENTAL_RESIST_ICON_SIZE,
                    height=COMBAT_ELEMENTAL_RESIST_ICON_SIZE,
                )
                icon_slot.pack(anchor="center")
                icon_slot.pack_propagate(False)

                icon_lbl = ctk.CTkLabel(
                    icon_slot,
                    text=icon,
                    font=ctk.CTkFont(size=18),
                    text_color=color,
                    cursor="hand2",
                    width=COMBAT_ELEMENTAL_RESIST_ICON_SIZE,
                    height=COMBAT_ELEMENTAL_RESIST_ICON_SIZE,
                    anchor="center",
                )
                icon_lbl.place(relx=0.5, rely=0.5, anchor="center")

                value_lbl = ctk.CTkLabel(
                    cell,
                    text=display,
                    font=ctk.CTkFont(size=13, weight="bold"),
                    text_color=color,
                    cursor="hand2",
                    anchor="center",
                )
                value_lbl.pack(anchor="center", pady=(1, 0))

                for widget in (cell, icon_slot, icon_lbl, value_lbl):
                    self._bind_elemental_resistance_hover(widget, element_key)
        except tk.TclError:
            pass
        except Exception as exc:
            print(f"Combat resistance footer error: {exc}")

    def add_defense(self):
        """Add manual defense from Stats page"""
        dtype = self.def_type_combo.get().strip()
        value = self.def_value_entry.get().strip()
        desc = self.def_desc_entry.get().strip()

        if not dtype or not desc:
            messagebox.showwarning("Missing Info", "Type and Description required.")
            return

        self._remember_defense_type(dtype)
        self.data.setdefault("defenses", []).append({
            "type": dtype,
            "value": value,          # now accepts strings like "10/adamantine"
            "desc": desc
        })
        self.def_value_entry.delete(0, "end")
        self.def_desc_entry.delete(0, "end")
        self.refresh_defenses()
        self._on_defenses_data_changed()

    def remove_defense(self, idx):
        """Remove a defense entry"""
        defenses = self.data.setdefault("defenses", [])
        if 0 <= idx < len(defenses):
            del defenses[idx]
            self.refresh_defenses()
            self._on_defenses_data_changed()

    def _get_racial_defense_entries(self):
        """Auto resistance/immunity entries granted by the current race."""
        entries = []
        race_name = self._get_current_race()
        resistances = self._get_race_data(race_name).get("elemental_resistances", {}) or {}
        label_by_key = {
            element_key: label for element_key, _icon, label, _color in ELEMENTAL_RESISTANCE_DEFS
        }
        for element_key, amount in resistances.items():
            try:
                resist_value = int(amount or 0)
            except (TypeError, ValueError):
                continue
            if resist_value <= 0:
                continue
            element_label = label_by_key.get(element_key, str(element_key).title())
            entries.append({
                "type": "Resistance",
                "value": str(resist_value),
                "desc": f"{element_label} ({race_name} racial)",
                "auto": True,
            })
        return entries

    def _get_class_defense_entries(self):
        entries = []
        dr = self._get_barbarian_class_bonuses().get("damage_reduction", 0)
        if dr:
            entries.append({
                "type": "DR",
                "value": f"{dr}/-",
                "desc": "Barbarian (class)",
                "auto": True,
            })
        warlock_dr = self._get_warlock_class_bonuses().get("damage_reduction", "")
        if warlock_dr:
            entries.append({
                "type": "DR",
                "value": warlock_dr,
                "desc": "Warlock (class)",
                "auto": True,
            })
        if HAS_WARLOCK_SUPPORT:
            warlock_level = self._get_warlock_level()
            resist_amount = _warlock_support.get_warlock_energy_resistance_amount(warlock_level)
            for energy_type in _warlock_support.get_warlock_energy_resistance_types(self.data):
                if resist_amount > 0:
                    entries.append({
                        "type": "Resistance",
                        "value": str(resist_amount),
                        "desc": f"{energy_type.title()} (Warlock Energy Resistance)",
                        "auto": True,
                    })
        entries.extend(self._get_racial_defense_entries())
        entries.extend(self._get_special_feature_defense_entries())
        entries.extend(self._get_equipment_defense_entries())
        entries.extend(self._get_magic_item_defense_entries())
        return entries

    def refresh_defenses(self):
        """Rebuild the scrolling defenses list"""
        if not hasattr(self, 'defenses_scroll'):
            return
        for widget in self.defenses_scroll.winfo_children():
            widget.destroy()

        for d in self._get_class_defense_entries():
            row = ctk.CTkFrame(self.defenses_scroll)
            row.pack(fill="x", pady=2, padx=5)
            txt = self._format_defense_entry_label(d)
            is_dr = str(d.get("type", "")).strip().lower() == "dr"
            dr_used = is_dr and self._is_hp_delta_mitigation_used(f"dr:{txt}")
            lbl = ctk.CTkLabel(
                row, text=txt, anchor="w",
                text_color=THEME_GREY if dr_used else THEME_ORANGE,
                cursor="hand2" if is_dr else "arrow",
            )
            lbl.pack(side="left", padx=5, fill="x", expand=True)
            if is_dr:
                lbl.bind("<Button-1>", lambda _e, entry=d: self._apply_dr_to_hp_delta(entry))
        
        for idx, d in enumerate(self.data.get("defenses", [])):
            row = ctk.CTkFrame(self.defenses_scroll)
            row.pack(fill="x", pady=2, padx=5)
            
            txt = self._format_defense_entry_label(d)
            is_dr = str(d.get("type", "")).strip().lower() == "dr"
            dr_used = is_dr and self._is_hp_delta_mitigation_used(f"dr:{txt}")
            lbl = ctk.CTkLabel(
                row, text=txt, anchor="w",
                text_color=THEME_GREY if dr_used else None,
                cursor="hand2" if is_dr else "arrow",
            )
            lbl.pack(side="left", padx=5, fill="x", expand=True)
            if is_dr:
                lbl.bind("<Button-1>", lambda _e, entry=d: self._apply_dr_to_hp_delta(entry))
            
            ctk.CTkButton(row, text="−", width=30, height=28, fg_color=getattr(self, 'primary_button_color', '#c77626'),
                          command=lambda i=idx: self.remove_defense(i)).pack(side="right", padx=5)

        self.refresh_elemental_resistance_display()

    def auto_add_defense_from_spell(self, spell_name):
        """Auto-add defenses when a spell is set to 'Active'"""
        if spell_name not in self.spells_db:
            return
        
        spell = self.spells_db[spell_name]
        auto_list = spell.get("auto_defenses", [])
        
        defenses = self.data.setdefault("defenses", [])
        added = False

        for auto in auto_list:
            new_def = {
                "type": auto.get("type", "Resistance"),
                "value": auto.get("value", ""),           # supports "10/adamantine", "20", etc.
                "desc": auto.get("string", auto.get("desc", ""))
            }
            
            # Prevent duplicates
            if not any(
                d["type"] == new_def["type"] and 
                str(d["value"]) == str(new_def["value"]) and 
                d["desc"] == new_def["desc"]
                for d in defenses
            ):
                defenses.append(new_def)
                added = True
        
        self.refresh_defenses()
        if added:
            self._on_defenses_data_changed()
    # ===================== END DEFENSES =====================
    # ===================== END HEALTH SYSTEM =====================

    # ===================== COMBAT PAGE =====================
    def _build_combat_modifiers_panel(self, parent):
        """Attack maneuvers (BAtk Bonus, Grapple/Gpl, Trip, etc.) — two-column layout so all are visible
        inside the fixed-width Combat Modifiers sidebar on the Combat page.
        """
        panel = ctk.CTkFrame(parent, fg_color="#2F2F2F")
        panel.pack(fill="both", expand=True, padx=8, pady=8)

        ctk.CTkLabel(
            panel, text="Combat Modifiers",
            font=ctk.CTkFont(size=16, weight="bold"), text_color="#c77626",
        ).pack(anchor="w", padx=12, pady=(10, 6))

        attack_frame = ctk.CTkFrame(panel, fg_color="transparent")
        attack_frame.pack(fill="x", padx=12, pady=4)

        ctk.CTkLabel(
            attack_frame, text="Attack Maneuvers",
            font=ctk.CTkFont(size=14, weight="bold"),
        ).pack(anchor="w", pady=(0, 4))

        # Two-column grid so the full list (BAtk, Gpl, Trip, Sunder, Feint, Disarm, Bull Rush)
        # is visible without clipping or excessive height in the narrow sidebar.
        maneuvers = [
            ("BAtk Bonus", "bab_label", "Attack", self._get_talespire_attack_bonus_total, "attack"),
            ("Gpl", "grapple_label", "Grapple", self._get_talespire_grapple_total, "grapple"),
            ("Trip", "trip_label", "Trip", self._get_talespire_trip_total, "trip"),
            ("Sunder", "sunder_label", "Sunder", self._get_talespire_sunder_total, "sunder"),
            ("Feint", "feint_label", "Feint", self._get_talespire_feint_total, "feint"),
            ("Disarm", "disarm_label", "Disarm", self._get_talespire_disarm_total, "disarm"),
            ("Bull Rush", "bull_rush_label", "Bull Rush", self._get_talespire_bull_rush_total, "bull_rush"),
        ]

        grid = ctk.CTkFrame(attack_frame, fg_color="transparent")
        grid.pack(fill="x", padx=2, pady=2)
        grid.grid_columnconfigure(0, weight=1)
        grid.grid_columnconfigure(1, weight=1)

        for idx, (short_name, attr_name, roll_label, getter, maneuver_key) in enumerate(maneuvers):
            r = idx // 2
            c = idx % 2
            lbl = ctk.CTkLabel(grid, text=f"{short_name}: +0")
            lbl.grid(row=r, column=c, sticky="w", padx=6, pady=2)
            setattr(self, attr_name, lbl)
            self._bind_talespire_click(
                lbl,
                lambda rl=roll_label, gt=getter: self._build_talespire_attack_roll(gt(), rl),
            )
            self._bind_hover_tooltip_builder(
                lbl,
                lambda mk=maneuver_key: self._build_attack_maneuver_tooltip(mk),
                wraplength=320,
                delay_ms=1000,
            )

    def _get_talespire_attack_bonus_total(self):
        bab = self._get_total_bab()
        size_attack = self._get_size_category_modifiers()["attack"]
        ce_penalty = self.get_combat_expertise_attack_penalty()
        armor_nonproficiency_penalty = self._get_armor_nonproficiency_check_penalty()
        return bab + size_attack + ce_penalty + armor_nonproficiency_penalty

    def _get_talespire_grapple_total(self):
        bab = self._get_total_bab()
        str_mod = self._ability_mod("Strength")
        grapple_size = self._get_size_category_modifiers()["grapple"]
        return (
            bab + str_mod + grapple_size
            + self._get_combat_maneuver_enchant_bonus("grapple")
        )

    def _get_talespire_trip_total(self):
        return (
            self._get_total_bab() + self._ability_mod("Strength")
            + self._get_combat_maneuver_enchant_bonus("trip")
        )

    def _get_talespire_sunder_total(self):
        return (
            self._get_total_bab() + self._ability_mod("Strength")
            + self._get_combat_maneuver_enchant_bonus("sunder")
        )

    def _get_talespire_feint_total(self):
        return self._get_total_bab() + self._get_combat_maneuver_enchant_bonus("feint")

    def _get_talespire_disarm_total(self):
        return (
            self._get_total_bab() + self._ability_mod("Strength")
            + self._get_combat_maneuver_enchant_bonus("disarm")
        )

    def _get_talespire_bull_rush_total(self):
        return (
            self._get_total_bab() + self._ability_mod("Strength")
            + self._get_combat_maneuver_enchant_bonus("bull_rush")
        )

    def build_combat_page(self):
        self.combat_frame = ctk.CTkFrame(self.content)
        self.data.setdefault("combat", {})
        self._combat_weapon_widgets = {}

        top = ctk.CTkFrame(self.combat_frame)
        top.pack(fill="x", padx=12, pady=8)
        ctk.CTkLabel(top, text="Combat", font=ctk.CTkFont(size=22, weight="bold")).pack(side="left", padx=8)
        ctk.CTkButton(
            top, text="Refresh Combat", fg_color=getattr(self, 'secondary_button_color', THEME_TEAL), width=160,
            command=self.refresh_combat_page,
        ).pack(side="right", padx=8)

        weapons_row = ctk.CTkFrame(self.combat_frame, fg_color="transparent")
        weapons_row.pack(fill="x", padx=12, pady=(0, 8))
        self.combat_weapons_row = weapons_row

        weapons_left = ctk.CTkFrame(weapons_row, fg_color="transparent")
        weapons_left.pack(side="left", fill="both", expand=True)
        self.combat_weapons_left = weapons_left
        self._combat_layout_mode = "wide"

        weapons_header = ctk.CTkFrame(weapons_left, fg_color="transparent")
        weapons_header.pack(fill="x", pady=(0, 4))
        ctk.CTkLabel(
            weapons_header, text="Owned Weapons",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(side="left", anchor="w")
        self.combat_feat_sliders_frame = ctk.CTkFrame(
            weapons_header, fg_color="#2a2a2a", corner_radius=6,
        )
        self._build_wielded_weapons_feat_sliders(self.combat_feat_sliders_frame)

        self.combat_weapons_scroll = ctk.CTkScrollableFrame(weapons_left, height=220)
        self.combat_weapons_scroll.pack(fill="x")

        self.combat_modifiers_frame = ctk.CTkFrame(weapons_row, width=320)
        self.combat_modifiers_frame.pack(side="right", fill="y", padx=(12, 0))
        self.combat_modifiers_frame.pack_propagate(False)
        self._build_combat_modifiers_panel(self.combat_modifiers_frame)

        summaries_row = ctk.CTkFrame(self.combat_frame, fg_color="transparent")
        summaries_row.pack(fill="both", expand=True, padx=12, pady=(0, 8))

        summaries_left = ctk.CTkFrame(summaries_row, fg_color="transparent")
        summaries_left.pack(side="left", fill="both", expand=True)

        summaries_header = ctk.CTkFrame(summaries_left, fg_color="transparent")
        summaries_header.pack(fill="x", padx=4, pady=(4, 2))
        ctk.CTkLabel(
            summaries_header, text="Attack Summaries",
            font=ctk.CTkFont(size=16, weight="bold"),
        ).pack(side="left", anchor="w")
        attack_summary_help = ctk.CTkLabel(
            summaries_header,
            text="?",
            fg_color="transparent",
            text_color="#aaaaaa",
            font=ctk.CTkFont(size=12, weight="bold"),
        )
        attack_summary_help.pack(side="left", padx=(6, 0), anchor="w")
        ctk.CTkLabel(
            summaries_header,
            text="Use ⚔ on Owned Weapons (Wielded) or natural attacks (bite/claw) to add them here.",
            font=ctk.CTkFont(size=11),
            text_color="#888888",
            wraplength=420,
            justify="left",
        ).pack(side="left", padx=(10, 0), anchor="w")
        self.combat_weather_label = ctk.CTkLabel(
            summaries_left,
            text="",
            font=ctk.CTkFont(size=11),
            text_color="#7ec8e3",
            wraplength=520,
            justify="left",
        )
        self.combat_weather_label.pack(fill="x", padx=8, pady=(0, 2))
        self._refresh_combat_weather_display()

        self._bind_hover_tooltip(
            attack_summary_help,
            "\n".join([
                "Hold Shift — Critical preview",
                "• Doubles weapon damage die and damage bonus",
                "• Shows Burst extra damage and on-critical effects",
                "",
                "Hold Ctrl — Bane preview",
                "• Adds Bane enhancement bonus to attack and damage",
                "• Shows Bane extra damage dice",
                "",
                "Shift and Ctrl can be held together.",
            ]),
            wraplength=320,
            delay_ms=1000,
        )

        self.combat_summary_scroll = ctk.CTkScrollableFrame(summaries_left, height=180)
        self.combat_summary_scroll.pack(fill="both", expand=True, pady=(0, 4))
        self._combat_spell_summary_widgets = []
        self._ensure_combat_shift_preview_bindings()

        self.movement_panel = ctk.CTkFrame(
            summaries_row, width=210, fg_color="#2F2F2F", corner_radius=8,
        )
        self.movement_panel.pack(side="right", fill="y", padx=(12, 0))
        self.movement_panel.pack_propagate(False)
        self._build_movement_panel(self.movement_panel, show_mount_button=True)

        footer = ctk.CTkFrame(self.combat_frame, fg_color="#2F2F2F", height=55)
        footer.pack(fill="x", padx=12, pady=4)
        footer.pack_propagate(False)

        # Create the three panels inside the fixed-height footer.
        # Pack: left (compact touches) | middle (expand to fill the gap) | right (compact AC).
        # This keeps Melee/Ranged Touch hugging the left, Resistances centered in the middle
        # of the bar, AC/Flat/Touch hugging the right. With fixed height + propagate(False)
        # the bar stays ~55px tall at page bottom no matter if resistances are empty or populated,
        # and left panel won't stretch wide on load.
        self.combat_spell_panel = ctk.CTkFrame(footer, fg_color="transparent")
        self.combat_resist_panel = ctk.CTkFrame(footer, fg_color="transparent")
        self.combat_ac_panel = ctk.CTkFrame(footer, fg_color="transparent")

        self.combat_spell_panel.pack(side="left", padx=10, pady=4, fill="y")
        # Pack the expanding middle *before* the right panel for reliable space allocation:
        # left (compact) | middle (expands to fill gap) | right (hugs right edge).
        # This lets the resistance icons truly sit in the horizontal center of the whole bar.
        self.combat_resist_panel.pack(side="left", padx=10, pady=4, fill="both", expand=True)
        self.combat_ac_panel.pack(side="right", padx=10, pady=4, fill="y")

        # Grid config on each panel so inner content (labels or resist row) is vertically
        # centered in the 55px footer. Left content left-aligned in its cell, right right-aligned,
        # middle (resist) fully centered so it sits in the middle of the bar.
        for p in (self.combat_spell_panel, self.combat_resist_panel, self.combat_ac_panel):
            p.grid_rowconfigure(0, weight=1)
            p.grid_columnconfigure(0, weight=1)

        # Pre-populate the melee touch and AC labels immediately (with short placeholders).
        # Use grid + sticky so they are vertically centered (no longer touching the top).
        melee_lbl = ctk.CTkLabel(
            self.combat_spell_panel,
            text="✨ Melee Touch ...",
            font=ctk.CTkFont(size=12, weight="bold"),
            text_color="#c77626",
            cursor="hand2",
        )
        melee_lbl.grid(row=0, column=0, sticky="w", padx=2)
        self._bind_talespire_click(melee_lbl, lambda: self._build_talespire_touch_attack_roll(False))

        ranged_lbl = ctk.CTkLabel(
            self.combat_spell_panel,
            text="    🏹 Ranged Touch ...",
            font=ctk.CTkFont(size=12, weight="bold"),
            text_color="#c77626",
            cursor="hand2",
        )
        ranged_lbl.grid(row=0, column=1, sticky="w", padx=2)
        self._bind_talespire_click(ranged_lbl, lambda: self._build_talespire_touch_attack_roll(True))

        self.combat_melee_touch_label = melee_lbl
        self.combat_ranged_touch_label = ranged_lbl

        self.combat_ac_label = ctk.CTkLabel(
            self.combat_ac_panel,
            text="🛡️ AC ...    👢 Flat ...    ✋ Touch ...",
            font=ctk.CTkFont(size=12, weight="bold"),
            text_color="#c77626",
        )
        self.combat_ac_label.grid(row=0, column=0, sticky="e", padx=2)

        self.refresh_combat_page()

    def _read_weapon_field(self, idx, key):
        reg_key = f"weapon_{idx}_{key}"
        if reg_key in self.widget_registry:
            widget = self.widget_registry[reg_key]
            try:
                raw = widget.get().strip() if hasattr(widget, "get") else str(widget)
                if key in ("weight", "value", "range"):
                    return float(raw or 0)
                if key in ("enh", "feat_atk", "feat_dmg"):
                    return int(raw or 0)
                return raw
            except (ValueError, AttributeError):
                pass
        if idx < len(self.data.get("weapons", [])):
            return self.data["weapons"][idx].get(key, 0 if key in ("enh", "feat_atk", "feat_dmg", "weight", "value", "range") else "")
        return 0 if key in ("enh", "feat_atk", "feat_dmg", "weight", "value", "range") else ""

    def _sync_weapon_slots_from_widgets(self):
        if self._should_skip_widget_to_data_sync():
            return
        if not hasattr(self, "weapon_vars"):
            return
        for i in range(min(5, len(self.data.get("weapons", [])))):
            weapon = self.data["weapons"][i]
            try:
                weapon["status"] = self.weapon_vars[i]["status"].get()
                weapon["name"] = self.weapon_vars[i]["name"].get()
                display_name = str(weapon.get("name") or "").strip()
                item = self._find_inventory_item_by_display_name(
                    display_name, "weapon",
                    exclude_inventory_ids=self._get_assigned_weapon_inventory_ids(
                        exclude_slot_idx=i,
                    ),
                )
                weapon["inventory_id"] = (
                    str(item.get("inventory_id") or "").strip() if item
                    else str(weapon.get("inventory_id") or "").strip()
                )
            except (KeyError, IndexError):
                pass
            for key in ["enh", "feat_atk", "feat_dmg", "damage", "special", "range"]:
                weapon[key] = self._read_weapon_field(i, key)

    def _get_weapon_slot(self, idx):
        self._sync_weapon_slots_from_widgets()
        if idx >= len(self.data.get("weapons", [])):
            return {}
        weapon = dict(self.data["weapons"][idx])
        for key in ["weight", "enh", "feat_atk", "feat_dmg", "damage", "special", "value", "range", "status", "name"]:
            weapon[key] = self._read_weapon_field(idx, key) if key not in ("status", "name") else weapon.get(key, "")
            if key in ("status", "name") and hasattr(self, "weapon_vars") and idx < len(self.weapon_vars):
                try:
                    weapon[key] = self.weapon_vars[idx][key].get()
                except (KeyError, IndexError):
                    pass
        return weapon

    def _get_owned_weapon_indices(self):
        """Inventory weapon slots with a name (any status). Shown in Owned Weapons on Combat."""
        indices = []
        for i in range(len(self.data.get("weapons", []))):
            weapon = self._get_weapon_slot(i)
            if str(weapon.get("name", "")).strip():
                indices.append(i)
        return indices

    def _get_wielded_weapon_indices(self):
        """Weapons set to wielded and carried on person. Shown in Attack Summaries on Combat."""
        indices = []
        for i in range(len(self.data.get("weapons", []))):
            weapon = self._get_weapon_slot(i)
            if weapon.get("status") != "wielded":
                continue
            if not str(weapon.get("name", "")).strip():
                continue
            if self._weapon_inventory_location(i) != "person":
                continue
            indices.append(i)
        return indices

    def _default_combat_weapon_config(self, weapon_data):
        raw_die = str(weapon_data.get("damage", "") or "").strip()
        die = raw_die if (raw_die and raw_die in (globals().get("DAMAGE_DICE") or [])) else "1d8"
        # Seed threat/crit from mundane weapon data if the inv slot has it (from dropdown autofill)
        crit_raw = str(weapon_data.get("critical", "") or "").strip()
        threat = "20"
        mult = "x2"
        if "/" in crit_raw:
            # e.g. "19-20/x2"
            parts = crit_raw.split("/")
            if len(parts) >= 2:
                threat = parts[0].strip()
                mult = parts[1].strip() if parts[1].strip() else "x2"
        elif crit_raw:
            # e.g. "x3" or "18-20/x2" already handled above; fallback simple
            if crit_raw.startswith("x"):
                mult = crit_raw
            else:
                threat = crit_raw.split("/")[0] if "/" in crit_raw else crit_raw
        return {
            "hit_ability": "Strength",
            "dmg_ability": "Strength",
            "damage_type": str(weapon_data.get("type", "Slashing")).split()[0].capitalize() or "Slashing",
            "weapon_style": "1H",
            "damage_die": die,
            "threat_range": threat or "20",
            "crit_multiplier": mult or "x2",
            "enchants": [],
            "temp_enh": 0,
            "temp_threat": "",
            "temp_damage": 0,
            "defend_amount": 0,
            "offhand_active": False,
            "rapid_shot_active": False,
            "bane_foe": "",
        }

    def _get_combat_weapon_config(self, idx, weapon_data):
        combat = self.data.setdefault("combat", {})
        weapons = combat.setdefault("weapons", {})
        key = self._get_weapon_combat_key(idx, weapon_data)
        legacy_key = str(idx)
        if key not in weapons and legacy_key in weapons:
            weapons[key] = copy.deepcopy(weapons[legacy_key])
        if key not in weapons:
            weapons[key] = self._default_combat_weapon_config(weapon_data)
        config = weapons[key]
        for field, default in self._default_combat_weapon_config(weapon_data).items():
            if field not in config:
                config[field] = default
        if "enchants" not in config or not isinstance(config["enchants"], list):
            config["enchants"] = []
        slot_enchants = self._filter_gear_enchants("weapon", weapon_data.get("enchants"))
        if slot_enchants:
            config["enchants"] = list(slot_enchants)
        slot_bane = str(weapon_data.get("bane_foe") or "").strip()
        if slot_bane:
            config["bane_foe"] = slot_bane
        return config

    def _save_combat_weapon_field(self, idx, field, value):
        config = self._get_combat_weapon_config(idx, self._get_weapon_slot(idx))
        if field == "enchants":
            config["enchants"] = list(value)
        elif field is not None:
            config[field] = value
        combat_key = self._get_weapon_combat_key(idx)
        self.data.setdefault("combat", {}).setdefault("weapons", {})[combat_key] = config

    def _natural_attack_storage_key(self, entry):
        attack_def = entry.get("attack") or {}
        return "|".join([
            str(entry.get("feature_name", "Special Feature")),
            str(entry.get("form_state", "")),
            str(attack_def.get("name", "Natural Attack")),
        ])

    def _default_natural_attack_config(self, attack_def):
        return {
            "hit_ability": attack_def.get("hit_ability", "Strength"),
            "dmg_ability": attack_def.get("dmg_ability", "Strength"),
            "damage_type": attack_def.get("damage_type", "Slashing"),
            "weapon_style": attack_def.get("weapon_style", "Light"),
            "damage_die": attack_def.get("damage_die", "1d4"),
            "threat_range": attack_def.get("threat_range", "20"),
            "crit_multiplier": attack_def.get("crit_multiplier", "x2"),
        }

    def _get_natural_attack_config(self, entry):
        attack_def = entry.get("attack") or {}
        key = self._natural_attack_storage_key(entry)
        natural = self.data.setdefault("combat", {}).setdefault("natural_attacks", {})
        if key not in natural:
            natural[key] = self._default_natural_attack_config(attack_def)
        config = natural[key]
        for field, default in self._default_natural_attack_config(attack_def).items():
            if field not in config:
                config[field] = default
        return config

    def _merged_natural_attack_def(self, entry):
        attack_def = dict(entry.get("attack") or {})
        attack_def.update(self._get_natural_attack_config(entry))
        return attack_def

    def _save_natural_attack_field(self, entry, field, value):
        key = self._natural_attack_storage_key(entry)
        config = self._get_natural_attack_config(entry)
        config[field] = value
        self.data.setdefault("combat", {}).setdefault("natural_attacks", {})[key] = config

    def _on_natural_attack_field_change(self, entry, field, value):
        self._save_natural_attack_field(entry, field, value)
        key = self._natural_attack_storage_key(entry)
        if key in getattr(self, "_combat_natural_summary_attack_labels", {}):
            self._refresh_natural_attack_summary(entry)
            combat_key = self._get_combat_page_key()
            self._combat_built_for_key = combat_key
            self._combat_summaries_built_for_key = combat_key
        elif self._is_page_active("Combat"):
            self.refresh_combat_page()

    def _refresh_natural_attack_summary(self, entry):
        key = self._natural_attack_storage_key(entry)
        atk_label = getattr(self, "_combat_natural_summary_attack_labels", {}).get(key)
        dmg_label = getattr(self, "_combat_natural_summary_damage_labels", {}).get(key)
        summary_card = getattr(self, "_combat_natural_summary_cards", {}).get(key)
        if not atk_label and not dmg_label:
            return
        attack_def = self._merged_natural_attack_def(entry)
        feature_name = entry.get("feature_name", "Special Feature")
        atk_name = attack_def.get("name", "Natural Attack")
        display_name = f"{atk_name} ({feature_name})"
        data = self._compute_natural_attack_data(attack_def, display_name)
        config = data.get("config") or {}
        data["name"] = display_name
        attack_str = self._format_attack_bonus_string(data.get("attack_bonuses", []))
        damage_str = self._build_attack_summary_damage_display(data)
        atk_display = self._build_attack_summary_attack_display(data)
        dmg_display = damage_str
        if atk_label:
            atk_label.configure(text=atk_display)
        if dmg_label:
            dmg_label.configure(text=" " + dmg_display if dmg_display else "")
        if summary_card:
            tooltip_lines = [
                display_name,
                f"Attack: {attack_str}",
                f"Damage: {damage_str}",
                f"Type: {config.get('damage_type', 'Slashing')}",
                f"Threat/Crit: {config.get('threat_range', '20')} {config.get('crit_multiplier', 'x2')}",
            ]
            self._bind_hover_tooltip(summary_card, "\n".join(tooltip_lines), wraplength=420)

    def _refresh_combat_weapon_summary(self, idx):
        atk_label = getattr(self, "_combat_summary_attack_labels", {}).get(idx)
        dmg_label = getattr(self, "_combat_summary_damage_labels", {}).get(idx)
        summary_card = getattr(self, "_combat_summary_cards", {}).get(idx)
        if not atk_label and not dmg_label:
            return
        data = self._compute_weapon_attack_data(idx)
        self._update_weapon_attack_summary_labels(idx, data)
        dmg_display = self._build_attack_summary_damage_display(data)
        if dmg_label:
            dmg_label.configure(text=" " + dmg_display if dmg_display else "")
        if summary_card:
            self._bind_hover_tooltip(
                summary_card,
                self._build_weapon_attack_tooltip(idx),
                wraplength=420,
            )

    def _apply_temp_weapon_override(self, idx, field, val):
        """Apply a temporary override (Enh/Threat/Damage) from Attack Summary boxes.
        These are cleared on rest and take precedence as described (better for Enh, override if not empty for Threat).
        """
        if field in ("temp_enh", "temp_damage"):
            try:
                val = int(str(val or 0))
            except (ValueError, TypeError):
                val = 0
        else:
            val = str(val or "").strip()
        self._save_combat_weapon_field(idx, field, val)
        self._refresh_combat_weapon_summary(idx)
        # Refresh tooltip
        card = getattr(self, "_combat_summary_cards", {}).get(idx)
        if card:
            tip = self._build_weapon_attack_tooltip(idx)
            self._bind_hover_tooltip(card, tip, wraplength=420)
        # Keep overall combat calcs in sync
        self.calculate_combat()
        self._update_combat_footer()

    def _on_defend_slider_drag(self, idx, val_lbl, val):
        """Live update during slider drag: persist defend value, refresh weapon summary and footer AC labels in real time."""
        try:
            ival = int(val)
        except (ValueError, TypeError):
            ival = 0
        val_lbl.configure(text=str(ival))
        self._save_combat_weapon_field(idx, "defend_amount", ival)
        self._refresh_combat_weapon_summary(idx)
        self._update_combat_ac_footer_labels()

    def _on_defend_slider_release(self, idx):
        """On slider release, perform the full side effects (AC update etc) once using the final defend value."""
        self.calculate_ac()
        self.calculate_combat()
        self._update_combat_footer()
        if hasattr(self, "stats_frame") and self._is_page_active("Stats"):
            self.refresh_stats_page()

    def _set_defend_amount(self, idx, amount):
        """Set Defending slider; adds untyped AC, reduces this weapon's eff enh in summaries."""
        weapon = self._get_weapon_slot(idx)
        enh = int(weapon.get("enh", 0) or 0)
        amount = max(0, min(int(amount or 0), enh))
        self._save_combat_weapon_field(idx, "defend_amount", amount)
        self._refresh_combat_weapon_summary(idx)
        card = getattr(self, "_combat_summary_cards", {}).get(idx)
        if card:
            tip = self._build_weapon_attack_tooltip(idx)
            self._bind_hover_tooltip(card, tip, wraplength=420)
        self.calculate_ac()
        self.calculate_combat()
        self._update_combat_footer()
        if hasattr(self, "stats_frame") and self._is_page_active("Stats"):
            self.refresh_stats_page()

    def _refresh_combat_attack_summaries(self):
        """Recalculate attack summaries and combat footer from current character stats."""
        if not hasattr(self, "combat_summary_scroll"):
            return
        labels = getattr(self, "_combat_summary_labels", {}) or {}
        atk_labels = getattr(self, "_combat_summary_attack_labels", {}) or {}
        dmg_labels = getattr(self, "_combat_summary_damage_labels", {}) or {}
        natural_atk = getattr(self, "_combat_natural_summary_attack_labels", {}) or {}
        if not labels and not atk_labels and not dmg_labels and not natural_atk:
            if self._combat_page_is_stale():
                self.refresh_combat_page()
            return
        self._sync_combat_widgets_to_data()
        all_idxs = set(list(labels.keys()) + list(atk_labels.keys()) + list(dmg_labels.keys()))
        for idx in all_idxs:
            self._refresh_combat_weapon_summary(idx)
        for entry in self._get_special_feature_natural_attacks():
            key = self._natural_attack_storage_key(entry)
            if key in natural_atk:
                self._refresh_natural_attack_summary(entry)
        self.calculate_combat()
        self._update_combat_footer()
        self.refresh_movement_display()
        # Also refresh the spell attack summaries (so add/remove via ⚔ is live even in light updates)
        self._refresh_spell_attack_summaries()
        self._refresh_mount_attack_summary()
        self._mark_combat_summaries_built()

    def _on_combat_field_change(self, idx, field, value):
        self._save_combat_weapon_field(idx, field, value)
        if field == "weapon_style":
            self.refresh_combat_page()
            return
        if idx in getattr(self, "_combat_summary_labels", {}):
            self._refresh_combat_weapon_summary(idx)
            combat_key = self._get_combat_page_key()
            self._combat_built_for_key = combat_key
            self._combat_summaries_built_for_key = combat_key
        else:
            self.refresh_combat_page()

    def _sync_combat_widgets_to_data(self):
        for idx, widgets in getattr(self, "_combat_weapon_widgets", {}).items():
            config = self._get_combat_weapon_config(idx, self._get_weapon_slot(idx))
            config["hit_ability"] = widgets["hit_ability"].get()
            config["dmg_ability"] = widgets["dmg_ability"].get()
            config["damage_type"] = widgets["damage_type"].get()
            config["weapon_style"] = widgets["weapon_style"].get()
            config["damage_die"] = widgets["damage_die"].get()
            config["threat_range"] = widgets["threat_range"].get()
            config["crit_multiplier"] = widgets["crit_multiplier"].get()
            combat_key = self._get_weapon_combat_key(idx)
            self.data.setdefault("combat", {}).setdefault("weapons", {})[combat_key] = config
        for key, widgets in getattr(self, "_combat_natural_attack_widgets", {}).items():
            entry = getattr(self, "_combat_natural_attack_entries", {}).get(key)
            if not entry:
                continue
            config = self._get_natural_attack_config(entry)
            config["hit_ability"] = widgets["hit_ability"].get()
            config["dmg_ability"] = widgets["dmg_ability"].get()
            config["damage_type"] = widgets["damage_type"].get()
            config["weapon_style"] = widgets["weapon_style"].get()
            config["damage_die"] = widgets["damage_die"].get()
            config["threat_range"] = widgets["threat_range"].get()
            config["crit_multiplier"] = widgets["crit_multiplier"].get()
            self.data.setdefault("combat", {}).setdefault("natural_attacks", {})[key] = config

    def _ability_mod(self, ability_name):
        if ability_name in (None, "", "None"):
            return 0
        return self._effective_ability_mod(ability_name)

    def _get_class_base_bab(self):
        """Class-level BAB only (no epic or racial HD BAB)."""
        total = 0
        for cls_name, lvl in self._class_levels_for_base_bab_saves():
            if cls_name == "None" or lvl == 0:
                continue
            prog = self.class_data.get(cls_name, {}).get("bab", "poor")
            if prog == "full":
                total += lvl
            elif prog == "medium":
                total += (lvl * 3) // 4
            else:
                total += lvl // 2
        return total

    def _get_total_bab(self):
        return (
            self._get_class_base_bab()
            + self._get_epic_attack_bonus()
            + self._get_racial_bab_bonus()
        )

    def _iterative_attack_bonuses(self, hit_extra):
        bab = self._get_total_bab()
        attacks = []
        while bab > 0:
            attacks.append(bab + hit_extra)
            if bab < 6:
                break
            bab -= 5
        return attacks or [hit_extra]

    def _style_damage_modifier(self, style, ability_mod):
        if style == "2H":
            return (ability_mod * 3) // 2
        if style in ("Offhand", "Light"):
            return ability_mod // 2
        if style == "Ranged":
            return 0
        return ability_mod

    def _style_attack_modifier(self, style):
        if style == "Offhand":
            return -2
        return 0

    def _get_two_weapon_fighting_tier(self):
        feats = self._get_all_selected_feats()
        if "Perfect Two-Weapon Fighting" in feats:
            return 4
        if "Greater Two-Weapon Fighting" in feats:
            return 3
        if "Improved Two-Weapon Fighting" in feats:
            return 2
        if "Two-Weapon Fighting" in feats:
            return 1
        return 0

    def _offhand_weapon_is_light(self, idx, config):
        style = config.get("weapon_style", "1H")
        if style == "Light":
            return True
        weapon = self._get_weapon_slot(idx)
        name = str(weapon.get("name", "") or "").lower()
        if "unarmed" in name:
            return True
        info = self._lookup_mundane_weapon_info(weapon.get("name", ""))
        specials = info.get("special") or []
        if isinstance(specials, str):
            specials = [specials]
        if any("light" in str(s).lower() for s in specials):
            return True
        desc = str(info.get("special_description", "") or "").lower()
        if "light weapon" in desc:
            return True
        return style == "Offhand"

    def _get_two_weapon_fighting_context(self):
        """Return TWF state when an off-hand weapon's summary toggle is on."""
        inactive = {
            "active": False,
            "tier": 0,
            "offhand_light": False,
            "primary_penalty": 0,
            "offhand_penalty": 0,
        }
        active_offhand_idx = None
        offhand_light = False
        for idx in self._get_wielded_weapon_indices():
            weapon = self._get_weapon_slot(idx)
            config = self._get_combat_weapon_config(idx, weapon)
            style = config.get("weapon_style", "1H")
            if style != "Offhand":
                continue
            if config.get("offhand_active"):
                active_offhand_idx = idx
                offhand_light = self._offhand_weapon_is_light(idx, config)
                break
        if active_offhand_idx is None:
            return inactive

        tier = self._get_two_weapon_fighting_tier()
        has_twf_feat = tier > 0
        if offhand_light:
            primary_penalty = -2 if has_twf_feat else -4
            offhand_penalty = -2 if has_twf_feat else -8
        else:
            primary_penalty = -4 if has_twf_feat else -6
            offhand_penalty = -4 if has_twf_feat else -10
        return {
            "active": True,
            "tier": tier,
            "offhand_light": offhand_light,
            "primary_penalty": primary_penalty,
            "offhand_penalty": offhand_penalty,
        }

    def _compute_offhand_attack_bonuses(self, hit_extra, tier):
        bab = self._get_total_bab()
        if tier >= 4:
            return self._iterative_attack_bonuses(hit_extra)
        attacks = [bab + hit_extra]
        if tier >= 2:
            attacks.append(max(0, bab - 5) + hit_extra)
        if tier >= 3:
            attacks.append(max(0, bab - 10) + hit_extra)
        return attacks

    def _classify_ammo_item(self, name):
        """Return 'arrow', 'bolt', 'bullet', or None for an inventory item name."""
        label = str(name or "").strip()
        if not label:
            return None
        lower = label.lower()
        info = self._lookup_mundane_weapon_info(label) or {}
        if str(info.get("category", "")).lower() != "ammunition":
            if "arrow" not in lower and "bolt" not in lower and "bullet" not in lower:
                return None
        if "bullet" in lower:
            return "bullet"
        if "bolt" in lower:
            return "bolt"
        if "arrow" in lower:
            return "arrow"
        return None

    def _get_weapon_ammo_kind(self, weapon_name):
        """Ammo type required by a ranged weapon (arrow, bolt, bullet), or None."""
        lower = str(weapon_name or "").lower()
        if "crossbow" in lower:
            return "bolt"
        if "sling" in lower:
            return "bullet"
        if "bow" in lower:
            return "arrow"
        return None

    def _weapon_is_bow(self, weapon_name):
        return self._get_weapon_ammo_kind(weapon_name) == "arrow"

    def _get_selected_ammo_for_weapon(self, weapon_idx):
        """Return the ammo stack used by a wielded ranged weapon, if any."""
        weapon = self._get_weapon_slot(weapon_idx)
        ammo_kind = self._get_weapon_ammo_kind(weapon.get("name", ""))
        if not ammo_kind:
            return None
        entries = [e for e in self._get_ammo_widget_entries() if e["kind"] == ammo_kind and e["quantity"] > 0]
        if not entries:
            return None
        priority_idx = self.data.get("ammo_priority_stack_id")
        if priority_idx is not None:
            for entry in entries:
                if entry["idx"] == priority_idx:
                    return entry
        return entries[0]

    def _character_has_rapid_shot(self):
        return "Rapid Shot" in self._get_all_selected_feats()

    def _character_has_haste(self):
        for entry in self.data.get("prepared_spells", []):
            norm = self._normalize_prepared_entry(entry)
            spell_name = str(norm.get("spell") or "").strip()
            if spell_name.lower() != "haste":
                continue
            entry_key = self._prepared_entry_key(entry)
            if self.data.get("spell_states", {}).get(entry_key, "Ready") == "Active":
                return True
        for buff in self.data.get("buffs", []):
            if not buff.get("active"):
                continue
            label = str(buff.get("spell_name") or buff.get("name") or "").strip().lower()
            if "haste" in label:
                return True
        for item_name in self.data.get("magic_items", []) or []:
            if item_name and "boots of speed" in str(item_name).lower():
                return True
        return False

    def _add_extra_attacks_at_highest(self, attack_bonuses, extra_count=1):
        if not attack_bonuses or extra_count <= 0:
            return list(attack_bonuses or [])
        highest = attack_bonuses[0]
        result = list(attack_bonuses)
        for _ in range(extra_count):
            result.insert(0, highest)
        return result

    def _format_ammo_used_message(self, count, ammo_kind):
        try:
            count = int(count or 0)
        except (TypeError, ValueError):
            count = 0
        if count <= 0 or not ammo_kind:
            return ""
        labels = {"arrow": "arrow", "bolt": "bolt", "bullet": "bullet"}
        unit = labels.get(ammo_kind, "ammo")
        if count != 1:
            unit += "s"
        return f"{count} {unit} used"

    def _peek_weapon_ammo_usage(self, weapon_idx):
        """Return (attack_count, ammo_kind) that would be consumed for this weapon roll."""
        weapon = self._get_weapon_slot(weapon_idx)
        if str(weapon.get("status", "")).lower() != "wielded":
            return 0, None
        ammo_kind = self._get_weapon_ammo_kind(weapon.get("name", ""))
        if ammo_kind is None:
            return 0, None
        ammo = self._get_selected_ammo_for_weapon(weapon_idx)
        if not ammo:
            return 0, ammo_kind
        data = self._compute_weapon_attack_data(weapon_idx)
        alt_held = getattr(self, "_combat_alt_preview", False)
        _, _, attack_bonuses = self._get_preview_attack_summary_values(
            data,
            getattr(self, "_combat_shift_preview", False),
            getattr(self, "_combat_ctrl_preview", False),
            alt_held=alt_held,
        )
        return len(attack_bonuses), ammo_kind

    def _consume_ammo_for_weapon_attack(self, weapon_idx):
        """Reduce widget ammo by the number of attacks rolled for a ranged weapon."""
        use_count, ammo_kind = self._peek_weapon_ammo_usage(weapon_idx)
        if use_count <= 0 or not ammo_kind:
            return 0
        ammo = self._get_selected_ammo_for_weapon(weapon_idx)
        if not ammo:
            return 0
        stacks = self.data.get("ammo_stacks", [])
        idx = ammo["idx"]
        if not (0 <= idx < len(stacks)):
            return 0
        stack = stacks[idx]
        try:
            qty = max(0, int(stack.get("quantity", 0) or 0))
        except (TypeError, ValueError):
            qty = 0
        stack["quantity"] = max(0, qty - use_count)
        if ammo_kind == "arrow":
            self.data["ammo_arrows_shot_since_gather"] = (
                int(self.data.get("ammo_arrows_shot_since_gather", 0) or 0) + use_count
            )
        if stack["quantity"] <= 0 and self.data.get("ammo_priority_stack_id") == idx:
            self.data["ammo_priority_stack_id"] = None
        self._refresh_ammo_widget()
        for widx in self._get_wielded_weapon_indices():
            self._refresh_combat_weapon_summary(widx)
        self._mark_cloud_sync_dirty()
        return use_count

    def _execute_weapon_combat_roll(self, weapon_idx, roll_builder):
        """Roll/copy a weapon attack and show copy or dice feedback including ammo used."""
        try:
            roll = roll_builder()
            if not roll:
                return
            ammo_count, ammo_kind = self._peek_weapon_ammo_usage(weapon_idx)
            ammo_detail = self._format_ammo_used_message(ammo_count, ammo_kind)
            self._execute_clickable_roll(
                roll,
                ammo_detail=ammo_detail or None,
                show_copied_toast=True,
            )
            self._consume_ammo_for_weapon_attack(weapon_idx)
        except Exception:
            pass

    def _bind_talespire_weapon_full_click(self, widget, weapon_idx):
        if widget is None:
            return
        if getattr(widget, "_talespire_full_click_bound", False):
            return

        def on_click(_event):
            self._execute_weapon_combat_roll(
                weapon_idx,
                lambda idx=weapon_idx: self._build_talespire_weapon_roll(idx),
            )
            return "break"

        try:
            widget.configure(cursor="hand2")
        except Exception:
            pass
        widget.bind("<Button-1>", on_click, add="+")
        widget._talespire_full_click_bound = True

    def _bind_talespire_weapon_attack_click(self, widget, weapon_idx):
        if widget is None:
            return
        if getattr(widget, "_talespire_attack_click_bound", False):
            return

        def on_click(_event):
            self._execute_weapon_combat_roll(
                weapon_idx,
                lambda idx=weapon_idx: self._build_talespire_weapon_attack_roll(idx),
            )
            return "break"

        try:
            widget.configure(cursor="hand2")
        except Exception:
            pass
        widget.bind("<Button-1>", on_click, add="+")
        widget._talespire_attack_click_bound = True

    def _on_rapid_shot_toggle(self, idx, active):
        self._save_combat_weapon_field(idx, "rapid_shot_active", bool(active))
        for widx in self._get_wielded_weapon_indices():
            self._refresh_combat_weapon_summary(widx)
        self.calculate_combat()
        self._update_combat_footer()

    def _on_offhand_toggle(self, idx, active):
        active = bool(active)
        if active:
            for widx in self._get_wielded_weapon_indices():
                if widx == idx:
                    continue
                other_weapon = self._get_weapon_slot(widx)
                other_config = self._get_combat_weapon_config(widx, other_weapon)
                if other_config.get("weapon_style") == "Offhand" and other_config.get("offhand_active"):
                    self._save_combat_weapon_field(widx, "offhand_active", False)
        self._save_combat_weapon_field(idx, "offhand_active", active)
        for widx in self._get_wielded_weapon_indices():
            self._refresh_combat_weapon_summary(widx)
        self.calculate_combat()
        self._update_combat_footer()

    def _get_ac_breakdown(self):
        all_bonuses = self.get_all_bonuses()
        effective_dex = self._get_effective_dex_for_ac()
        affliction_ac = self.get_affliction_penalties().get("ac", 0)

        armor_bonus = 0
        if self.data["armor"].get("status") == "worn":
            armor_bonus = (
                int(self.data["armor"].get("bonus", 0) or 0)
                + int(self.data["armor"].get("enh", 0) or 0)
                + int(self.data["armor"].get("feat", 0) or 0)
            )
        shield_bonus = 0
        if self.data["shield"].get("status") == "worn":
            shield_bonus = (
                int(self.data["shield"].get("bonus", 0) or 0)
                + int(self.data["shield"].get("enh", 0) or 0)
                + int(self.data["shield"].get("feat", 0) or 0)
            )

        armor_buff = all_bonuses.get("armor_bonus", 0)
        if armor_buff > 0:
            effective_armor = max(armor_bonus, armor_buff)
        else:
            effective_armor = armor_bonus + armor_buff
        shield_buff = all_bonuses.get("shield_bonus", 0)
        if shield_buff > 0:
            effective_shield = max(shield_bonus, shield_buff)
        else:
            effective_shield = shield_bonus + shield_buff
        wild_form = self._get_active_wild_shape_form()
        if wild_form:
            natural = int(wild_form.get("natural_armor", 0) or 0)
        else:
            natural = (
                all_bonuses.get("natural_armor", 0)
                + self._get_racial_natural_armor()
                + self._get_special_feature_natural_armor()
            )
        deflection = all_bonuses.get("deflection", 0)
        insight = all_bonuses.get("insight", 0)
        dodge_bonus = (
            (self.get_combat_expertise_dodge() if hasattr(self, "combat_expertise_var") else 0)
            + all_bonuses.get("dodge", 0)
        )
        sacred = all_bonuses.get("sacred", 0)
        profane = all_bonuses.get("profane", 0)
        ac_bonus = all_bonuses.get("ac_bonus", 0)
        size_ac = self._get_size_category_modifiers()["ac"]
        rage_ac = self._get_rage_bonuses().get("ac", 0)
        defend_ac = self._get_defending_ac_bonus()

        ac = (
            10 + effective_dex + effective_armor + effective_shield
            + deflection + natural + insight + dodge_bonus + affliction_ac
            + rage_ac + size_ac + sacred + profane + ac_bonus + defend_ac
        )

        # Monk AC bonus (class level-based + Wis) if unarmored, no shield, light load.
        # Applies to AC, Flat-footed, and Touch per SRD.
        monk_ac = self._get_monk_ac_bonus()
        ac += monk_ac
        flat = ac - effective_dex
        touch = (
            10 + effective_dex + deflection + insight + dodge_bonus + affliction_ac
            + rage_ac + size_ac + monk_ac + sacred + profane + ac_bonus + defend_ac
        )
        return {"ac": ac, "flat": flat, "touch": touch}

    def _get_defending_ac_bonus(self):
        """Total untyped AC from Defending weapons' slider amounts (for wielded weapons)."""
        total = 0
        for i in range(5):
            w = self.data.get("weapons", [{}])[i] if i < len(self.data.get("weapons", [])) else {}
            if str(w.get("status", "")).strip().lower() == "wielded":
                cfg = self._get_combat_weapon_config(i, w)
                if "Defending" in cfg.get("enchants", []):
                    total += int(cfg.get("defend_amount", 0) or 0)
        return total

    def _get_effective_monk_level(self):
        """Effective monk level for purposes of the Monk AC bonus table and unarmed strike damage die.
        Monk's Belt (and similar) advances this: monks get +5, non-monks treat the belt bonus as their monk level (e.g. 5).
        """
        base = self._get_class_level("Monk") or 0
        try:
            bonuses = self.get_all_bonuses()
            bonus = int(bonuses.get("monk_level_bonus", 0) or 0)
        except Exception:
            bonus = 0
        if base > 0:
            return base + bonus
        return bonus  # non-monks get the granted equiv level when belt (etc) worn

    def _get_monk_ac_bonus(self):
        """Return the total Monk AC bonus (SRD class AC bonus by level + Wisdom modifier)
        only if the monk is unarmored (no armor worn), not using a shield, and not encumbered
        (light load or less). This bonus applies to AC, flat-footed, and touch AC.
        Belt effects (effective monk level + Wis enh) are included when worn.
        """
        eff = self._get_effective_monk_level()
        if eff <= 0:
            return 0
        # Class AC Bonus (Ex) table from SRD (use effective level for belt/monk belt)
        if eff >= 17:
            class_ac = 4
        elif eff >= 13:
            class_ac = 3
        elif eff >= 9:
            class_ac = 2
        elif eff >= 5:
            class_ac = 1
        else:
            class_ac = 0
        wis_mod = self._effective_ability_mod("Wisdom")
        # Conditions for both the class bonus and Wis bonus (apply even to belt-granted 'monk' AC)
        armor = self.data.get("armor") or {}
        if str(armor.get("status", "")).strip().lower() == "worn":
            return 0
        shield = self.data.get("shield") or {}
        if str(shield.get("status", "")).strip().lower() == "worn":
            return 0
        load = self._get_encumbrance_load_state().get("load", "light")
        if load in ("medium", "heavy", "overloaded"):
            return 0
        return class_ac + wis_mod

    def _update_monk_ac_display(self):
        """Update the Monk AC bonus section in the Inventory page (under Shields)."""
        if not hasattr(self, "monk_ac_bonus_label"):
            return
        try:
            bonus = self._get_monk_ac_bonus()
            eff = self._get_effective_monk_level()
            if eff >= 17:
                class_ac = 4
            elif eff >= 13:
                class_ac = 3
            elif eff >= 9:
                class_ac = 2
            elif eff >= 5:
                class_ac = 1
            else:
                class_ac = 0
            wis_mod = self._effective_ability_mod("Wisdom")
            self.monk_ac_bonus_label.configure(text=self._format_modifier(bonus))
            detail = f"(+{class_ac} class + Wis {self._format_modifier(wis_mod)})"
            armor = self.data.get("armor") or {}
            shield = self.data.get("shield") or {}
            load = self._get_encumbrance_load_state().get("load", "light")
            inactive_reasons = []
            if str(armor.get("status", "")).strip().lower() == "worn":
                inactive_reasons.append("armor worn")
            if str(shield.get("status", "")).strip().lower() == "worn":
                inactive_reasons.append("shield used")
            if load in ("medium", "heavy", "overloaded"):
                inactive_reasons.append("encumbered")
            if inactive_reasons:
                detail += " — inactive (" + ", ".join(inactive_reasons) + ")"
                self.monk_ac_bonus_label.configure(text_color="#888888")
            else:
                self.monk_ac_bonus_label.configure(text_color="#c77626")
            self.monk_ac_detail_label.configure(text=detail)
        except Exception as e:
            print(f"Monk AC UI update error: {e}")

    def _get_touch_attacks(self):
        bab = self._get_total_bab()
        size_attack = self._get_size_category_modifiers()["attack"]
        ce_penalty = self.get_combat_expertise_attack_penalty()
        armor_nonproficiency_penalty = self._get_armor_nonproficiency_check_penalty()
        melee_touch = (
            bab + self._ability_mod("Strength") + size_attack + ce_penalty
            + armor_nonproficiency_penalty
        )
        ranged_touch = (
            bab + self._ability_mod("Dexterity") + size_attack + ce_penalty
            + armor_nonproficiency_penalty
        )
        return melee_touch, ranged_touch

    def _build_talespire_touch_attack_roll(self, is_ranged=False):
        m, r = self._get_touch_attacks()
        mod = r if is_ranged else m
        name = "Ranged Touch" if is_ranged else "Melee Touch"
        return self._format_talespire_roll(name, [f"1d20{self._format_modifier(mod)}"])

    def _format_modifier(self, value):
        return f"+{value}" if value >= 0 else str(value)

    def _format_attack_bonus_string(self, bonuses):
        return "/".join(self._format_modifier(v) for v in bonuses)

    def _weapon_style_label(self, style):
        return {
            "1H": "One-handed",
            "2H": "Two-handed",
            "Light": "Light weapon",
            "Offhand": "Off-hand",
            "Ranged": "Ranged",
            "Thrown": "Thrown",
        }.get(style, style)

    def _normalize_crit_multiplier(self, value):
        raw = str(value or "x2").strip().lower()
        if raw.startswith("x"):
            return f"x{raw[1:]}" if raw[1:] else "x2"
        return f"x{raw}" if raw else "x2"

    def _format_threat_crit_display(self, config):
        threat = str(config.get("threat_range", "20") or "20").strip()
        crit = self._normalize_crit_multiplier(config.get("crit_multiplier", "x2"))
        return f"{threat} {crit}"

    def _compute_weapon_attack_data(self, idx):
        weapon = self._get_weapon_slot(idx)
        config = self._get_combat_weapon_config(idx, weapon)
        name = str(weapon.get("name", "Weapon")).strip() or "Weapon"

        enh = int(weapon.get("enh", 0) or 0)
        feat_atk = int(weapon.get("feat_atk", 0) or 0)
        feat_dmg = int(weapon.get("feat_dmg", 0) or 0)
        weapon_feat_bonuses = self._compute_weapon_feat_bonuses_for_name(
            name, damage_type=config.get("damage_type"),
        )
        feat_atk += int(weapon_feat_bonuses.get("attack", 0) or 0)
        feat_dmg += int(weapon_feat_bonuses.get("damage", 0) or 0)
        feat_atk_lines = list(weapon_feat_bonuses.get("attack_lines") or [])
        feat_dmg_lines = list(weapon_feat_bonuses.get("damage_lines") or [])
        style = config.get("weapon_style", "1H")
        hit_ability = config.get("hit_ability", "Strength")
        dmg_ability = config.get("dmg_ability", "Strength")

        # Apply temporary overrides from Attack Summaries (clear on rest)
        temp_enh = int(config.get("temp_enh", 0) or 0)
        enh = max(enh, temp_enh)  # better of inventory Enh or summary override
        temp_threat = str(config.get("temp_threat", "") or "").strip()
        temp_dmg = int(config.get("temp_damage", 0) or 0)

        # Defending property: slider reduces effective enh for this weapon's atk/dmg, adds to AC (untyped)
        defend_amt = 0
        if "Defending" in config.get("enchants", []):
            defend_amt = min(int(config.get("defend_amount", 0) or 0), enh)
        eff_enh = enh - defend_amt

        enchant_atk = 0
        enchant_dmg = 0
        enchant_atk_lines = []
        enchant_dmg_lines = []
        extra_damage_parts = []
        critical_parts = []

        for enchant_name in config.get("enchants", []):
            info = self.weapon_enchants_db.get(enchant_name, {})
            bonus_atk = int(info.get("attack_bonus", 0) or 0)
            bonus_dmg = int(info.get("damage_bonus", 0) or 0)
            enchant_atk += bonus_atk
            enchant_dmg += bonus_dmg
            if bonus_atk:
                enchant_atk_lines.append(f"  {enchant_name}: {self._format_modifier(bonus_atk)}")
            if bonus_dmg:
                enchant_dmg_lines.append(f"  {enchant_name}: {self._format_modifier(bonus_dmg)}")
            if info.get("extra_damage") and self._enchant_extra_damage_applies(enchant_name, config):
                extra_damage_parts.append(info["extra_damage"])
            if info.get("critical_extra"):
                critical_parts.append(info["critical_extra"])

        hit_mod = self._ability_mod(hit_ability)
        if dmg_ability == "None":
            dmg_mod = 0
            raw_dmg_mod = 0
        else:
            raw_dmg_mod = self._ability_mod(dmg_ability)
            dmg_mod = self._style_damage_modifier(style, raw_dmg_mod)
        twf = self._get_two_weapon_fighting_context()
        style_atk = 0
        style_atk_label = ""
        if twf["active"]:
            if style in ("1H", "Light"):
                style_atk = twf["primary_penalty"]
                style_atk_label = "Two-Weapon Fighting (primary)"
            elif style == "Offhand":
                style_atk = twf["offhand_penalty"]
                style_atk_label = "Two-Weapon Fighting (off-hand)"
        else:
            style_atk = self._style_attack_modifier(style)
            if style_atk:
                style_atk_label = self._weapon_style_label(style)
        bab = self._get_total_bab()

        global_attack = self.get_all_bonuses().get("attack_bonus", 0)
        global_damage = self.get_all_bonuses().get("damage_bonus", 0)
        afflictions = self.get_affliction_penalties()
        affliction_attack = afflictions.get("attack", 0)
        if style in ("Ranged", "Thrown"):
            affliction_attack += afflictions.get("ranged_attack", 0)
        else:
            affliction_attack += afflictions.get("melee_attack", 0)
        pa_attack_penalty, pa_damage_bonus = self._get_weapon_power_attack_modifiers(style, hit_ability)
        ce_attack_penalty = self.get_combat_expertise_attack_penalty()
        size_attack = self._get_size_category_modifiers()["attack"]
        buckler_attack_penalty = self._get_buckler_melee_attack_penalty(style)
        weather_attack_penalty, weather_ranged_impossible = self._get_weather_attack_modifiers(style)
        material_effects = self._get_weapon_material_combat_effects(weapon)
        weapon_nonproficiency_penalty = self._get_weapon_nonproficiency_penalty(name)
        armor_nonproficiency_penalty = self._get_armor_nonproficiency_check_penalty()
        hit_extra = (
            hit_mod + eff_enh + feat_atk + enchant_atk + style_atk + global_attack
            + affliction_attack + pa_attack_penalty + ce_attack_penalty + size_attack
            + buckler_attack_penalty + weapon_nonproficiency_penalty + armor_nonproficiency_penalty
            + int(material_effects.get("attack", 0) or 0)
        )
        if not weather_ranged_impossible:
            hit_extra += weather_attack_penalty
        if twf["active"] and style == "Offhand":
            attack_bonuses = self._compute_offhand_attack_bonuses(hit_extra, twf["tier"])
        else:
            attack_bonuses = self._iterative_attack_bonuses(hit_extra)

        rapid_shot_active = bool(config.get("rapid_shot_active", False))
        rapid_shot_penalty = 0
        extra_attacks = 0
        if self._character_has_haste():
            extra_attacks += 1
        if (
            rapid_shot_active
            and style == "Ranged"
            and self._weapon_is_bow(name)
            and self._character_has_rapid_shot()
        ):
            extra_attacks += 1
            rapid_shot_penalty = -2
        if extra_attacks:
            attack_bonuses = self._add_extra_attacks_at_highest(attack_bonuses, extra_attacks)
        if rapid_shot_penalty:
            attack_bonuses = [bonus + rapid_shot_penalty for bonus in attack_bonuses]

        ammo_entry = None
        ammo_enh_bonus = 0
        ammo_qty = None
        if style == "Ranged" and self._get_weapon_ammo_kind(name):
            ammo_entry = self._get_selected_ammo_for_weapon(idx)
            if ammo_entry:
                ammo_qty = int(ammo_entry.get("quantity", 0) or 0)
                ammo_enh = int(ammo_entry.get("enh", 0) or 0)
                if ammo_enh > eff_enh:
                    ammo_enh_bonus = ammo_enh - eff_enh
                    attack_bonuses = [bonus + ammo_enh_bonus for bonus in attack_bonuses]
            pre_ammo_attack_count = len(attack_bonuses)
            if ammo_qty is not None:
                attack_bonuses = attack_bonuses[:max(0, ammo_qty)]
        else:
            pre_ammo_attack_count = len(attack_bonuses)

        total_damage_mod = (
            dmg_mod + eff_enh + feat_dmg + enchant_dmg + afflictions.get("damage", 0) + pa_damage_bonus + temp_dmg + global_damage
            + int(material_effects.get("damage", 0) or 0) + ammo_enh_bonus
        )
        die = config.get("damage_die", "1d8")

        # Monk's belt (and monk class levels) boost the damage die for unarmed strike weapons
        # when the character has an effective monk level (non-monks with belt get 5th-level monk unarmed die).
        lname = str(name or "").lower()
        if "unarmed" in lname:
            eff = self._get_effective_monk_level()
            if eff > 0:
                die = self._get_monk_unarmed_die(eff)

        # Effective threat for this summary (override if temp_threat not empty)
        threat_cfg = dict(config)
        if temp_threat:
            threat_cfg["threat_range"] = temp_threat
        if weapon_feat_bonuses.get("double_threat"):
            threat_cfg["threat_range"] = self._double_threat_range(
                threat_cfg.get("threat_range", "20"),
            )

        burst_effects = self._collect_burst_effects_for_attack(idx)
        bane_effects = self._collect_bane_effects_for_attack(idx)
        bane_foe = str(config.get("bane_foe", "") or "").strip()

        return {
            "name": name,
            "enchants": list(config.get("enchants", [])),
            "bane_foe": bane_foe,
            "style": style,
            "hit_ability": hit_ability,
            "dmg_ability": dmg_ability,
            "enh": enh,
            "defend_amt": defend_amt,
            "eff_enh": eff_enh,
            "feat_atk": feat_atk,
            "feat_dmg": feat_dmg,
            "bab": bab,
            "hit_mod": hit_mod,
            "dmg_mod": dmg_mod,
            "raw_dmg_mod": raw_dmg_mod,
            "global_attack": global_attack,
            "global_damage": global_damage,
            "style_atk": style_atk,
            "style_atk_label": style_atk_label,
            "twf_active": twf["active"],
            "twf_tier": twf["tier"],
            "enchant_atk": enchant_atk,
            "enchant_dmg": enchant_dmg,
            "enchant_atk_lines": enchant_atk_lines,
            "enchant_dmg_lines": enchant_dmg_lines,
            "feat_atk_lines": feat_atk_lines,
            "feat_dmg_lines": feat_dmg_lines,
            "attack_bonuses": attack_bonuses,
            "die": die,
            "total_damage_mod": total_damage_mod,
            "affliction_attack": affliction_attack,
            "affliction_damage": afflictions.get("damage", 0),
            "global_damage": global_damage,
            "pa_attack_penalty": pa_attack_penalty,
            "pa_damage_bonus": pa_damage_bonus,
            "ce_attack_penalty": ce_attack_penalty,
            "size_attack": size_attack,
            "buckler_attack_penalty": buckler_attack_penalty,
            "weapon_nonproficiency_penalty": weapon_nonproficiency_penalty,
            "armor_nonproficiency_penalty": armor_nonproficiency_penalty,
            "extra_damage_parts": extra_damage_parts,
            "burst_damage_parts": burst_effects["damage_parts"],
            "burst_text_parts": burst_effects["text_parts"],
            "burst_attack_bonus": burst_effects["attack_bonus"],
            "bane_enh_bonus": bane_effects["enh_bonus"],
            "bane_damage_parts": bane_effects["damage_parts"],
            "bane_text_parts": bane_effects["text_parts"],
            "critical_parts": critical_parts,
            "threat_crit": self._format_threat_crit_display(threat_cfg),
            "crit_multiplier": self._normalize_crit_multiplier(
                config.get("crit_multiplier", "x2"),
            ),
            "material_effects": material_effects,
            "rapid_shot_active": rapid_shot_active,
            "rapid_shot_penalty": rapid_shot_penalty,
            "weather_attack_penalty": weather_attack_penalty,
            "weather_ranged_impossible": weather_ranged_impossible,
            "haste_active": self._character_has_haste(),
            "ammo_entry": ammo_entry,
            "ammo_enh_bonus": ammo_enh_bonus,
            "ammo_qty": ammo_qty,
            "pre_ammo_attack_count": pre_ammo_attack_count,
            "weapon_idx": idx,
        }

    def _build_weapon_attack_summary(self, idx):
        data = self._compute_weapon_attack_data(idx)
        attack_str = self._format_attack_bonus_string(data["attack_bonuses"])
        damage_str = self._build_attack_summary_damage_display(data)

        title = data["name"]
        if data["enchants"]:
            enchant_display = self._format_weapon_enchants_for_summary(
                data["enchants"], data.get("bane_foe"),
            )
            title = f"{title} — {', '.join(enchant_display)}"

        parts = [title, attack_str, damage_str, data["threat_crit"]]
        return "  ".join(parts)

    def _build_weapon_attack_tooltip(self, idx):
        data = self._compute_weapon_attack_data(idx)
        lines = ["ATTACK BONUSES", f"  Base Attack Bonus: {self._format_modifier(data['bab'])}"]

        if data["hit_mod"]:
            lines.append(f"  {data['hit_ability']}: {self._format_modifier(data['hit_mod'])}")
        if data.get("defend_amt"):
            lines.append(f"  Defending: -{data['defend_amt']} enh → AC (untyped)")
        show_enh = data.get("eff_enh", data.get("enh", 0))
        if show_enh or data.get("enh"):
            lines.append(f"  Weapon Enhancement: {self._format_modifier(show_enh)}")
        if data.get("feat_atk_lines"):
            lines.extend(data["feat_atk_lines"])
        elif data["feat_atk"]:
            lines.append(f"  Feat Bonus: {self._format_modifier(data['feat_atk'])}")
        lines.extend(data["enchant_atk_lines"])
        if data["style_atk"]:
            atk_label = data.get("style_atk_label") or self._weapon_style_label(data["style"])
            lines.append(
                f"  {atk_label}: {self._format_modifier(data['style_atk'])}"
            )
        if data.get("twf_active") and data.get("style") == "Offhand":
            tier = int(data.get("twf_tier", 0) or 0)
            tier_names = {
                0: "no TWF feat (1 off-hand attack)",
                1: "Two-Weapon Fighting (1 off-hand attack)",
                2: "Improved Two-Weapon Fighting (2 off-hand attacks)",
                3: "Greater Two-Weapon Fighting (3 off-hand attacks)",
                4: "Perfect Two-Weapon Fighting (full iterative)",
            }
            lines.append(f"  Off-hand attacks: {tier_names.get(tier, '')}")
        if data.get("rapid_shot_active") and data.get("rapid_shot_penalty"):
            lines.append(
                f"  Rapid Shot: extra attack at highest, "
                f"{self._format_modifier(data['rapid_shot_penalty'])} to all bow attacks"
            )
        if data.get("haste_active"):
            lines.append("  Haste: +1 attack at highest bonus")
        ammo_entry = data.get("ammo_entry")
        if ammo_entry:
            ammo_line = f"  Ammo: {ammo_entry.get('name', 'Ammo')} ×{ammo_entry.get('quantity', 0)}"
            if data.get("ammo_enh_bonus"):
                ammo_line += f" (+{data['ammo_enh_bonus']} enh over weapon)"
            lines.append(ammo_line)
        if (
            data.get("ammo_qty") is not None
            and data.get("pre_ammo_attack_count", 0) > len(data.get("attack_bonuses", []))
        ):
            lines.append(
                f"  Limited to {len(data.get('attack_bonuses', []))} attack(s) by available ammo "
                f"({data['ammo_qty']} remaining)"
            )
        if data.get("affliction_attack"):
            lines.append(f"  Afflictions: {self._format_modifier(data['affliction_attack'])}")
        if data.get("weather_ranged_impossible") and data.get("style") in ("Ranged", "Thrown"):
            lines.append("  Weather: Ranged attacks impossible")
        elif data.get("weather_attack_penalty"):
            lines.append(f"  Weather: {self._format_modifier(data['weather_attack_penalty'])}")
        if data.get("pa_attack_penalty"):
            lines.append(f"  Power Attack: {self._format_modifier(data['pa_attack_penalty'])}")
        if data.get("ce_attack_penalty"):
            lines.append(f"  Combat Expertise: {self._format_modifier(data['ce_attack_penalty'])}")
        if data.get("size_attack"):
            lines.append(
                f"  Size ({self._get_effective_size()}): "
                f"{self._format_modifier(data['size_attack'])}"
            )
        if data.get("buckler_attack_penalty"):
            lines.append(
                f"  Buckler (2H): {self._format_modifier(data['buckler_attack_penalty'])}"
            )
        if data.get("weapon_nonproficiency_penalty"):
            lines.append(
                "  Weapon non-proficiency: "
                f"{self._format_modifier(data['weapon_nonproficiency_penalty'])}"
            )
        if data.get("armor_nonproficiency_penalty"):
            lines.append(
                "  Armor/shield non-proficiency: "
                f"{self._format_modifier(data['armor_nonproficiency_penalty'])}"
            )
        material_effects = data.get("material_effects") or {}
        if material_effects.get("attack"):
            lines.append(
                f"  Special Material: {self._format_modifier(material_effects['attack'])}"
            )
        for note in material_effects.get("notes") or []:
            lower = note.lower()
            if "damage" not in lower:
                lines.append(f"  {note}")

        attack_str = self._format_attack_bonus_string(data["attack_bonuses"])
        lines.extend(["", f"Attack rolls: {attack_str}", "", "DAMAGE"])
        lines.append(f"  Damage Die: {data['die']}")

        if data["dmg_mod"]:
            dmg_note = data["dmg_ability"]
            if data["style"] == "2H":
                dmg_note += " ×1.5 two-handed"
            elif data["style"] in ("Offhand", "Light"):
                dmg_note += " ×½ off-hand/light"
            lines.append(f"  {dmg_note}: {self._format_modifier(data['dmg_mod'])}")
        show_enh = data.get("eff_enh", data.get("enh", 0))
        if show_enh or data.get("enh"):
            lines.append(f"  Weapon Enhancement: {self._format_modifier(show_enh)}")
        if data.get("feat_dmg_lines"):
            lines.extend(data["feat_dmg_lines"])
        elif data["feat_dmg"]:
            lines.append(f"  Feat Bonus: {self._format_modifier(data['feat_dmg'])}")
        lines.extend(data["enchant_dmg_lines"])
        if data.get("affliction_damage"):
            lines.append(f"  Afflictions: {self._format_modifier(data['affliction_damage'])}")
        if data.get("global_damage"):
            lines.append(f"  Buffs / Global: {self._format_modifier(data['global_damage'])}")
        if data.get("pa_damage_bonus"):
            pa_note = " (×2 two-handed)" if data["style"] == "2H" else ""
            lines.append(
                f"  Power Attack{pa_note}: {self._format_modifier(data['pa_damage_bonus'])}"
            )
        if material_effects.get("damage"):
            lines.append(
                f"  Special Material: {self._format_modifier(material_effects['damage'])}"
            )
        for note in material_effects.get("notes") or []:
            if "damage" in note.lower():
                lines.append(f"  {note}")

        total_damage_mod = data["total_damage_mod"]
        damage_total = (
            f"{data['die']}{self._format_modifier(total_damage_mod)}"
            if total_damage_mod
            else data["die"]
        )
        damage_total = self._append_sneak_attack_to_damage_die(
            damage_total, data.get("style", "1H"),
        )
        lines.extend(["", f"Damage total: {damage_total}"])
        if self._format_sneak_attack_damage_suffix() and self._weapon_qualifies_for_sneak_attack_display(
            data.get("style", "1H"),
        ):
            lines.append("  (Sneak Attack when conditions met: flanking, flat-footed, etc.)")
        lines.extend(["", f"Threat / Crit: {data['threat_crit']}"])

        if data["extra_damage_parts"]:
            lines.extend(["", "EXTRA DAMAGE", *[f"  {part}" for part in data["extra_damage_parts"]]])
        if data["critical_parts"]:
            lines.extend(["", "CRITICAL", *[f"  {part}" for part in data["critical_parts"]]])

        return "\n".join(lines)

    def open_weapon_enchants_popup(self, weapon_idx):
        config = self._get_combat_weapon_config(weapon_idx, self._get_weapon_slot(weapon_idx))
        selected_enchants, saved_bane_foe = self._get_weapon_enchants(weapon_idx)
        selected = set(selected_enchants)

        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Weapon Enchantments — {self._get_weapon_slot(weapon_idx).get('name', 'Weapon')}")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=840, min_height=660)

        footer = ctk.CTkFrame(popup, fg_color="transparent")
        footer.pack(side="bottom", fill="x", padx=24, pady=(8, 20))
        ctk.CTkButton(
            footer, text="Close", width=120, height=36,
            fg_color=getattr(self, 'primary_button_color', '#c77626'), command=popup.destroy,
        ).pack(anchor="e")

        body = ctk.CTkFrame(popup, fg_color="transparent")
        body.pack(fill="both", expand=True, padx=24, pady=(16, 8))

        ctk.CTkLabel(
            body, text="Select Weapon Enchantments",
            font=ctk.CTkFont(size=20, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        detail_frame = ctk.CTkFrame(body, fg_color="#2F2F2F", height=52, corner_radius=6)
        detail_frame.pack(fill="x", pady=(0, 8))
        detail_frame.pack_propagate(False)
        detail_label = ctk.CTkLabel(
            detail_frame,
            text="Hover an enchantment to see its summary.",
            wraplength=740,
            justify="left",
            text_color="#aaaaaa",
            anchor="nw",
        )
        detail_label.pack(fill="both", expand=True, padx=10, pady=8)

        bane_row = ctk.CTkFrame(body, fg_color="#2a2a2a", corner_radius=6)
        ctk.CTkLabel(
            bane_row,
            text="Bane designated foe:",
            font=ctk.CTkFont(size=12, weight="bold"),
        ).pack(side="left", padx=(10, 6), pady=8)
        if not saved_bane_foe:
            saved_bane_foe = str(config.get("bane_foe", "") or "").strip()
        if saved_bane_foe not in BANE_DESIGNATED_FOE_OPTIONS:
            bane_values = [saved_bane_foe] + list(BANE_DESIGNATED_FOE_OPTIONS) if saved_bane_foe else list(BANE_DESIGNATED_FOE_OPTIONS)
        else:
            bane_values = list(BANE_DESIGNATED_FOE_OPTIONS)
        bane_foe_combo = ctk.CTkComboBox(
            bane_row,
            values=bane_values,
            width=220,
            command=lambda val: self._save_bane_foe_and_refresh(weapon_idx, val),
        )
        if saved_bane_foe:
            bane_foe_combo.set(saved_bane_foe)
        elif bane_values:
            bane_foe_combo.set(bane_values[0])
        bane_foe_combo.pack(side="left", padx=(0, 10), pady=8)

        scroll = ctk.CTkScrollableFrame(body, height=390)
        scroll.pack(fill="both", expand=True)

        checkbox_vars = {}

        def _bane_selected():
            return checkbox_vars.get("Bane") and checkbox_vars["Bane"].get()

        def _sync_bane_row_visibility():
            if _bane_selected():
                if not bane_row.winfo_ismapped():
                    bane_row.pack(fill="x", pady=(0, 8), before=scroll)
            else:
                bane_row.pack_forget()

        def update_enchants():
            chosen = [name for name, var in checkbox_vars.items() if var.get()]
            self._set_weapon_enchants(weapon_idx, chosen)
            _sync_bane_row_visibility()
            if weapon_idx in getattr(self, "_combat_summary_labels", {}):
                self._refresh_combat_weapon_summary(weapon_idx)
                self._combat_built_for_key = self._get_combat_page_key()
            elif hasattr(self, "combat_frame") and self._is_page_active("Combat"):
                self.refresh_combat_page()

        for enchant_name in sorted(self.weapon_enchants_db.keys()):
            info = self.weapon_enchants_db[enchant_name]
            row = ctk.CTkFrame(scroll)
            row.pack(fill="x", pady=3, padx=4)

            var = BooleanVar(value=enchant_name in selected)
            checkbox_vars[enchant_name] = var

            cb = ctk.CTkCheckBox(
                row, text=enchant_name, variable=var, width=220,
                command=update_enchants,
            )
            cb.pack(side="left", padx=8, pady=6)

            def show_detail(event=None, enchant_info=info):
                extra = []
                if enchant_info.get("extra_damage"):
                    extra.append(f"Extra damage: {enchant_info['extra_damage']}")
                if enchant_info.get("critical_extra"):
                    extra.append(f"Critical: {enchant_info['critical_extra']}")
                if enchant_info.get("attack_bonus"):
                    extra.append(f"Attack: {self._format_modifier(enchant_info['attack_bonus'])}")
                if enchant_info.get("damage_bonus"):
                    extra.append(f"Damage: {self._format_modifier(enchant_info['damage_bonus'])}")
                for burst_value in self._iter_burst_values_from_record(enchant_info):
                    extra.append(f"Burst (Shift): {burst_value}")
                for bane_value in self._iter_bane_values_from_record(enchant_info):
                    extra.append(f"Bane (Ctrl): {bane_value}")
                combat_mods = enchant_info.get("combat_modifiers") or {}
                if combat_mods:
                    mod_bits = []
                    labels = {
                        "trip": "Trip", "grapple": "Grapple", "sunder": "Sunder",
                        "disarm": "Disarm", "bull_rush": "Bull Rush", "feint": "Feint",
                        "overrun": "Overrun",
                    }
                    for key, value in combat_mods.items():
                        if str(key).lower() in ("burst", "bane"):
                            continue
                        label = labels.get(key, key.replace("_", " ").title())
                        mod_bits.append(f"{label}: {self._format_modifier(int(value or 0))}")
                    if mod_bits:
                        extra.append("Combat: " + ", ".join(mod_bits))
                detail = enchant_info.get("description", "")
                if extra:
                    detail = f"{detail} | {' | '.join(extra)}"
                detail_label.configure(
                    text=self._truncate_to_lines(detail, max_lines=2, line_width=74),
                )

            def hide_detail(event=None):
                detail_label.configure(text="Hover an enchantment to see its summary.")

            row.bind("<Enter>", show_detail)
            row.bind("<Leave>", hide_detail)
            cb.bind("<Enter>", show_detail)
            cb.bind("<Leave>", hide_detail)

        _sync_bane_row_visibility()

    def _save_bane_foe_and_refresh(self, weapon_idx, bane_foe):
        enchants, _ = self._get_weapon_enchants(weapon_idx)
        self._set_weapon_enchants(weapon_idx, enchants, bane_foe=str(bane_foe or "").strip())
        if weapon_idx in getattr(self, "_combat_summary_labels", {}):
            self._refresh_combat_weapon_summary(weapon_idx)
            self._combat_built_for_key = self._get_combat_page_key()
        elif hasattr(self, "combat_frame") and self._is_page_active("Combat"):
            self.refresh_combat_page()

    def _is_natural_attack_in_combat_summary(self, entry):
        return bool(self._get_natural_attack_config(entry).get("in_summary", False))

    def _toggle_natural_attack_summary(self, entry):
        """Toggle a natural attack (bite/claw) into/out of Attack Summaries."""
        key = self._natural_attack_storage_key(entry)
        config = self._get_natural_attack_config(entry)
        config["in_summary"] = not bool(config.get("in_summary", False))
        self.data.setdefault("combat", {}).setdefault("natural_attacks", {})[key] = config
        if hasattr(self, "combat_weapons_scroll") and self._is_page_active("Combat"):
            self.refresh_combat_page()
        else:
            self._mark_combat_page_stale()
            self._refresh_combat_attack_summaries()

    def _build_natural_attack_summary_card(self, entry):
        """Attack summary row for a natural attack toggled into summaries."""
        if not hasattr(self, "_combat_natural_summary_attack_labels"):
            self._combat_natural_summary_attack_labels = {}
        if not hasattr(self, "_combat_natural_summary_damage_labels"):
            self._combat_natural_summary_damage_labels = {}
        if not hasattr(self, "_combat_natural_summary_cards"):
            self._combat_natural_summary_cards = {}

        attack_def = self._merged_natural_attack_def(entry)
        feature_name = entry.get("feature_name", "Special Feature")
        atk_name = attack_def.get("name", "Natural Attack")
        display_name = f"{atk_name} ({feature_name})"
        storage_key = self._natural_attack_storage_key(entry)
        data = self._compute_natural_attack_data(attack_def, display_name)
        attack_config = data.get("config") or {}

        summary_card = ctk.CTkFrame(self.combat_summary_scroll, fg_color="#1f2a1f", height=50)
        summary_card.pack(fill="x", pady=2, padx=6)
        summary_card.pack_propagate(False)

        data["name"] = display_name
        attack_str = self._format_attack_bonus_string(data.get("attack_bonuses", []))
        damage_str = self._build_attack_summary_damage_display(data)
        atk_display = self._build_attack_summary_attack_display(data)
        dmg_display = damage_str

        atk_lbl = ctk.CTkLabel(
            summary_card,
            text=atk_display,
            wraplength=700, justify="left", anchor="w",
            font=ctk.CTkFont(size=12),
            cursor="hand2",
        )
        atk_lbl.pack(side="left", padx=(8, 2), pady=2)
        dmg_lbl = ctk.CTkLabel(
            summary_card,
            text=" " + dmg_display if dmg_display else "",
            wraplength=700, justify="left", anchor="w",
            font=ctk.CTkFont(size=12),
            cursor="hand2",
        )
        dmg_lbl.pack(side="left", padx=(2, 8), pady=2)

        tooltip_lines = [
            display_name,
            f"Attack: {attack_str}",
            f"Damage: {damage_str}",
            f"Type: {attack_config.get('damage_type', 'Slashing')}",
            f"Threat/Crit: {attack_config.get('threat_range', '20')} {attack_config.get('crit_multiplier', 'x2')}",
        ]
        self._bind_hover_tooltip(summary_card, "\n".join(tooltip_lines), wraplength=420)

        dice_groups = [data.get("die", "1d4")]
        self._bind_talespire_click(
            atk_lbl,
            lambda bonuses=data.get("attack_bonuses", []), lbl=display_name: self._format_talespire_roll(
                f"{lbl} Attack",
                [
                    self._format_talespire_dice_with_modifier("1d20", bonus)
                    for bonus in (bonuses or [0])
                ],
            ),
        )
        self._bind_talespire_click(
            dmg_lbl,
            lambda d=dice_groups, lbl=display_name, mod=data.get("total_damage_mod", 0): self._format_talespire_roll(
                f"{lbl} Damage",
                [f"{die}{self._format_modifier(mod)}" if mod else die for die in d],
            ),
        )
        self._combat_natural_summary_attack_labels[storage_key] = atk_lbl
        self._combat_natural_summary_damage_labels[storage_key] = dmg_lbl
        self._combat_natural_summary_cards[storage_key] = summary_card

    def _append_special_natural_attacks_combat(self, natural_attacks, show_weapon_header=False):
        """Add special-feature natural attacks to combat wielded list and attack summaries."""
        if not natural_attacks:
            return
        if not hasattr(self, "_combat_natural_attack_widgets"):
            self._combat_natural_attack_widgets = {}
        if not hasattr(self, "_combat_natural_attack_entries"):
            self._combat_natural_attack_entries = {}
        if not hasattr(self, "_combat_natural_sword_buttons"):
            self._combat_natural_sword_buttons = {}
        if not hasattr(self, "_combat_natural_summary_attack_labels"):
            self._combat_natural_summary_attack_labels = {}
        if not hasattr(self, "_combat_natural_summary_damage_labels"):
            self._combat_natural_summary_damage_labels = {}
        if not hasattr(self, "_combat_natural_summary_cards"):
            self._combat_natural_summary_cards = {}

        if show_weapon_header:
            header = ctk.CTkFrame(self.combat_weapons_scroll)
            header.pack(fill="x", pady=(0, 6), padx=4)
            for text, width in [
                ("Weapon", 130), ("Hit Abil", 88), ("Dmg Abil", 88), ("Type", 88),
                ("Style", 82), ("Damage Die", 82), ("Threat", 68), ("Crit", 52),
                ("Inv Bonuses", 118),
            ]:
                ctk.CTkLabel(header, text=text, width=width, font=ctk.CTkFont(weight="bold")).pack(
                    side="left", padx=3,
                )

        for entry in natural_attacks:
            attack_def = self._merged_natural_attack_def(entry)
            feature_name = entry.get("feature_name", "Special Feature")
            atk_name = attack_def.get("name", "Natural Attack")
            display_name = f"{atk_name} ({feature_name})"
            config = self._get_natural_attack_config(entry)
            storage_key = self._natural_attack_storage_key(entry)

            row = ctk.CTkFrame(self.combat_weapons_scroll)
            row.pack(fill="x", pady=4, padx=4)

            in_summary = self._is_natural_attack_in_combat_summary(entry)
            sword_btn = ctk.CTkButton(
                row, text="⚔", width=18, height=18,
                fg_color="transparent",
                border_width=0,
                text_color="#777777",
                hover_color=getattr(self, "secondary_hover_color", "#1f7f75"),
                font=ctk.CTkFont(size=11),
                command=lambda ent=entry: self._toggle_natural_attack_summary(ent),
            )
            sword_btn.pack(side="left", padx=(2, 4))
            self._set_sword_active(sword_btn, in_summary)
            self._bind_hover_tooltip(
                sword_btn,
                "Toggle in Attack Summaries — natural attacks (bite, claw, etc.)",
            )
            self._combat_natural_sword_buttons[storage_key] = sword_btn

            ctk.CTkLabel(row, text=display_name[:22], width=118, anchor="w").pack(side="left", padx=3)

            hit_combo = ctk.CTkComboBox(
                row, values=HIT_ABILITIES, width=88,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "hit_ability", val),
            )
            hit_combo.set(config.get("hit_ability", "Strength"))
            hit_combo.pack(side="left", padx=3)

            dmg_combo = ctk.CTkComboBox(
                row, values=DMG_ABILITIES, width=88,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "dmg_ability", val),
            )
            dmg_combo.set(config.get("dmg_ability", "Strength"))
            dmg_combo.pack(side="left", padx=3)

            type_combo = ctk.CTkComboBox(
                row, values=DAMAGE_TYPES, width=88,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "damage_type", val),
            )
            type_combo.set(config.get("damage_type", "Slashing"))
            type_combo.pack(side="left", padx=3)

            style_combo = ctk.CTkComboBox(
                row, values=WEAPON_STYLES, width=82,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "weapon_style", val),
            )
            style_combo.set(config.get("weapon_style", "Light"))
            style_combo.pack(side="left", padx=3)

            die_combo = ctk.CTkComboBox(
                row, values=DAMAGE_DICE, width=82,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "damage_die", val),
            )
            die_combo.set(config.get("damage_die", "1d4"))
            die_combo.pack(side="left", padx=3)

            threat_combo = ctk.CTkComboBox(
                row, values=list(THREAT_RANGES), width=68,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "threat_range", val),
            )
            threat_combo.set(config.get("threat_range", "20"))
            threat_combo.pack(side="left", padx=3)

            crit_combo = ctk.CTkComboBox(
                row, values=list(CRIT_MULTIPLIERS), width=52,
                command=lambda val, ent=entry: self._on_natural_attack_field_change(ent, "crit_multiplier", val),
            )
            crit_combo.set(self._normalize_crit_multiplier(config.get("crit_multiplier", "x2")))
            crit_combo.pack(side="left", padx=3)

            ctk.CTkLabel(
                row, text="natural",
                width=118, anchor="w",
            ).pack(side="left", padx=3)
            ctk.CTkLabel(row, text="", width=82).pack(side="left", padx=3)

            self._combat_natural_attack_entries[storage_key] = entry
            self._combat_natural_attack_widgets[storage_key] = {
                "hit_ability": hit_combo,
                "dmg_ability": dmg_combo,
                "damage_type": type_combo,
                "weapon_style": style_combo,
                "damage_die": die_combo,
                "threat_range": threat_combo,
                "crit_multiplier": crit_combo,
            }

            if in_summary:
                self._build_natural_attack_summary_card(entry)

    def _build_weapon_attack_summary_card(self, idx):
        """Attack summary row for a wielded inventory weapon."""
        weapon = self._get_weapon_slot(idx)
        summary_card = ctk.CTkFrame(self.combat_summary_scroll, fg_color="#1f2a1f", height=50)
        summary_card.pack(fill="x", pady=2, padx=6)
        summary_card.pack_propagate(False)

        data = self._compute_weapon_attack_data(idx)
        weapon_name, enchant_suffix, gem_suffix = self._build_attack_summary_attack_parts(data)
        dmg_display = self._build_attack_summary_damage_display(data)
        tooltip_text = self._build_weapon_attack_tooltip(idx)

        atk_row = ctk.CTkFrame(summary_card, fg_color="transparent")
        atk_row.pack(side="left", padx=(8, 2), pady=2)
        name_lbl = ctk.CTkLabel(
            atk_row,
            text=weapon_name,
            font=ctk.CTkFont(size=12),
            cursor="hand2",
        )
        name_lbl.pack(side="left")
        suffix_lbl = ctk.CTkLabel(
            atk_row,
            text=enchant_suffix,
            font=ctk.CTkFont(size=12),
            cursor="hand2",
        )
        suffix_lbl.pack(side="left")
        gem_lbl = ctk.CTkLabel(
            atk_row,
            text=gem_suffix,
            font=ctk.CTkFont(size=12),
            text_color=THEME_TEAL,
            cursor="hand2",
        )
        gem_lbl.pack(side="left")
        self._bind_hover_tooltip_builder(
            name_lbl,
            lambda weapon_idx=idx: self._build_weapon_enchant_descriptions_tooltip(weapon_idx),
            wraplength=420,
        )

        dmg_lbl = ctk.CTkLabel(
            summary_card,
            text=" " + dmg_display if dmg_display else "",
            wraplength=700, justify="left", anchor="w",
            font=ctk.CTkFont(size=12),
            cursor="hand2",
        )
        dmg_lbl.pack(side="left", padx=(2, 8), pady=2)

        right_frame = ctk.CTkFrame(summary_card, fg_color="transparent")
        right_frame.pack(side="right", padx=4, pady=2)

        config = self._get_combat_weapon_config(idx, weapon)
        if config.get("weapon_style") == "Offhand":
            offhand_var = ctk.BooleanVar(value=bool(config.get("offhand_active", False)))
            offhand_switch = ctk.CTkSwitch(
                right_frame,
                text="Off-hand",
                variable=offhand_var,
                width=88,
                command=lambda i=idx, v=offhand_var: self._on_offhand_toggle(i, v.get()),
            )
            offhand_switch.pack(side="left", padx=(0, 4))
            self._bind_hover_tooltip(
                offhand_switch,
                "Enable two-weapon fighting penalties and off-hand attacks "
                "(uses Two-Weapon Fighting feat tier if present).",
                wraplength=320,
            )
        elif (
            config.get("weapon_style") == "Ranged"
            and self._weapon_is_bow(weapon.get("name", ""))
            and self._character_has_rapid_shot()
        ):
            rapid_var = ctk.BooleanVar(value=bool(config.get("rapid_shot_active", False)))
            rapid_switch = ctk.CTkSwitch(
                right_frame,
                text="Rapid Shot",
                variable=rapid_var,
                width=98,
                command=lambda i=idx, v=rapid_var: self._on_rapid_shot_toggle(i, v.get()),
            )
            rapid_switch.pack(side="left", padx=(0, 4))
            self._bind_hover_tooltip(
                rapid_switch,
                "Gain one extra bow attack at your highest bonus. All bow attacks take -2.",
                wraplength=320,
            )
        has_def = "Defending" in config.get("enchants", [])
        if has_def:
            enh_val = int(weapon.get("enh", 0) or 0)
            ctk.CTkLabel(right_frame, text="Defend", font=ctk.CTkFont(size=9)).pack(side="left")
            def_var = ctk.IntVar(value=int(config.get("defend_amount", 0) or 0))
            slider = ctk.CTkSlider(
                right_frame,
                from_=0,
                to=enh_val,
                number_of_steps=max(1, enh_val),
                variable=def_var,
                width=70,
            )
            slider.pack(side="left", padx=2)
            val_lbl = ctk.CTkLabel(right_frame, text=str(def_var.get()), width=18, font=ctk.CTkFont(size=9))
            val_lbl.pack(side="left", padx=1)
            slider.configure(command=lambda v, i=idx, vl=val_lbl: self._on_defend_slider_drag(i, vl, v))
            slider.bind("<ButtonRelease-1>", lambda e, i=idx: self._on_defend_slider_release(i))
        else:
            spacer = ctk.CTkFrame(right_frame, width=95, fg_color="transparent")
            spacer.pack(side="left", fill="y")
            spacer.pack_propagate(False)

        self._bind_hover_tooltip(summary_card, tooltip_text, wraplength=420)

        for talespire_widget in (name_lbl, suffix_lbl, gem_lbl, atk_row):
            self._bind_talespire_weapon_attack_click(talespire_widget, idx)
        self._bind_talespire_click(
            dmg_lbl,
            lambda weapon_idx=idx: self._build_talespire_weapon_damage_roll(weapon_idx),
        )
        self._bind_talespire_weapon_full_click(summary_card, idx)

        self._combat_summary_labels[idx] = suffix_lbl
        self._combat_summary_attack_labels[idx] = suffix_lbl
        self._combat_summary_weapon_name_labels[idx] = name_lbl
        self._combat_summary_attack_suffix_labels[idx] = suffix_lbl
        if not hasattr(self, "_combat_summary_gem_suffix_labels"):
            self._combat_summary_gem_suffix_labels = {}
        self._combat_summary_gem_suffix_labels[idx] = gem_lbl
        self._combat_summary_damage_labels[idx] = dmg_lbl
        self._combat_summary_cards[idx] = summary_card

    def refresh_combat_page(self):
        if not hasattr(self, "combat_weapons_scroll"):
            return

        self._refresh_combat_weather_display()
        self._combat_layout_mode = "wide"
        self._cancel_hover_tooltip()
        if not self._should_skip_widget_to_data_sync():
            self.sync_inventory_to_data()
            self._sync_combat_widgets_to_data()

        for widget in self.combat_weapons_scroll.winfo_children():
            widget.destroy()
        for widget in self.combat_summary_scroll.winfo_children():
            widget.destroy()
        self._combat_spell_summary_widgets = []
        self._combat_mount_summary_widgets = []
        self._combat_flurry_summary_label = None
        self._combat_flurry_summary_params = None
        for attr in ("combat_touch_label", "combat_ac_label", "combat_melee_touch_label", "combat_ranged_touch_label"):
            if hasattr(self, attr):
                delattr(self, attr)
        for widget in self.combat_spell_panel.winfo_children():
            widget.destroy()
        for widget in self.combat_ac_panel.winfo_children():
            widget.destroy()

        self._combat_weapon_widgets = {}
        self._combat_owned_weapon_sword_buttons = {}
        self._combat_natural_sword_buttons = {}
        self._combat_natural_attack_widgets = {}
        self._combat_natural_attack_entries = {}
        self._combat_natural_summary_attack_labels = {}
        self._combat_natural_summary_damage_labels = {}
        self._combat_natural_summary_cards = {}
        self._combat_summary_labels = {}
        self._combat_summary_attack_labels = {}
        self._combat_summary_weapon_name_labels = {}
        self._combat_summary_attack_suffix_labels = {}
        self._combat_summary_gem_suffix_labels = {}
        self._combat_summary_damage_labels = {}
        self._combat_summary_cards = {}
        # Do NOT clear self.weapon_vars / self.weapon_combos here — those hold the live
        # StringVars for the 5 weapon slot editors on the Inventory page (name dropdown + range/value boxes).
        # Clearing them breaks autofill .set() on subsequent dropdown changes.
        # The combat owned-weapons list uses its own _combat_weapon_widgets etc.
        natural_attacks = self._get_special_feature_natural_attacks()
        hide_wielded = self._special_features_hide_wielded_weapons()
        owned = [] if hide_wielded else self._get_owned_weapon_indices()
        wielded = [] if hide_wielded else self._get_wielded_weapon_indices()

        if not owned and not natural_attacks:
            ctk.CTkLabel(
                self.combat_weapons_scroll,
                text="No owned weapons found. Add weapons to your inventory, then assign them in an Inventory weapon slot.",
                wraplength=900, justify="left", text_color="#aaaaaa",
            ).pack(pady=20, padx=12, anchor="w")
        elif owned:
            header = ctk.CTkFrame(self.combat_weapons_scroll)
            header.pack(fill="x", pady=(0, 6), padx=4)
            for text, width in [
                ("Weapon", 130), ("Hit Abil", 88), ("Dmg Abil", 88), ("Type", 88),
                ("Style", 82), ("Damage Die", 82), ("Threat", 68), ("Crit", 52),
                ("Inv Bonuses", 118),
            ]:
                ctk.CTkLabel(header, text=text, width=width, font=ctk.CTkFont(weight="bold")).pack(
                    side="left", padx=3,
                )

            for idx in owned:
                weapon = self._get_weapon_slot(idx)
                config = self._get_combat_weapon_config(idx, weapon)

                row = ctk.CTkFrame(self.combat_weapons_scroll)
                row.pack(fill="x", pady=4, padx=4)

                is_wielded = str(weapon.get("status", "")).strip().lower() == "wielded"
                sword_btn = ctk.CTkButton(
                    row, text="⚔", width=18, height=18,
                    fg_color="transparent",
                    border_width=0,
                    text_color="#777777",
                    hover_color=getattr(self, "secondary_hover_color", "#1f7f75"),
                    font=ctk.CTkFont(size=11),
                    command=lambda i=idx: self._toggle_weapon_wielded_for_summaries(i),
                )
                sword_btn.pack(side="left", padx=(2, 4))
                self._set_sword_active(sword_btn, is_wielded)
                self._bind_hover_tooltip(
                    sword_btn,
                    "Toggle Wielded — wielded weapons appear in Attack Summaries",
                )
                self._combat_owned_weapon_sword_buttons[idx] = sword_btn

                ctk.CTkLabel(row, text=str(weapon.get("name", "Weapon"))[:18], width=118, anchor="w").pack(
                    side="left", padx=3,
                )

                hit_combo = ctk.CTkComboBox(
                    row, values=HIT_ABILITIES, width=88,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "hit_ability", val),
                )
                hit_combo.set(config.get("hit_ability", "Strength"))
                hit_combo.pack(side="left", padx=3)

                dmg_combo = ctk.CTkComboBox(
                    row, values=DMG_ABILITIES, width=88,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "dmg_ability", val),
                )
                dmg_combo.set(config.get("dmg_ability", "Strength"))
                dmg_combo.pack(side="left", padx=3)

                type_combo = ctk.CTkComboBox(
                    row, values=DAMAGE_TYPES, width=88,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "damage_type", val),
                )
                type_combo.set(config.get("damage_type", "Slashing"))
                type_combo.pack(side="left", padx=3)

                style_combo = ctk.CTkComboBox(
                    row, values=WEAPON_STYLES, width=82,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "weapon_style", val),
                )
                style_combo.set(config.get("weapon_style", "1H"))
                style_combo.pack(side="left", padx=3)

                die_combo = ctk.CTkComboBox(
                    row, values=DAMAGE_DICE, width=82,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "damage_die", val),
                )
                die_combo.set(config.get("damage_die", "1d8"))
                die_combo.pack(side="left", padx=3)

                threat_combo = ctk.CTkComboBox(
                    row, values=list(THREAT_RANGES), width=68,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "threat_range", val),
                )
                threat_combo.set(config.get("threat_range", "20"))
                threat_combo.pack(side="left", padx=3)

                crit_combo = ctk.CTkComboBox(
                    row, values=list(CRIT_MULTIPLIERS), width=52,
                    command=lambda val, i=idx: self._on_combat_field_change(i, "crit_multiplier", val),
                )
                crit_combo.set(self._normalize_crit_multiplier(config.get("crit_multiplier", "x2")))
                crit_combo.pack(side="left", padx=3)

                enh = int(weapon.get("enh", 0) or 0)
                feat_atk = int(weapon.get("feat_atk", 0) or 0)
                feat_dmg = int(weapon.get("feat_dmg", 0) or 0)
                ctk.CTkLabel(
                    row, text=f"+{enh} enh | +{feat_atk} atk | +{feat_dmg} dmg",
                    width=118, anchor="w",
                ).pack(side="left", padx=3)

                self._combat_weapon_widgets[idx] = {
                    "hit_ability": hit_combo,
                    "dmg_ability": dmg_combo,
                    "damage_type": type_combo,
                    "weapon_style": style_combo,
                    "damage_die": die_combo,
                    "threat_range": threat_combo,
                    "crit_multiplier": crit_combo,
                }

        for idx in wielded:
            self._build_weapon_attack_summary_card(idx)

        if natural_attacks:
            self._append_special_natural_attacks_combat(
                natural_attacks,
                show_weapon_header=not owned,
            )

        # Spells category in attack summaries (added via crossed-swords button in Prepared Spells)
        self._refresh_spell_attack_summaries()
        self._refresh_mount_attack_summary()

        self._refresh_wielded_weapons_feat_sliders()
        monk_lvl = self._get_class_level("Monk")
        if monk_lvl > 0:
            eff_for_die = self._get_effective_monk_level()
            self._add_flurry_of_blows_summary(self.combat_summary_scroll, monk_lvl, eff_for_die)
        self.calculate_combat()
        self._update_combat_footer()
        self.refresh_movement_display()
        self._apply_combat_responsive_layout()
        self._mark_combat_page_built()
        self._mark_combat_summaries_built()

    def _get_monk_flurry_bases(self, monk_level):
        # Base attack bonuses from SRD Flurry of Blows column (the "base" part before ability mod)
        # From table for standard progression
        bases_map = {
            1: [-2, -2],
            2: [-1, -1],
            3: [0, 0],
            4: [1, 1],
            5: [2, 2],
            6: [3, 3],
            7: [4, 4],
            8: [5, 5, 0],
            9: [6, 6, 1],
            10: [7, 7, 2],
            11: [8, 8, 8, 3],
            12: [9, 9, 9, 4],
            13: [9, 9, 9, 4],
            14: [10, 10, 10, 5],
            15: [11, 11, 11, 6, 1],
            16: [12, 12, 12, 7, 2],
            17: [12, 12, 12, 7, 2],
            18: [13, 13, 13, 8, 3],
            19: [14, 14, 14, 9, 4],
            20: [15, 15, 15, 10, 5],
        }
        return bases_map.get(monk_level, [0])

    def _get_monk_unarmed_die(self, monk_level):
        # Medium monk unarmed damage from SRD table
        if monk_level >= 20: return "2d10"
        if monk_level >= 16: return "2d8"
        if monk_level >= 12: return "2d6"
        if monk_level >= 8: return "1d10"
        if monk_level >= 4: return "1d8"
        return "1d6"

    def _add_flurry_of_blows_summary(self, parent, monk_level, die_level=None):
        """Add special Flurry of Blows attack summary card for Monk, using chosen abilities and bonuses from feature UI.
        die_level (from belt etc) may be higher than monk_level for boosted unarmed damage die only.
        """
        if die_level is None or die_level < monk_level:
            die_level = monk_level
        state = self.data.get("class_feature_state", {})
        tohit_abil = state.get("monk_flurry_tohit_ability", "Strength")
        dmg_abil = state.get("monk_flurry_damage_ability", "Strength")
        tohit_b = state.get("monk_flurry_tohit_bonus", 0)
        dmg_b = state.get("monk_flurry_damage_bonus", 0)

        tohit_mod = self._effective_ability_mod(tohit_abil)
        dmg_mod = self._effective_ability_mod(dmg_abil)

        bases = self._get_monk_flurry_bases(monk_level)
        die = self._get_monk_unarmed_die(die_level)

        frame = ctk.CTkFrame(parent, fg_color="#2F2F2F", corner_radius=6, height=50)
        frame.pack(fill="x", pady=2, padx=4)
        frame.pack_propagate(False)  # match ~50px height of weapon summary rows

        header = ctk.CTkFrame(frame, fg_color="transparent")
        header.pack(fill="x", padx=8, pady=(2, 1))
        ctk.CTkLabel(header, text=f"Flurry of Blows (Monk {monk_level})", font=ctk.CTkFont(size=12, weight="bold"), text_color="#c77626").pack(side="left")

        # attacks
        atk_strs = []
        for base in bases:
            total = base + tohit_mod + tohit_b
            atk_strs.append(self._format_modifier(total))
        atk_line = "/".join(atk_strs)

        # dmg
        dmg_line = f"{die} {self._format_modifier(dmg_mod + dmg_b)}"

        flurry_label = ctk.CTkLabel(
            frame,
            text=f"Attacks: {atk_line}   Damage: {dmg_line} ({len(bases)} attacks)",
            font=ctk.CTkFont(size=11),
        )
        flurry_label.pack(anchor="w", padx=8, pady=(0, 2))
        self._combat_flurry_summary_label = flurry_label
        self._combat_flurry_summary_params = {
            "monk_level": monk_level,
            "die_level": die_level,
            "tohit_abil": tohit_abil,
            "dmg_abil": dmg_abil,
            "tohit_b": tohit_b,
            "dmg_b": dmg_b,
        }
        ctk.CTkLabel(frame, text=f"to-hit: {tohit_abil}{self._format_modifier(tohit_b)}   dmg: {dmg_abil}{self._format_modifier(dmg_b)} + base", font=ctk.CTkFont(size=10), text_color="#888888").pack(anchor="w", padx=8, pady=(0, 4))

    def _is_spell_in_combat_summary(self, spell_name, prepared_entry):
        if self._is_eldritch_blast_spell(spell_name):
            return self._is_eldritch_blast_in_combat_summary()
        norm = self._normalize_prepared_entry(prepared_entry)
        key = (spell_name, norm.get("slot_level", 0), norm.get("prep_id"))
        attacks = self.data.get("combat_spell_attacks", [])
        return any(
            (a.get("spell"), a.get("slot_level"), a.get("prep_id")) == key for a in attacks
        )

    def _set_sword_active(self, btn, active):
        if btn is None:
            return
        try:
            teal = getattr(self, 'secondary_button_color', THEME_TEAL)
            dim = "#777777"
            btn.configure(
                text_color=(teal if active else dim),
                fg_color="transparent",
                border_width=0
            )
        except Exception:
            pass

    def _set_sword_active_for_entry(self, entry_key, active):
        if not hasattr(self, "prepared_widgets"):
            return
        w = self.prepared_widgets.get(entry_key) or {}
        self._set_sword_active(w.get("sword_btn"), active)

    def _toggle_spell_attack_summary(self, spell_name, prepared_entry):
        """Toggle a qualifying prepared spell into/out of the Combat 'Spells' attack summaries.
        Button only appears for spells with 'vs' or [CL, formula. Transparent no-border icon.
        Teal text when active (present in summaries); clicking again removes + resets style.
        """
        if self._is_eldritch_blast_spell(spell_name):
            active = self._toggle_eldritch_blast_attack_summary()
            entry_key = self._prepared_entry_key(prepared_entry)
            self._set_sword_active_for_entry(entry_key, bool(active))
            return

        norm = self._normalize_prepared_entry(prepared_entry)
        slot_level = norm.get("slot_level", self.spells_db.get(spell_name, {}).get("level", 1))
        dc_level = self._get_prepared_dc_level(norm)
        prep_id = norm.get("prep_id")
        key = (spell_name, slot_level, prep_id)

        attacks = self.data.setdefault("combat_spell_attacks", [])
        existing_idx = None
        for i, a in enumerate(attacks):
            if (a.get("spell"), a.get("slot_level"), a.get("prep_id")) == key:
                existing_idx = i
                break

        entry_key = self._prepared_entry_key(prepared_entry)

        if existing_idx is not None:
            # Remove
            del attacks[existing_idx]
            self._set_sword_active_for_entry(entry_key, False)
        else:
            # Add: build entry data (die with CL support, dc, etc.)
            spell = self.spells_db.get(spell_name, {})
            attack_type = spell.get("attack_type") or "Special"
            vs = spell.get("vs")
            assigned = norm.get("caster_class") or "Cleric"

            die = spell.get("damage_die")
            if not die:
                desc = spell.get("description", "") + " " + str(spell.get("effects", {}))
                m = re.search(r'(\d+d\d+(?:[+-]\d+)?)', desc)
                die = m.group(1) if m else "varies"
                raw_desc = self._get_raw_spell_description(spell_name) or spell.get("description", "")
                if "[CL," in raw_desc:
                    try:
                        cl = self._get_effective_cl_for_spell(spell_name, assigned)
                        formatted = self._resolve_cl_formulas(raw_desc, cl)
                        m2 = re.search(r'(\d+d\d+(?:[+-]\d+)?)', formatted)
                        if m2:
                            die = m2.group(1)
                    except Exception:
                        pass

            dc = None
            if vs and vs in ("Fort", "Ref", "Will", "AC"):
                try:
                    dc = self.get_spell_dc(assigned, dc_level)
                except Exception:
                    ability_mod = self._effective_ability_mod("Wisdom")
                    dc = 10 + dc_level + ability_mod

            entry = {
                "spell": spell_name,
                "slot_level": slot_level,
                "dc_level": dc_level,
                "prep_id": prep_id,
                "attack_type": attack_type,
                "vs": vs,
                "die": die,
                "dc": dc,
            }
            attacks.append(entry)
            self._set_sword_active_for_entry(entry_key, True)

        # Update the spell attack summaries live if the combat summary area has been built.
        # This makes toggling the ⚔ button (add or remove) immediately reflected in the combat "Spells" section
        # without requiring a full page rebuild or tab switch.
        if hasattr(self, "combat_summary_scroll"):
            self._refresh_spell_attack_summaries()
        # Also mark stale for the case when combat page hasn't been visited yet (so first visit shows correct list).
        self._mark_combat_page_stale()
        self._mark_cloud_sync_dirty()
        # If the combat frame is currently visible, a full refresh is also fine (it will call the spell refresh internally too).
        if hasattr(self, "combat_frame") and self._is_page_active("Combat"):
            self.refresh_combat_page()

    def _refresh_spell_attack_summaries(self):
        """Clear any previous spell header/cards (using tracked list) and re-pack current ones from data.
        Safe to call from light refreshes or directly from toggle to make add/remove live without full weapon rebuild.
        """
        if not hasattr(self, "combat_summary_scroll"):
            return
        # Destroy previously tracked spell widgets (header + cards)
        for w in getattr(self, "_combat_spell_summary_widgets", []) or []:
            try:
                if w and w.winfo_exists():
                    w.destroy()
            except Exception:
                pass
        self._combat_spell_summary_widgets = []
        spell_attacks = self.data.get("combat_spell_attacks", [])
        if spell_attacks:
            spell_header = ctk.CTkFrame(self.combat_summary_scroll, fg_color="#2a3a2f", height=22)
            spell_header.pack(fill="x", pady=(6, 1), padx=4)
            spell_header.pack_propagate(False)
            ctk.CTkLabel(spell_header, text="Spells", font=ctk.CTkFont(size=11, weight="bold"), text_color=THEME_TEAL).pack(side="left", padx=6)
            self._combat_spell_summary_widgets.append(spell_header)
            for sp in spell_attacks:
                card = self._add_spell_attack_summary_card(self.combat_summary_scroll, sp)
                if card:
                    self._combat_spell_summary_widgets.append(card)

    def _get_spell_or_invocation_attack_info(self, spell_name):
        """Attack metadata for combat spell summaries (invocations fall back before spells)."""
        if (
            HAS_WARLOCK_SUPPORT
            and self._is_eldritch_blast_spell(spell_name)
        ):
            return _warlock_support.get_eldritch_blast_definition(
                getattr(self, "invocations_db", {}) or {},
            )
        info = (getattr(self, "invocations_db", {}) or {}).get(spell_name)
        if info:
            return info
        return self.spells_db.get(spell_name, {}) or {}

    def _add_spell_attack_summary_card(self, parent, sp_data):
        """Create a compact attack summary card for a spell (in 'Spells' category).
        Supports attack_type (for touch etc Talespire) and vs (DC vs save).
        """
        spell_name = sp_data["spell"]
        display_name = str(sp_data.get("label") or spell_name).strip() or spell_name
        spell = self._get_spell_or_invocation_attack_info(spell_name)
        attack_type = sp_data.get("attack_type") or spell.get("attack_type")
        vs = sp_data.get("vs") or spell.get("vs")
        essence_save = sp_data.get("essence_save")
        die = sp_data.get("die", "varies")
        slot_level = sp_data.get("slot_level", 1)
        dc_level = sp_data.get("dc_level", slot_level)

        is_eldritch_blast = (
            HAS_WARLOCK_SUPPORT and self._is_eldritch_blast_spell(spell_name)
        )
        is_save = bool(
            vs and vs in ("Fort", "Ref", "Will")
            and not (is_eldritch_blast and essence_save)
        )
        is_touch_attack = bool(
            attack_type in ("Touch", "Ranged Touch", "Melee Touch")
            or (vs and str(vs).strip().upper() == "AC")
            or is_eldritch_blast
        )
        dc = sp_data.get("dc")
        if is_save and not dc:
            assigned = "Cleric"
            try:
                dc = self.get_spell_dc(assigned, dc_level)
            except Exception:
                dc = 10 + dc_level + self._effective_ability_mod("Wisdom")
        if (
            not dc
            and essence_save
            and is_eldritch_blast
        ):
            try:
                dc = self.get_spell_dc("Warlock", dc_level)
            except Exception:
                dc = None

        frame = ctk.CTkFrame(parent, fg_color="#2f3a2f", height=50)
        frame.pack(fill="x", pady=2, padx=6)
        frame.pack_propagate(False)

        if is_save:
            main_text = f"{display_name} (DC {dc} vs {vs})"
            atk_lbl = ctk.CTkLabel(frame, text=main_text, font=ctk.CTkFont(size=12, weight="bold"))
            atk_lbl.pack(side="left", padx=8, pady=2)
            self._bind_hover_tooltip(frame, f"Spell save DC {dc} vs {vs}")
        else:
            # Per refined rules: for Ranged Touch show "+ranged touch +X", for Touch "+Touch attack +X".
            # Then append die or "Vs Fort/Ref/Will" info.
            melee_touch, ranged_touch = self._get_touch_attacks()
            if attack_type == "Ranged Touch":
                type_str = f"+ranged touch {self._format_modifier(ranged_touch)}"
            elif attack_type in ("Touch", "Melee Touch"):
                type_str = f"+Touch attack {self._format_modifier(melee_touch)}"
            elif is_touch_attack and vs and str(vs).strip().upper() == "AC":
                type_str = f"+ranged touch {self._format_modifier(ranged_touch)}"
            else:
                type_str = f"+{attack_type}" if attack_type else ""
            extra = ""
            if not is_eldritch_blast or not essence_save:
                extra = f" {die}" if (die and die != "varies") else ""
                if vs and vs in ("Fort", "Ref", "Will") and dc is not None:
                    extra += f" (DC {dc} vs {vs})"
            main_text = f"{display_name} {type_str}{extra}".strip() if (type_str or extra) else display_name

            atk_lbl = ctk.CTkLabel(frame, text=main_text, font=ctk.CTkFont(size=12, weight="bold"), cursor="hand2")
            atk_lbl.pack(side="left", padx=8, pady=2)

            dmg_lbl = None
            if die and die != "varies":
                dmg_lbl = ctk.CTkLabel(frame, text=die, font=ctk.CTkFont(size=11), cursor="hand2")
                dmg_lbl.pack(side="left", padx=4)

            if attack_type in ("Touch", "Ranged Touch", "Melee Touch", "Melee", "Ranged") or is_touch_attack:
                is_ranged = "Ranged" in str(attack_type or "")
                self._bind_talespire_click(atk_lbl, lambda ir=is_ranged: self._build_talespire_touch_attack_roll(ir))
                if dmg_lbl is not None:
                    self._bind_talespire_click(
                        dmg_lbl,
                        lambda d=die, lbl=display_name: self._format_talespire_roll(f"{lbl} Damage", [d]),
                    )
            self._bind_hover_tooltip(frame, main_text)

        return frame

    def _update_combat_ac_footer_labels(self):
        """Refresh only the combat footer AC / Flat / Touch text (lightweight; safe during slider drag)."""
        label = getattr(self, "combat_ac_label", None)
        if not self._widget_is_alive(label):
            return
        ac = self._get_ac_breakdown()
        label.configure(
            text=f"🛡️ AC {ac['ac']}    👢 Flat {ac['flat']}    ✋ Touch {ac['touch']}"
        )

    def _update_combat_footer(self):
        spell_panel = getattr(self, "combat_spell_panel", None)
        ac_panel = getattr(self, "combat_ac_panel", None)
        if not self._widget_is_alive(spell_panel) or not self._widget_is_alive(ac_panel):
            return
        ac = self._get_ac_breakdown()
        melee_touch, ranged_touch = self._get_touch_attacks()
        if not self._widget_is_alive(getattr(self, "combat_melee_touch_label", None)):
            for widget in spell_panel.winfo_children():
                widget.destroy()
            for widget in ac_panel.winfo_children():
                widget.destroy()
            spell_panel.grid_rowconfigure(0, weight=1)
            spell_panel.grid_columnconfigure(0, weight=1)
            ac_panel.grid_rowconfigure(0, weight=1)
            ac_panel.grid_columnconfigure(0, weight=1)

            melee_lbl = ctk.CTkLabel(
                spell_panel,
                text=f"✨ Melee Touch {self._format_modifier(melee_touch)}",
                font=ctk.CTkFont(size=12, weight="bold"),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                cursor="hand2",
            )
            melee_lbl.grid(row=0, column=0, sticky="w", padx=2)
            self._bind_talespire_click(melee_lbl, lambda: self._build_talespire_touch_attack_roll(False))

            ranged_lbl = ctk.CTkLabel(
                spell_panel,
                text=f"    🏹 Ranged Touch {self._format_modifier(ranged_touch)}",
                font=ctk.CTkFont(size=12, weight="bold"),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
                cursor="hand2",
            )
            ranged_lbl.grid(row=0, column=1, sticky="w", padx=2)
            self._bind_talespire_click(ranged_lbl, lambda: self._build_talespire_touch_attack_roll(True))

            self.combat_melee_touch_label = melee_lbl
            self.combat_ranged_touch_label = ranged_lbl

            self.combat_ac_label = ctk.CTkLabel(
                ac_panel,
                text=f"🛡️ AC {ac['ac']}    👢 Flat {ac['flat']}    ✋ Touch {ac['touch']}",
                font=ctk.CTkFont(size=12, weight="bold"),
                text_color=getattr(self, 'primary_button_color', THEME_ORANGE),
            )
            self.combat_ac_label.grid(row=0, column=0, sticky="e", padx=2)
        else:
            melee_label = getattr(self, "combat_melee_touch_label", None)
            ranged_label = getattr(self, "combat_ranged_touch_label", None)
            if self._widget_is_alive(melee_label):
                melee_label.configure(text=f"✨ Melee Touch {self._format_modifier(melee_touch)}")
            if self._widget_is_alive(ranged_label):
                ranged_label.configure(text=f"    🏹 Ranged Touch {self._format_modifier(ranged_touch)}")
            self._update_combat_ac_footer_labels()
        self._refresh_combat_footer_resistances()

    def _ensure_description_data(self):
        desc = self.data.setdefault("description", {})
        defaults = {
            "age": "",
            "age_category": "Young",
            "height": "",
            "weight": "",
            "hair": "",
            "eyes": "",
            "ethnicity": "",
            "deity": "",
            "enemies_allies": "",
            "backstory": "",
            "enemies_allies_entries": [],
            "character_journey_entries": [],
            "factions_entries": [],
            "followers_entries": [],
            "notes": "",
            "portrait_file": "",
        }
        for key, value in defaults.items():
            desc.setdefault(key, value)
        if self.data.get("notes") and not desc.get("notes"):
            desc["notes"] = self.data["notes"]
        self._migrate_description_entries(desc)
        return desc

    def _migrate_description_entries(self, desc):
        if not desc.get("enemies_allies_entries") and desc.get("enemies_allies", "").strip():
            desc["enemies_allies_entries"] = [{
                "id": uuid.uuid4().hex,
                "name": "Imported Entry",
                "type": "Neutral",
                "goals": "",
                "location": "",
                "notes": desc.get("enemies_allies", "").strip(),
            }]
            desc["enemies_allies"] = ""
        if not desc.get("character_journey_entries") and desc.get("backstory", "").strip():
            desc["character_journey_entries"] = [{
                "id": uuid.uuid4().hex,
                "backstory": desc.get("backstory", "").strip(),
                "short_term_goals": "",
                "mid_term_goals": "",
                "long_term_goals": "",
                "section_order": list(JOURNEY_SECTION_ORDER_DEFAULT),
                "section_heights": {},
            }]
            desc["backstory"] = ""
        desc.setdefault("enemies_allies_entries", [])
        desc.setdefault("character_journey_entries", [])
        desc.setdefault("factions_entries", [])
        desc.setdefault("followers_entries", [])
        self._strip_follower_statblocks_from_data(desc)

    def _strip_follower_statblocks_from_data(self, data=None):
        """Keep follower statblocks on the server; local sheet stores metadata only."""
        target = data if data is not None else self.data
        if not isinstance(target, dict):
            return
        if "followers_entries" in target:
            desc = target
        else:
            desc = target.get("description")
        if not isinstance(desc, dict):
            return
        for entry in desc.get("followers_entries") or []:
            if isinstance(entry, dict):
                entry.pop("monster_json", None)
                entry.pop("view_data_json", None)

    def _description_entry_title(self, entry, fallback):
        for key in ("name", "backstory"):
            text = str(entry.get(key, "") or "").strip()
            if text:
                title = self._markdown_plain_text(text.splitlines()[0])
                return title[:48] + ("…" if len(title) > 48 else "")
        return fallback

    def _markdown_font_family(self):
        if not hasattr(self, "_cached_markdown_font_family"):
            try:
                self._cached_markdown_font_family = tkfont.nametofont("TkDefaultFont").actual("family")
            except Exception:
                self._cached_markdown_font_family = "Segoe UI"
        return self._cached_markdown_font_family

    def _markdown_plain_text(self, text):
        plain = str(text or "")
        plain = re.sub(r"^#{1,6}\s+", "", plain)
        plain = re.sub(r"\*\*(.+?)\*\*", r"\1", plain)
        plain = re.sub(r"__(.+?)__", r"\1", plain)
        plain = re.sub(r"(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)", r"\1", plain)
        plain = re.sub(r"(?<!_)_(?!_)(.+?)(?<!_)_(?!_)", r"\1", plain)
        return plain.strip()

    def _configure_markdown_text_tags(self, text_widget, base_size=12):
        family = self._markdown_font_family()
        styles = {
            "body": (base_size, "normal", 1, 3),
            "h1": (base_size + 6, "bold", 4, 8),
            "h2": (base_size + 4, "bold", 3, 6),
            "h3": (base_size + 2, "bold", 2, 5),
        }
        for tag_name, (size, weight, spacing1, spacing3) in styles.items():
            text_widget.tag_configure(
                tag_name,
                font=(family, size, weight),
                spacing1=spacing1,
                spacing3=spacing3,
            )
            text_widget.tag_configure(
                f"{tag_name}_bold",
                font=(family, size, "bold"),
                spacing1=spacing1,
                spacing3=spacing3,
            )
            text_widget.tag_configure(
                f"{tag_name}_italic",
                font=(family, size, "italic"),
                spacing1=spacing1,
                spacing3=spacing3,
            )

    def _insert_inline_markdown(self, text_widget, text, base_tag):
        pattern = re.compile(r"\*\*(.+?)\*\*|__(.+?)__|\*(.+?)\*|_(.+?)_")
        pos = 0
        for match in pattern.finditer(text):
            if match.start() > pos:
                text_widget.insert("end", text[pos:match.start()], (base_tag,))
            if match.group(1) is not None or match.group(2) is not None:
                content = match.group(1) if match.group(1) is not None else match.group(2)
                text_widget.insert("end", content, (f"{base_tag}_bold",))
            else:
                content = match.group(3) if match.group(3) is not None else match.group(4)
                text_widget.insert("end", content, (f"{base_tag}_italic",))
            pos = match.end()
        if pos < len(text):
            text_widget.insert("end", text[pos:], (base_tag,))

    def _journey_section_height(self, entry, section_key):
        heights = (entry or {}).get("section_heights", {})
        try:
            value = int(heights.get(section_key, JOURNEY_SECTION_DEFAULT_HEIGHT) or JOURNEY_SECTION_DEFAULT_HEIGHT)
        except (TypeError, ValueError):
            value = JOURNEY_SECTION_DEFAULT_HEIGHT
        return max(JOURNEY_SECTION_MIN_HEIGHT, min(value, JOURNEY_SECTION_MAX_HEIGHT))

    def _journey_markdown_line_height(self, text_widget):
        try:
            line_px = int(text_widget.winfo_fpixels("linespace"))
            return max(14, line_px)
        except Exception:
            return JOURNEY_MARKDOWN_LINE_PX

    def _journey_pixels_to_markdown_lines(self, text_widget, pixel_height):
        line_px = self._journey_markdown_line_height(text_widget)
        return max(3, int(pixel_height / line_px))

    def _configure_ctk_textbox_height(self, textbox, pixel_height):
        pixel_height = max(
            JOURNEY_SECTION_MIN_HEIGHT,
            min(int(pixel_height), JOURNEY_SECTION_MAX_HEIGHT),
        )
        try:
            textbox.configure(height=pixel_height)
        except Exception:
            pass
        inner = getattr(textbox, "_textbox", None)
        if inner is not None:
            try:
                inner.configure(height=pixel_height)
            except Exception:
                pass
        try:
            textbox._desired_height = pixel_height
        except Exception:
            pass
        draw = getattr(textbox, "_draw", None)
        if callable(draw):
            try:
                draw(no_color_updates=True)
            except TypeError:
                try:
                    draw()
                except Exception:
                    pass
        return pixel_height

    def _apply_journey_section_pixel_height(self, widget, pixel_height, is_textbox=False, container=None):
        pixel_height = max(
            JOURNEY_SECTION_MIN_HEIGHT,
            min(int(pixel_height), JOURNEY_SECTION_MAX_HEIGHT),
        )
        if container is not None:
            try:
                container.configure(height=pixel_height if is_textbox else pixel_height + 24)
                container.pack_propagate(False)
                container.grid_propagate(False)
            except Exception:
                pass
        if is_textbox:
            self._configure_ctk_textbox_height(widget, pixel_height)
        else:
            try:
                widget.configure(state="normal")
                widget.configure(
                    height=self._journey_pixels_to_markdown_lines(widget, pixel_height),
                )
                widget.configure(state="disabled")
            except Exception:
                pass
        try:
            widget.update_idletasks()
            if container is not None:
                container.update_idletasks()
        except Exception:
            pass
        return pixel_height

    def _clear_journey_resize_bindings(self):
        try:
            self.root.unbind("<B1-Motion>")
            self.root.unbind("<ButtonRelease-1>")
        except Exception:
            pass

    def _finish_journey_section_resize(self, _event=None):
        resize = getattr(self, "_journey_resize", None)
        self._clear_journey_resize_bindings()
        if not resize:
            return
        entry = resize.get("entry")
        section_key = resize.get("key")
        if entry is not None and section_key:
            heights = entry.setdefault("section_heights", {})
            heights[section_key] = resize.get("current_height", JOURNEY_SECTION_DEFAULT_HEIGHT)
        self._journey_resize = None

    def _on_journey_section_resize_motion(self, event):
        resize = getattr(self, "_journey_resize", None)
        if not resize:
            return
        delta = event.y_root - resize["start_y"]
        new_height = resize["start_height"] + delta
        resize["current_height"] = self._apply_journey_section_pixel_height(
            resize["widget"],
            new_height,
            is_textbox=resize.get("is_textbox", False),
            container=resize.get("container"),
        )

    def _current_journey_widget_pixel_height(self, widget, is_textbox, entry, section_key):
        if is_textbox:
            try:
                configured = int(widget.cget("height"))
                if configured > 0:
                    return max(JOURNEY_SECTION_MIN_HEIGHT, min(configured, JOURNEY_SECTION_MAX_HEIGHT))
            except Exception:
                pass
            try:
                desired = int(getattr(widget, "_desired_height", 0) or 0)
                if desired > 0:
                    return max(JOURNEY_SECTION_MIN_HEIGHT, min(desired, JOURNEY_SECTION_MAX_HEIGHT))
            except Exception:
                pass
        else:
            try:
                lines = int(widget.cget("height"))
                return max(
                    JOURNEY_SECTION_MIN_HEIGHT,
                    min(lines * self._journey_markdown_line_height(widget), JOURNEY_SECTION_MAX_HEIGHT),
                )
            except Exception:
                pass
        return self._journey_section_height(entry, section_key)

    def _bind_journey_section_resize(
        self, handle, entry, section_key, widget, is_textbox=False, container=None,
    ):
        def _start_resize(event):
            self._clear_journey_drag_bindings()
            current_height = self._current_journey_widget_pixel_height(
                widget, is_textbox, entry, section_key,
            )
            self._journey_resize = {
                "entry": entry,
                "key": section_key,
                "start_y": event.y_root,
                "start_height": current_height,
                "widget": widget,
                "container": container,
                "is_textbox": is_textbox,
                "current_height": current_height,
            }
            self._clear_journey_resize_bindings()
            self.root.bind("<B1-Motion>", self._on_journey_section_resize_motion)
            self.root.bind("<ButtonRelease-1>", self._finish_journey_section_resize)

        handle.bind("<ButtonPress-1>", _start_resize)

    def _populate_markdown_text_widget(self, text_widget, markdown_text, display_height_px=None):
        text_widget.configure(state="normal")
        text_widget.delete("1.0", "end")
        self._configure_markdown_text_tags(text_widget)

        content = (markdown_text or "").strip()
        if not content:
            text_widget.insert("end", "—", ("body",))
            if display_height_px is not None:
                self._apply_journey_section_pixel_height(text_widget, display_height_px, is_textbox=False)
            else:
                text_widget.configure(height=1)
            return

        for line in content.splitlines():
            header_tag = "body"
            line_text = line
            if line.startswith("### "):
                header_tag = "h3"
                line_text = line[4:]
            elif line.startswith("## "):
                header_tag = "h2"
                line_text = line[3:]
            elif line.startswith("# "):
                header_tag = "h1"
                line_text = line[2:]

            self._insert_inline_markdown(text_widget, line_text, header_tag)
            text_widget.insert("end", "\n", (header_tag,))

        if text_widget.get("end-2c", "end-1c") == "\n":
            text_widget.delete("end-2c", "end-1c")

        if display_height_px is not None:
            self._apply_journey_section_pixel_height(text_widget, display_height_px, is_textbox=False)
        else:
            line_count = max(1, int(float(text_widget.index("end-1c"))))
            text_widget.configure(height=min(line_count, 40))

    def _build_journey_markdown_help_button(self, parent):
        return ctk.CTkButton(
            parent,
            text="H",
            width=28,
            height=28,
            fg_color="#555555",
            hover_color="#666666",
            font=ctk.CTkFont(size=13, weight="bold"),
            command=self._open_character_journey_markdown_help,
        )

    def _open_character_journey_markdown_help(self):
        popup = ctk.CTkToplevel(self.root)
        popup.title("Character Journey Markdown")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=560, min_height=580)

        scroll = ctk.CTkScrollableFrame(popup)
        scroll.pack(fill="both", expand=True, padx=20, pady=(16, 8))

        ctk.CTkLabel(
            scroll,
            text="Markdown Formatting",
            font=ctk.CTkFont(size=18, weight="bold"),
        ).pack(anchor="w", pady=(0, 8))

        ctk.CTkLabel(
            scroll,
            text=(
                "Type Markdown in the edit window. Journey sections on the tab "
                "render it automatically. Drag sections vertically to reorder them.\n\n"
                "Headers (larger, bold):\n"
                "  # Main header\n"
                "  ## Subheader\n"
                "  ### Section title\n\n"
                "Emphasis:\n"
                "  **bold**  or  __bold__\n"
                "  *italic*  or  _italic_"
            ),
            font=ctk.CTkFont(size=13),
            justify="left",
            anchor="w",
            wraplength=480,
        ).pack(anchor="w", pady=(0, 12))

        ctk.CTkLabel(
            scroll,
            text="Example input",
            font=ctk.CTkFont(size=14, weight="bold"),
        ).pack(anchor="w", pady=(0, 4))
        example_box = ctk.CTkTextbox(scroll, height=130, width=460)
        example_box.pack(anchor="w", pady=(0, 12))
        example_box.insert("1.0", JOURNEY_MARKDOWN_EXAMPLE)
        example_box.configure(state="disabled")

        ctk.CTkLabel(
            scroll,
            text="Rendered preview",
            font=ctk.CTkFont(size=14, weight="bold"),
        ).pack(anchor="w", pady=(0, 4))
        preview_frame = ctk.CTkFrame(scroll, fg_color="#252525", corner_radius=6)
        preview_frame.pack(fill="x", pady=(0, 8))
        self._create_markdown_display_widget(
            preview_frame, JOURNEY_MARKDOWN_EXAMPLE,
        ).pack(fill="x", padx=10, pady=10)

        ctk.CTkButton(
            popup, text="Close", width=100, fg_color="#666666",
            command=popup.destroy,
        ).pack(pady=(4, 16))

    def _create_markdown_display_widget(self, parent, markdown_text, bg="#252525", display_height_px=None):
        text_widget = tk.Text(
            parent,
            wrap="word",
            relief="flat",
            borderwidth=0,
            highlightthickness=0,
            bg=bg,
            fg="#DCE4EE",
            insertbackground="#DCE4EE",
            selectbackground="#4a4a4a",
            selectforeground="#DCE4EE",
            padx=2,
            pady=2,
            cursor="arrow",
        )
        self._populate_markdown_text_widget(text_widget, markdown_text, display_height_px)
        text_widget.configure(state="disabled")
        return text_widget

    def _build_description_feature_card(
        self, parent, title, lines, entry_id, on_edit, on_delete=None,
    ):
        frame = ctk.CTkFrame(parent, fg_color="#2F2F2F")
        frame.pack(fill="x", pady=8, padx=4)

        header = ctk.CTkFrame(frame, fg_color="transparent")
        header.pack(fill="x", padx=12, pady=(10, 4))
        ctk.CTkLabel(
            header, text=title, font=ctk.CTkFont(size=14, weight="bold"), anchor="w",
        ).pack(side="left", fill="x", expand=True)
        ctk.CTkButton(
            header, text="Edit", width=56, height=26, fg_color=THEME_ORANGE,
            hover_color=getattr(self, 'primary_hover_color', '#a56b32'),
            command=lambda eid=entry_id: on_edit(eid),
        ).pack(side="right", padx=(4, 0))
        if on_delete:
            ctk.CTkButton(
                header, text="✕", width=30, height=26, fg_color="#555555",
                hover_color="#666666",
                command=lambda eid=entry_id: on_delete(eid),
            ).pack(side="right", padx=(4, 0))

        body = "\n\n".join(line for line in lines if line)
        ctk.CTkLabel(
            frame, text=body or "No details yet.", wraplength=520,
            justify="left", anchor="w",
        ).pack(anchor="w", padx=15, pady=(0, 12))
        frame.bind(
            "<Button-1>",
            lambda _e, eid=entry_id: on_edit(eid),
        )
        return frame

    def _build_description_expandable_section(
        self, parent, title, content, default_expanded=False, render_markdown=False,
    ):
        frame = ctk.CTkFrame(parent, fg_color="#2F2F2F")
        frame.pack(fill="x", pady=6, padx=4)

        expanded = {"open": default_expanded}
        body_text = (content or "").strip() or "—"

        header = ctk.CTkFrame(frame, fg_color="transparent")
        header.pack(fill="x", padx=12, pady=(10, 4))

        toggle_btn = ctk.CTkButton(
            header, text="▲" if default_expanded else "▼", width=30, height=28,
            fg_color="#444444", hover_color="#555555",
            font=ctk.CTkFont(size=14, weight="bold"),
        )
        toggle_btn.pack(side="left", padx=(0, 8))

        ctk.CTkLabel(
            header, text=title, font=ctk.CTkFont(size=14, weight="bold"), anchor="w",
        ).pack(side="left", fill="x", expand=True)

        content_frame = ctk.CTkFrame(frame, fg_color="#252525", corner_radius=6)
        if render_markdown:
            content_widget = self._create_markdown_display_widget(content_frame, content)
            content_widget.pack(fill="x", expand=True, padx=12, pady=10)
        else:
            content_widget = ctk.CTkLabel(
                content_frame, text=body_text, wraplength=520,
                justify="left", anchor="nw",
            )
            content_widget.pack(anchor="w", padx=12, pady=10)

        def _sync_wraplength(event=None):
            if render_markdown:
                try:
                    chars = max(24, int((frame.winfo_width() - 56) / 8))
                    content_widget.configure(state="normal", width=chars)
                    content_widget.configure(state="disabled")
                except Exception:
                    pass
            else:
                try:
                    content_widget.configure(wraplength=max(180, frame.winfo_width() - 48))
                except Exception:
                    pass

        def _toggle(_event=None):
            expanded["open"] = not expanded["open"]
            if expanded["open"]:
                content_frame.pack(fill="x", padx=12, pady=(0, 12))
                toggle_btn.configure(text="▲")
            else:
                content_frame.pack_forget()
                toggle_btn.configure(text="▼")

        toggle_btn.configure(command=_toggle)
        header.bind("<Button-1>", _toggle)
        for child in header.winfo_children():
            if child is not toggle_btn:
                child.bind("<Button-1>", _toggle)

        frame.bind("<Configure>", _sync_wraplength)
        if default_expanded:
            content_frame.pack(fill="x", padx=12, pady=(0, 12))
        frame.after_idle(_sync_wraplength)
        return frame

    def _normalize_journey_section_order(self, entry):
        order = list(entry.get("section_order") or JOURNEY_SECTION_ORDER_DEFAULT)
        valid = [key for key in order if key in JOURNEY_SECTION_LABELS]
        for key in JOURNEY_SECTION_ORDER_DEFAULT:
            if key not in valid:
                valid.append(key)
        entry["section_order"] = valid
        return valid

    def _journey_drop_index(self, y_root):
        frames = getattr(self, "_journey_section_frames", [])
        if not frames:
            return 0
        for index, frame in enumerate(frames):
            midpoint = frame.winfo_rooty() + (frame.winfo_height() // 2)
            if y_root < midpoint:
                return index
        return len(frames) - 1

    def _clear_journey_drag_bindings(self):
        if hasattr(self, "character_journey_scroll"):
            try:
                self.character_journey_scroll.unbind("<B1-Motion>")
                self.character_journey_scroll.unbind("<ButtonRelease-1>")
            except Exception:
                pass

    def _finish_journey_section_drag(self, event, entry):
        drag = getattr(self, "_journey_drag", None)
        self._clear_journey_drag_bindings()
        if not drag:
            return

        for frame in getattr(self, "_journey_section_frames", []):
            frame.configure(fg_color="#2F2F2F")

        from_index = drag["index"]
        to_index = self._journey_drop_index(event.y_root)
        order = self._normalize_journey_section_order(entry)
        if from_index != to_index:
            key = order.pop(from_index)
            order.insert(to_index, key)
            entry["section_order"] = order
            self._refresh_character_journey_tab()
        self._journey_drag = None

    def _bind_journey_section_drag(self, frame, drag_widgets, entry, section_key, index):
        def _start_drag(event):
            self._journey_drag = {
                "key": section_key,
                "index": index,
                "frame": frame,
            }
            frame.configure(fg_color="#3a3a3a")
            self._clear_journey_drag_bindings()
            self.character_journey_scroll.bind(
                "<B1-Motion>",
                lambda e, ent=entry: self._highlight_journey_drop_target(e, ent),
            )
            self.character_journey_scroll.bind(
                "<ButtonRelease-1>",
                lambda e, ent=entry: self._finish_journey_section_drag(e, ent),
            )

        for widget in drag_widgets:
            widget.bind("<ButtonPress-1>", _start_drag)

    def _highlight_journey_drop_target(self, event, entry):
        if not getattr(self, "_journey_drag", None):
            return
        drop_index = self._journey_drop_index(event.y_root)
        for idx, frame in enumerate(getattr(self, "_journey_section_frames", [])):
            if idx == drop_index and idx != self._journey_drag["index"]:
                frame.configure(fg_color="#3d3428")
            elif frame is not self._journey_drag.get("frame"):
                frame.configure(fg_color="#2F2F2F")
            else:
                frame.configure(fg_color="#3a3a3a")

    def _build_journey_draggable_section(
        self, parent, entry, entry_id, section_key, index, title, content,
    ):
        frame = ctk.CTkFrame(parent, fg_color="#2F2F2F")
        frame.pack(fill="x", pady=6, padx=4)

        header = ctk.CTkFrame(frame, fg_color="transparent")
        header.pack(fill="x", padx=12, pady=(10, 4))

        grip = ctk.CTkLabel(
            header,
            text="⋮⋮",
            width=20,
            font=ctk.CTkFont(size=16, weight="bold"),
            text_color="#888888",
            cursor="hand2",
        )
        grip.pack(side="left", padx=(0, 8))

        ctk.CTkLabel(
            header, text=title, font=ctk.CTkFont(size=14, weight="bold"), anchor="w",
        ).pack(side="left", fill="x", expand=True)

        section_height = self._journey_section_height(entry, section_key)
        content_frame = ctk.CTkFrame(
            frame, fg_color="#252525", corner_radius=6, height=section_height + 24,
        )
        content_frame.pack(fill="x", padx=12, pady=(0, 4))
        content_frame.pack_propagate(False)
        content_widget = self._create_markdown_display_widget(
            content_frame, content, display_height_px=section_height,
        )
        content_widget.pack(fill="both", expand=True, padx=12, pady=(10, 4))

        resize_handle = ctk.CTkFrame(
            frame, fg_color="#555555", height=10, corner_radius=4, cursor="sb_v_double_arrow",
        )
        resize_handle.pack_propagate(False)
        resize_handle.pack(fill="x", padx=16, pady=(0, 10))
        self._bind_journey_section_resize(
            resize_handle,
            entry,
            section_key,
            content_widget,
            is_textbox=False,
            container=content_frame,
        )

        def _sync_wraplength(event=None):
            try:
                chars = max(24, int((frame.winfo_width() - 56) / 8))
                content_widget.configure(state="normal", width=chars)
                content_widget.configure(state="disabled")
            except Exception:
                pass

        frame.bind("<Configure>", _sync_wraplength)
        frame.after_idle(_sync_wraplength)
        frame.bind(
            "<Double-Button-1>",
            lambda _e, eid=entry_id: self._open_character_journey_popup(eid),
        )
        self._bind_journey_section_drag(frame, (header, grip), entry, section_key, index)
        return frame

    def _find_description_entry(self, entries, entry_id):
        for entry in entries:
            if entry.get("id") == entry_id:
                return entry
        return None

    def _cache_follower_server_row(self, row):
        cloud_id = str((row or {}).get("id") or "").strip()
        if not cloud_id:
            return
        self._followers_server_cache[cloud_id] = row

    def _invalidate_followers_server_cache(self):
        self._followers_tab_loaded = False
        self._followers_tab_loading = False

    def _merge_follower_with_server_row(self, index_entry, server_row):
        merged = dict(index_entry or {})
        if normalize_monster:
            merged["monster_json"] = normalize_monster(server_row)
        if normalize_view_data:
            merged["view_data_json"] = normalize_view_data(server_row)
        if follower_display_name:
            merged["name"] = follower_display_name(server_row)
        merged["shared_by"] = server_row.get("shared_by") or merged.get("shared_by") or "DM"
        merged["created_at"] = server_row.get("created_at") or merged.get("created_at")
        return merged

    def _follower_entry_view_data(self, entry):
        if not entry:
            return {}
        raw = entry.get("view_data_json")
        if isinstance(raw, dict) and raw:
            return raw
        cloud_id = str(entry.get("cloud_id") or "").strip()
        cached = (getattr(self, "_followers_server_cache", None) or {}).get(cloud_id)
        if cached and normalize_view_data:
            return normalize_view_data(cached)
        if normalize_view_data:
            return normalize_view_data(entry)
        return {}

    def _get_local_follower_cloud_ids(self):
        return set(self._local_followers_by_cloud_id().keys())

    def _local_followers_by_cloud_id(self):
        desc = self._ensure_description_data()
        out = {}
        for entry in desc.get("followers_entries") or []:
            cid = str(entry.get("cloud_id") or "").strip()
            if cid:
                out[cid] = entry
        return out

    def _get_dismissed_follower_cloud_ids(self):
        desc = self._ensure_description_data()
        raw = desc.get("followers_dismissed_cloud_ids") or []
        if not isinstance(raw, list):
            return set()
        return {str(x).strip() for x in raw if str(x).strip()}

    def _dismiss_follower_cloud_id(self, cloud_id):
        cloud_id = str(cloud_id or "").strip()
        if not cloud_id:
            return
        desc = self._ensure_description_data()
        dismissed = list(self._get_dismissed_follower_cloud_ids())
        if cloud_id not in dismissed:
            dismissed.append(cloud_id)
        desc["followers_dismissed_cloud_ids"] = dismissed[-100:]
        if self.follower_statblock_sync:
            try:
                self.follower_statblock_sync.mark_follower_seen(cloud_id)
            except Exception:
                pass

    def _seed_follower_seen_from_local(self):
        if not self.follower_statblock_sync:
            return
        ids = list(self._get_local_follower_cloud_ids() | self._get_dismissed_follower_cloud_ids())
        if not ids:
            return
        try:
            self.follower_statblock_sync.mark_followers_seen(ids)
        except Exception:
            pass

    def _follower_index_payload(self, row, *, local_id=None, notes=""):
        cloud_id = str((row or {}).get("id") or "").strip()
        source_id = str((row or {}).get("source_id") or "").strip()
        name = follower_display_name(row) if follower_display_name else str(row.get("follower_name") or "Follower")
        return {
            "id": local_id or uuid.uuid4().hex,
            "cloud_id": cloud_id,
            "source_id": source_id,
            "name": name,
            "shared_by": str(row.get("shared_by") or "DM"),
            "created_at": row.get("created_at"),
            "notes": notes or "",
        }

    def _upsert_follower_from_cloud(self, row):
        """Store follower metadata locally; full statblock stays on the server."""
        cloud_id = str((row or {}).get("id") or "").strip()
        source_id = str((row or {}).get("source_id") or "").strip()
        if cloud_id and cloud_id in self._get_dismissed_follower_cloud_ids():
            return None
        desc = self._ensure_description_data()
        entries = desc.setdefault("followers_entries", [])
        if cloud_id:
            for existing in entries:
                if str(existing.get("cloud_id") or "").strip() == cloud_id:
                    return None
        if source_id:
            for index, existing in enumerate(entries):
                if str(existing.get("source_id") or "").strip() == source_id:
                    replacement = self._follower_index_payload(
                        row,
                        local_id=existing.get("id"),
                        notes=str(existing.get("notes") or ""),
                    )
                    entries[index] = replacement
                    return replacement
        share_name = (
            follower_display_name(row) if follower_display_name
            else str(row.get("follower_name") or "Follower")
        ).strip()
        if share_name:
            for index, existing in enumerate(entries):
                if str(existing.get("source_id") or "").strip():
                    continue
                if str(existing.get("name") or "").strip().casefold() == share_name.casefold():
                    replacement = self._follower_index_payload(
                        row,
                        local_id=existing.get("id"),
                        notes=str(existing.get("notes") or ""),
                    )
                    entries[index] = replacement
                    return replacement
        entry = self._follower_index_payload(row)
        entries.append(entry)
        return entry

    def _on_description_subtab_changed(self, *_args):
        try:
            if self.description_tabview.get() == "Followers":
                self._load_followers_from_server()
        except Exception:
            pass

    def _load_followers_from_server(self, *, force=False):
        if self._followers_tab_loading:
            return
        if self._followers_tab_loaded and not force:
            return
        if not self.follower_statblock_sync or not self.follower_statblock_sync.is_player_configured():
            self._followers_tab_loaded = True
            return
        cloud_ids = [
            cid for cid in self._get_local_follower_cloud_ids()
            if cid not in self._get_dismissed_follower_cloud_ids()
        ]
        if not cloud_ids:
            self._followers_tab_loaded = True
            return
        self._followers_tab_loading = True
        self._refresh_followers_tab(loading=True)

        def _worker():
            try:
                rows = self.follower_statblock_sync.fetch_followers_by_ids(cloud_ids)
                for row in rows or []:
                    self._cache_follower_server_row(row)
                self._followers_tab_loaded = True
                self._schedule_on_main(self._refresh_followers_tab)
            except Exception as exc:
                print(f"Follower statblock load: {exc}")
                self._schedule_on_main(
                    lambda: self._refresh_followers_tab(
                        error=str(exc),
                    ),
                )
            finally:
                self._followers_tab_loading = False

        threading.Thread(target=_worker, daemon=True).start()

    def _refresh_followers_tab(self, *, loading=False, error=None):
        scroll = getattr(self, "followers_scroll", None)
        if scroll is None:
            return
        for child in scroll.winfo_children():
            child.destroy()
        desc = self._ensure_description_data()
        entries = list(desc.get("followers_entries") or [])
        if loading:
            ctk.CTkLabel(
                scroll,
                text="Loading followers from server...",
                text_color="#888888",
                justify="left",
                wraplength=520,
            ).pack(anchor="w", padx=10, pady=12)
            return
        if error:
            ctk.CTkLabel(
                scroll,
                text=f"Could not load followers from server.\n{error}",
                text_color="#cc8888",
                justify="left",
                wraplength=520,
            ).pack(anchor="w", padx=10, pady=12)
            return
        if not entries:
            ctk.CTkLabel(
                scroll,
                text="No followers yet.\nWhen your DM shares an NPC statblock, it appears here.",
                text_color="#888888",
                justify="left",
                wraplength=520,
            ).pack(anchor="w", padx=10, pady=12)
            return
        if (
            not self._followers_tab_loaded
            and self.follower_statblock_sync
            and self.follower_statblock_sync.is_player_configured()
        ):
            ctk.CTkLabel(
                scroll,
                text="Select this tab to load follower statblocks from the server.",
                text_color="#888888",
                justify="left",
                wraplength=520,
            ).pack(anchor="w", padx=10, pady=(12, 6))
        for entry in entries:
            name = str(entry.get("name") or "Follower").strip() or "Follower"
            shared_by = str(entry.get("shared_by") or "DM").strip() or "DM"
            created = str(entry.get("created_at") or "").strip()
            created_txt = created[:16].replace("T", " ") if created else ""
            lines = [f"Shared by {shared_by}"]
            if created_txt:
                lines.append(f"Received {created_txt}")
            notes = str(entry.get("notes") or "").strip()
            if notes:
                lines.append(notes)
            entry_id = entry.get("id")

            def _view(eid=entry_id, payload=entry):
                self._show_follower_statblock_popup(payload)

            def _delete(eid=entry_id, ent=entry):
                desc_local = self._ensure_description_data()
                rows = desc_local.get("followers_entries") or []
                desc_local["followers_entries"] = [r for r in rows if r.get("id") != eid]
                removed_cloud_id = str(ent.get("cloud_id") or "").strip()
                self._dismiss_follower_cloud_id(removed_cloud_id)
                if removed_cloud_id:
                    self._followers_server_cache.pop(removed_cloud_id, None)
                self._invalidate_followers_server_cache()
                self._strip_follower_statblocks_from_data()
                self._quick_save_character_file()
                self._mark_cloud_sync_dirty()
                self._refresh_followers_tab()

            self._build_description_feature_card(
                scroll,
                title=name,
                lines=lines,
                entry_id=entry_id,
                on_edit=_view,
                on_delete=_delete,
            )
            card = scroll.winfo_children()[-1]
            for child in card.winfo_children():
                if isinstance(child, ctk.CTkFrame):
                    for btn in child.winfo_children():
                        if isinstance(btn, ctk.CTkButton) and btn.cget("text") == "Edit":
                            btn.configure(text="View")

    def _show_follower_statblock_popup(self, entry, *, modal=True):
        view_data = self._follower_entry_view_data(entry)
        if view_data:
            self._render_follower_statblock_popup(entry, view_data, modal=modal)
            return
        cloud_id = str((entry or {}).get("cloud_id") or "").strip()
        if not cloud_id or not self.follower_statblock_sync:
            messagebox.showwarning("Follower", "This follower has no statblock data to display.")
            return

        wait_popup = ctk.CTkToplevel(self.root)
        wait_popup.title("Follower")
        wait_popup.geometry("320x100")
        wait_popup.transient(self.root)
        wait_popup.grab_set()
        ctk.CTkLabel(
            wait_popup, text="Loading statblock from server...",
            text_color="#aaaaaa",
        ).pack(expand=True, padx=16, pady=16)

        def _worker():
            try:
                rows = self.follower_statblock_sync.fetch_followers_by_ids([cloud_id])
                if not rows:
                    raise RuntimeError("Follower not found on server.")
                row = rows[0]
                self._cache_follower_server_row(row)
                merged = self._merge_follower_with_server_row(entry, row)
                view = self._follower_entry_view_data(merged)

                def _open():
                    try:
                        if wait_popup.winfo_exists():
                            wait_popup.destroy()
                    except Exception:
                        pass
                    if view:
                        self._render_follower_statblock_popup(merged, view, modal=modal)
                    else:
                        messagebox.showwarning(
                            "Follower", "This follower has no statblock data to display.",
                        )

                self._schedule_on_main(_open)
            except Exception as exc:
                def _fail():
                    try:
                        if wait_popup.winfo_exists():
                            wait_popup.destroy()
                    except Exception:
                        pass
                    messagebox.showwarning("Follower", f"Could not load statblock:\n{exc}")

                self._schedule_on_main(_fail)

        threading.Thread(target=_worker, daemon=True).start()

    def _render_follower_statblock_popup(self, entry, view_data, *, modal=True):
        name = str(entry.get("name") or "Follower").strip() or "Follower"
        shared_by = str(entry.get("shared_by") or "DM").strip() or "DM"

        popup = ctk.CTkToplevel(self.root)
        popup.title(f"Follower — {name}")
        popup.geometry("960x720")
        popup.minsize(720, 520)
        popup.transient(self.root)
        if modal:
            popup.grab_set()
        popup.protocol(
            "WM_DELETE_WINDOW",
            lambda p=popup: p.destroy(),
        )

        header = ctk.CTkFrame(popup, fg_color="#1e1e1e")
        header.pack(fill="x")
        ctk.CTkLabel(
            header, text=name, font=ctk.CTkFont(size=18, weight="bold"),
            text_color=getattr(self, "primary_button_color", THEME_ORANGE),
        ).pack(side="left", padx=14, pady=10)
        ctk.CTkLabel(
            header, text=f"Shared by {shared_by}", font=ctk.CTkFont(size=11), text_color="#888888",
        ).pack(side="left", padx=(0, 12), pady=10)
        ctk.CTkButton(
            header, text="Close", width=72, fg_color="#555555", hover_color="#666666",
            command=popup.destroy,
        ).pack(side="right", padx=12, pady=8)

        body = ctk.CTkFrame(popup, fg_color="#0c0c0e")
        body.pack(fill="both", expand=True, padx=8, pady=8)
        body.grid_columnconfigure(0, weight=3)
        body.grid_columnconfigure(1, weight=2)
        body.grid_rowconfigure(0, weight=1)

        scroll_left = ctk.CTkScrollableFrame(
            body, fg_color="#0c0c0e",
            scrollbar_button_color="#3d2228",
            scrollbar_button_hover_color="#FF6B5B",
        )
        scroll_left.grid(row=0, column=0, sticky="nsew", padx=(0, 4))
        scroll_features = ctk.CTkScrollableFrame(
            body, fg_color="#0c0c0e",
            scrollbar_button_color="#3d2228",
            scrollbar_button_hover_color="#FF6B5B",
        )
        scroll_features.grid(row=0, column=1, sticky="nsew", padx=(4, 0))

        entry_key = str(entry.get("id") or entry.get("cloud_id") or name)
        checkbox_states = self._follower_checkbox_states.setdefault(entry_key, {})
        if render_follower_statblock:
            render_follower_statblock(
                self,
                scroll_left,
                view_data,
                features_parent=scroll_features,
                checkbox_states=checkbox_states,
            )
        else:
            ctk.CTkLabel(
                scroll_left, text="Statblock viewer unavailable.", text_color="#888888",
            ).pack(padx=12, pady=12)

    def _refresh_enemies_allies_tab(self):
        if not hasattr(self, "enemies_allies_scroll"):
            return
        for widget in self.enemies_allies_scroll.winfo_children():
            widget.destroy()
        desc = self._ensure_description_data()
        entries = desc.get("enemies_allies_entries", [])
        if not entries:
            ctk.CTkLabel(
                self.enemies_allies_scroll,
                text="No enemies or allies yet. Click + to add one.",
                text_color="#888888",
                font=ctk.CTkFont(size=13, slant="italic"),
            ).pack(anchor="w", padx=8, pady=20)
            return
        for entry in entries:
            lines = [
                f"Type: {entry.get('type', 'Neutral')}",
                f"Current Goals: {entry.get('goals', '') or '—'}",
                f"Last Known Location: {entry.get('location', '') or '—'}",
                f"Notes: {entry.get('notes', '') or '—'}",
            ]
            self._build_description_feature_card(
                self.enemies_allies_scroll,
                self._description_entry_title(entry, "Unnamed Contact"),
                lines,
                entry.get("id"),
                self._open_enemy_ally_popup,
                self._delete_enemy_ally_entry,
            )

    def _refresh_factions_tab(self):
        if not hasattr(self, "factions_scroll"):
            return
        for widget in self.factions_scroll.winfo_children():
            widget.destroy()
        desc = self._ensure_description_data()
        entries = desc.get("factions_entries", [])
        if not entries:
            ctk.CTkLabel(
                self.factions_scroll,
                text="No factions yet. Click + to add one.",
                text_color="#888888",
                font=ctk.CTkFont(size=13, slant="italic"),
            ).pack(anchor="w", padx=8, pady=20)
