    def _update_character_journey_header_button(self):
        if not hasattr(self, "character_journey_header_btn"):
            return
        desc = self._ensure_description_data()
        entries = desc.get("character_journey_entries", [])
        if entries:
            entry_id = entries[0].get("id")
            self.character_journey_header_btn.configure(
                text="Edit",
                width=56,
                height=30,
                font=ctk.CTkFont(size=13, weight="bold"),
                command=lambda eid=entry_id: self._open_character_journey_popup(eid),
            )
        else:
            self.character_journey_header_btn.configure(
                text="+",
                width=30,
                height=30,
                font=ctk.CTkFont(size=22, weight="bold"),
                command=lambda: self._open_character_journey_popup(),
            )

    def _refresh_character_journey_tab(self):
        if not hasattr(self, "character_journey_scroll"):
            return
        for widget in self.character_journey_scroll.winfo_children():
            widget.destroy()
        desc = self._ensure_description_data()
        entries = desc.get("character_journey_entries", [])
        self._update_character_journey_header_button()
        if not entries:
            ctk.CTkLabel(
                self.character_journey_scroll,
                text="No character journey yet. Click + to add one.",
                text_color="#888888",
                font=ctk.CTkFont(size=13, slant="italic"),
            ).pack(anchor="w", padx=8, pady=20)
            return
        entry = entries[0]
        entry_id = entry.get("id")
        section_order = self._normalize_journey_section_order(entry)
        self._journey_section_frames = []
        self._journey_drag = None
        for index, key in enumerate(section_order):
            section = self._build_journey_draggable_section(
                self.character_journey_scroll,
                entry,
                entry_id,
                key,
                index,
                JOURNEY_SECTION_LABELS[key],
                entry.get(key, ""),
            )
            self._journey_section_frames.append(section)

    def _open_enemy_ally_popup(self, entry_id=None):
        desc = self._ensure_description_data()
        existing = self._find_description_entry(desc["enemies_allies_entries"], entry_id) if entry_id else None

        popup = ctk.CTkToplevel(self.root)
        popup.title("Edit Contact" if existing else "Add Enemy / Ally")
        popup.geometry("560x580")
        popup.grab_set()

        body = ctk.CTkScrollableFrame(popup)
        body.pack(fill="both", expand=True, padx=20, pady=16)

        ctk.CTkLabel(body, text="Name", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        name_var = ctk.StringVar(value=existing.get("name", "") if existing else "")
        ctk.CTkEntry(body, textvariable=name_var, width=420).pack(anchor="w", pady=(0, 10))

        ctk.CTkLabel(body, text="Enemy / Ally / Neutral", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        type_var = ctk.StringVar(value=existing.get("type", "Neutral") if existing else "Neutral")
        ctk.CTkComboBox(body, values=list(ENEMY_ALLY_TYPES), variable=type_var, width=200).pack(anchor="w", pady=(0, 10))

        ctk.CTkLabel(body, text="Current Goals", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        goals_box = ctk.CTkTextbox(body, height=70, width=420)
        goals_box.pack(anchor="w", pady=(0, 10))
        if existing:
            goals_box.insert("1.0", existing.get("goals", ""))

        ctk.CTkLabel(body, text="Last Known Location", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        location_var = ctk.StringVar(value=existing.get("location", "") if existing else "")
        ctk.CTkEntry(body, textvariable=location_var, width=420).pack(anchor="w", pady=(0, 10))

        ctk.CTkLabel(body, text="Notes", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        notes_box = ctk.CTkTextbox(body, height=90, width=420)
        notes_box.pack(anchor="w", pady=(0, 10))
        if existing:
            notes_box.insert("1.0", existing.get("notes", ""))

        btn_row = ctk.CTkFrame(popup, fg_color="transparent")
        btn_row.pack(pady=12)

        def save_entry():
            name = name_var.get().strip()
            if not name:
                messagebox.showwarning("Missing Name", "Enter a name for this contact.", parent=popup)
                return
            payload = {
                "id": entry_id or uuid.uuid4().hex,
                "name": name,
                "type": type_var.get().strip() or "Neutral",
                "goals": goals_box.get("1.0", "end-1c").strip(),
                "location": location_var.get().strip(),
                "notes": notes_box.get("1.0", "end-1c").strip(),
            }
            entries = desc["enemies_allies_entries"]
            if existing:
                for index, item in enumerate(entries):
                    if item.get("id") == entry_id:
                        entries[index] = payload
                        break
            else:
                entries.append(payload)
            self._refresh_enemies_allies_tab()
            self._mark_description_page_built()
            popup.destroy()

        ctk.CTkButton(
            btn_row, text="Save", width=100, fg_color=THEME_ORANGE,
            hover_color=getattr(self, 'primary_hover_color', '#a56b32'), command=save_entry,
        ).pack(side="left", padx=6)
        ctk.CTkButton(
            btn_row, text="Cancel", width=100, fg_color="#666666",
            command=popup.destroy,
        ).pack(side="left", padx=6)

    def _delete_enemy_ally_entry(self, entry_id):
        if not messagebox.askyesno("Delete Contact", "Remove this enemy/ally entry?"):
            return
        desc = self._ensure_description_data()
        desc["enemies_allies_entries"] = [
            e for e in desc["enemies_allies_entries"] if e.get("id") != entry_id
        ]
        self._refresh_enemies_allies_tab()
        self._mark_description_page_built()

    def _open_faction_popup(self, entry_id=None):
        desc = self._ensure_description_data()
        existing = self._find_description_entry(desc.get("factions_entries", []), entry_id) if entry_id else None

        popup = ctk.CTkToplevel(self.root)
        popup.title("Edit Faction" if existing else "Add Faction")
        popup.geometry("520x580")
        popup.grab_set()

        body = ctk.CTkScrollableFrame(popup)
        body.pack(fill="both", expand=True, padx=20, pady=16)

        ctk.CTkLabel(body, text="Faction Name", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        name_var = ctk.StringVar(value=existing.get("name", "") if existing else "")
        ctk.CTkEntry(body, textvariable=name_var, width=420).pack(anchor="w", pady=(0, 10))

        ctk.CTkLabel(body, text="Disposition", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        disp_var = ctk.StringVar(value=existing.get("disposition", "Neutral") if existing else "Neutral")
        ctk.CTkComboBox(body, values=list(FACTION_DISPOSITIONS), variable=disp_var, width=200).pack(anchor="w", pady=(0, 10))

        ctk.CTkLabel(body, text="Faction Goals", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        goals_box = ctk.CTkTextbox(body, height=70, width=420)
        goals_box.pack(anchor="w", pady=(0, 10))
        if existing:
            goals_box.insert("1.0", existing.get("goals", ""))

        ctk.CTkLabel(body, text="Faction Quests", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        quests_box = ctk.CTkTextbox(body, height=70, width=420)
        quests_box.pack(anchor="w", pady=(0, 10))
        if existing:
            quests_box.insert("1.0", existing.get("quests", ""))

        ctk.CTkLabel(body, text="Notes", font=ctk.CTkFont(weight="bold")).pack(anchor="w", pady=(0, 4))
        notes_box = ctk.CTkTextbox(body, height=90, width=420)
        notes_box.pack(anchor="w", pady=(0, 10))
        if existing:
            notes_box.insert("1.0", existing.get("notes", ""))

        hint = ctk.CTkLabel(
            body,
            text="Goals, Quests, and Notes support Markdown formatting.",
            font=ctk.CTkFont(size=11),
            text_color="#888888",
        )
        hint.pack(anchor="w", pady=(0, 8))

        btn_row = ctk.CTkFrame(popup, fg_color="transparent")
        btn_row.pack(pady=12)

        def save_entry():
            name = name_var.get().strip()
            if not name:
                messagebox.showwarning("Missing Name", "Enter a name for this faction.", parent=popup)
                return
            payload = {
                "id": entry_id or uuid.uuid4().hex,
                "name": name,
                "disposition": disp_var.get().strip() or "Neutral",
                "goals": goals_box.get("1.0", "end-1c").strip(),
                "quests": quests_box.get("1.0", "end-1c").strip(),
                "notes": notes_box.get("1.0", "end-1c").strip(),
            }
            entries = desc.setdefault("factions_entries", [])
            if existing:
                for index, item in enumerate(entries):
                    if item.get("id") == entry_id:
                        entries[index] = payload
                        break
            else:
                entries.append(payload)
            self._refresh_factions_tab()
            popup.destroy()

        ctk.CTkButton(
            btn_row, text="Save", width=100, fg_color=THEME_ORANGE,
            hover_color=getattr(self, 'primary_hover_color', '#a56b32'), command=save_entry,
        ).pack(side="left", padx=6)
        ctk.CTkButton(
            btn_row, text="Cancel", width=100, fg_color="#666666",
            command=popup.destroy,
        ).pack(side="left", padx=6)

    def _delete_faction_entry(self, entry_id):
        if not messagebox.askyesno("Delete Faction", "Remove this faction?"):
            return
        desc = self._ensure_description_data()
        desc["factions_entries"] = [
            e for e in desc.get("factions_entries", []) if e.get("id") != entry_id
        ]
        self._refresh_factions_tab()

    def _open_character_journey_popup(self, entry_id=None):
        desc = self._ensure_description_data()
        entries = desc["character_journey_entries"]
        if entry_id is None and entries:
            entry_id = entries[0].get("id")
        existing = self._find_description_entry(entries, entry_id) if entry_id else None

        popup = ctk.CTkToplevel(self.root)
        popup.title("Edit Character Journey" if existing else "Add Character Journey")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=580, min_height=640)
        popup.resizable(True, True)
        popup.minsize(480, 420)
        popup.grid_rowconfigure(0, weight=0)
        popup.grid_rowconfigure(1, weight=1)
        popup.grid_rowconfigure(2, weight=0)
        popup.grid_columnconfigure(0, weight=1)

        hint_row = ctk.CTkFrame(popup, fg_color="transparent")
        hint_row.grid(row=0, column=0, sticky="ew", padx=20, pady=(16, 4))
        ctk.CTkLabel(
            hint_row,
            text="Character's Journey supports Markdown formatting.",
            font=ctk.CTkFont(size=12),
            text_color="#888888",
            justify="left",
        ).pack(side="left", anchor="w")
        self._build_journey_markdown_help_button(hint_row).pack(side="right")

        body = ctk.CTkScrollableFrame(popup, label_text="")
        body.grid(row=1, column=0, sticky="nsew", padx=20, pady=(8, 8))

        field_boxes = {}
        section_order = (
            self._normalize_journey_section_order(existing)
            if existing else list(JOURNEY_SECTION_ORDER_DEFAULT)
        )
        height_store = existing if existing is not None else {}

        for key in section_order:
            label = JOURNEY_SECTION_LABELS[key]
            section_height = self._journey_section_height(height_store, key)
            section = ctk.CTkFrame(body, fg_color="#2F2F2F", corner_radius=8)
            section.pack(fill="x", pady=4, padx=2)

            section_header = ctk.CTkFrame(section, fg_color="transparent")
            section_header.pack(fill="x", padx=12, pady=(10, 4))
            ctk.CTkLabel(
                section_header, text=label, font=ctk.CTkFont(size=14, weight="bold"),
                anchor="w",
            ).pack(side="left", fill="x", expand=True)

            content_frame = ctk.CTkFrame(
                section, fg_color="transparent", height=section_height,
            )
            content_frame.pack(fill="x", padx=12, pady=(0, 4))
            content_frame.pack_propagate(False)
            box = ctk.CTkTextbox(content_frame, height=section_height)
            self._configure_ctk_textbox_height(box, section_height)
            box.pack(fill="both", expand=True)
            if existing:
                box.insert("1.0", existing.get(key, ""))
            field_boxes[key] = box

            resize_handle = ctk.CTkFrame(
                section, fg_color="#555555", height=10, corner_radius=4, cursor="sb_v_double_arrow",
            )
            resize_handle.pack_propagate(False)
            resize_handle.pack(fill="x", padx=16, pady=(0, 10))
            self._bind_journey_section_resize(
                resize_handle,
                height_store,
                key,
                box,
                is_textbox=True,
                container=content_frame,
            )

        btn_row = ctk.CTkFrame(popup, fg_color="transparent")
        btn_row.grid(row=2, column=0, sticky="ew", pady=12)

        def save_entry():
            backstory = field_boxes["backstory"].get("1.0", "end-1c").strip()
            if not backstory:
                messagebox.showwarning(
                    "Missing Backstory",
                    "Enter a backstory for this journey entry.",
                    parent=popup,
                )
                return
            section_heights = dict(height_store.get("section_heights", {}))
            for key in section_order:
                if key not in section_heights:
                    section_heights[key] = self._current_journey_widget_pixel_height(
                        field_boxes[key], True, height_store, key,
                    )
            payload = {
                "id": entry_id or uuid.uuid4().hex,
                "backstory": backstory,
                "short_term_goals": field_boxes["short_term_goals"].get("1.0", "end-1c").strip(),
                "mid_term_goals": field_boxes["mid_term_goals"].get("1.0", "end-1c").strip(),
                "long_term_goals": field_boxes["long_term_goals"].get("1.0", "end-1c").strip(),
                "section_order": list(section_order),
                "section_heights": section_heights,
            }
            desc["character_journey_entries"] = [payload]
            self._refresh_character_journey_tab()
            self._mark_description_page_built()
            popup.destroy()

        def delete_entry():
            if not existing:
                popup.destroy()
                return
            if not messagebox.askyesno(
                "Delete Journey",
                "Remove this character journey?",
                parent=popup,
            ):
                return
            desc["character_journey_entries"] = []
            self._refresh_character_journey_tab()
            self._mark_description_page_built()
            popup.destroy()

        ctk.CTkButton(
            btn_row, text="Save", width=100, fg_color=THEME_ORANGE,
            hover_color=getattr(self, 'primary_hover_color', '#a56b32'), command=save_entry,
        ).pack(side="left", padx=6)
        if existing:
            ctk.CTkButton(
                btn_row, text="Delete", width=100, fg_color="#555555",
                hover_color="#666666", command=delete_entry,
            ).pack(side="left", padx=6)
        ctk.CTkButton(
            btn_row, text="Cancel", width=100, fg_color="#666666",
            command=popup.destroy,
        ).pack(side="left", padx=6)

    def _delete_character_journey_entry(self, entry_id):
        if not messagebox.askyesno("Delete Journey Entry", "Remove this character journey entry?"):
            return
        desc = self._ensure_description_data()
        desc["character_journey_entries"] = [
            e for e in desc["character_journey_entries"] if e.get("id") != entry_id
        ]
        self._refresh_character_journey_tab()
        self._mark_description_page_built()

    def _schedule_portrait_height_sync(self, event=None):
        """Debounced configure handler to avoid recursive expand storms when window is not maximized."""
        if not self._is_page_active("Description"):
            return
        if getattr(self, "_portrait_sync_after", None):
            try:
                self.root.after_cancel(self._portrait_sync_after)
            except Exception:
                pass
        self._portrait_sync_after = self.root.after(80, self._do_sync_portrait_panel_height)

    def _ensure_portrait_panel_sized(self):
        """Size/render the portrait after the Description page is visible and laid out."""
        self._portrait_height_retry_count = 0
        self._portrait_last_sync_dims = None
        self.root.after_idle(self._do_sync_portrait_panel_height)
        self.root.after(120, self._do_sync_portrait_panel_height)
        self.root.after(300, self._do_sync_portrait_panel_height)

    def _do_sync_portrait_panel_height(self):
        self._sync_portrait_panel_height()

    def _measure_portrait_target_dims(self):
        """Return (width, height) for the portrait, or None if layout is not ready yet."""
        if not hasattr(self, "portrait_image_frame") or not hasattr(self, "description_left_panel"):
            return None
        try:
            if hasattr(self, "description_frame"):
                self.description_frame.update_idletasks()
            self.description_left_panel.update_idletasks()
        except Exception:
            pass
        left_h = int(self.description_left_panel.winfo_height() or 0)
        if left_h < 80:
            return None
        base_h = max(PORTRAIT_DISPLAY_HEIGHT, left_h - 8)
        target_h = base_h
        if hasattr(self, "root") and self.root.winfo_exists():
            root_h = int(self.root.winfo_height() or 0)
            max_h = max(120, root_h - 180)
            target_h = min(target_h, max_h)
        portrait_w = int(target_h * PORTRAIT_ASPECT_W / PORTRAIT_ASPECT_H)
        return portrait_w, target_h

    def _schedule_portrait_height_retry(self):
        count = int(getattr(self, "_portrait_height_retry_count", 0) or 0)
        if count >= 12 or not self._is_page_active("Description"):
            return
        self._portrait_height_retry_count = count + 1
        if getattr(self, "_portrait_height_retry_after", None):
            return
        self._portrait_height_retry_after = self.root.after(
            100, self._do_portrait_height_retry,
        )

    def _do_portrait_height_retry(self):
        self._portrait_height_retry_after = None
        self._sync_portrait_panel_height()

    def _sync_portrait_panel_height(self, event=None):
        if not hasattr(self, "portrait_image_frame") or not hasattr(self, "description_left_panel"):
            return
        if getattr(self, "_in_portrait_sync", False):
            return
        self._in_portrait_sync = True
        try:
            measured = self._measure_portrait_target_dims()
            if measured is None:
                self._schedule_portrait_height_retry()
                return
            portrait_w, target_h = measured
            new_dims = (portrait_w, target_h)
            if new_dims == getattr(self, "_portrait_last_sync_dims", None):
                return
            self._portrait_height_retry_count = 0
            self._portrait_render_width = portrait_w
            self._portrait_render_height = target_h
            self._portrait_last_sync_dims = new_dims
            self.portrait_panel.configure(width=portrait_w + 28, height=target_h + 58)
            self.portrait_image_frame.configure(width=portrait_w, height=target_h)
            self.portrait_image_label.configure(width=portrait_w, height=target_h)
            if new_dims != getattr(self, "_portrait_last_image_dims", None):
                self._portrait_last_image_dims = new_dims
                self._refresh_portrait_display()
        except Exception:
            pass
        finally:
            self._in_portrait_sync = False

    def _get_age_category(self):
        if hasattr(self, "description_age_var"):
            return self.description_age_var.get() or "Young"
        return self._ensure_description_data().get("age_category", "Young")

    def _get_stacked_age_mods(self, category=None):
        category = category or self._get_age_category()
        if category == "Young":
            return {}
        stacked = defaultdict(int)
        for tier in AGE_CATEGORY_ORDER:
            tier_mods = AGE_CATEGORY_MODS.get(tier, {})
            for ability_name, mod in tier_mods.items():
                stacked[ability_name] += int(mod or 0)
            if tier == category:
                break
        return dict(stacked)

    def _get_age_ability_mod(self, ability_name):
        mods = self._get_stacked_age_mods()
        return int(mods.get(ability_name, 0) or 0)

    def _format_age_modifiers(self, category):
        mods = self._get_stacked_age_mods(category)
        if not mods:
            return "No ability adjustments"
        physical = []
        mental = []
        for ab in ("Strength", "Dexterity", "Constitution"):
            val = mods.get(ab, 0)
            if val:
                physical.append(f"{ABILITY_DISPLAY_NAMES.get(ab, ab)} {val:+d}")
        for ab in ("Intelligence", "Wisdom", "Charisma"):
            val = mods.get(ab, 0)
            if val:
                mental.append(f"{ABILITY_DISPLAY_NAMES.get(ab, ab)} {val:+d}")
        parts = []
        if physical:
            parts.append(", ".join(physical))
        if mental:
            parts.append(", ".join(mental))
        return "  |  ".join(parts) if parts else "No ability adjustments"

    def _format_race_age_ranges(self, race):
        ranges = RACE_AGE_RANGES.get(race)
        if not ranges:
            return None
        return (
            f"Aging (SRD): Middle age {ranges['middle']} yr.; "
            f"Old {ranges['old']} yr.; Venerable {ranges['venerable']} yr.; "
            f"Maximum age {ranges['max_age']}"
        )

    def _get_current_race(self):
        if hasattr(self, "race_var"):
            return self.race_var.get().strip() or self.data.get("race", "Human")
        return self.data.get("race", "Human")

    def _get_race_data(self, race=None):
        return self.races.get(race or self._get_current_race(), {})

    def _get_racial_hit_dice_info(self, race=None):
        return self._get_race_data(race).get("racial_hit_dice")

    def _get_racial_level_adjustment(self, race=None):
        return int(self._get_race_data(race).get("level_adjustment", 0) or 0)

    def _get_racial_hit_dice_count(self, race=None):
        hd_info = self._get_racial_hit_dice_info(race)
        return int(hd_info.get("count", 0) or 0) if hd_info else 0

    def _get_effective_character_level(self):
        return (
            self._get_total_character_level()
            + self._get_racial_hit_dice_count()
            + self._get_racial_level_adjustment()
            + self._get_manual_level_adjustment()
        )

    def _format_ecl_breakdown(self):
        class_level = self._get_total_character_level()
        racial_hd = self._get_racial_hit_dice_count()
        la = self._get_racial_level_adjustment()
        generic_hd = self._get_generic_hd_count()
        manual_la = self._get_manual_level_adjustment()
        ecl = class_level + racial_hd + la + generic_hd + manual_la
        parts = [f"class {class_level}"]
        if racial_hd:
            parts.append(f"{racial_hd} racial HD")
        if generic_hd:
            parts.append(f"{generic_hd} generic HD")
        if la:
            parts.append(f"+{la} LA")
        if manual_la:
            parts.append(f"+{manual_la} LA")
        return ecl, " + ".join(parts)

    def _ensure_racial_hd_rolls(self):
        health = self.data.setdefault("health", {})
        count = self._get_racial_hit_dice_count()
        rolls = list(health.get("racial_hd_rolls", []))
        while len(rolls) < count:
            rolls.append(0)
        health["racial_hd_rolls"] = rolls[:count] if count else []
        return health["racial_hd_rolls"]

    def _get_racial_hd_hp_bonus(self):
        hd_info = self._get_racial_hit_dice_info()
        count = self._get_racial_hit_dice_count()
        if not hd_info or count <= 0:
            return 0
        rolls = self._ensure_racial_hd_rolls()
        rolls_sum = sum(int(roll or 0) for roll in rolls[:count])
        con_mod = self._effective_ability_mod("Constitution")
        return rolls_sum + (con_mod * count)

    def _get_racial_hd_skill_points(self):
        hd_info = self._get_racial_hit_dice_info()
        if not hd_info:
            return 0
        multiplier = int(hd_info.get("skill_points_multiplier", 0) or 0)
        rank_base = int(hd_info.get("skill_rank_base", 2) or 2)
        if multiplier <= 0:
            return 0
        int_mod = self._effective_ability_mod("Intelligence")
        return multiplier * (rank_base + int_mod)

    def _rebuild_generic_hd_rolls_ui(self):
        """Rebuild the rolls entry row for generic HD based on current count var."""
        if not hasattr(self, "generic_hd_rolls_frame") or not self.generic_hd_rolls_frame.winfo_exists():
            return
        for w in self.generic_hd_rolls_frame.winfo_children():
            w.destroy()
        self.generic_hd_roll_widgets.clear()

        try:
            count = max(0, int(self.generic_hd_count_var.get() or 0))
        except Exception:
            count = 0

        if count <= 0:
            return

        ctk.CTkLabel(
            self.generic_hd_rolls_frame,
            text=f"Racial HD rolls (manual, {count} dice):",
            font=ctk.CTkFont(size=12), text_color="#aaaaaa",
        ).pack(side="left", padx=(0, 6))

        rolls = self._ensure_generic_hd_rolls()
        for i in range(count):
            ctk.CTkLabel(self.generic_hd_rolls_frame, text=f"HD{i+1}:", width=40, anchor="w").pack(side="left")
            val = rolls[i] if i < len(rolls) else 0
            var = ctk.StringVar(value=str(val))
            ctk.CTkEntry(self.generic_hd_rolls_frame, textvariable=var, width=50).pack(side="left", padx=(0, 6))
            self.generic_hd_roll_widgets.append(var)

    def _get_generic_hd_count(self):
        return int(self.data.get("health", {}).get("generic_hd_count", 0) or 0)

    def _ensure_generic_hd_rolls(self):
        health = self.data.setdefault("health", {})
        count = self._get_generic_hd_count()
        rolls = list(health.get("generic_hd_rolls", []))
        while len(rolls) < count:
            rolls.append(0)
        health["generic_hd_rolls"] = rolls[:count] if count else []
        return health["generic_hd_rolls"]

    def _get_generic_hd_hp_bonus(self):
        health = self.data.get("health", {})
        if "racial_hd_hp" in health:
            return int(health.get("racial_hd_hp", 0) or 0)
        count = self._get_generic_hd_count()
        if count <= 0:
            return 0
        rolls = self._ensure_generic_hd_rolls()
        rolls_sum = sum(int(roll or 0) for roll in rolls[:count])
        con_mod = self._effective_ability_mod("Constitution")
        return rolls_sum + (con_mod * count)

    def _get_manual_level_adjustment(self):
        return int(self.data.get("health", {}).get("level_adjustment", 0) or 0)

    def _get_racial_hd_class_skills(self):
        hd_info = self._get_racial_hit_dice_info()
        if not hd_info:
            return set()
        return set(hd_info.get("class_skills", []))

    def _get_racial_skill_bonus_for_key(self, skill_key):
        bonuses = self._get_race_data().get("skill_bonuses", {})
        if not bonuses:
            return 0
        base = self._skill_base_name(skill_key)
        return int(bonuses.get(base, bonuses.get(skill_key, 0)) or 0)

    def _get_racial_natural_armor(self):
        return int(self._get_race_data().get("natural_armor", 0) or 0)

    def _get_racial_bab_bonus(self):
        hd_info = self._get_racial_hit_dice_info()
        return int(hd_info.get("bab", 0) or 0) if hd_info else 0

    def _get_racial_save_bonuses(self):
        hd_info = self._get_racial_hit_dice_info()
        if not hd_info:
            return {"fort": 0, "ref": 0, "will": 0}
        return {
            "fort": int(hd_info.get("fort", 0) or 0),
            "ref": int(hd_info.get("ref", 0) or 0),
            "will": int(hd_info.get("will", 0) or 0),
        }

    def _portrait_storage_path(self, portrait_file):
        if not portrait_file:
            return None
        if os.path.isabs(portrait_file) and os.path.isfile(portrait_file):
            return portrait_file
        return os.path.join(PORTRAITS_DIR, portrait_file)

    def _sidebar_bg_storage_path(self, bg_file):
        if not bg_file:
            return None
        if os.path.isabs(bg_file) and os.path.isfile(bg_file):
            return bg_file
        return os.path.join(SIDEBAR_BACKGROUNDS_DIR, bg_file)

    def _get_theme_default_bg_path(self):
        """Return path to default sidebar bg PNG for current theme, if the file exists in Theme BG folder.
        App-provided defaults (from the bundle / install dir's _internal/Theme BG) take precedence.
        User can add/override by placing PNGs in the install folder's Theme BG directory.
        """
        theme = getattr(self, "current_theme", "Dicey Default")
        filename = f"{theme}.png"
        # Check bundled app-provided Theme BG first (BUNDLE_DIR in frozen = _MEIPASS / the bundle root that contains _internal in the installed EXE layout)
        path = os.path.join(THEME_BG_DIR, filename)
        if os.path.isfile(path):
            return path
        # Also explicitly check common installed locations (in case _MEIPASS resolves differently)
        if getattr(sys, "frozen", False):
            try:
                install_dir = os.path.dirname(sys.executable)
                for cand in [
                    os.path.join(install_dir, "_internal", "Theme BG", filename),
                    os.path.join(install_dir, "Theme BG", filename),
                    os.path.join(sys._MEIPASS, "Theme BG", filename) if hasattr(sys, "_MEIPASS") else None,
                ]:
                    if cand and os.path.isfile(cand):
                        return cand
            except Exception:
                pass
        # Fallback to install-folder Theme BG (for custom theme defaults added by user)
        try:
            user_data_theme = os.path.join(os.path.dirname(CHARACTERS_DIR), "Theme BG", filename)
            if os.path.isfile(user_data_theme):
                return user_data_theme
        except Exception:
            pass
        return None

    def _get_sidebar_background_path(self):
        """Return the path to use for sidebar bg: character override (higher priority) or theme default.
        If lame_mode is enabled, return None to disable all sidebar background images.
        """
        if isinstance(getattr(self, "data", None), dict) and self.data.get("lame_mode", True):
            return None
        # Character-specific has higher priority
        bg_file = self.data.get("sidebar_bg_file", "") if isinstance(getattr(self, "data", None), dict) else ""
        if bg_file:
            path = self._sidebar_bg_storage_path(bg_file)
            if path and os.path.isfile(path):
                return path
        # Fallback to theme default
        return self._get_theme_default_bg_path()

    def _portrait_target_ratio(self):
        return PORTRAIT_ASPECT_W / PORTRAIT_ASPECT_H

    def _portrait_image_needs_crop(self, image_path, tolerance=0.01):
        if not HAS_PIL or not image_path or not os.path.isfile(image_path):
            return False
        with Image.open(image_path) as image:
            src_w, src_h = image.size
        if src_h <= 0 or src_w <= 0:
            return True
        ratio = src_w / src_h
        target = self._portrait_target_ratio()
        return abs(ratio - target) / target > tolerance

    def _portrait_max_crop_box(self, src_w, src_h):
        target_ratio = self._portrait_target_ratio()
        src_ratio = src_w / src_h if src_h else target_ratio
        if src_ratio >= target_ratio:
            crop_h = src_h
            crop_w = int(crop_h * target_ratio)
        else:
            crop_w = src_w
            crop_h = int(crop_w / target_ratio)
        crop_w = max(1, min(crop_w, src_w))
        crop_h = max(1, min(crop_h, src_h))
        return crop_w, crop_h

    def _sidebar_bg_target_ratio(self):
        return SIDEBAR_BG_TARGET_RATIO

    def _sidebar_bg_max_crop_box(self, src_w, src_h):
        """Calculate a tall crop box for sidebar bg (recommended ~200x1000)."""
        target_ratio = self._sidebar_bg_target_ratio()
        src_ratio = src_w / src_h if src_h else target_ratio
        if src_ratio >= target_ratio:
            # source is wider than target -> crop width to match tall ratio
            crop_h = src_h
            crop_w = int(crop_h * target_ratio)
        else:
            crop_w = src_w
            crop_h = int(crop_w / target_ratio)
        crop_w = max(1, min(crop_w, src_w))
        crop_h = max(1, min(crop_h, src_h))
        return crop_w, crop_h

    def _open_portrait_crop_popup(self, source_path, on_complete):
        pil_image = Image.open(source_path).convert("RGBA")
        src_w, src_h = pil_image.size
        crop_w, crop_h = self._portrait_max_crop_box(src_w, src_h)
        crop_state = {
            "x": max(0, (src_w - crop_w) // 2),
            "y": max(0, (src_h - crop_h) // 2),
            "w": crop_w,
            "h": crop_h,
        }
        lock_x = crop_w >= src_w
        lock_y = crop_h >= src_h

        popup = ctk.CTkToplevel(self.root)
        popup.title("Crop Portrait (9:16)")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=680, min_height=720)
        popup.resizable(True, True)
        popup.minsize(520, 560)

        header = ctk.CTkFrame(popup, fg_color="transparent")
        header.pack(fill="x", padx=20, pady=(16, 8))
        ctk.CTkLabel(
            header,
            text="Drag the highlighted area to choose your 9:16 portrait crop.",
            font=ctk.CTkFont(size=14),
            wraplength=580,
            justify="left",
        ).pack(anchor="w")

        canvas_host = ctk.CTkFrame(popup, fg_color="#1f1f1f", corner_radius=8)
        canvas_host.pack(fill="both", expand=True, padx=20, pady=(0, 8))

        max_preview_w, max_preview_h = 580, 520
        scale = min(max_preview_w / src_w, max_preview_h / src_h)
        preview_w = max(1, int(src_w * scale))
        preview_h = max(1, int(src_h * scale))

        canvas = tk.Canvas(
            canvas_host,
            width=preview_w,
            height=preview_h,
            bg="#1f1f1f",
            highlightthickness=0,
            cursor="fleur",
        )
        canvas.pack(padx=12, pady=12)

        preview_image = pil_image.resize((preview_w, preview_h), Image.Resampling.LANCZOS)
        preview_photo = ImageTk.PhotoImage(preview_image)
        canvas.create_image(0, 0, anchor="nw", image=preview_photo, tags=("base_image",))
        canvas.image = preview_photo

        overlay_items = []

        def _preview_rect():
            x1 = int(crop_state["x"] * scale)
            y1 = int(crop_state["y"] * scale)
            x2 = int((crop_state["x"] + crop_state["w"]) * scale)
            y2 = int((crop_state["y"] + crop_state["h"]) * scale)
            return x1, y1, x2, y2

        def _redraw_crop_overlay():
            for item_id in overlay_items:
                canvas.delete(item_id)
            overlay_items.clear()

            x1, y1, x2, y2 = _preview_rect()
            shade = "#000000"
            if y1 > 0:
                overlay_items.append(canvas.create_rectangle(
                    0, 0, preview_w, y1, fill=shade, stipple="gray50", outline="",
                ))
            if y2 < preview_h:
                overlay_items.append(canvas.create_rectangle(
                    0, y2, preview_w, preview_h, fill=shade, stipple="gray50", outline="",
                ))
            if x1 > 0:
                overlay_items.append(canvas.create_rectangle(
                    0, y1, x1, y2, fill=shade, stipple="gray50", outline="",
                ))
            if x2 < preview_w:
                overlay_items.append(canvas.create_rectangle(
                    x2, y1, preview_w, y2, fill=shade, stipple="gray50", outline="",
                ))
            overlay_items.append(canvas.create_rectangle(
                x1, y1, x2, y2, outline=THEME_ORANGE, width=3,
            ))

        drag_state = {"active": False, "start_x": 0, "start_y": 0, "orig_x": 0, "orig_y": 0}

        def _clamp_crop_position():
            crop_state["x"] = max(0, min(src_w - crop_state["w"], crop_state["x"]))
            crop_state["y"] = max(0, min(src_h - crop_state["h"], crop_state["y"]))
            if lock_x:
                crop_state["x"] = 0
            if lock_y:
                crop_state["y"] = 0

        def _on_press(event):
            drag_state["active"] = True
            drag_state["start_x"] = event.x
            drag_state["start_y"] = event.y
            drag_state["orig_x"] = crop_state["x"]
            drag_state["orig_y"] = crop_state["y"]

        def _on_drag(event):
            if not drag_state["active"]:
                return
            dx = (event.x - drag_state["start_x"]) / scale
            dy = (event.y - drag_state["start_y"]) / scale
            crop_state["x"] = int(drag_state["orig_x"] + dx)
            crop_state["y"] = int(drag_state["orig_y"] + dy)
            _clamp_crop_position()
            _redraw_crop_overlay()

        def _on_release(_event=None):
            drag_state["active"] = False

        canvas.bind("<ButtonPress-1>", _on_press)
        canvas.bind("<B1-Motion>", _on_drag)
        canvas.bind("<ButtonRelease-1>", _on_release)

        def _on_resize(event=None):
            nonlocal preview_w, preview_h, scale, preview_photo
            host_w = max(120, event.width - 24) if event and event.width > 40 else preview_w
            host_h = max(120, event.height - 24) if event and event.height > 40 else preview_h
            scale = min(host_w / src_w, host_h / src_h)
            preview_w = max(1, int(src_w * scale))
            preview_h = max(1, int(src_h * scale))
            canvas.configure(width=preview_w, height=preview_h)
            preview_image = pil_image.resize((preview_w, preview_h), Image.Resampling.LANCZOS)
            preview_photo = ImageTk.PhotoImage(preview_image)
            canvas.image = preview_photo
            canvas.delete("base_image")
            canvas.create_image(0, 0, anchor="nw", image=preview_photo, tags=("base_image",))
            canvas.tag_lower("base_image")
            _redraw_crop_overlay()

        canvas_host.bind("<Configure>", _on_resize)
        _redraw_crop_overlay()

        btn_row = ctk.CTkFrame(popup, fg_color="transparent")
        btn_row.pack(pady=(4, 16))

        def _close_crop_popup():
            try:
                popup.grab_release()
            except tk.TclError:
                pass
            popup.destroy()

        def _apply_crop():
            box = (
                crop_state["x"],
                crop_state["y"],
                crop_state["x"] + crop_state["w"],
                crop_state["y"] + crop_state["h"],
            )
            cropped = pil_image.crop(box)
            _close_crop_popup()
            self.root.after_idle(lambda img=cropped.copy(): on_complete(img))

        ctk.CTkButton(
            btn_row, text="Use Crop", width=110, fg_color=THEME_ORANGE,
            hover_color=getattr(self, 'primary_hover_color', '#a56b32'), command=_apply_crop,
        ).pack(side="left", padx=6)
        ctk.CTkButton(
            btn_row, text="Cancel", width=110, fg_color="#666666",
            command=_close_crop_popup,
        ).pack(side="left", padx=6)

    def _open_sidebar_bg_crop_popup(self, source_path, on_complete):
        """Crop tool for sidebar background. Recommends a tall narrow image (~200x1000).
        User drags the box to pick the vertical slice of their image to use as the bg.
        The cropped result will be scaled to exactly fill the sidebar at display time.
        """
        if not HAS_PIL:
            return
        pil_image = Image.open(source_path).convert("RGBA")
        src_w, src_h = pil_image.size
        crop_w, crop_h = self._sidebar_bg_max_crop_box(src_w, src_h)
        crop_state = {
            "x": max(0, (src_w - crop_w) // 2),
            "y": max(0, (src_h - crop_h) // 2),
            "w": crop_w,
            "h": crop_h,
        }
        lock_x = crop_w >= src_w
        lock_y = crop_h >= src_h

        popup = ctk.CTkToplevel(self.root)
        popup.title("Crop Sidebar Background")
        popup.grab_set()
        self._size_and_center_popup_to_content(popup, min_width=680, min_height=720)
        popup.resizable(True, True)
        popup.minsize(520, 560)

        header = ctk.CTkFrame(popup, fg_color="transparent")
        header.pack(fill="x", padx=20, pady=(16, 8))
        ctk.CTkLabel(
            header,
            text="Drag the box to select the area for your sidebar background.\n"
                 "Recommended: 200px wide × 900–1200px tall (tall image to fill the left sidebar).\n"
                 "The selection will be resized to perfectly fit the sidebar width & height.",
            font=ctk.CTkFont(size=13),
            wraplength=620,
            justify="left",
        ).pack(anchor="w")

        canvas_host = ctk.CTkFrame(popup, fg_color="#1f1f1f", corner_radius=8)
        canvas_host.pack(fill="both", expand=True, padx=20, pady=(0, 8))

        max_preview_w, max_preview_h = 580, 520
        scale = min(max_preview_w / src_w, max_preview_h / src_h)
        preview_w = max(1, int(src_w * scale))
        preview_h = max(1, int(src_h * scale))

        canvas = tk.Canvas(
            canvas_host,
            width=preview_w,
            height=preview_h,
            bg="#1f1f1f",
            highlightthickness=0,
            cursor="fleur",
        )
        canvas.pack(padx=12, pady=12)

        preview_image = pil_image.resize((preview_w, preview_h), Image.Resampling.LANCZOS)
        preview_photo = ImageTk.PhotoImage(preview_image)
        canvas.create_image(0, 0, anchor="nw", image=preview_photo, tags=("base_image",))
        canvas.image = preview_photo

        overlay_items = []

        def _preview_rect():
            x1 = int(crop_state["x"] * scale)
            y1 = int(crop_state["y"] * scale)
            x2 = int((crop_state["x"] + crop_state["w"]) * scale)
            y2 = int((crop_state["y"] + crop_state["h"]) * scale)
            return x1, y1, x2, y2

        def _redraw_crop_overlay():
            for item_id in overlay_items:
                canvas.delete(item_id)
            overlay_items.clear()

            x1, y1, x2, y2 = _preview_rect()
            shade = "#000000"
            # Darken the parts outside the crop box (top, bottom, sides)
            if y1 > 0:
                overlay_items.append(canvas.create_rectangle(0, 0, preview_w, y1, fill=shade, stipple="gray50", outline=""))
            if y2 < preview_h:
                overlay_items.append(canvas.create_rectangle(0, y2, preview_w, preview_h, fill=shade, stipple="gray50", outline=""))
            if x1 > 0:
                overlay_items.append(canvas.create_rectangle(0, y1, x1, y2, fill=shade, stipple="gray50", outline=""))
            if x2 < preview_w:
                overlay_items.append(canvas.create_rectangle(x2, y1, preview_w, y2, fill=shade, stipple="gray50", outline=""))

            # Bright border around the selected crop area
            overlay_items.append(canvas.create_rectangle(x1, y1, x2, y2, outline="#c77626", width=2))

        def _clamp_crop_position():
            crop_state["x"] = max(0, min(src_w - crop_state["w"], crop_state["x"]))
            crop_state["y"] = max(0, min(src_h - crop_state["h"], crop_state["y"]))

        def _on_press(event):
            drag_state["active"] = True
            drag_state["orig_x"] = crop_state["x"]
            drag_state["orig_y"] = crop_state["y"]
            drag_state["start_x"] = event.x
            drag_state["start_y"] = event.y

        def _on_drag(event):
            if not drag_state.get("active"):
                return
            dx = (event.x - drag_state["start_x"]) / scale
            dy = (event.y - drag_state["start_y"]) / scale
            crop_state["x"] = int(drag_state["orig_x"] + dx)
            crop_state["y"] = int(drag_state["orig_y"] + dy)
            _clamp_crop_position()
            _redraw_crop_overlay()

        def _on_release(event):
            drag_state["active"] = False

        drag_state = {"active": False}
        canvas.bind("<ButtonPress-1>", _on_press)
        canvas.bind("<B1-Motion>", _on_drag)
        canvas.bind("<ButtonRelease-1>", _on_release)

        def _on_resize(event):
            # simple re-scale on host resize (basic support)
            pass

        canvas_host.bind("<Configure>", _on_resize)
        _redraw_crop_overlay()

        btn_row = ctk.CTkFrame(popup, fg_color="transparent")
        btn_row.pack(pady=(4, 16))

        def _close_crop_popup():
            try:
                popup.grab_release()
            except tk.TclError:
                pass
            popup.destroy()

        def _apply_crop():
            box = (
                crop_state["x"],
                crop_state["y"],
                crop_state["x"] + crop_state["w"],
                crop_state["y"] + crop_state["h"],
            )
            cropped = pil_image.crop(box)
            _close_crop_popup()
            self.root.after_idle(lambda img=cropped.copy(): on_complete(img))

        ctk.CTkButton(
            btn_row, text="Use Crop", width=110, fg_color=THEME_ORANGE,
            hover_color=getattr(self, 'primary_hover_color', '#a56b32'), command=_apply_crop,
        ).pack(side="left", padx=6)
        ctk.CTkButton(
            btn_row, text="Cancel", width=110, fg_color="#666666",
            command=_close_crop_popup,
        ).pack(side="left", padx=6)

    def _store_portrait_image(self, pil_image=None, source_path=None):
        os.makedirs(PORTRAITS_DIR, exist_ok=True)
        safe_name = re.sub(
            r"[^\w\-]+", "_", self.data.get("name", "character"),
        ).strip("_") or "character"
        dest_name = f"{safe_name}_{uuid.uuid4().hex[:8]}.png"
        dest_path = os.path.join(PORTRAITS_DIR, dest_name)
        try:
            if pil_image is not None:
                pil_image.save(dest_path, format="PNG")
            elif source_path:
                ext = os.path.splitext(source_path)[1].lower() or ".png"
                dest_name = f"{safe_name}_{uuid.uuid4().hex[:8]}{ext}"
                dest_path = os.path.join(PORTRAITS_DIR, dest_name)
                shutil.copy2(source_path, dest_path)
            else:
                return
        except OSError as exc:
            messagebox.showerror("Portrait Upload", f"Could not save image:\n{exc}")
            return

        desc = self._ensure_description_data()
        old_file = desc.get("portrait_file", "")
        desc["portrait_file"] = dest_name
        old_path = self._portrait_storage_path(old_file)
        if old_path and old_path != dest_path and os.path.isfile(old_path):
            try:
                os.remove(old_path)
            except OSError:
                pass
        self._refresh_portrait_display(pil_image=pil_image)
        self._mark_description_page_built()
        self._portrait_needs_cloud_upload = True
        self._mark_cloud_sync_dirty()

    def _embed_portrait_for_cloud(self):
        """Embed local portrait as base64 into description['portrait_base64'] for cloud sync.
        The image bytes travel with the character data so portraits persist across machines/cloud.
        """
        try:
            desc = self.data.setdefault("description", {})
            portrait_file = desc.get("portrait_file", "")
            if not portrait_file:
                return
            full_path = self._portrait_storage_path(portrait_file)
            if not full_path or not os.path.isfile(full_path):
                return
            with open(full_path, "rb") as f:
                img_bytes = f.read()
            desc["portrait_base64"] = base64.b64encode(img_bytes).decode("ascii")
            desc["portrait_file"] = portrait_file  # keep filename ref
        except Exception as e:
            print(f"Portrait embed for cloud failed: {e}")

    def _extract_and_save_cloud_portrait(self):
        """If cloud data contains portrait_base64, decode + save to local PORTRAITS_DIR,
        update portrait_file, strip the base64 (don't keep it in local JSONs), and refresh UI.
        """
        try:
            desc = self.data.setdefault("description", {})
            b64_data = desc.get("portrait_base64")
            if not b64_data:
                return
            self._update_cloud_portrait_cache(
                portrait_base64=b64_data,
                portrait_file=desc.get("portrait_file", ""),
            )
            img_bytes = base64.b64decode(b64_data)
            os.makedirs(PORTRAITS_DIR, exist_ok=True)
            safe_name = re.sub(
                r"[^\w\-]+", "_", self.data.get("name", "character"),
            ).strip("_") or "character"
            dest_name = f"{safe_name}_{uuid.uuid4().hex[:8]}.png"
            dest_path = os.path.join(PORTRAITS_DIR, dest_name)
            with open(dest_path, "wb") as f:
                f.write(img_bytes)
            old_file = desc.get("portrait_file", "")
            desc["portrait_file"] = dest_name
            if "portrait_base64" in desc:
                del desc["portrait_base64"]
            self._update_cloud_portrait_cache(
                portrait_base64=b64_data,
                portrait_file=dest_name,
            )
            # cleanup previous local file
            if old_file and old_file != dest_name:
                old_path = self._portrait_storage_path(old_file)
                if old_path and os.path.isfile(old_path) and old_path != dest_path:
                    try:
                        os.remove(old_path)
                    except OSError:
                        pass
            # refresh display
            if hasattr(self, "_refresh_portrait_display"):
                try:
                    self.root.after_idle(self._refresh_portrait_display)
                except Exception:
                    pass
            self._mark_description_page_stale()
        except Exception as e:
            print(f"Portrait extract from cloud failed: {e}")

    def _strip_portrait_base64(self):
        """Remove portrait_base64 from local data (keeps local JSONs smaller;
        the actual image file stays in PORTRAITS_DIR).
        """
        try:
            desc = self.data.setdefault("description", {})
            if "portrait_base64" in desc:
                del desc["portrait_base64"]
        except Exception:
            pass

    def _portrait_image_for_display(self, source_path=None, pil_image=None, width=None, height=None):
        if not HAS_PIL:
            return None
        display_w = width or getattr(self, "_portrait_render_width", PORTRAIT_DISPLAY_WIDTH)
        display_h = height or getattr(self, "_portrait_render_height", PORTRAIT_DISPLAY_HEIGHT)
        if pil_image is not None:
            image = pil_image.convert("RGBA")
        elif source_path and os.path.isfile(source_path):
            image = Image.open(source_path).convert("RGBA")
        else:
            return None
        target_ratio = PORTRAIT_ASPECT_W / PORTRAIT_ASPECT_H
        src_w, src_h = image.size
        src_ratio = src_w / src_h if src_h else 1
        if src_ratio > target_ratio:
            new_w = int(src_h * target_ratio)
            left = (src_w - new_w) // 2
            image = image.crop((left, 0, left + new_w, src_h))
        elif src_ratio < target_ratio:
            new_h = int(src_w / target_ratio)
            top = (src_h - new_h) // 2
            image = image.crop((0, top, src_w, top + new_h))
        image = image.resize((display_w, display_h), Image.Resampling.LANCZOS)
        return ctk.CTkImage(
            light_image=image,
            dark_image=image,
            size=(display_w, display_h),
        )

    def _portrait_has_image(self):
        desc = self._ensure_description_data()
        path = self._portrait_storage_path(desc.get("portrait_file", ""))
        return bool(path and os.path.isfile(path) and HAS_PIL)

    def _cancel_portrait_hover_hide(self):
        after_id = getattr(self, "_portrait_hover_hide_after_id", None)
        if after_id is not None:
            try:
                self.root.after_cancel(after_id)
            except Exception:
                pass
            self._portrait_hover_hide_after_id = None

    def _hide_portrait_remove_button(self):
        self._cancel_portrait_hover_hide()
        if hasattr(self, "portrait_remove_btn"):
            self.portrait_remove_btn.place_forget()

    def _show_portrait_remove_button(self):
        if not self._portrait_has_image() or not hasattr(self, "portrait_remove_btn"):
            return
        self._cancel_portrait_hover_hide()
        self.portrait_remove_btn.place(relx=1.0, rely=0.0, x=-8, y=8, anchor="ne")
        self.portrait_remove_btn.lift()

    def _on_portrait_hover_enter(self, _event=None):
        self._show_portrait_remove_button()

    def _on_portrait_hover_leave(self, _event=None):
        self._cancel_portrait_hover_hide()
        self._portrait_hover_hide_after_id = self.root.after(
            120, self._hide_portrait_remove_button,
        )

    def _bind_portrait_hover_controls(self, enabled):
        if not hasattr(self, "portrait_image_frame"):
            return
        widgets = [
            self.portrait_image_frame,
            self.portrait_image_label,
        ]
        if hasattr(self, "portrait_remove_btn"):
            widgets.append(self.portrait_remove_btn)
        for widget in widgets:
            widget.unbind("<Enter>")
            widget.unbind("<Leave>")
            if enabled:
                widget.bind("<Enter>", self._on_portrait_hover_enter)
                widget.bind("<Leave>", self._on_portrait_hover_leave)

    def _refresh_portrait_display(self, pil_image=None):
        if not hasattr(self, "portrait_image_label"):
            return
        if pil_image is not None:
            portrait_image = self._portrait_image_for_display(pil_image=pil_image)
        else:
            desc = self._ensure_description_data()
            path = self._portrait_storage_path(desc.get("portrait_file", ""))
            portrait_image = self._portrait_image_for_display(source_path=path)
        has_portrait = portrait_image is not None
        if portrait_image:
            self._portrait_ctk_image = portrait_image
            self.portrait_image_label.configure(image=portrait_image, text="")
        else:
            self._portrait_ctk_image = None
            self.portrait_image_label.configure(image=None, text="")
        if hasattr(self, "portrait_add_btn"):
            if has_portrait:
                self.portrait_add_btn.place_forget()
            else:
                self.portrait_add_btn.place(relx=0.5, rely=0.46, anchor="center")
        if hasattr(self, "portrait_empty_title"):
            if has_portrait:
                self.portrait_empty_title.place_forget()
            else:
                self.portrait_empty_title.place(relx=0.5, rely=0.18, anchor="center")
        self._refresh_sb_portrait()
        if hasattr(self, "portrait_hint_label"):
            if has_portrait:
                self.portrait_hint_label.place_forget()
            else:
                self.portrait_hint_label.place(relx=0.5, rely=0.82, anchor="center")
        self._bind_portrait_hover_controls(has_portrait)
        if not has_portrait:
            self._hide_portrait_remove_button()

    def _upload_portrait(self):
        if not HAS_PIL:
            messagebox.showerror(
                "Portrait Upload",
                "Image support requires Pillow.\nInstall with: pip install Pillow",
            )
            return
        file_path = filedialog.askopenfilename(
            title="Choose Character Portrait",
            filetypes=[
                ("Image files", "*.png *.jpg *.jpeg *.gif *.webp *.bmp"),
                ("All files", "*.*"),
            ],
        )
        if not file_path:
            return
        if self._portrait_image_needs_crop(file_path):
            self._open_portrait_crop_popup(
                file_path,
                on_complete=lambda image: self._store_portrait_image(pil_image=image),
            )
            return
        self._store_portrait_image(source_path=file_path)

    def _clear_portrait(self):
        desc = self._ensure_description_data()
        old_path = self._portrait_storage_path(desc.get("portrait_file", ""))
        desc["portrait_file"] = ""
        if old_path and os.path.isfile(old_path):
            try:
                os.remove(old_path)
            except OSError:
                pass
        self._hide_portrait_remove_button()
        self._refresh_portrait_display()
        self._mark_description_page_built()
        self._update_cloud_portrait_cache()
        self._portrait_needs_cloud_upload = True
        self._mark_cloud_sync_dirty()

    def _choose_sidebar_background(self):
        if not HAS_PIL:
            messagebox.showerror(
                "Sidebar Background",
                "Image support requires Pillow.\nInstall with: pip install Pillow",
            )
            return
        file_path = filedialog.askopenfilename(
            title="Choose Sidebar Background Image (local only)",
            filetypes=[
                ("Image files", "*.png *.jpg *.jpeg *.gif *.webp *.bmp"),
                ("All files", "*.*"),
            ],
        )
        if not file_path:
            return
        # For sidebar, we always offer crop UI for flexibility (user can adjust the slice)
        # Recommend tall image; crop box will be tall/narrow by default.
        self._open_sidebar_bg_crop_popup(
            file_path,
            on_complete=lambda image: self._store_sidebar_bg_image(pil_image=image),
        )

    def _clear_sidebar_background(self):
        old_file = self.data.get("sidebar_bg_file", "")
        self.data["sidebar_bg_file"] = ""
        # Clearing custom bg puts back to default "lame mode" (no sidebar bg images)
        self.data["lame_mode"] = True
        if hasattr(self, "hamburger_lame_var"):
            try:
                self.hamburger_lame_var.set(True)
            except Exception:
                pass
        old_path = self._sidebar_bg_storage_path(old_file)
        if old_path and os.path.isfile(old_path):
            try:
                os.remove(old_path)
            except OSError:
                pass
        self._refresh_sidebar_background()

    def _store_sidebar_bg_image(self, pil_image=None, source_path=None):
        os.makedirs(SIDEBAR_BACKGROUNDS_DIR, exist_ok=True)
        safe_name = re.sub(
            r"[^\w\-]+", "_", self.data.get("name", "character"),
        ).strip("_") or "character"
        dest_name = f"sidebar_{safe_name}_{uuid.uuid4().hex[:8]}.png"
        dest_path = os.path.join(SIDEBAR_BACKGROUNDS_DIR, dest_name)
        try:
            if pil_image is not None:
                pil_image.save(dest_path, format="PNG")
            elif source_path:
                ext = os.path.splitext(source_path)[1].lower() or ".png"
                dest_name = f"sidebar_{safe_name}_{uuid.uuid4().hex[:8]}{ext}"
                dest_path = os.path.join(SIDEBAR_BACKGROUNDS_DIR, dest_name)
                shutil.copy2(source_path, dest_path)
            else:
                return
        except OSError as exc:
            messagebox.showerror("Sidebar Background", f"Could not save image:\n{exc}")
            return

        old_file = self.data.get("sidebar_bg_file", "")
        self.data["sidebar_bg_file"] = dest_name
        # Adding a custom sidebar background turns off lame mode (so the custom one shows)
        self.data["lame_mode"] = False
        if hasattr(self, "hamburger_lame_var"):
            try:
                self.hamburger_lame_var.set(False)
            except Exception:
                pass
        old_path = self._sidebar_bg_storage_path(old_file)
        if old_path and old_path != dest_path and os.path.isfile(old_path):
            try:
                os.remove(old_path)
            except OSError:
                pass
        self._refresh_sidebar_background()
        self._refresh_sb_portrait()

    def _refresh_sb_portrait(self):
        """Refresh the SB portrait in sidebar (if enabled).
        Uses the same portrait source image, center-cropped to 9:16 (matching description portrait ratio),
        resized larger. No border around it. Clipping is acceptable if it exceeds available space.
        """
        if not hasattr(self, "sb_portrait_frame") or not hasattr(self, "sb_portrait_label"):
            return
        enabled = bool(self.data.get("sb_portrait", False)) if isinstance(getattr(self, "data", None), dict) else False
        if not enabled:
            try:
                self.sb_portrait_frame.pack_forget()
            except Exception:
                pass
            return
        # Re-pack above the roll chat if it was removed from the layout.
        try:
            chat = getattr(self, "sb_roll_log_frame", None)
            chat_visible = (
                chat is not None
                and chat.winfo_exists()
                and not getattr(self, "_sb_roll_log_hidden", False)
            )
            if chat_visible:
                self.sb_portrait_frame.pack(pady=(2, 6), padx=4, before=chat)
            else:
                self.sb_portrait_frame.pack(pady=(2, 6), padx=4)
        except Exception:
            pass
        if not HAS_PIL:
            self.sb_portrait_label.configure(image=None, text="No PIL")
            return
        # Get portrait source (same as description portrait)
        desc = self._ensure_description_data()
        path = self._portrait_storage_path(desc.get("portrait_file", "") or self.data.get("portrait_file", ""))
        if not path or not os.path.isfile(path):
            self.sb_portrait_label.configure(image=None, text="No Portrait")
            return
        try:
            pil = Image.open(path).convert("RGBA")
            src_w, src_h = pil.size
            target_ratio = 9.0 / 16.0
            src_ratio = src_w / float(src_h) if src_h else target_ratio
            if src_ratio >= target_ratio:
                crop_h = src_h
                crop_w = int(crop_h * target_ratio)
            else:
                crop_w = src_w
                crop_h = int(crop_w / target_ratio)
            crop_w = max(1, min(crop_w, src_w))
            crop_h = max(1, min(crop_h, src_h))
            left = max(0, (src_w - crop_w) // 2)
            top = max(0, (src_h - crop_h) // 2)
            cropped = pil.crop((left, top, left + crop_w, top + crop_h))
            display_w = 172
            display_h = int(display_w * 16 / 9)
            resized = cropped.resize((display_w, display_h), Image.Resampling.LANCZOS)
            ctk_img = ctk.CTkImage(light_image=resized, dark_image=resized, size=(display_w, display_h))
            self.sb_portrait_label.configure(image=ctk_img, text="")
            self._sb_portrait_ctk_image = ctk_img  # retain reference
        except Exception as e:
            print(f"SB Portrait refresh error: {e}")
            self.sb_portrait_label.configure(image=None, text="Error")

    def _refresh_sidebar_background(self):
        """Load (if any) local sidebar bg file, resize it to current sidebar dims, and draw on the canvas.
        The canvas sits behind the nav buttons etc.
        """
        if not hasattr(self, "sidebar_bg_canvas") or not HAS_PIL:
            return
        path = self._get_sidebar_background_path()
        canvas = self.sidebar_bg_canvas
        canvas.delete("bg")
        self._sidebar_bg_photo = None
        if not path or not os.path.isfile(path):
            # fallback dark
            try:
                canvas.configure(bg="#1f1f1f")
            except Exception:
                pass
            return
        try:
            pil = Image.open(path).convert("RGBA")
            # ensure sidebar has current size
            if hasattr(self, "sidebar"):
                self.sidebar.update_idletasks()
                w = max(10, self.sidebar.winfo_width())
                h = max(10, self.sidebar.winfo_height())
            else:
                w, h = SIDEBAR_BG_RECOMMENDED_WIDTH, SIDEBAR_BG_RECOMMENDED_HEIGHT
            resized = pil.resize((w, h), Image.Resampling.LANCZOS)
            self._sidebar_bg_photo = ImageTk.PhotoImage(resized)
            canvas.create_image(0, 0, anchor="nw", image=self._sidebar_bg_photo, tags="bg")
            # keep canvas at bottom
            canvas.lower()
        except Exception as e:
            print(f"Sidebar bg refresh error: {e}")
            try:
                canvas.configure(bg="#1f1f1f")
            except Exception:
                pass

        # Also refresh the SB Portrait widget (if the toggle is on; it forces lame_mode so no full bg conflicts)
        self._refresh_sb_portrait()
        self._refresh_death_skull_overlay()

    def _on_description_age_changed(self, choice):
        if hasattr(self, "description_age_mods_label"):
            self.description_age_mods_label.configure(
                text=self._format_age_modifiers(choice),
            )
        self.refresh_all()

    def _on_description_age_years_changed(self, _event=None):
        if hasattr(self, "description_age_years_var"):
            self._ensure_description_data()["age"] = self.description_age_years_var.get().strip()

    def _set_description_textbox(self, widget, text):
        widget.delete("1.0", "end")
        widget.insert("1.0", text or "")

    def _bind_description_textbox(self, widget, key):
        def sync(_event=None):
            self._ensure_description_data()[key] = widget.get("1.0", "end-1c")
        widget.bind("<FocusOut>", sync)
        widget.bind("<KeyRelease>", sync)

    def _sync_description_to_data(self):
        if not hasattr(self, "description_textboxes"):
            return
        desc = self._ensure_description_data()
        for key, widget in self.description_textboxes.items():
            try:
                desc[key] = widget.get("1.0", "end-1c")
            except Exception:
                pass
        if hasattr(self, "description_age_years_var"):
            desc["age"] = self.description_age_years_var.get().strip()
        if hasattr(self, "description_age_var"):
            desc["age_category"] = self.description_age_var.get()
        if hasattr(self, "description_height_var"):
            desc["height"] = self.description_height_var.get()
        if hasattr(self, "description_weight_var"):
            desc["weight"] = self.description_weight_var.get()
        if hasattr(self, "description_hair_var"):
            desc["hair"] = self.description_hair_var.get()
        if hasattr(self, "description_eyes_var"):
            desc["eyes"] = self.description_eyes_var.get()
        if hasattr(self, "description_ethnicity_var"):
            desc["ethnicity"] = self.description_ethnicity_var.get()
        if hasattr(self, "description_deity_var"):
            desc["deity"] = self.description_deity_var.get()
        self.data["notes"] = desc.get("notes", "")

    def build_description_page(self):
        self._ensure_description_data()
        if not hasattr(self, "description_frame") or self.description_frame is None:
            self.description_frame = ctk.CTkFrame(self.content)
        else:
            for widget in self.description_frame.winfo_children():
                widget.destroy()

        self.description_frame.columnconfigure(0, weight=1)
        self.description_frame.rowconfigure(1, weight=1)

        ctk.CTkLabel(
            self.description_frame, text="Description",
            font=ctk.CTkFont(size=22, weight="bold"),
        ).grid(row=0, column=0, sticky="w", padx=16, pady=(12, 6))

        content_row = ctk.CTkFrame(self.description_frame, fg_color="transparent")
        content_row.grid(row=1, column=0, sticky="nsew", padx=12, pady=(0, 12))
        content_row.columnconfigure(0, weight=1)
        content_row.columnconfigure(1, weight=0)
        content_row.rowconfigure(0, weight=1)

        desc = self._ensure_description_data()
        self._portrait_render_width = PORTRAIT_DISPLAY_WIDTH
        self._portrait_render_height = PORTRAIT_DISPLAY_HEIGHT
        self._portrait_last_sync_dims = None
        self._portrait_last_image_dims = None
        self._portrait_height_retry_count = 0

        self.description_left_panel = ctk.CTkFrame(content_row, fg_color="transparent")
        self.description_left_panel.grid(row=0, column=0, sticky="nsew", padx=(0, 12))
        self.description_left_panel.rowconfigure(1, weight=1)
        self.description_left_panel.columnconfigure(0, weight=1)

